            html_block = (
                "<div class='matrix-col'>"
                "<div class='matrix-head'>"
                f"<div><h3>{_html(rec['name'])}</h3><span class='status-badge'>{_html(rec.get('status', 'Monitor'))}</span></div>"
                f"<span class='deviation-badge {_deviation_class(construction_dev)}'><span><span class='deviation-title'>Deviation vs Forecast</span><span class='dev-number'>{_html(_fmt_deviation(construction_dev))}</span></span></span>"
                "</div>"
                f"{progress_bar_html('Construction progress', rec.get('construction_actual'), rec.get('construction_forecast'), construction_dev, rec.get('construction_etc', scope_baseline_etc(rec['scope_id'], selected_year, selected_week)))}"
                f"{progress_bar_html('Engineering progress', engineering_actual, engineering_forecast, engineering_dev, rec.get('engineering_etc', 'To be provided'))}"
                f"{cost_candle_html(rec['scope_id'], cost, 'Cost position')}"
                f"<div class='next-fc'><b>Next week FC</b>{_html(rec.get('next_week_fc') or 'Not published in selected-week data')}</div>"
                "<div class='gate-row'>"
                f"<div class='gate-pill'><span>Open quality gates</span><b>{len(q_items)}</b>{tooltip_html(rec['name'] + ' open quality gates', q_items, 'Active-week quality / completion gates.')}</div>"
                f"<div class='gate-pill'><span>Open engineering gates</span><b>{len(e_items)}</b>{tooltip_html(rec['name'] + ' open engineering gates', e_items, 'Active-week engineering / design gates.')}</div>"
                "</div>"
                "</div>"
            )
            st.markdown(html_block, unsafe_allow_html=True)

