def build_milestone_df(records: List[Dict[str, Any]], scope_filter: Optional[str] = None) -> pd.DataFrame:
    rows: List[Dict[str, Any]] = []
    for rec in records:
        if scope_filter and rec["scope_id"] != scope_filter:
            continue
        for ms in rec.get("milestones", []) or []:
            fc = _parse_date(ms.get("forecast"))
            if pd.isna(fc):
                continue
            basis = milestone_date_basis(ms.get("name", "Milestone"))
            rows.append({
                "Scope": rec["name"],
                "Milestone": ms.get("name", "Milestone"),
                "Risk": ms.get("risk", "Milestone"),
                "Date basis": basis,
                "Responsible": ms.get("responsible") or rec.get("default_responsible") or infer_responsible(ms.get("name", ""), rec.get("default_responsible", "TBC")),
                "Start / planned": _parse_date(ms.get("planned")),
                "Forecast": fc,
                "Start label": _normalize_date_label(ms.get("planned")),
                "Forecast label": _normalize_date_label(ms.get("forecast")),
                "Start week": _date_week_label(ms.get("planned")),
                "Forecast week": _date_week_label(ms.get("forecast")),
            })
    return pd.DataFrame(rows)

def render_milestone_timeline(
    records: List[Dict[str, Any]],
    scope_filter: Optional[str] = None,
    title: str = "Milestones",
    selected_year: Optional[int] = None,
    selected_week: Optional[int] = None,
    current_date: Optional[pd.Timestamp] = None,
) -> None:
    df = build_milestone_df(records, scope_filter=scope_filter)
    st.markdown(f"<div class='section-title'>{_html(title)}</div>", unsafe_allow_html=True)
    if df.empty:
        st.info("No dated forecast milestones loaded for this selected week.")
        return

    selected_week_start = iso_week_start(selected_year or int(pd.Timestamp.today().isocalendar().year), selected_week or int(pd.Timestamp.today().isocalendar().week)).normalize()
    df["Start sort"] = df["Start / planned"].where(pd.notna(df["Start / planned"]), df["Forecast"])
    df = df.sort_values(["Start sort", "Forecast", "Scope"], na_position="last").reset_index(drop=True)
    df["Label"] = df.apply(lambda r: f"{r['Scope']} - {compact_text(str(r['Milestone']), 46)}" if not scope_filter else compact_text(str(r["Milestone"]), 62), axis=1)
    df["Y"] = list(range(len(df)))
    y_ticks = df["Y"].tolist()
    y_text = df["Label"].tolist()

    df["Plot date"] = df["Forecast"].where(df["Forecast"] >= selected_week_start, selected_week_start)
    df["Timing status"] = df["Forecast"].apply(lambda v: "Overdue / before selected week" if pd.notna(v) and pd.Timestamp(v).normalize() < selected_week_start else "Upcoming")
    df["FC text"] = df.apply(
        lambda r: ("Overdue<br>" if r["Timing status"].startswith("Overdue") else "") + ("Start" if r["Date basis"] == "Start forecast" else ("Finish" if r["Date basis"] == "Finish forecast" else "Event")) + "<br>" + pd.Timestamp(r["Forecast"]).strftime("%d %b") + "<br>" + r["Forecast week"],
        axis=1,
    )

    fig = go.Figure()
    for scope_name, sdf in df.groupby("Scope", sort=False):
        fig.add_trace(go.Scatter(
            x=sdf["Plot date"],
            y=sdf["Y"],
            mode="markers+text",
            text=sdf["FC text"],
            textposition="middle right",
            name=str(scope_name),
            customdata=sdf[["Milestone", "Risk", "Start label", "Start week", "Forecast label", "Forecast week", "Scope", "Timing status", "Date basis", "Responsible"]],
            marker=dict(size=14),
            hovertemplate=(
                "<b>%{customdata[0]}</b><br>"
                "Scope: %{customdata[6]}<br>"
                "Date basis: %{customdata[8]}<br>"
                "Responsible: %{customdata[9]}<br>"
                "Status: %{customdata[7]}<br>"
                "Risk: %{customdata[1]}<br>"
                "Start / planned: %{customdata[2]} (%{customdata[3]})<br>"
                "Forecast event date: %{customdata[4]} (%{customdata[5]})"
                "<extra></extra>"
            ),
        ))

    future_dates = [pd.Timestamp(v).normalize() for v in pd.to_datetime(df["Plot date"]).dropna()]
    max_candidate = max(future_dates) if future_dates else selected_week_start + pd.Timedelta(days=28)
    max_axis = max(max_candidate + pd.Timedelta(days=7), selected_week_start + pd.Timedelta(days=28))
    week_ticks = list(pd.date_range(selected_week_start, max_axis, freq="W-MON"))
    if not week_ticks or week_ticks[0] != selected_week_start:
        week_ticks.insert(0, selected_week_start)
    tick_vals = sorted(set(pd.Timestamp(v).normalize() for v in week_ticks))
    tick_text = [f"{int(v.isocalendar().year)} W{int(v.isocalendar().week):02d}<br>{v.strftime('%d %b')}" for v in tick_vals]

    current_ts = selected_week_start
    fig.add_vline(x=current_ts, line_width=2, line_dash="dash", line_color="#111111")
    annotation = f"Actual week {period_display(selected_year, selected_week)}" if selected_year and selected_week else "Actual week"
    fig.add_annotation(x=current_ts, y=1.08, xref="x", yref="paper", text=annotation, showarrow=False, font=dict(size=12, color="#111111"), bgcolor="#ffffff", bordercolor="#111111", borderwidth=1)

    fig.update_layout(
        title="Forecast event dates - Start / Finish indicated; timeline starts at selected week",
        height=max(360, 50 * len(df) + 145),
        margin=dict(l=30, r=30, t=78, b=62),
        paper_bgcolor="rgba(0,0,0,0)",
        plot_bgcolor="rgba(0,0,0,0)",
        xaxis_title="Date / ISO week",
        yaxis_title="",
        legend=dict(orientation="h", yanchor="bottom", y=1.02, xanchor="right", x=1),
    )
    fig.update_yaxes(tickmode="array", tickvals=y_ticks, ticktext=y_text, autorange="reversed")
    fig.update_xaxes(range=[selected_week_start, max_axis], tickmode="array", tickvals=tick_vals, ticktext=tick_text, tickangle=-45, showgrid=True, tickfont=dict(size=9))
    st.markdown("<div class='timeline-note'>Timeline starts at the selected week. Y-axis is ordered by earliest start/planned activity to latest. Each point identifies whether the weekly report date is a start forecast, finish forecast or general forecast event. Overdue items are pinned to the selected-week marker and keep the original FC date in hover.</div>", unsafe_allow_html=True)
    st.plotly_chart(fig, use_container_width=True)

def render_progress_gauge(rec: Dict[str, Any]) -> None:
    actual = rec.get("construction_actual")
    forecast = rec.get("construction_forecast")
    deviation = rec.get("construction_deviation")
    if actual is None and forecast is None:
        st.markdown(
            "<div class='mini-kpi'><h4>Progress publication</h4><div class='value'>No % published</div><p>This scope is controlled through readiness gates, quality actions and forecast milestones until a reliable progress percentage is published.</p></div>",
            unsafe_allow_html=True,
        )
        return
    if deviation is None and actual is not None and forecast is not None:
        deviation = actual - forecast
    actual_value = actual if actual is not None else 0.0
    forecast_value = forecast if forecast is not None else actual_value
    dev_class = _deviation_class(deviation)
    dev_color = {"positive": "#058b55", "negative": "#c73535", "zero": "#6b7280"}[dev_class]
    fig = go.Figure(go.Indicator(
        mode="gauge+number",
        value=actual_value,
        number={"suffix": "%", "font": {"size": 38}},
        title={"text": f"{rec['name']} construction progress", "font": {"size": 18}},
        domain={"x": [0, 1], "y": [0.18, 1]},
        gauge={
            "axis": {"range": [0, 100], "tickwidth": 1},
            "bar": {"color": "#6f2da8", "thickness": 0.28},
            "bgcolor": "white",
            "borderwidth": 1,
            "bordercolor": "#e7e2ed",
            "steps": [
                {"range": [0, 50], "color": "#f0edf5"},
                {"range": [50, 80], "color": "#e5d5f4"},
                {"range": [80, 100], "color": "#d6c0eb"},
            ],
            "threshold": {"line": {"color": "#111111", "width": 4}, "thickness": 0.82, "value": forecast_value},
        },
    ))
    fig.update_layout(height=340, margin=dict(l=30, r=30, t=62, b=18), paper_bgcolor="rgba(0,0,0,0)")
    st.plotly_chart(fig, use_container_width=True)
    st.markdown(
        "<div class='gauge-footer'>"
        f"<div class='gf-cell'><span>Actual</span><b>{_html(_fmt_pct(actual))}</b></div>"
        f"<div class='gf-cell'><span>Forecast</span><b>{_html(_fmt_pct(forecast))}</b></div>"
        f"<div class='gf-cell gf-dev {dev_class}'><span>Deviation vs Forecast</span><b>{_html(_fmt_deviation(deviation))}</b></div>"
        "</div>",
        unsafe_allow_html=True,
    )


def render_progress_trend(rec: Dict[str, Any], selected_year: Optional[int] = None, selected_week: Optional[int] = None) -> None:
    df = rec.get("progress_series", pd.DataFrame())
    if df is None or df.empty:
        st.info("No scope progress trend loaded for the selected period.")
        return
    df = df.sort_values("period_sort") if "period_sort" in df.columns else df
    rows = []
    for _, r in df.iterrows():
        actual = _safe_float(r.get("actual"))
        forecast = _safe_float(r.get("forecast"))
        deviation = _safe_float(r.get("deviation"))
        if deviation is None and actual is not None and forecast is not None:
            deviation = actual - forecast
        if actual is not None:
            rows.append({"Period": r.get("period_label"), "Progress type": "Actual", "Progress": actual, "Deviation": deviation, "Forecast": forecast, "Sort": r.get("period_sort")})
        if forecast is not None:
            rows.append({"Period": r.get("period_label"), "Progress type": "Forecast", "Progress": forecast, "Deviation": deviation, "Forecast": forecast, "Sort": r.get("period_sort")})
    chart_df = pd.DataFrame(rows)
    if chart_df.empty:
        st.info("No actual / forecast progress values loaded for this scope.")
        return
    chart_df = chart_df.sort_values("Sort")
    fig = px.line(
        chart_df,
        x="Period",
        y="Progress",
        color="Progress type",
        markers=True,
        title=f"{rec['name']} progress trend - all loaded weeks",
        hover_data={"Progress": ":.2f", "Forecast": ":.2f", "Deviation": ":+.2f", "Sort": False},
    )
    # Show labels only at first, last and changed values; hover gives full information for every week.
    for trace in fig.data:
        yvals = list(trace.y)
        labels = []
        prev = None
        for idx, val in enumerate(yvals):
            show = idx == 0 or idx == len(yvals) - 1 or prev is None or abs(float(val) - float(prev)) > 0.0049
            labels.append(f"{float(val):.2f}%" if show else "")
            prev = val
        trace.text = labels
        trace.mode = "lines+markers+text"
        trace.textposition = "top center"
    if selected_year and selected_week:
        active_label = period_display(selected_year, selected_week)
        if active_label in set(chart_df["Period"]):
            ymin = float(chart_df["Progress"].min())
            ymax = float(chart_df["Progress"].max())
            pad = max(0.15, (ymax - ymin) * 0.10)
            fig.add_trace(go.Scatter(
                x=[active_label, active_label],
                y=[ymin - pad, ymax + pad],
                mode="lines",
                name="Active week",
                line=dict(color="#111111", dash="dash", width=2),
                hoverinfo="skip",
                showlegend=True,
            ))
            active_points = chart_df[chart_df["Period"] == active_label]
            fig.add_trace(go.Scatter(
                x=active_points["Period"],
                y=active_points["Progress"],
                mode="markers",
                name="Active values",
                marker=dict(size=13, symbol="diamond-open", color="#111111", line=dict(width=2)),
                customdata=active_points[["Progress type", "Forecast", "Deviation"]],
                hovertemplate="<b>Active week</b><br>%{customdata[0]}: %{y:.2f}%<br>Forecast: %{customdata[1]:.2f}%<br>Deviation: %{customdata[2]:+.2f}%<extra></extra>",
            ))
    fig.update_layout(
        height=360,
        margin=dict(l=30, r=20, t=60, b=35),
        paper_bgcolor="rgba(0,0,0,0)",
        plot_bgcolor="rgba(0,0,0,0)",
        yaxis_title="Progress %",
        xaxis_title="Week / year",
        legend=dict(orientation="h", yanchor="bottom", y=1.02, xanchor="right", x=1),
    )
    fig.update_xaxes(type="category")
    st.plotly_chart(fig, use_container_width=True)


