def _baseline_data() -> Dict[str, Any]:
    return cached_baseline_schedule()


def _monthly_cost_data() -> Dict[str, Any]:
    pack = cached_monthly_cost_reports()
    reports = pack.get("reports", {})
    selected = st.session_state.get("active_cost_report_id")
    if selected not in reports:
        selected = pack.get("default_id")
        st.session_state["active_cost_report_id"] = selected
    return reports.get(selected, cached_monthly_cost())


def render_cost_report_selector(section_key: str) -> Dict[str, Any]:
    pack = cached_monthly_cost_reports()
    reports: Dict[str, Dict[str, Any]] = pack.get("reports", {})
    labels: Dict[str, str] = pack.get("labels", {})
    options = list(reports.keys())
    if not options:
        return cached_monthly_cost()
    current = st.session_state.get("active_cost_report_id")
    if current not in options:
        current = pack.get("default_id") or options[-1]
    index = options.index(current) if current in options else 0
    selected = st.selectbox(
        "Monthly report to use",
        options,
        index=index,
        key=f"monthly_cost_selector_{section_key}",
        format_func=lambda x: labels.get(x, x),
        help="The active monthly cost report controls all cost cards, candle bars and cost tables on this page.",
    )
    st.session_state["active_cost_report_id"] = selected
    cost = reports[selected]
    meta = cost.get("metadata") or {}
    st.markdown(
        f"<div class='cost-report-active'>Active cost report: <b>{_html(labels.get(selected, selected))}</b> | Source: {_html(meta.get('source_file') or 'normalized cost JSON')} | Currency: EUR</div>",
        unsafe_allow_html=True,
    )
    return cost


def _fmt_money(value: Any, decimals: int = 1) -> str:
    num = _safe_float(value)
    if num is None:
        return "N/A"
    sign = "-" if num < 0 else ""
    n = abs(num)
    if n >= 1_000_000:
        return f"{sign}€{n/1_000_000:.{decimals}f}m"
    if n >= 1_000:
        return f"{sign}€{n/1_000:.0f}k"
    return f"{sign}€{n:.0f}"


def _fmt_money_full(value: Any) -> str:
    num = _safe_float(value)
    if num is None:
        return "N/A"
    return f"€{num:,.0f}"


def _fmt_date_short(value: Any) -> str:
    if value is None or value == "":
        return "N/A"
    dt = pd.to_datetime(value, errors="coerce")
    if pd.isna(dt):
        return str(value)
    return pd.Timestamp(dt).strftime("%d %b %Y")


def _cost_summary(scope_id: str, cost_data: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    cost_data = cost_data or _monthly_cost_data()
    return (cost_data.get("scope_summary") or {}).get(scope_id, {}) or {}


def _cost_packages(scope_id: str, cost_data: Optional[Dict[str, Any]] = None) -> List[Dict[str, Any]]:
    cost_data = cost_data or _monthly_cost_data()
    return list((cost_data.get("packages_by_scope") or {}).get(scope_id, []) or [])


def _cost_components(scope_id: str, cost_data: Optional[Dict[str, Any]] = None) -> List[Dict[str, Any]]:
    cost_data = cost_data or _monthly_cost_data()
    return list((cost_data.get("components_by_scope") or {}).get(scope_id, []) or [])


def _cost_exposures(scope_id: str, cost_data: Optional[Dict[str, Any]] = None) -> List[Dict[str, Any]]:
    cost_data = cost_data or _monthly_cost_data()
    rows = list((cost_data.get("exposures_by_scope") or {}).get(scope_id, []) or [])
    def sort_key(r: Dict[str, Any]) -> Tuple[int, pd.Timestamp, str]:
        rank = {"critical": 0, "high": 1, "medium": 2, "low": 3}.get(str(r.get("criticality") or "").lower(), 9)
        dt = pd.to_datetime(r.get("award_date"), errors="coerce")
        if pd.isna(dt):
            dt = pd.Timestamp.max
        return rank, dt, str(r.get("description") or r.get("main_description") or "")
    return sorted(rows, key=sort_key)




def _cost_values(scope_id: str, cost_data: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    cs = _cost_summary(scope_id, cost_data)
    forecast = cs.get("forecast") if cs.get("forecast") is not None else cs.get("eac")
    exposure = cs.get("potential_exposure") if cs.get("potential_exposure") is not None else (cs.get("potential_deviation") if cs.get("potential_deviation") is not None else cs.get("exposure_total"))
    potential_forecast = cs.get("potential_forecast")
    if potential_forecast is None and _safe_float(forecast) is not None and _safe_float(exposure) is not None:
        potential_forecast = (_safe_float(forecast) or 0) + (_safe_float(exposure) or 0)
    return {
        "budget": cs.get("budget") if cs.get("budget") is not None else cs.get("baseline_control_budget"),
        "co": cs.get("co") if cs.get("co") is not None else cs.get("change_order"),
        "forecast": forecast,
        "potential_exposure": exposure,
        "potential_forecast": potential_forecast,
        "basis": cs.get("basis") or "Monthly cost report",
        "risk_note": cs.get("risk_note") or cs.get("display_note") or "",
        "exposure_count": cs.get("exposure_count") or 0,
        "high_exposure_count": cs.get("high_exposure_count") or 0,
    }


def cost_candle_html(scope_id: str, cost_data: Optional[Dict[str, Any]] = None, title: str = "Cost position") -> str:
    vals = _cost_values(scope_id, cost_data)
    series = [
        ("Budget", vals.get("budget"), "budget"),
        ("CO", vals.get("co"), "co"),
        ("Forecast", vals.get("forecast"), "forecast"),
        ("Exposure", vals.get("potential_exposure"), "exposure"),
        ("Potential FC", vals.get("potential_forecast"), "potential"),
    ]
    numeric = [abs(_safe_float(v) or 0) for _, v, _ in series]
    maxv = max(numeric) if numeric else 1
    if maxv <= 0:
        maxv = 1
    rows = []
    for label, value, cls in series:
        width = max(2, min(100, (abs(_safe_float(value) or 0) / maxv) * 100))
        rows.append(
            f"<div class='cost-line'><span>{_html(label)}</span><div class='cost-bar {cls}'><i style='width:{width:.2f}%;'></i></div><b>{_html(_fmt_money(value))}</b></div>"
        )
    return f"<div class='cost-candle-mini'><h4>{_html(title)}</h4>{''.join(rows)}</div>"


def render_cost_candle_chart(scope_id: str, cost_data: Optional[Dict[str, Any]] = None, title: Optional[str] = None) -> None:
    vals = _cost_values(scope_id, cost_data)
    labels = ["Budget", "CO", "Forecast", "Potential exposure", "Potential forecast"]
    values = [vals.get("budget"), vals.get("co"), vals.get("forecast"), vals.get("potential_exposure"), vals.get("potential_forecast")]
    df = pd.DataFrame({"Cost position": labels, "EUR": [_safe_float(v) or 0 for v in values], "Value": [_fmt_money(v) for v in values]})
    fig = go.Figure()
    fig.add_trace(go.Bar(
        x=df["EUR"],
        y=df["Cost position"],
        orientation="h",
        text=df["Value"],
        textposition="auto",
        hovertemplate="%{y}: €%{x:,.0f}<extra></extra>",
    ))
    fig.update_layout(
        title=title or f"{_scope_label(scope_id)} cost candle bar - Budget / CO / Forecast / Exposure / Potential FC",
        height=320,
        margin=dict(l=25, r=25, t=55, b=25),
        paper_bgcolor="rgba(0,0,0,0)",
        plot_bgcolor="rgba(0,0,0,0)",
        xaxis_title="EUR",
        yaxis_title="",
        showlegend=False,
    )
    st.plotly_chart(fig, use_container_width=True)


def _status_for_action_text(action: str, selected_year: int, selected_week: int, current_date: Optional[pd.Timestamp] = None) -> Tuple[str, str, str, str]:
    expected = infer_expected_date(action, selected_year, selected_week)
    if is_closed_action(action):
        return "✅", "Closed", "closed", expected
    symbol, status, cls = action_status(expected, selected_year, selected_week, current_date=current_date)
    return symbol, status, cls, expected


def executive_priority_table_html(records: List[Dict[str, Any]], selected_year: int, selected_week: int, current_date: Optional[pd.Timestamp] = None) -> str:
    rows_data: List[Tuple[str, str, str, str, str, str]] = []
    for rec in records:
        for item in rec.get("priority_items", []) or []:
            action = clean_action_text(item)
            if not action:
                continue
            symbol, status, cls, expected = _status_for_action_text(action, selected_year, selected_week, current_date=current_date)
            if status not in {"Delayed", "Near due"}:
                continue
            responsible = infer_responsible(action, rec.get("default_responsible", "TBC"))
            rows_data.append((rec["name"], action, responsible, expected, f"{symbol} {status}", cls))
    def sort_key(row: Tuple[str, str, str, str, str, str]) -> Tuple[int, pd.Timestamp, str, str]:
        due = parse_expected_date_label(row[3], selected_year, selected_week)
        if pd.isna(due):
            due = pd.Timestamp.max
        rank = 0 if "Delayed" in row[4] else 1
        return rank, due, row[0], row[1]
    rows_data = sorted(rows_data, key=sort_key)
    if not rows_data:
        return "<div class='action-empty'>No delayed or near-due priority / high-exposure items extracted for the active week.</div>"
    head = "<div class='exec-action-row exec-action-head'><div class='exec-action-cell'>Scope</div><div class='exec-action-cell'>Action / issue</div><div class='exec-action-cell'>Responsible</div><div class='exec-action-cell'>Expected date</div><div class='exec-action-cell'>Status</div></div>"
    body = []
    for scope, action, resp, expected, status, cls in rows_data:
        body.append(
            "<div class='exec-action-row'>"
            f"<div class='exec-action-cell action-resp'>{_html(scope)}</div>"
            f"<div class='exec-action-cell action-main'>{_html(action)}</div>"
            f"<div class='exec-action-cell action-resp'>{_html(resp)}</div>"
            f"<div class='exec-action-cell action-date'>{_html(expected)}</div>"
            f"<div class='exec-action-cell'><span class='status-pill {cls}'>{_html(status)}</span></div>"
            "</div>"
        )
    return "<div class='action-table-scroll'><div class='exec-action-table'>" + head + "".join(body) + "</div></div>"


def milestone_date_basis(name: Any) -> str:
    lower = str(name or "").lower()
    if re.search(r"\b(start|commence|begin|beginning|resume|restart|mobilization|mobilisation)\b", lower):
        return "Start forecast"
    if re.search(r"\b(finish|completion|complete|completed|ready|handover|commissioning|operation|operative|available)\b", lower):
        return "Finish forecast"
    return "Forecast event date"


def _normalize_match_text(text: Any) -> str:
    s = re.sub(r"[^a-z0-9]+", " ", str(text or "").lower())
    stop = {"the", "and", "for", "with", "from", "bop", "construction", "activity", "work", "works", "need", "available", "scope", "by"}
    return " ".join(w for w in s.split() if w not in stop)


def _token_overlap_score(a: str, b: str) -> float:
    ta = set(_normalize_match_text(a).split())
    tb = set(_normalize_match_text(b).split())
    if not ta or not tb:
        return 0.0
    overlap = len(ta & tb) / max(1, len(ta | tb))
    ratio = SequenceMatcher(None, _normalize_match_text(a), _normalize_match_text(b)).ratio()
    return 0.55 * overlap + 0.45 * ratio


def scope_baseline_etc(scope_id: str, selected_year: int, selected_week: int) -> str:
    baseline = _baseline_data()
    rows = []
    for r in baseline.get("activities", []) or []:
        scopes = r.get("scopes") or ([r.get("scope_id")] if r.get("scope_id") else [])
        if scope_id not in scopes:
            continue
        finish = pd.to_datetime(r.get("finish_date") or r.get("baseline_finish") or r.get("finish"), errors="coerce")
        if pd.isna(finish):
            continue
        # Prefer completion/commissioning/availability milestones where available.
        name = str(r.get("activity_name") or "")
        weight = 1 if re.search(r"completion|commission|operative|available|handover|completed", name, flags=re.I) else 0
        rows.append((weight, finish, r))
    if not rows:
        return "Baseline ETC not published"
    rows.sort(key=lambda x: (x[0], x[1]))
    finish = rows[-1][1]
    return f"BL CC E006 ETC: {_fmt_date_short(finish)} ({_date_week_label(finish)})"


def baseline_deviation_df(rec: Dict[str, Any], selected_year: int, selected_week: int) -> pd.DataFrame:
    weekly = build_milestone_df([rec], scope_filter=rec["scope_id"])
    if weekly.empty:
        return pd.DataFrame()
    baseline = _baseline_data()
    base = _baseline_rows(rec["scope_id"], baseline, selected_year, selected_week, horizon_days=1200, milestones_only=False)
    rows = []
    for _, w in weekly.iterrows():
        best = None
        best_score = 0.0
        for _, b in base.iterrows():
            score = _token_overlap_score(w.get("Milestone"), b.get("Activity"))
            if score > best_score:
                best_score = score
                best = b
        weekly_fc = pd.to_datetime(w.get("Forecast"), errors="coerce")
        if best is None or best_score < 0.24:
            rows.append({
                "Milestone": w.get("Milestone"),
                "Date basis": w.get("Date basis"),
                "Weekly FC": _fmt_date_short(weekly_fc),
                "Baseline match": "No confident BL match",
                "Baseline finish": "N/A",
                "Deviation days": None,
                "Status": "⚪ Not matched",
                "Class": "unmatched",
                "Confidence": f"{best_score:.0%}",
            })
            continue
        base_finish = pd.to_datetime(best.get("Finish"), errors="coerce")
        deviation = None if pd.isna(weekly_fc) or pd.isna(base_finish) else int((weekly_fc.normalize() - base_finish.normalize()).days)
        if deviation is None:
            status, cls = "⚪ TBC", "unmatched"
        elif deviation > 0:
            status, cls = f"🔴 {deviation}d late vs BL", "late"
        elif deviation < 0:
            status, cls = f"🟢 {abs(deviation)}d early vs BL", "early"
        else:
            status, cls = "⚫ On baseline", "onbl"
        rows.append({
            "Milestone": w.get("Milestone"),
            "Date basis": w.get("Date basis"),
            "Weekly FC": _fmt_date_short(weekly_fc),
            "Baseline match": compact_text(best.get("Activity"), 120),
            "Baseline finish": _fmt_date_short(base_finish),
            "Deviation days": deviation,
            "Status": status,
            "Class": cls,
            "Confidence": f"{best_score:.0%}",
        })
    return pd.DataFrame(rows)


def render_baseline_deviation_analysis(rec: Dict[str, Any], selected_year: int, selected_week: int) -> None:
    st.markdown("<div class='section-title'>Milestone forecast vs BL CC E006 baseline</div>", unsafe_allow_html=True)
    df = baseline_deviation_df(rec, selected_year, selected_week)
    if df.empty:
        st.info("No milestone forecast dates available to compare with the baseline.")
        return
    rows = []
    for _, r in df.iterrows():
        rows.append([
            r.get("Milestone"),
            r.get("Date basis"),
            r.get("Weekly FC"),
            r.get("Baseline finish"),
            r.get("Baseline match"),
            f"<span class='baseline-flag {r.get('Class')}'>{_html(r.get('Status'))}</span>",
            r.get("Confidence"),
        ])
    # HTML status badge is intentional, so build table manually instead of escaping the status column.
    headers = ["Milestone", "Date basis", "Weekly FC", "BL finish", "BL match", "Deviation", "Match"]
    head = "".join(f"<th>{_html(h)}</th>" for h in headers)
    body = []
    for row in rows:
        cells = []
        for i, val in enumerate(row):
            if i == 5:
                cells.append(f"<td>{val}</td>")
            else:
                cells.append(f"<td>{_html(val)}</td>")
        body.append("<tr>" + "".join(cells) + "</tr>")
    st.markdown("<div class='rc-table-scroll'><table class='rc-table'><thead><tr>" + head + "</tr></thead><tbody>" + "".join(body) + "</tbody></table></div>", unsafe_allow_html=True)

def _rc_html_table(headers: List[str], rows: List[List[Any]], numeric_cols: Optional[set] = None) -> str:
    numeric_cols = numeric_cols or set()
    if not rows:
        return "<div class='action-empty'>No items loaded for this section.</div>"
    head = "".join(f"<th>{_html(h)}</th>" for h in headers)
    body_parts = []
    for row in rows:
        cells = []
        for i, val in enumerate(row):
            cls = " class='rc-num'" if i in numeric_cols else ""
            cells.append(f"<td{cls}>{_html(val)}</td>")
        body_parts.append("<tr>" + "".join(cells) + "</tr>")
    return "<div class='rc-table-scroll'><table class='rc-table'><thead><tr>" + head + "</tr></thead><tbody>" + "".join(body_parts) + "</tbody></table></div>"


def _scope_label(scope_id: str) -> str:
    return {"rail": "Rail", "ponds": "Ponds", "roads": "Roads", "": ""}.get(scope_id, scope_id.title())


def _baseline_rows(scope_id: str, baseline: Optional[Dict[str, Any]] = None, selected_year: int = 2026, selected_week: int = 1, horizon_days: int = 430, milestones_only: bool = True) -> pd.DataFrame:
    baseline = baseline or _baseline_data()
    rows = []
    selected_week_start = iso_week_start(selected_year, selected_week).normalize()
    max_date = selected_week_start + pd.Timedelta(days=horizon_days)
    for r in baseline.get("activities", []) or []:
        scopes = r.get("scopes") or r.get("scope_tags") or ([r.get("scope_id")] if r.get("scope_id") else [])
        if scope_id not in scopes:
            continue
        is_milestone = bool(r.get("is_milestone")) or str(r.get("activity_type") or "").lower() == "milestone" or _safe_float(r.get("remaining_duration") if r.get("remaining_duration") is not None else r.get("remaining_duration_days")) == 0
        if milestones_only and not is_milestone:
            continue
        finish_raw = r.get("finish_date") or r.get("baseline_finish") or r.get("finish")
        start_raw = r.get("start_date") or r.get("baseline_start") or r.get("start") or finish_raw
        finish = pd.to_datetime(finish_raw, errors="coerce")
        if pd.isna(finish):
            continue
        if finish > max_date:
            continue
        if finish < selected_week_start - pd.Timedelta(days=90):
            continue
        start = pd.to_datetime(start_raw, errors="coerce")
        if pd.isna(start):
            start = finish
        plot_date = finish if finish >= selected_week_start else selected_week_start
        rows.append({
            "Scope": _scope_label(scope_id),
            "Scope ID": scope_id,
            "Activity ID": r.get("activity_id"),
            "Activity": r.get("activity_name"),
            "Discipline": r.get("discipline") or r.get("activity_type") or "Baseline",
            "Start": start,
            "Finish": finish,
            "Plot date": plot_date,
            "Critical": bool(r.get("is_critical") or r.get("critical")),
            "Source page": r.get("source_page"),
            "Status": "Overdue vs baseline" if finish < selected_week_start else "Future baseline gate",
        })
    df = pd.DataFrame(rows)
    if df.empty:
        return df
    return df.sort_values(["Start", "Finish", "Scope", "Activity"])


def _baseline_timeline(df: pd.DataFrame, selected_year: int, selected_week: int, title: str, limit: int = 54) -> None:
    if df.empty:
        st.info("No dated baseline items found for this selection.")
        return
    selected_week_start = iso_week_start(selected_year, selected_week).normalize()
    plot_df = df.head(limit).copy().reset_index(drop=True)
    plot_df["Y"] = list(range(len(plot_df)))
    plot_df["Label"] = plot_df.apply(lambda r: f"{r['Scope']} - {compact_text(str(r['Activity']), 62)}" if len(set(plot_df["Scope ID"])) > 1 else compact_text(str(r["Activity"]), 82), axis=1)
    plot_df["Finish week"] = plot_df["Finish"].apply(_date_week_label)
    plot_df["Start text"] = plot_df["Start"].apply(_fmt_date_short)
    plot_df["Finish text"] = plot_df["Finish"].apply(_fmt_date_short)
    fig = go.Figure()
    for scope, sdf in plot_df.groupby("Scope", sort=False):
        fig.add_trace(go.Scatter(
            x=sdf["Plot date"],
            y=sdf["Y"],
            mode="markers+text",
            text=sdf.apply(lambda r: ("Overdue<br>" if r["Status"].startswith("Overdue") else "") + pd.Timestamp(r["Finish"]).strftime("%d %b") + "<br>" + r["Finish week"], axis=1),
            textposition="middle right",
            name=str(scope),
            marker=dict(size=13, symbol=sdf["Critical"].apply(lambda x: "diamond" if x else "circle")),
            customdata=sdf[["Activity ID", "Activity", "Discipline", "Start text", "Finish text", "Finish week", "Source page", "Status", "Critical"]],
            hovertemplate=(
                "<b>%{customdata[1]}</b><br>Activity ID: %{customdata[0]}<br>"
                "Status: %{customdata[7]}<br>Discipline: %{customdata[2]}<br>"
                "Start / planned: %{customdata[3]}<br>Baseline finish: %{customdata[4]} (%{customdata[5]})<br>"
                "Critical: %{customdata[8]}<br>Schedule page: %{customdata[6]}<extra></extra>"
            ),
        ))
    max_axis = max(plot_df["Plot date"].max() + pd.Timedelta(days=14), selected_week_start + pd.Timedelta(days=42))
    ticks = list(pd.date_range(selected_week_start, max_axis, freq="W-MON"))
    if not ticks or ticks[0] != selected_week_start:
        ticks.insert(0, selected_week_start)
    ticks = sorted(set(pd.Timestamp(v).normalize() for v in ticks))
    tick_text = [f"{v.isocalendar().year} W{v.isocalendar().week:02d}<br>{v.strftime('%d %b')}" for v in ticks]
    fig.add_vline(x=selected_week_start, line_width=2, line_dash="dash", line_color="#111111")
    fig.add_annotation(x=selected_week_start, y=1.08, xref="x", yref="paper", text=f"Active {period_display(selected_year, selected_week)}", showarrow=False, font=dict(size=12, color="#111111"), bgcolor="#ffffff", bordercolor="#111111", borderwidth=1)
    fig.update_layout(title=title, height=max(390, 46 * len(plot_df) + 145), margin=dict(l=30, r=30, t=78, b=62), paper_bgcolor="rgba(0,0,0,0)", plot_bgcolor="rgba(0,0,0,0)", xaxis_title="Date / ISO week", yaxis_title="", legend=dict(orientation="h", yanchor="bottom", y=1.02, xanchor="right", x=1))
    fig.update_yaxes(tickmode="array", tickvals=plot_df["Y"].tolist(), ticktext=plot_df["Label"].tolist(), autorange="reversed")
    fig.update_xaxes(range=[selected_week_start, max_axis], tickmode="array", tickvals=ticks, ticktext=tick_text, tickangle=-45, showgrid=True, tickfont=dict(size=9))
    st.markdown("<div class='timeline-note'>Timeline starts at the active week. Y-axis is ordered by earliest start/planned date. Overdue baseline gates are pinned to the active-week marker; hover shows the original baseline finish.</div>", unsafe_allow_html=True)
    st.plotly_chart(fig, use_container_width=True)


def render_baseline_overview(records: List[Dict[str, Any]], selected_year: int, selected_week: int) -> None:
    baseline = _baseline_data()
    meta = baseline.get("metadata") or baseline.get("meta") or baseline
    st.markdown("<div class='section-title'>Time schedule baseline - BL CC E006</div>", unsafe_allow_html=True)
    st.markdown(f"<span class='source-pill'>Baseline: {_html(meta.get('baseline_name') or 'BL CC E006')}</span><span class='source-pill'>Cut-off: {_html(_fmt_date_short(meta.get('cutoff')))}</span><span class='source-pill'>Print date: {_html(_fmt_date_short(meta.get('print_date')))}</span>", unsafe_allow_html=True)
    cols = st.columns(3)
    all_rows = []
    for col, rec in zip(cols, records):
        df = _baseline_rows(rec["scope_id"], baseline, selected_year, selected_week, horizon_days=430, milestones_only=True)
        all_rows.append(df)
        next_gate = df.iloc[0] if not df.empty else None
        critical_count = int(df["Critical"].sum()) if not df.empty else 0
        overdue_count = int((df["Status"] == "Overdue vs baseline").sum()) if not df.empty else 0
        with col:
            if next_gate is None:
                body = "<p>No future baseline gate loaded.</p>"
            else:
                body = f"<p><b>Next FC:</b> {_html(_fmt_date_short(next_gate['Finish']))} / {_html(_date_week_label(next_gate['Finish']))}</p><p>{_html(compact_text(str(next_gate['Activity']), 135))}</p><p><b>Critical gates:</b> {critical_count} &nbsp; <b>Overdue shown:</b> {overdue_count}</p>"
            st.markdown(f"<div class='baseline-stat-card'><h4>{_html(rec['name'])}</h4>{body}</div>", unsafe_allow_html=True)
    merged = pd.concat([df for df in all_rows if not df.empty], ignore_index=True) if any(not df.empty for df in all_rows) else pd.DataFrame()
    _baseline_timeline(merged, selected_year, selected_week, "Baseline schedule look-ahead - Rail / Ponds / Roads", limit=36)




