# v11 final milestone/baseline comparison override - start/finish aware.
def _baseline_dates_from_match(match: Optional[Dict[str, Any]]) -> Tuple[pd.Timestamp, pd.Timestamp]:
    if not match:
        return pd.NaT, pd.NaT
    bl_finish = pd.to_datetime(match.get("baseline_finish") or match.get("finish_date") or match.get("finish"), errors="coerce")
    bl_start = pd.to_datetime(match.get("baseline_start") or match.get("start_date") or match.get("start") or bl_finish, errors="coerce")
    if pd.isna(bl_start) and pd.notna(bl_finish):
        bl_start = bl_finish
    return bl_start, bl_finish


def _baseline_compare_date_for_basis(match: Optional[Dict[str, Any]], date_basis: str) -> Tuple[pd.Timestamp, str]:
    bl_start, bl_finish = _baseline_dates_from_match(match)
    basis_low = str(date_basis or "").lower()
    if basis_low.startswith("forecast start"):
        return bl_start, "BL start"
    # Completion, ready, handover, available, commissioning and generic milestone controls
    # are compared to BL finish/availability because the weekly report FC date is the
    # forecast completion/control point for the activity.
    return bl_finish, "BL finish / availability"


def build_milestone_df(records: List[Dict[str, Any]], scope_filter: Optional[str] = None, selected_year: Optional[int] = None, selected_week: Optional[int] = None) -> pd.DataFrame:
    baseline = _baseline_data()
    rows: List[Dict[str, Any]] = []
    for rec in records:
        if scope_filter and rec["scope_id"] != scope_filter:
            continue
        for ms in rec.get("milestones", []) or []:
            fc = _parse_date(ms.get("forecast"))
            if pd.isna(fc):
                continue
            planned = _parse_date(ms.get("planned"))
            name = ms.get("name", "Milestone")
            date_basis = _milestone_date_basis(name)
            match = _baseline_match_for_milestone(rec["scope_id"], name, baseline, forecast_date=fc)
            bl_start, bl_finish = _baseline_dates_from_match(match)
            bl_compare, bl_compare_basis = _baseline_compare_date_for_basis(match, date_basis)
            bl_name = "No reliable BL match"
            bl_id = ""
            bl_page = ""
            score = None
            if match:
                bl_name = match.get("activity_name") or "Baseline activity"
                bl_id = match.get("activity_id") or ""
                bl_page = match.get("source_page") or ""
                score = match.get("match_score")
            deviation_days = None
            if pd.notna(fc) and pd.notna(bl_compare):
                deviation_days = int((pd.Timestamp(fc).normalize() - pd.Timestamp(bl_compare).normalize()).days)
            if deviation_days is None:
                dev_label = "No reliable BL match"
                dev_class = "No BL match"
            elif deviation_days > 0:
                dev_label = f"+{deviation_days} days vs {bl_compare_basis}"
                dev_class = "Later than BL"
            elif deviation_days < 0:
                dev_label = f"{deviation_days} days vs {bl_compare_basis}"
                dev_class = "Earlier than BL"
            else:
                dev_label = f"0 days vs {bl_compare_basis}"
                dev_class = "Aligned to BL"
            rows.append({
                "Scope": rec["name"],
                "Scope ID": rec["scope_id"],
                "Milestone": name,
                "Risk": ms.get("risk", "Milestone"),
                "Start / planned": planned,
                "Forecast": fc,
                "Start label": _normalize_date_label(ms.get("planned")),
                "Forecast label": _normalize_date_label(ms.get("forecast")),
                "Start week": _date_week_label(ms.get("planned")),
                "Forecast week": _date_week_label(ms.get("forecast")),
                "Date basis": date_basis,
                "Baseline activity": bl_name,
                "Baseline ID": bl_id,
                "Baseline start": bl_start,
                "Baseline finish": bl_finish,
                "Baseline comparison date": bl_compare,
                "Baseline comparison basis": bl_compare_basis if pd.notna(bl_compare) else "No BL match",
                "Baseline start label": _fmt_date_short(bl_start) if pd.notna(bl_start) else "N/A",
                "Baseline start week": _date_week_label(bl_start) if pd.notna(bl_start) else "N/A",
                "Baseline finish label": _fmt_date_short(bl_finish) if pd.notna(bl_finish) else "No reliable BL match",
                "Baseline finish week": _date_week_label(bl_finish) if pd.notna(bl_finish) else "N/A",
                "Baseline comparison label": _fmt_date_short(bl_compare) if pd.notna(bl_compare) else "No reliable BL match",
                "Baseline comparison week": _date_week_label(bl_compare) if pd.notna(bl_compare) else "N/A",
                "Baseline week": _date_week_label(bl_compare) if pd.notna(bl_compare) else "N/A",
                "Baseline page": bl_page,
                "Match score": score,
                "Deviation days": deviation_days,
                "Deviation label": dev_label,
                "Deviation class": dev_class,
            })
    return pd.DataFrame(rows)


def _baseline_comparison_table_html(rec: Dict[str, Any], selected_year: int, selected_week: int) -> str:
    df = build_milestone_df([rec], scope_filter=rec["scope_id"], selected_year=selected_year, selected_week=selected_week)
    if df.empty:
        return "<div class='action-empty'>No weekly forecast milestones available for baseline comparison.</div>"
    df["Sort date"] = df["Start / planned"].where(pd.notna(df["Start / planned"]), df["Forecast"])
    df = df.sort_values(["Sort date", "Forecast", "Milestone"], na_position="last")
    rows = []
    for _, r in df.iterrows():
        days = r.get("Deviation days")
        if days is None or pd.isna(days):
            status = "⚪ No BL match"
            variance = "N/A"
        else:
            days_int = int(days)
            if days_int > 14:
                status = "🔴 Delayed vs BL"
            elif days_int > 0:
                status = "🟠 Minor slip vs BL"
            elif days_int < 0:
                status = "🟢 Ahead of BL"
            else:
                status = "🟢 Aligned"
            variance = f"{days_int:+d} days"
        rows.append([
            r.get("Milestone"),
            r.get("Date basis"),
            r.get("Forecast label"),
            r.get("Forecast week"),
            r.get("Baseline comparison basis"),
            r.get("Baseline comparison label"),
            r.get("Baseline comparison week"),
            status,
            variance,
            r.get("Baseline activity"),
        ])
    return _rc_html_table(["Weekly milestone", "Weekly date type", "Weekly FC", "FC week", "BL comparison basis", "BL comparison date", "BL week", "Deviation", "Variance", "Matched BL activity"], rows)


def render_milestone_timeline(
    records: List[Dict[str, Any]],
    scope_filter: Optional[str] = None,
    title: str = "Milestones",
    selected_year: Optional[int] = None,
    selected_week: Optional[int] = None,
    current_date: Optional[pd.Timestamp] = None,
) -> None:
    df = build_milestone_df(records, scope_filter=scope_filter, selected_year=selected_year, selected_week=selected_week)
    st.markdown(f"<div class='section-title'>{_html(title)}</div>", unsafe_allow_html=True)
    st.markdown(
        "<div class='timeline-deviation-note'><span class='timeline-type-pill'>FC point</span> Points are weekly-report forecast dates. Hover identifies whether each point is a start date, finish/availability date or general control date. Deviations compare each point with the matching BL CC E006 start or finish/availability date, according to the point type.</div>",
        unsafe_allow_html=True,
    )
    if df.empty:
        st.info("No dated forecast milestones loaded for this selected week.")
        return
    sy = selected_year or int(pd.Timestamp.today().isocalendar().year)
    sw = selected_week or int(pd.Timestamp.today().isocalendar().week)
    selected_week_start = iso_week_start(sy, sw).normalize()
    df["Start sort"] = df["Start / planned"].where(pd.notna(df["Start / planned"]), df["Forecast"])
    df = df.sort_values(["Start sort", "Forecast", "Scope"], na_position="last").reset_index(drop=True)
    df["Label"] = df.apply(lambda r: f"{r['Scope']} - {compact_text(str(r['Milestone']), 46)}" if not scope_filter else compact_text(str(r["Milestone"]), 64), axis=1)
    df["Y"] = list(range(len(df)))
    df["Plot date"] = df["Forecast"].where(df["Forecast"] >= selected_week_start, selected_week_start)
    df["Timing status"] = df["Forecast"].apply(lambda v: "Overdue / before selected week" if pd.notna(v) and pd.Timestamp(v).normalize() < selected_week_start else "Upcoming")
    df["FC text"] = df.apply(
        lambda r: ("Overdue<br>" if r["Timing status"].startswith("Overdue") else "") + pd.Timestamp(r["Forecast"]).strftime("%d %b %Y") + "<br>" + r["Forecast week"],
        axis=1,
    )
    symbol_map = {"Later than BL": "diamond", "Earlier than BL": "triangle-up", "Aligned to BL": "circle", "No BL match": "circle-open"}
    fig = go.Figure()
    for status, sdf in df.groupby("Deviation class", sort=False):
        fig.add_trace(go.Scatter(
            x=sdf["Plot date"],
            y=sdf["Y"],
            mode="markers+text",
            text=sdf["FC text"],
            textposition="middle right",
            name=str(status),
            marker=dict(size=13, symbol=symbol_map.get(str(status), "circle")),
            customdata=sdf[["Scope", "Milestone", "Risk", "Start label", "Start week", "Forecast label", "Forecast week", "Timing status", "Date basis", "Baseline activity", "Baseline ID", "Baseline comparison basis", "Baseline comparison label", "Baseline comparison week", "Deviation label", "Baseline page", "Match score"]],
            hovertemplate=(
                "<b>%{customdata[1]}</b><br>Scope: %{customdata[0]}<br>Risk: %{customdata[2]}<br>"
                "Weekly date type: %{customdata[8]}<br>Start / planned: %{customdata[3]} (%{customdata[4]})<br>"
                "Weekly FC: %{customdata[5]} (%{customdata[6]})<br>Status: %{customdata[7]}<br>"
                "Baseline match: %{customdata[9]}<br>Baseline ID: %{customdata[10]}<br>"
                "BL comparison basis: %{customdata[11]}<br>BL comparison date: %{customdata[12]} (%{customdata[13]})<br>Deviation: %{customdata[14]}<br>"
                "BL source page: %{customdata[15]} / match score %{customdata[16]}<extra></extra>"
            ),
        ))
    max_axis = max(df["Plot date"].max() + pd.Timedelta(days=14), selected_week_start + pd.Timedelta(days=42))
    tick_vals = list(pd.date_range(selected_week_start, max_axis, freq="W-MON"))
    if not tick_vals or tick_vals[0] != selected_week_start:
        tick_vals.insert(0, selected_week_start)
    tick_vals = sorted(set(pd.Timestamp(v).normalize() for v in tick_vals))
    tick_text = [f"{v.isocalendar().year} W{v.isocalendar().week:02d}<br>{v.strftime('%d %b')}" for v in tick_vals]
    fig.add_vline(x=selected_week_start, line_width=2, line_dash="dash", line_color="#111111")
    fig.add_annotation(x=selected_week_start, y=1.08, xref="x", yref="paper", text=f"Active {period_display(sy, sw)}", showarrow=False, font=dict(size=12, color="#111111"), bgcolor="#ffffff", bordercolor="#111111", borderwidth=1)
    fig.update_layout(
        title=f"{title} - weekly FC dates with BL CC E006 comparison",
        height=max(410, 48 * len(df) + 145),
        margin=dict(l=30, r=35, t=78, b=62),
        paper_bgcolor="rgba(0,0,0,0)",
        plot_bgcolor="rgba(0,0,0,0)",
        xaxis_title="Date / ISO week",
        yaxis_title="",
        legend=dict(orientation="h", yanchor="bottom", y=1.02, xanchor="right", x=1),
    )
    fig.update_yaxes(tickmode="array", tickvals=df["Y"].tolist(), ticktext=df["Label"].tolist(), autorange="reversed")
    fig.update_xaxes(range=[selected_week_start, max_axis], tickmode="array", tickvals=tick_vals, ticktext=tick_text, tickangle=-45, showgrid=True, tickfont=dict(size=9))
    st.markdown("<div class='timeline-note'>Timeline starts at the selected week. Y-axis is ordered from earliest activity/start date to latest. Overdue items are pinned to the selected-week marker and keep their original FC date in hover.</div>", unsafe_allow_html=True)
    st.plotly_chart(fig, use_container_width=True)

