# v11.1 milestone-to-baseline matching refinement

def _specific_refs_for_match(text: Any) -> List[Tuple[str, str]]:
    low = str(text or "").lower()
    refs: List[Tuple[str, str]] = []
    for kind, pat in [
        ("section", r"\bsection\s*(\d+[a-z]?)\b"),
        ("track", r"\btrack\s*(\d+[a-z]?)\b"),
        ("road", r"\broad\s*(\d+(?:\.\d+)?)\b"),
        ("avenue", r"\b(?:avenue|av\.?|ave\.?|av)\s*(\d+(?:\.\d+)?)\b"),
        ("pond", r"\b(?:west\s+pond|east\s+pond|pond)\s*(\d+)\b"),
    ]:
        for m in re.finditer(pat, low, flags=re.I):
            refs.append((kind, m.group(1).lower()))
    for word in ["ssy", "south shunting", "scrap yard", "clp", "contact water", "east stormwater"]:
        if word in low:
            refs.append(("word", word))
    return refs


def _ref_is_present(ref: Tuple[str, str], candidate: str) -> bool:
    kind, val = ref
    cand = str(candidate or "").lower()
    if kind == "word":
        if val == "ssy":
            return "ssy" in cand or "south shunting" in cand
        return val in cand
    if kind in {"section", "track"}:
        return bool(re.search(rf"\b{kind}\s*{re.escape(val)}\b", cand))
    if kind == "road":
        # Road 6 should also match Road 6.0 / Road 6.1, but Road 6.1 should not match Road 6.0.
        if "." in val:
            return bool(re.search(rf"\broad\s*{re.escape(val)}\b", cand))
        return bool(re.search(rf"\broad\s*{re.escape(val)}(?:\b|\.)", cand))
    if kind == "avenue":
        alt = val.split(".")[0]
        if "." in val:
            return bool(re.search(rf"\b(?:avenue|av\.?|ave\.?)\s*{re.escape(val)}\b", cand)) or bool(re.search(rf"\b(?:avenue|av\.?|ave\.?)\s*{re.escape(alt)}\b", cand))
        return bool(re.search(rf"\b(?:avenue|av\.?|ave\.?)\s*{re.escape(val)}\b", cand))
    if kind == "pond":
        return bool(re.search(rf"\bpond\s*{re.escape(val)}\b", cand)) or bool(re.search(rf"\bwest\s*{re.escape(val)}\b", cand))
    return False


def _baseline_match_for_milestone(scope_id: str, milestone_name: str, baseline: Optional[Dict[str, Any]] = None, forecast_date: Any = None) -> Optional[Dict[str, Any]]:
    baseline = baseline or _baseline_data()
    target_tokens = _tokenize_match(milestone_name)
    if not target_tokens:
        return None
    refs = _specific_refs_for_match(milestone_name)
    best = None
    best_score = 0.0
    forecast_dt = pd.to_datetime(forecast_date, errors="coerce")
    target_low = str(milestone_name or "").lower()
    for r in _baseline_rows_raw(scope_id, baseline):
        name = r.get("activity_name") or r.get("Activity") or ""
        name_l = str(name).lower()
        # If a milestone has an explicit road/section/pond/etc. reference, do not match a different reference.
        hard_refs = [ref for ref in refs if ref[0] in {"section", "road", "avenue", "pond", "word"}]
        if hard_refs and not all(_ref_is_present(ref, name_l) for ref in hard_refs):
            continue
        tokens = _tokenize_match(name)
        if not tokens:
            continue
        overlap = len(target_tokens & tokens)
        if overlap == 0:
            continue
        score = overlap / max(1.0, (len(target_tokens) ** 0.5) * (len(tokens) ** 0.5))
        if "sub-base" in target_low or "subbase" in target_low:
            score += 0.22 if re.search(r"sub[- ]?base|base layers", name_l) else -0.08
        if "trench" in target_low or "excavat" in target_low:
            score += 0.22 if re.search(r"excava|trench|groundworks", name_l) else -0.08
        if "drain" in target_low:
            score += 0.20 if "drain" in name_l else -0.10
        if "ballast" in target_low:
            score += 0.20 if "ballast" in name_l else -0.08
        if "commission" in target_low and not re.search(r"commission|operative|available|handover", name_l):
            score -= 0.18
        finish = pd.to_datetime(r.get("baseline_finish") or r.get("finish_date") or r.get("finish"), errors="coerce")
        if pd.notna(forecast_dt) and pd.notna(finish):
            days = abs(int((pd.Timestamp(forecast_dt).normalize() - pd.Timestamp(finish).normalize()).days))
            score += 0.25 * max(0.0, 1.0 - min(days, 365) / 365.0)
            if days > 365:
                score -= 0.20
        if score > best_score:
            best_score = score
            best = r
    if best is None or best_score < 0.28:
        return None
    out = dict(best)
    out["match_score"] = round(best_score, 3)
    return out


def build_milestone_df(records: List[Dict[str, Any]], scope_filter: Optional[str] = None) -> pd.DataFrame:
    baseline = _baseline_data()
    rows: List[Dict[str, Any]] = []
    for rec in records:
        if scope_filter and rec["scope_id"] != scope_filter:
            continue
        for ms in rec.get("milestones", []) or []:
            fc = _parse_date(ms.get("forecast"))
            if pd.isna(fc):
                continue
            planned = _parse_date(ms.get("planned"))
            name = ms.get("name", "Milestone")
            match = _baseline_match_for_milestone(rec["scope_id"], name, baseline, forecast_date=fc)
            bl_finish = pd.NaT
            bl_name = "No reliable BL match"
            bl_id = ""
            bl_page = ""
            score = None
            if match:
                bl_finish = pd.to_datetime(match.get("baseline_finish") or match.get("finish_date") or match.get("finish"), errors="coerce")
                bl_name = match.get("activity_name") or "Baseline activity"
                bl_id = match.get("activity_id") or ""
                bl_page = match.get("source_page") or ""
                score = match.get("match_score")
            deviation_days = None
            if pd.notna(fc) and pd.notna(bl_finish):
                deviation_days = int((pd.Timestamp(fc).normalize() - pd.Timestamp(bl_finish).normalize()).days)
            if deviation_days is None:
                dev_label = "No reliable BL match"
                dev_class = "No BL match"
            elif deviation_days > 0:
                dev_label = f"+{deviation_days} days vs BL"
                dev_class = "Later than BL"
            elif deviation_days < 0:
                dev_label = f"{deviation_days} days vs BL"
                dev_class = "Earlier than BL"
            else:
                dev_label = "0 days vs BL"
                dev_class = "Aligned to BL"
            rows.append({
                "Scope": rec["name"],
                "Scope ID": rec["scope_id"],
                "Milestone": name,
                "Risk": ms.get("risk", "Milestone"),
                "Start / planned": planned,
                "Forecast": fc,
                "Start label": _normalize_date_label(ms.get("planned")),
                "Forecast label": _normalize_date_label(ms.get("forecast")),
                "Start week": _date_week_label(ms.get("planned")),
                "Forecast week": _date_week_label(ms.get("forecast")),
                "Date basis": _milestone_date_basis(name),
                "Baseline activity": bl_name,
                "Baseline ID": bl_id,
                "Baseline finish": bl_finish,
                "Baseline finish label": _fmt_date_short(bl_finish) if pd.notna(bl_finish) else "No reliable BL match",
                "Baseline week": _date_week_label(bl_finish) if pd.notna(bl_finish) else "N/A",
                "Baseline page": bl_page,
                "Match score": score,
                "Deviation days": deviation_days,
                "Deviation label": dev_label,
                "Deviation class": dev_class,
            })
    return pd.DataFrame(rows)


