def _baseline_deviation_cell(dev_days: Any, label: str) -> str:
    if dev_days is None or pd.isna(dev_days):
        return "⚪ No reliable BL match"
    try:
        d = int(dev_days)
    except Exception:
        return _html(label or "No reliable BL match")
    if d > 0:
        return f"🔴 +{d} days vs BL"
    if d < 0:
        return f"🟢 {d} days vs BL"
    return "⚪ 0 days vs BL"


def _baseline_compare_rows_for_scope(rec: Dict[str, Any]) -> List[List[Any]]:
    df = build_milestone_df([rec], scope_filter=rec["scope_id"])
    if df.empty:
        return []
    df["Sort date"] = df["Start / planned"].where(pd.notna(df["Start / planned"]), df["Forecast"])
    df = df.sort_values(["Sort date", "Forecast", "Milestone"], na_position="last")
    rows: List[List[Any]] = []
    for _, r in df.iterrows():
        rows.append([
            compact_text(r.get("Milestone"), 110),
            r.get("Date basis") or "Forecast control date",
            _fmt_date_short(r.get("Forecast")),
            r.get("Forecast week") or _date_week_label(r.get("Forecast")),
            compact_text(r.get("Baseline activity"), 120),
            r.get("Baseline ID") or "-",
            r.get("Baseline finish label") or _fmt_date_short(r.get("Baseline finish")),
            r.get("Baseline week") or _date_week_label(r.get("Baseline finish")),
            _baseline_deviation_cell(r.get("Deviation days"), r.get("Deviation label")),
        ])
    return rows


