# v11 cost metric correction - prefer singular change_order from corrected monthly cost report.
def _cost_metric_values(scope_id: str, cost_data: Dict[str, Any]) -> Dict[str, Any]:
    cs = _cost_summary(scope_id, cost_data)
    budget = cs.get("budget") if cs.get("budget") is not None else cs.get("baseline_control_budget")
    co = cs.get("change_order") if cs.get("change_order") is not None else (cs.get("change_orders") if cs.get("change_orders") is not None else (cs.get("approved_change_deviation") or 0))
    forecast = cs.get("forecast") if cs.get("forecast") is not None else cs.get("eac")
    exposure = cs.get("potential_exposure") if cs.get("potential_exposure") is not None else (cs.get("potential_deviation") if cs.get("potential_deviation") is not None else cs.get("potential_changes"))
    potential_forecast = cs.get("potential_forecast")
    return {"budget": budget, "change_orders": co, "forecast": forecast, "potential_exposure": exposure, "potential_forecast": potential_forecast}


