    col1, col2 = st.columns([1, 1])
    with col1:
        render_progress_gauge(rec)
    with col2:
        render_progress_trend(rec, selected_year, selected_week)

    render_action_table(f"{rec['name']} priority & high-exposure items - {selected_label}", rec.get("priority_items", []), selected_year, selected_week, rec.get("default_responsible", "TBC"), max_items=999, current_date=current_date)
