    df["Label"] = df.apply(lambda r: f"{r['Scope']} - {compact_text(str(r['Milestone']), 46)}" if not scope_filter else compact_text(str(r["Milestone"]), 64), axis=1)
    df["Y"] = list(range(len(df)))
