def _cost_active_date_label(cost_data: Dict[str, Any]) -> str:
    meta = cost_data.get("metadata") or {}
    raw = meta.get("cutoff_month") or meta.get("active_date") or meta.get("data_date") or meta.get("report_date")
    text = str(raw or "").strip()
    if not text:
        return "Active cost report"
    if re.match(r"^20\d{2}-\d{2}$", text):
        dt = pd.to_datetime(text + "-01", errors="coerce")
        return dt.strftime("%b %Y") if pd.notna(dt) else text
    dt = pd.to_datetime(text, errors="coerce")
    if pd.notna(dt):
        return pd.Timestamp(dt).strftime("%d %b %Y")
    return text


def _cost_reports() -> List[Dict[str, Any]]:
    pack = cached_monthly_cost_reports()
    reports = pack.get("reports", {}) or {}
    out: List[Dict[str, Any]] = []
    for rid, data in reports.items():
        meta = data.get("metadata") or {}
        active_date = _cost_active_date_label(data)
        report_name = meta.get("report_name") or meta.get("report") or "Monthly cost report"
        out.append({"id": rid, "label": f"{active_date} - {report_name}", "active_date": active_date, "data": data})
    if not out:
        data = cached_monthly_cost()
        out = [{"id": "active", "label": f"{_cost_active_date_label(data)} - Monthly cost report", "active_date": _cost_active_date_label(data), "data": data}]
    return out


def _select_cost_report(scope_id: str = "portfolio") -> Dict[str, Any]:
    reports = _cost_reports()
    labels = [r["label"] for r in reports]
    key = f"monthly_cost_report_choice_{scope_id}"
    if key not in st.session_state or st.session_state.get(key) not in labels:
        st.session_state[key] = labels[-1] if labels else ""
    selected = st.selectbox(
        "Monthly report to use",
        labels,
        key=key,
        help="Select the monthly report used by this cost-control section.",
    ) if labels else ""
    for report in reports:
        if report["label"] == selected:
            return report["data"]
    return reports[-1]["data"] if reports else cached_monthly_cost()


def _active_cost_data(scope_id: str = "portfolio") -> Tuple[Dict[str, Any], str, str]:
    reports = _cost_reports()
    labels = [r["label"] for r in reports]
    key = f"monthly_cost_report_choice_{scope_id}"
    selected = st.session_state.get(key) if st.session_state.get(key) in labels else (labels[-1] if labels else "")
    for report in reports:
        if report["label"] == selected:
            return report["data"], report["label"], report["active_date"]
    if reports:
        return reports[-1]["data"], reports[-1]["label"], reports[-1]["active_date"]
    data = cached_monthly_cost()
    return data, "Monthly cost report", _cost_active_date_label(data)


def _table_column_keep(headers: List[str], rows: List[List[Any]]) -> List[int]:
    keep: List[int] = []
    for i, header in enumerate(headers):
        values = []
        for row in rows:
            values.append(row[i] if i < len(row) else "")
        def has_value(v: Any) -> bool:
            txt = str(v or "").strip()
            if txt == "":
                return False
            if txt.upper() in {"N/A", "NA", "NONE", "NULL"}:
                return False
            return True
        if has_value(header) and any(has_value(v) for v in values):
            keep.append(i)
    return keep or list(range(len(headers)))


def _rc_html_table(headers: List[str], rows: List[List[Any]], numeric_cols: Optional[set] = None) -> str:
    numeric_cols = numeric_cols or set()
    if not rows:
        return "<div class='action-empty'>No items loaded for this section.</div>"
    keep = _table_column_keep(headers, rows)
    headers2 = [headers[i] for i in keep]
    rows2 = [[row[i] if i < len(row) else "" for i in keep] for row in rows]
    numeric2 = {new_i for new_i, old_i in enumerate(keep) if old_i in numeric_cols}
    head = "".join(f"<th>{_html(h)}</th>" for h in headers2)
    body_parts = []
    for row in rows2:
        cells = []
        for i, val in enumerate(row):
            txt = str(val or "")
            long_cls = " wide-text" if len(txt) > 80 else ""
            if i == 0 and len(txt) > 45:
                long_cls += " driver-text"
            cls = " class='rc-num'" if i in numeric2 else (f" class='{long_cls.strip()}'" if long_cls.strip() else "")
            cells.append(f"<td{cls}>{_html(val)}</td>")
        body_parts.append("<tr>" + "".join(cells) + "</tr>")
    return "<div class='rc-table-scroll'><table class='rc-table'><thead><tr>" + head + "</tr></thead><tbody>" + "".join(body_parts) + "</tbody></table></div>"


def action_table_html(
    items: List[Any],
    selected_year: int,
    selected_week: int,
    default_responsible: str = "TBC",
    max_items: int = 10,
    current_date: Optional[pd.Timestamp] = None,
) -> str:
    if not items:
        return "<div class='action-empty'>No active actions extracted for this section.</div>"
    sorted_items = sorted(items, key=lambda x: action_sort_key(x, selected_year, selected_week))
    parts = ["<div class='action-table-scroll'><div class='action-table'>"]
    parts.append("<div class='action-row action-head'><div class='action-cell'>Action / issue</div><div class='action-cell'>Responsible</div><div class='action-cell'>Expected date</div><div class='action-cell'>Status</div></div>")
    for item in sorted_items[:max_items]:
        if isinstance(item, dict):
            action = clean_action_text(item.get("issue") or item.get("action") or "")
            responsible = item.get("owner") or infer_responsible(action, default_responsible)
            expected = item.get("due_date") or infer_expected_date(action, selected_year, selected_week)
        else:
            action = clean_action_text(item)
            responsible = infer_responsible(action, default_responsible)
            expected = infer_expected_date(action, selected_year, selected_week)
        if is_closed_action(action):
            symbol, status, status_class = "OK", "Closed", "closed"
        else:
            symbol, status, status_class = action_status(expected, selected_year, selected_week, current_date=current_date)
        parts.append(
            "<div class='action-row'>"
            f"<div class='action-cell action-main'>{_html(action)}</div>"
            f"<div class='action-cell action-resp'>{_html(responsible or 'TBC')}</div>"
            f"<div class='action-cell action-date'>{_html(expected or 'TBC')}</div>"
            f"<div class='action-cell'><span class='status-pill {status_class}'>{_html(symbol)} {_html(status)}</span></div>"
            "</div>"
        )
    parts.append("</div></div>")
    return "".join(parts)


def render_header(bundle: Dict[str, Any], selected_label: str) -> None:
    sched_latest = latest_row(bundle.get("schedule", []))
    hse_latest = latest_row(bundle.get("hse", []))
    actual_date = _normalize_date_label(sched_latest.get("cutoff") or hse_latest.get("cutoff"))
    logo_src = logo_data_uri()
    logo_html = f"<span class='app-logo-inline'><img src='{logo_src}'></span>" if logo_src else ""
    st.markdown(
        "<div class='hero-template'>"
        "<div class='hero-content'>"
        "<div class='hero-kicker'>Rail - Ponds - Roads</div>"
        f"<h1>{logo_html}Roger Campbell Scopes Control Center</h1>"
        "<div class='hero-meta'>"
        f"<span class='hero-chip actual-week'>Actual week: <b>{_html(selected_label)}</b></span>"
        f"<span class='hero-chip'>Actual date / cut-off: <b>{_html(actual_date)}</b></span>"
        "</div></div></div>"
        f"<div class='floating-week-square'><span>Active week</span><b>{_html(selected_label)}</b><small>{_html(actual_date)}</small></div>",
        unsafe_allow_html=True,
    )
    periods = available_periods(st.session_state.get("bundle", {}))
    labels = [period_display(y, w) for y, w in periods]
    current_idx = labels.index(selected_label) if selected_label in labels else (len(labels) - 1 if labels else 0)
    nav_cols = st.columns([0.10, 0.10, 0.80])
    with nav_cols[0]:
        st.button(
            "Back",
            key="top_week_back",
            use_container_width=True,
            disabled=current_idx <= 0,
            on_click=_set_active_week_by_offset,
            args=(-1,),
        )
    with nav_cols[1]:
        st.button(
            "Next",
            key="top_week_next",
            use_container_width=True,
            disabled=(not labels or current_idx >= len(labels) - 1),
            on_click=_set_active_week_by_offset,
            args=(1,),
        )
    with nav_cols[2]:
        st.markdown(
            f"<div class='week-nav-strip'><span class='week-highlight'>Active: {_html(selected_label)}</span><span class='week-note'>Actual date / cut-off: {_html(actual_date)}. Use Back / Next to move week by week.</span></div>",
            unsafe_allow_html=True,
        )


