def _baseline_feedback_from_row(r: pd.Series) -> str:
    days = r.get("Deviation days")
    if days is None or pd.isna(days):
        return "No reliable BL match. PM review required before using this as a baseline variance."
    days_int = int(days)
    basis = str(r.get("Baseline comparison basis") or "BL date")
    if days_int > 14:
        return f"Delayed vs {basis}. Immediate recovery plan / decision required."
    if days_int > 0:
        return f"Minor slip vs {basis}. Monitor and confirm mitigation in next weekly report."
    if days_int < 0:
        return f"Ahead of {basis}. Protect the gain and verify downstream interfaces."
    return f"Aligned with {basis}. Maintain current execution path."


def _baseline_comparison_table_html(rec: Dict[str, Any], selected_year: int, selected_week: int) -> str:
    df = build_milestone_df([rec], scope_filter=rec["scope_id"], selected_year=selected_year, selected_week=selected_week)
    if df.empty:
        return "<div class='action-empty'>No weekly forecast milestones available for baseline comparison.</div>"
    df = df.copy()
    df["Sort date"] = df["Forecast"].where(pd.notna(df["Forecast"]), df["Start / planned"])
    df = df.sort_values(["Sort date", "Milestone"], na_position="last")
    rows = []
    for _, r in df.iterrows():
        days = r.get("Deviation days")
        if days is None or pd.isna(days):
            status = "No BL match"
            variance = "N/A"
        else:
            days_int = int(days)
            if days_int > 14:
                status = "Delayed vs BL"
            elif days_int > 0:
                status = "Minor slip vs BL"
            elif days_int < 0:
                status = "Ahead of BL"
            else:
                status = "Aligned"
            variance = f"{days_int:+d} days"
        rows.append([
            r.get("Milestone"),
            r.get("Date basis"),
            r.get("Forecast label"),
            r.get("Forecast week"),
            r.get("Baseline comparison basis"),
            r.get("Baseline comparison label"),
            r.get("Baseline comparison week"),
            status,
            variance,
            _baseline_feedback_from_row(r),
            r.get("Baseline activity"),
        ])
    return _rc_html_table(["Weekly milestone", "Date basis", "Weekly FC", "FC week", "BL basis", "BL date", "BL week", "Deviation", "Variance", "Feedback", "Matched BL activity"], rows)


def render_milestone_timeline(
    records: List[Dict[str, Any]],
    scope_filter: Optional[str] = None,
    title: str = "Milestones",
    selected_year: Optional[int] = None,
    selected_week: Optional[int] = None,
    current_date: Optional[pd.Timestamp] = None,
) -> None:
    df = build_milestone_df(records, scope_filter=scope_filter, selected_year=selected_year, selected_week=selected_week)
    st.markdown(f"<div class='section-title'>{_html(title)}</div>", unsafe_allow_html=True)
    st.markdown(
        "<div class='timeline-deviation-note'><span class='timeline-type-pill'>Weekly FC point</span> Points are weekly-report forecast/control dates. Y-axis is ordered by the forecast/control date from earliest to latest. Hover includes the baseline feedback for each milestone where a reliable BL match exists.</div>",
        unsafe_allow_html=True,
    )
    if df.empty:
        st.info("No dated forecast milestones loaded for this selected week.")
        return
    sy = selected_year or int(pd.Timestamp.today().isocalendar().year)
    sw = selected_week or int(pd.Timestamp.today().isocalendar().week)
    selected_week_start = iso_week_start(sy, sw).normalize()
    df = df.copy()
    df["Feedback"] = df.apply(_baseline_feedback_from_row, axis=1)
    df["Sort date"] = df["Forecast"].where(pd.notna(df["Forecast"]), df["Start / planned"])
    df = df.sort_values(["Sort date", "Scope", "Milestone"], na_position="last").reset_index(drop=True)
    df["Label"] = df.apply(lambda r: f"{r['Scope']} - {compact_text(str(r['Milestone']), 46)}" if not scope_filter else compact_text(str(r["Milestone"]), 70), axis=1)
    df["Y"] = list(range(len(df)))
    df["Plot date"] = df["Forecast"].where(df["Forecast"] >= selected_week_start, selected_week_start)
    df["Timing status"] = df["Forecast"].apply(lambda v: "Overdue / before selected week" if pd.notna(v) and pd.Timestamp(v).normalize() < selected_week_start else "Upcoming")
    df["FC text"] = df.apply(lambda r: ("Overdue<br>" if r["Timing status"].startswith("Overdue") else "") + pd.Timestamp(r["Forecast"]).strftime("%d %b %Y") + "<br>" + str(r["Forecast week"]), axis=1)
    symbol_map = {"Forecast start date": "triangle-up", "Forecast finish / availability date": "diamond", "Forecast control date": "circle"}
    fig = go.Figure()
    for basis, sdf in df.groupby("Date basis", sort=False):
        fig.add_trace(go.Scatter(
            x=sdf["Plot date"],
            y=sdf["Y"],
            mode="markers+text",
            text=sdf["FC text"],
            textposition="middle right",
            name=str(basis),
            marker=dict(size=13, symbol=symbol_map.get(str(basis), "circle")),
            customdata=sdf[["Scope", "Milestone", "Risk", "Start label", "Start week", "Forecast label", "Forecast week", "Timing status", "Date basis", "Baseline comparison basis", "Baseline comparison label", "Baseline comparison week", "Deviation label", "Feedback"]],
            hovertemplate=(
                "<b>%{customdata[1]}</b><br>Scope: %{customdata[0]}<br>Risk / type: %{customdata[2]}<br>"
                "Weekly date type: %{customdata[8]}<br>Start / planned: %{customdata[3]} (%{customdata[4]})<br>"
                "Weekly FC/control date: %{customdata[5]} (%{customdata[6]})<br>Status: %{customdata[7]}<br>"
                "BL basis: %{customdata[9]}<br>BL date: %{customdata[10]} (%{customdata[11]})<br>Deviation: %{customdata[12]}<br>Feedback: %{customdata[13]}<extra></extra>"
            ),
        ))
    max_axis = max(df["Plot date"].max() + pd.Timedelta(days=14), selected_week_start + pd.Timedelta(days=42))
    tick_vals = list(pd.date_range(selected_week_start, max_axis, freq="W-MON"))
    if not tick_vals or pd.Timestamp(tick_vals[0]).normalize() != selected_week_start:
        tick_vals.insert(0, selected_week_start)
    tick_vals = sorted(set(pd.Timestamp(v).normalize() for v in tick_vals))
    tick_text = [f"{v.isocalendar().year} W{v.isocalendar().week:02d}<br>{v.strftime('%d %b')}" for v in tick_vals]
    fig.add_vline(x=selected_week_start, line_width=2, line_dash="dash", line_color="#111111")
    fig.add_annotation(x=selected_week_start, y=1.08, xref="x", yref="paper", text=f"Active {period_display(sy, sw)}", showarrow=False, font=dict(size=12, color="#111111"), bgcolor="#ffffff", bordercolor="#111111", borderwidth=1)
    fig.update_layout(
        title=f"{title} - weekly report FC/control dates",
        height=max(410, 48 * len(df) + 145),
        margin=dict(l=30, r=35, t=78, b=62),
        paper_bgcolor="rgba(0,0,0,0)",
        plot_bgcolor="rgba(0,0,0,0)",
        xaxis_title="Date / ISO week",
        yaxis_title="",
        legend=dict(orientation="h", yanchor="bottom", y=1.02, xanchor="right", x=1),
    )
    fig.update_yaxes(tickmode="array", tickvals=df["Y"].tolist(), ticktext=df["Label"].tolist(), autorange="reversed")
    fig.update_xaxes(range=[selected_week_start, max_axis], tickmode="array", tickvals=tick_vals, ticktext=tick_text, tickangle=-45, showgrid=True, tickfont=dict(size=9))
    st.markdown("<div class='timeline-note'>Timeline starts at the selected week. Y-axis is ordered from the earliest weekly FC/control date to the latest. Overdue items are pinned to the selected-week marker while preserving their original FC/control date in hover.</div>", unsafe_allow_html=True)
    st.plotly_chart(fig, use_container_width=True)


