# v13  Distribution integration - BOP | Distribution ()
def _ugp_distribution_history(bundle: Dict[str, Any]) -> List[Dict[str, Any]]:
    rows = [r for r in (bundle.get("ugp_distribution_history") or []) if isinstance(r, dict)]
    return sorted(rows, key=lambda r: (int(r.get("year") or 0), int(r.get("week") or 0)))


def _selected_ugp_distribution(bundle: Dict[str, Any], selected_year: int, selected_week: int) -> Optional[Dict[str, Any]]:
    rows = _ugp_distribution_history(bundle)
    eligible = [r for r in rows if (int(r.get("year") or 0), int(r.get("week") or 0)) <= (int(selected_year), int(selected_week))]
    return eligible[-1] if eligible else (rows[0] if rows else None)


def _ugp_milestones_from_distribution(dist: Optional[Dict[str, Any]]) -> List[Dict[str, Any]]:
    if not dist:
        return []
    items = []
    for wp in dist.get("waypoints", []) or []:
        fc = wp.get("forecast") or wp.get("forecast_raw")
        if not fc:
            continue
        name = wp.get("name") or " route waypoint"
        items.append({
            "name": f" - {name}",
            "planned": wp.get("planned") or wp.get("planned_raw"),
            "forecast": fc,
            "risk": "BOP Distribution route waypoint",
            "responsible": wp.get("responsible") or "Roger Campbell /  delivery team",
        })
    return items


def _apply_ugp_distribution_to_record(rec: Dict[str, Any], bundle: Dict[str, Any], selected_year: int, selected_week: int) -> Dict[str, Any]:
    if rec.get("scope_id") != "":
        return rec
    dist = _selected_ugp_distribution(bundle, selected_year, selected_week)
    if not dist:
        return rec
    sched = dist.get("ugp_schedule") or {}
    eng = dist.get("engineering_mdr") or {}
    proc = dist.get("procurement_tg") or {}
    actual = _safe_float(sched.get("actual"))
    forecast = _safe_float(sched.get("forecast"))
    deviation = actual - forecast if actual is not None and forecast is not None else None
    rec["construction_actual"] = actual
    rec["construction_forecast"] = forecast
    rec["construction_deviation"] = deviation
    rec["basis"] = "BOP | Distribution () -  (Schedule) cumulative row"
    rec["construction_etc"] = f"Next FC {_fmt_pct(sched.get('next_fc'))} | Plan {_fmt_pct(sched.get('plan'))}"
    rec["milestones"] = _ugp_milestones_from_distribution(dist) or rec.get("milestones", [])
    rec["ugp_distribution"] = dist
    # Keep distribution-specific route and schedule items visible in the active  panel.
    route_items = []
    for wp in dist.get("waypoints", []) or []:
        route_items.append(f"{wp.get('name')}: planned {wp.get('planned_raw') or 'TBC'} / forecast {wp.get('forecast_raw') or 'TBC'}")
    red = dist.get("red_activity_text")
    add_items = []
    if red:
        add_items.append(red)
    add_items.extend(route_items)
    rec["priority_items"] = merge_unique(add_items + rec.get("priority_items", []), limit=120)
    rec["interface_items"] = merge_unique(route_items + rec.get("interface_items", []), limit=24)
    rec["engineering_items"] = merge_unique([
        f"PB &  Engineering (MDR): actual {_fmt_pct(eng.get('actual'))}, forecast {_fmt_pct(eng.get('forecast'))}, next FC {_fmt_pct(eng.get('next_fc'))}",
        f"Procurement (TG): actual {_fmt_pct(proc.get('actual'))}, forecast {_fmt_pct(proc.get('forecast'))}",
    ] + rec.get("engineering_items", []), limit=24)
    return rec


def _ugp_distribution_table_rows(dist: Dict[str, Any]) -> List[List[Any]]:
    rows = []
    for wp in dist.get("waypoints", []) or []:
        planned = _parse_date(wp.get("planned") or wp.get("planned_raw"))
        forecast = _parse_date(wp.get("forecast") or wp.get("forecast_raw"))
        if pd.notna(planned) and pd.notna(forecast):
            delta = int((pd.Timestamp(forecast).normalize() - pd.Timestamp(planned).normalize()).days)
            if delta > 14:
                status = f"🔴 +{delta} days"
            elif delta > 0:
                status = f"🟠 +{delta} days"
            elif delta < 0:
                status = f"🟢 {delta} days"
            else:
                status = "⚪ 0 days"
        else:
            status = "⚪ TBC"
        rows.append([
            wp.get("name"),
            wp.get("planned_raw") or _fmt_date_short(wp.get("planned")),
            wp.get("forecast_raw") or _fmt_date_short(wp.get("forecast")),
            _date_week_label(wp.get("forecast") or wp.get("forecast_raw")),
            status,
            wp.get("responsible") or "Roger Campbell /  delivery team",
        ])
    return rows


def _ugp_distribution_chart(bundle: Dict[str, Any], selected_year: int, selected_week: int) -> None:
    hist = _ugp_distribution_history(bundle)
    if not hist:
        st.info("No BOP Distribution  history loaded.")
        return
    rows = []
    for r in hist:
        sched = r.get("ugp_schedule") or {}
        for label, key in [("Actual", "actual"), ("Plan", "plan"), ("Forecast", "forecast"), ("Next FC", "next_fc")]:
            val = _safe_float(sched.get(key))
            if val is None:
                continue
            rows.append({"Period": period_display(int(r.get("year") or 2026), int(r.get("week") or 0)), "Type": label, "Progress": val, "Sort": int(r.get("year") or 0)*100+int(r.get("week") or 0)})
    df = pd.DataFrame(rows)
    if df.empty:
        return
    fig = px.line(df.sort_values("Sort"), x="Period", y="Progress", color="Type", markers=True, title=" distribution progress trend - actual / plan / forecast / next FC", hover_data={"Progress": ":.2f", "Sort": False})
    active_label = period_display(selected_year, selected_week)
    if active_label in set(df["Period"]):
        ymin = float(df["Progress"].min()); ymax = float(df["Progress"].max()); pad = max(.2, (ymax-ymin)*.10)
        fig.add_trace(go.Scatter(x=[active_label, active_label], y=[ymin-pad, ymax+pad], mode="lines", name="Active week", line=dict(color="#111111", dash="dash", width=2), hoverinfo="skip"))
    fig.update_layout(height=360, margin=dict(l=30, r=20, t=60, b=35), paper_bgcolor="rgba(0,0,0,0)", plot_bgcolor="rgba(0,0,0,0)", yaxis_title=" schedule %", xaxis_title="Week / year", legend=dict(orientation="h", yanchor="bottom", y=1.02, xanchor="right", x=1))
    fig.update_xaxes(type="category")
    st.plotly_chart(fig, use_container_width=True)


def render_ugp_distribution_section(selected_year: int, selected_week: int) -> None:
    bundle = st.session_state.get("bundle", {})
    dist = _selected_ugp_distribution(bundle, selected_year, selected_week)
    st.markdown("<div class='section-title'>BOP Distribution  control</div>", unsafe_allow_html=True)
    if not dist:
        st.info("No BOP Distribution  page has been parsed yet.")
        return
    sched = dist.get("ugp_schedule") or {}; eng = dist.get("engineering_mdr") or {}; proc = dist.get("procurement_tg") or {}
    c1, c2, c3, c4 = st.columns(4)
    cards = [
        (" schedule", f"{_fmt_pct(sched.get('actual'))}", f"Forecast {_fmt_pct(sched.get('forecast'))} | Plan {_fmt_pct(sched.get('plan'))}"),
        ("Deviation vs forecast", _fmt_deviation((_safe_float(sched.get('actual')) or 0) - (_safe_float(sched.get('forecast')) or 0)), f"Next FC {_fmt_pct(sched.get('next_fc'))}"),
        ("PB &  engineering", f"{_fmt_pct(eng.get('actual'))}", f"Forecast {_fmt_pct(eng.get('forecast'))} | Next FC {_fmt_pct(eng.get('next_fc'))}"),
        ("Procurement TG", f"{_fmt_pct(proc.get('actual'))}", f"Forecast {_fmt_pct(proc.get('forecast'))}"),
    ]
    for col, (title, value, note) in zip([c1,c2,c3,c4], cards):
        with col:
            st.markdown(f"<div class='mini-kpi'><h4>{_html(title)}</h4><div class='value'>{_html(value)}</div><p>{_html(note)}</p></div>", unsafe_allow_html=True)
    st.markdown(f"<div class='ref-note'><b>Source:</b> {_html(dist.get('section_title'))}, {_html(dist.get('period_label'))}, file {_html(dist.get('file_name'))}. This section is excluded from the Executive overview and controls  as a detail-only scope.</div>", unsafe_allow_html=True)
    _ugp_distribution_chart(bundle, selected_year, selected_week)
    st.markdown("<div class='subsection-title'>Route waypoints from BOP Distribution  page</div>", unsafe_allow_html=True)
    st.markdown(_rc_html_table(["Route waypoint", "Planned", "Forecast", "FC week", "Delta", "Responsible"], _ugp_distribution_table_rows(dist)), unsafe_allow_html=True)
    if dist.get("red_activity_text"):
        st.markdown("<div class='subsection-title'>Active red activity / mitigation text</div>", unsafe_allow_html=True)
        st.markdown(f"<div class='item-card high'>{_html(dist.get('red_activity_text'))}</div>", unsafe_allow_html=True)


# v13 override: apply BOP Distribution  history to records.
_build_scope_records_base_v13 = build_scope_records

def build_scope_records(bundle: Dict[str, Any], profiles: Dict[str, Any], selected_year: int, selected_week: int, scopes: Optional[List[Tuple[str, str, str]]] = None) -> List[Dict[str, Any]]:
    records = _build_scope_records_base_v13(bundle, profiles, selected_year, selected_week, scopes=scopes)
