def _scope_label(scope_id: str) -> str:
    return {"rail": "Rail On Site (ROS)", "ponds": "Ponds", "roads": "Roads"}.get(scope_id, scope_id.title())


def _scope_display_name(rec_or_scope: Any) -> str:
    if isinstance(rec_or_scope, dict):
        sid = rec_or_scope.get("scope_id")
        name = rec_or_scope.get("name") or _scope_label(sid)
    else:
        sid = str(rec_or_scope)
        name = _scope_label(sid)
    return name


def _scope_icon(scope_id: str) -> str:
    return SCOPE_ICONS.get(scope_id, "▦")


def _fmt_date_full(value: Any) -> str:
    dt = _parse_date(value)
    if pd.isna(dt):
        return "To be provided"
    return pd.Timestamp(dt).strftime("%d %B %Y")


def _baseline_etc_for_scope(scope_id: str, selected_year: int, selected_week: int, mode: str = "next") -> str:
    baseline = _baseline_data()
    df = _baseline_rows(scope_id, baseline, selected_year, selected_week, horizon_days=620, milestones_only=True)
    if df.empty:
        return "To be provided"
    df = df.copy()
    finish_col = "Finish" if "Finish" in df.columns else ("Baseline finish" if "Baseline finish" in df.columns else None)
    if not finish_col:
        return "To be provided"
    df["FinishDT"] = pd.to_datetime(df[finish_col], errors="coerce")
    df = df[pd.notna(df["FinishDT"])]
    if df.empty:
        return "To be provided"
    if mode == "final":
        target = df["FinishDT"].max()
    else:
        active = iso_week_start(selected_year, selected_week).normalize()
        future = df[df["FinishDT"] >= active]
        target = (future["FinishDT"].min() if not future.empty else df["FinishDT"].max())
    return _fmt_date_full(target)


def scope_baseline_etc(scope_id: str, selected_year: int, selected_week: int) -> str:
    return _baseline_etc_for_scope(scope_id, selected_year, selected_week, mode="final")


def _update_query_week(label: str) -> None:
    try:
        st.query_params["week"] = label
    except Exception:
        pass


def _set_active_week_by_offset(offset: int) -> None:
    periods = available_periods(st.session_state.get("bundle", {}))
    if not periods:
        return
    labels = [period_display(y, w) for y, w in periods]
    current = st.session_state.get("week_selector_value") or labels[-1]
    idx = labels.index(current) if current in labels else len(labels) - 1
    new_idx = max(0, min(len(labels) - 1, idx + offset))
    if new_idx != idx:
        st.session_state["week_selector_value"] = labels[new_idx]
        _update_query_week(labels[new_idx])


def _safe_filename(name: str, suffix: str = "") -> str:
    base = re.sub(r"[^A-Za-z0-9_.-]+", "_", str(name or "file")).strip("_")
    if suffix and not base.lower().endswith(suffix.lower()):
        base += suffix
    return base or ("file" + suffix)


def _active_month_label_from_cost(cost_data: Dict[str, Any]) -> str:
    meta = cost_data.get("metadata") or {}
    raw = meta.get("cutoff_month") or meta.get("active_date") or meta.get("data_date") or meta.get("report_date")
    if not raw:
        return "Active month"
    if isinstance(raw, str) and re.match(r"^20\d{2}-\d{2}$", raw):
        dt = pd.to_datetime(raw + "-01", errors="coerce")
    else:
        dt = pd.to_datetime(raw, errors="coerce")
    if pd.notna(dt):
        return pd.Timestamp(dt).strftime("%Y-%B")
    return str(raw)


def _cost_reports() -> List[Dict[str, Any]]:
    pack = cached_monthly_cost_reports()
    reports = pack.get("reports", {}) or {}
    out: List[Dict[str, Any]] = []
    for rid, data in reports.items():
        label = _active_month_label_from_cost(data)
        # Keep labels unique but visually clean.
        if any(r["label"] == label for r in out):
            label = f"{label} ({rid})"
        out.append({"id": rid, "label": label, "active_date": label, "data": data})
    if not out:
        data = cached_monthly_cost()
        out = [{"id": "active", "label": _active_month_label_from_cost(data), "active_date": _active_month_label_from_cost(data), "data": data}]
    return sorted(out, key=lambda r: r["label"])


def _select_cost_report(scope_id: str = "portfolio") -> Dict[str, Any]:
    reports = _cost_reports()
    labels = [r["label"] for r in reports]
    key = f"monthly_cost_report_choice_{scope_id}"
    if key not in st.session_state or st.session_state.get(key) not in labels:
        st.session_state[key] = labels[-1] if labels else ""
    selected = st.selectbox("Monthly report to use", labels, key=key) if labels else ""
    for report in reports:
        if report["label"] == selected:
            return report["data"]
    return reports[-1]["data"] if reports else cached_monthly_cost()


def _active_cost_data(scope_id: str = "portfolio") -> Tuple[Dict[str, Any], str, str]:
    cost = _select_cost_report(scope_id)
    label = st.session_state.get(f"monthly_cost_report_choice_{scope_id}") or _active_month_label_from_cost(cost)
    return cost, label, label


def _vowd_for_scope(scope_id: str, cost_data: Optional[Dict[str, Any]] = None) -> Optional[float]:
    data = cost_data or _monthly_cost_data()
    v = (data.get("vowd_by_scope") or {}).get(scope_id)
    return _safe_float(v) if v is not None else VOWD_FALLBACK.get(scope_id)


def _cost_numbers(scope_id: str, cost_data: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    cost_data = cost_data or _monthly_cost_data()
    cs = _cost_summary(scope_id, cost_data)
    comps = _cost_components(scope_id, cost_data)
    packages = _cost_packages(scope_id, cost_data)
    budget = _first_not_none(cs.get("budget"), cs.get("baseline_control_budget"), cs.get("approved_control_budget"))
    if budget is None and scope_id == "rail":
        budget = _sum_values(packages, ["baseline_control_budget"])
    if budget is None and scope_id == "ponds":
        budget = PONDS_BUDGET_FALLBACK
    co = _first_not_none(cs.get("change_order"), cs.get("co"), cs.get("change_orders"))
    if co is None:
        if comps:
            co = _sum_values(comps, ["change_order", "co", "approved_change_deviation"])
        else:
            co = _sum_values(packages, ["approved_change_deviation", "change_order", "co"])
    forecast = _first_not_none(cs.get("forecast"), cs.get("eac"))
    exposure = _first_not_none(cs.get("potential_exposure"), cs.get("potential_deviation"), cs.get("exposure_total"), cs.get("potential_changes"))
    potential_forecast = cs.get("potential_forecast")
    if potential_forecast is None and _safe_float(forecast) is not None:
        potential_forecast = (_safe_float(forecast) or 0) + (_safe_float(exposure) or 0)
    vowd = _vowd_for_scope(scope_id, cost_data)
    etc = (_safe_float(forecast) or 0) - (vowd or 0) if forecast is not None and vowd is not None else None
    return {
        "budget": budget,
        "change_order": co,
        "forecast": forecast,
        "potential_exposure": exposure,
        "potential_forecast": potential_forecast,
        "vowd": vowd,
        "forecast_minus_vowd": etc,
        "basis": cs.get("basis") or "Monthly cost report",
        "exposure_count": cs.get("exposure_count") or 0,
        "high_exposure_count": cs.get("high_exposure_count") or 0,
        "display_note": cs.get("display_note") or "Values are normalized for scope control. Shared package splits are shown as component allocations where available.",
    }


def _cost_plain_html(scope_id: str, cost_data: Optional[Dict[str, Any]] = None) -> str:
    nums = _cost_numbers(scope_id, cost_data)
    cells = "".join([
        f"<div class='cost-plain-cell'><span>Forecast</span><b>{_html(_fmt_money(nums.get('forecast')))}</b></div>",
        f"<div class='cost-plain-cell'><span>VOWD</span><b>{_html(_fmt_money(nums.get('vowd')))}</b></div>",
    ])
    return f"<div class='cost-plain-card only-forecast-vowd'><div class='cost-plain-title'>Cost position - Forecast / VOWD</div><div class='cost-plain-grid two'>{cells}</div></div>"


def _waterfall_numbers(scope_id: str, cost_data: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    nums = _cost_numbers(scope_id, cost_data)
    budget = _safe_float(nums.get("budget"))
    co = _safe_float(nums.get("change_order"))
    forecast = _safe_float(nums.get("forecast"))
    exposure = _safe_float(nums.get("potential_exposure"))
    potential_forecast = _safe_float(nums.get("potential_forecast"))
    if potential_forecast is None and forecast is not None and exposure is not None:
        potential_forecast = forecast + exposure
    return {"budget": budget, "co": co, "forecast": forecast, "exposure": exposure, "potential_forecast": potential_forecast, "basis": nums.get("basis"), "note": nums.get("display_note")}


def _cost_candle_figure(scope_id: str, cost_data: Optional[Dict[str, Any]] = None, title: str = "Cost Status") -> go.Figure:
    vals = _waterfall_numbers(scope_id, cost_data)
    budget = vals.get("budget") or 0.0
    co = vals.get("co") or 0.0
    forecast = vals.get("forecast") or 0.0
    exposure = vals.get("exposure") or 0.0
    potential_forecast = vals.get("potential_forecast") or (forecast + exposure)
    labels = ["Budget", "CO", "Forecast", "Potential\nexposure", "Potential\nforecast"]
    y_vals = [budget, co, forecast, exposure, potential_forecast]
    measures = ["absolute", "relative", "total", "relative", "total"]
    text_vals = [_fmt_money(v) for v in y_vals]
    fig = go.Figure(go.Waterfall(
        x=labels,
        y=y_vals,
        measure=measures,
        text=text_vals,
        textposition="outside",
        connector={"line": {"color": "#9aa1ad", "width": 1}},
        increasing={"marker": {"color": "#007a45"}},
        decreasing={"marker": {"color": "#d00000"}},
        totals={"marker": {"color": "#c76df1"}},
        hovertemplate="%{x}<br>EUR %{y:,.0f}<extra></extra>",
    ))
    fig.update_layout(
        title={"text": title, "x": 0.02, "xanchor": "left"},
        height=360,
        margin=dict(l=34, r=22, t=62, b=64),
        paper_bgcolor="rgba(0,0,0,0)",
        plot_bgcolor="rgba(0,0,0,0)",
        yaxis_title="EUR",
        xaxis_title="",
        showlegend=False,
    )
    fig.update_xaxes(tickangle=-20)
    return fig


def tooltip_html(title: str, items: List[str], note: str = "Active-week items only.") -> str:
    if not items:
        items = ["No active items extracted for this week."]
    rows = "".join(f"<div class='hover-row'><span class='idx'>{i+1:02d}</span>{_html(compact_text(item, 210))}</div>" for i, item in enumerate(items[:12]))
    if len(items) > 12:
        rows += f"<div class='hover-row'><span class='idx'>+</span>{len(items)-12} more items in the table below.</div>"
    return (
        "<div class='tooltip'>"
        f"<div class='tooltip-title'>{_html(title)}</div>"
        f"<div class='tooltip-note'>{_html(note)}</div>"
        f"<div class='tooltip-list'>{rows}</div>"
        "</div>"
    )


def _html_table_raw(headers: List[str], rows: List[List[Any]], classes: str = "") -> str:
    if not rows:
        return "<div class='action-empty'>No rows available for this active selection.</div>"
    head = "".join(f"<th>{_html(h)}</th>" for h in headers)
    body = []
    for row in rows:
        cells = "".join(str(cell) if str(cell).startswith("<") else f"<td>{_html(cell)}</td>" for cell in row)
        body.append("<tr>" + cells + "</tr>")
    return f"<div class='copy-note'>Tip: select and copy this table directly from the browser to paste into Excel, Word or email as a table.</div><div class='action-table-scroll'><table class='action-copy-table {classes}'><thead><tr>{head}</tr></thead><tbody>{''.join(body)}</tbody></table></div>"


def action_table_html(
    items: List[Any],
    selected_year: int,
    selected_week: int,
    default_responsible: str = "TBC",
    max_items: int = 10,
    current_date: Optional[pd.Timestamp] = None,
) -> str:
    if not items:
        return "<div class='action-empty'>No active actions extracted for this section.</div>"
    sorted_items = sorted(items, key=lambda x: action_sort_key(x, selected_year, selected_week))[:max_items]
    rows = []
    for item in sorted_items:
        if isinstance(item, dict):
            action = clean_action_text(item.get("issue") or item.get("action") or "")
            responsible = item.get("owner") or infer_responsible(action, default_responsible)
            expected = item.get("due_date") or infer_expected_date(action, selected_year, selected_week)
        else:
            action = clean_action_text(item)
            responsible = infer_responsible(action, default_responsible)
            expected = infer_expected_date(action, selected_year, selected_week)
        if is_closed_action(action):
            symbol, status, status_class = "✅", "Closed", "closed"
        else:
            symbol, status, status_class = action_status(expected, selected_year, selected_week, current_date=current_date)
        rows.append([
            f"<td class='col-action action-main'>{_html(action)}</td>",
            f"<td class='col-resp action-resp'>{_html(responsible or 'TBC')}</td>",
            f"<td class='col-date action-date'>{_html(expected or 'TBC')}</td>",
            f"<td class='col-status'><span class='status-pill {status_class}'>{_html(symbol)} {_html(status)}</span></td>",
        ])
    return _html_table_raw(["Action / issue", "Responsible", "Expected date", "Status"], rows)


def render_executive_priority_delayed_near_table(records: List[Dict[str, Any]], selected_label: str, selected_year: int, selected_week: int, current_date: Optional[pd.Timestamp]) -> None:
    st.markdown(f"<div class='section-title'>Priority & high-exposure items requiring action - {_html(selected_label)}</div>", unsafe_allow_html=True)
    rows_data = _build_exec_action_rows(records, selected_year, selected_week, current_date)
    if not rows_data:
        st.markdown("<div class='action-empty'>No delayed or near-due priority/high-exposure items identified for the active week.</div>", unsafe_allow_html=True)
        return
    rows = []
    for r in rows_data:
        rows.append([
            f"<td class='col-scope scope'>{_html(r['Scope'])}</td>",
            f"<td class='col-action action-main'>{_html(r['Action'])}</td>",
            f"<td class='col-resp'>{_html(r['Responsible'])}</td>",
            f"<td class='col-date'>{_html(r['Expected'])}</td>",
            f"<td class='col-status'><span class='status-pill {r['StatusClass']}'>{_html(r['Symbol'])} {_html(r['Status'])}</span></td>",
        ])
    st.markdown(_html_table_raw(["Scope", "Action / issue", "Responsible", "Expected date", "Status"], rows, classes="exec-copy-table"), unsafe_allow_html=True)


def _build_exec_action_rows(records: List[Dict[str, Any]], selected_year: int, selected_week: int, current_date: Optional[pd.Timestamp]) -> List[Dict[str, Any]]:
    rows: List[Dict[str, Any]] = []
    for rec in records:
        for item in rec.get("priority_items", []) or []:
            action = clean_action_text(item)
            if not action:
                continue
            symbol, status, cls, expected = _status_for_action_text(action, selected_year, selected_week, current_date=current_date)
            if status not in {"Delayed", "Near due"}:
                continue
            rows.append({
                "Scope": rec.get("name"),
                "Action": action,
                "Responsible": infer_responsible(action, rec.get("default_responsible", "TBC")),
                "Expected": expected,
                "Status": status,
                "Symbol": symbol,
                "StatusClass": cls,
            })
    def sort_key(r: Dict[str, Any]) -> Tuple[int, pd.Timestamp, str, str]:
        due = parse_expected_date_label(r.get("Expected"), selected_year, selected_week)
        if pd.isna(due):
            due = pd.Timestamp.max
        return (0 if r.get("Status") == "Delayed" else 1, due, str(r.get("Scope")), str(r.get("Action")))
    return sorted(rows, key=sort_key)


def _baseline_reports() -> List[Dict[str, Any]]:
    reports = []
    dir_path = APP_DIR / "data" / "baseline_schedules"
    if dir_path.exists():
        for path in sorted(dir_path.glob("*.json")):
            try:
                data = json.loads(path.read_text(encoding="utf-8"))
            except Exception:
                continue
            meta = data.get("metadata") or data.get("meta") or data
            name = meta.get("baseline_name") or data.get("baseline_name") or path.stem
            cutoff = _fmt_date_short(meta.get("cutoff") or data.get("cutoff"))
            label = f"{name} | {cutoff}" if cutoff not in {"N/A", ""} else str(name)
            reports.append({"id": path.stem, "label": label, "path": path, "data": data})
    if not reports and BASELINE_SCHEDULE_PATH.exists():
        data = cached_baseline_schedule()
        meta = data.get("metadata") or data.get("meta") or data
        name = meta.get("baseline_name") or data.get("baseline_name") or "Project Baseline BL CC E006"
        cutoff = _fmt_date_short(meta.get("cutoff") or data.get("cutoff"))
        reports.append({"id": "default", "label": f"{name} | {cutoff}", "path": BASELINE_SCHEDULE_PATH, "data": data})
    return reports


def _select_baseline() -> Dict[str, Any]:
    reports = _baseline_reports()
    labels = [r["label"] for r in reports]
    key = "schedule_baseline_choice"
    if labels and (key not in st.session_state or st.session_state.get(key) not in labels):
        st.session_state[key] = labels[-1]
    if labels:
        st.sidebar.selectbox("Schedule baseline to use", labels, key=key, help="Select the baseline used for ETC and milestone variance analysis.")
        for r in reports:
            if r["label"] == st.session_state.get(key):
                st.session_state["active_baseline_data"] = r["data"]
                return r["data"]
    data = cached_baseline_schedule()
    st.session_state["active_baseline_data"] = data
    return data


def _baseline_data() -> Dict[str, Any]:
    return st.session_state.get("active_baseline_data") or cached_baseline_schedule()


def _parse_uploaded_cost_xlsx(uploaded_file: Any) -> Optional[Dict[str, Any]]:
    try:
        from openpyxl import load_workbook
        import tempfile
        with tempfile.NamedTemporaryFile(delete=False, suffix=".xlsx") as tmp:
            tmp.write(uploaded_file.getvalue())
            tmp_path = tmp.name
        wb = load_workbook(tmp_path, data_only=True, read_only=True)
        data: Dict[str, Any] = {"metadata": {"report_name": uploaded_file.name, "currency": "EUR"}, "scope_summary": {}, "packages_by_scope": {}, "components_by_scope": {}, "exposures_by_scope": {}, "vowd_by_scope": VOWD_FALLBACK.copy()}
        # Active date from common sheets.
        for sname in ["P. BOD-BOP-019E", "P. Packages", "Summary", "Cover"]:
            if sname in wb.sheetnames:
                ws = wb[sname]
                for row in ws.iter_rows(min_row=1, max_row=min(12, ws.max_row), values_only=True):
                    for i, v in enumerate(row):
                        if isinstance(v, str) and "data date" in v.lower():
                            nxt = row[i+1] if i+1 < len(row) else None
                            if nxt:
                                data["metadata"]["data_date"] = str(nxt)
                        if isinstance(v, str) and "cut-off month" in v.lower():
                            nxt = row[i+1] if i+1 < len(row) else None
                            if nxt:
                                data["metadata"]["cutoff_month"] = str(nxt)
        # Rail total from P. Packages.
        if "P. Packages" in wb.sheetnames:
            ws = wb["P. Packages"]
            for row in ws.iter_rows(values_only=True):
                vals = list(row)
                txt = " | ".join(str(v) for v in vals if v is not None).lower()
                if "rails on site - total" in txt:
                    nums = [x for x in vals if isinstance(x, (int, float))]
                    # Expected columns: budget, uncommitted, original committed, %, CO, %, committed, %, approved budget/eac, deviation, ..., potential changes, potential forecast.
                    budget = nums[0] if len(nums)>0 else None
                    co = nums[4] if len(nums)>4 else None
                    forecast = nums[8] if len(nums)>8 else (nums[6] if len(nums)>6 else None)
                    exposure = nums[13] if len(nums)>13 else None
                    potential_forecast = nums[14] if len(nums)>14 else (forecast + exposure if forecast and exposure else None)
                    data["scope_summary"]["rail"] = {"scope_id":"rail", "basis":"P. Packages - Rails On Site Total row", "budget":budget, "change_order":co, "forecast":forecast, "eac":forecast, "potential_exposure":exposure, "potential_forecast":potential_forecast, "display_note":"Parsed from uploaded cost report Rails On Site total row."}
                    break
        # Split package sheet for Ponds/Roads.
        if "P. BOD-BOP-019E" in wb.sheetnames:
            ws = wb["P. BOD-BOP-019E"]
            split_map = {"Ponds and Culverts":"ponds", "Roads and ditches":"roads"}
            comps = {"ponds": [], "roads": []}
            for row in ws.iter_rows(values_only=True):
                vals = list(row)
                label = str(vals[0] or "").strip()
                if label in split_map:
                    sid = split_map[label]
                    numeric = [v for v in vals[1:] if isinstance(v, (int,float))]
                    # columns after row label: Contracted TG5, Change Order, Pending Change, Potential Change, Grand Total. Some can be absent.
                    contracted = numeric[0] if len(numeric)>0 else None
                    change_order = numeric[1] if len(numeric)>1 else numeric[0] if numeric else None
                    pending = numeric[2] if len(numeric)>2 else None
                    potential = numeric[3] if len(numeric)>3 else None
                    grand = numeric[4] if len(numeric)>4 else (numeric[-1] if numeric else None)
                    if sid == "ponds" and not contracted:
                        contracted = PONDS_BUDGET_FALLBACK
                    data["scope_summary"][sid] = {"scope_id":sid, "basis":f"P. BOD-BOP-019E - {label} line", "budget":contracted, "change_order":change_order, "pending_changes":pending, "forecast":grand, "eac":grand, "potential_exposure":potential, "potential_forecast":(grand + potential if grand and potential else grand), "display_note":f"Parsed from uploaded cost report {label} split line."}
                    comps[sid].append({"component":label,"row_label":label,"package":"BOD-BOP-019E","contracted_tg5":contracted,"change_order":change_order,"pending_changes":pending,"potential_changes":potential,"grand_total":grand})
            data["components_by_scope"] = comps
        # Ensure missing scopes exist from previous active report.
        active = cached_monthly_cost()
        for sid in ["rail", "ponds", "roads"]:
            if sid not in data["scope_summary"] and sid in (active.get("scope_summary") or {}):
                data["scope_summary"][sid] = active["scope_summary"][sid]
            data.setdefault("packages_by_scope", {}).setdefault(sid, [])
            data.setdefault("components_by_scope", {}).setdefault(sid, (active.get("components_by_scope") or {}).get(sid, []))
            data.setdefault("exposures_by_scope", {}).setdefault(sid, (active.get("exposures_by_scope") or {}).get(sid, []))
        return data
    except Exception as e:
        st.sidebar.error(f"Could not parse cost report: {e}")
        return None


def _save_uploaded_cost_report(uploaded_file: Any) -> None:
    if uploaded_file is None:
        return
    MONTHLY_COST_DIR.mkdir(exist_ok=True)
    sources = APP_DIR / "sources"
    sources.mkdir(exist_ok=True)
    safe = _safe_filename(uploaded_file.name)
    (sources / safe).write_bytes(uploaded_file.getvalue())
    parsed = None
    if safe.lower().endswith(".json"):
        try:
            parsed = json.loads(uploaded_file.getvalue().decode("utf-8"))
        except Exception as e:
            st.sidebar.error(f"Could not read uploaded JSON cost report: {e}")
    elif safe.lower().endswith(".xlsx"):
        parsed = _parse_uploaded_cost_xlsx(uploaded_file)
    if parsed:
        label = _active_month_label_from_cost(parsed).replace(" ", "_")
        out = MONTHLY_COST_DIR / f"{label}_{Path(safe).stem}.json"
        out.write_text(json.dumps(parsed, ensure_ascii=False, indent=2), encoding="utf-8")
        try:
            cached_monthly_cost_reports.clear()
        except Exception:
            pass
        st.sidebar.success(f"Loaded cost report {label}")
        st.rerun()
    else:
        st.sidebar.info("Cost source saved. Upload a supported cost workbook/JSON to make it selectable.")


def _save_uploaded_baseline(uploaded_file: Any) -> None:
    if uploaded_file is None:
        return
    sources = APP_DIR / "sources"
    sources.mkdir(exist_ok=True)
    safe = _safe_filename(uploaded_file.name)
    (sources / safe).write_bytes(uploaded_file.getvalue())
    bs_dir = APP_DIR / "data" / "baseline_schedules"
    bs_dir.mkdir(exist_ok=True)
    if safe.lower().endswith(".json"):
        try:
            data = json.loads(uploaded_file.getvalue().decode("utf-8"))
            out = bs_dir / _safe_filename(Path(safe).stem, ".json")
            out.write_text(json.dumps(data, ensure_ascii=False, indent=2), encoding="utf-8")
            st.sidebar.success("Baseline JSON added and selectable.")
            st.rerun()
        except Exception as e:
            st.sidebar.error(f"Could not read baseline JSON: {e}")
    else:
        st.sidebar.info("Baseline source saved. For immediate selection upload the parsed baseline JSON; PDF/XER sources are stored for parser refresh.")


def render_sidebar(bundle: Dict[str, Any]) -> Tuple[str, int, int]:
    logo_src = logo_data_uri()
    if logo_src:
        st.sidebar.markdown(f"<div class='sidebar-logo'><img src='{logo_src}'><span>Scope controls</span></div>", unsafe_allow_html=True)
    st.sidebar.title("Control settings")

    periods = available_periods(st.session_state["bundle"])
    if not periods:
        selected_year, selected_week = (2026, 0)
    else:
        latest_y, latest_w = latest_period(st.session_state["bundle"])
        period_labels = [period_display(y, w) for y, w in periods]
        default_label = period_display(latest_y, latest_w)
        if default_label not in period_labels:
            default_label = period_labels[-1]
        # Query-param week support for floating Back/Next links.
        try:
            qp_week = st.query_params.get("week")
            if isinstance(qp_week, list):
                qp_week = qp_week[0] if qp_week else None
            if qp_week in period_labels:
                st.session_state["week_selector_value"] = qp_week
        except Exception:
            pass
        if st.session_state.get("week_selector_value") not in period_labels:
            st.session_state["week_selector_value"] = default_label
        selected_label = st.sidebar.selectbox("Week to display", period_labels, key="week_selector_value", help="Select any loaded report week manually. The dashboard uses data up to the selected week and active item lists from that week.")
        _update_query_week(selected_label)
        current_idx = period_labels.index(selected_label)
        st.sidebar.caption(f"Selected week {current_idx + 1} of {len(period_labels)}")
        selected_year, selected_week = periods[current_idx]

    st.sidebar.markdown("---")
    _select_baseline()

    st.sidebar.markdown("---")
    st.sidebar.markdown("<div class='subsection-title'>Panel</div>", unsafe_allow_html=True)
    if "panel_choice" not in st.session_state or st.session_state.get("panel_choice") not in [p[0] for p in PANEL_OPTIONS]:
        st.session_state["panel_choice"] = "Executive overview"
    icons = {"Executive overview": "▦", "Rail On Site (ROS)": "🚆", "Ponds": "💧", "Roads": "🛣️"}
    for key, label, _icon in PANEL_OPTIONS:
        button_label = f"{icons.get(key, '•')}  {label}"
        if st.sidebar.button(button_label, key=f"nav_{key}", use_container_width=True):
            st.session_state["panel_choice"] = key
    st.sidebar.markdown(f"<div class='nav-active'>Active panel: {icons.get(st.session_state['panel_choice'], '•')} {_html(st.session_state['panel_choice'])}</div>", unsafe_allow_html=True)
    st.sidebar.markdown("<div class='nav-hint'>Use the week selector to lock the dashboard to a historical report. Priority lists show only the active week. Milestones are timeline-only.</div>", unsafe_allow_html=True)

    st.sidebar.markdown("---")
    st.sidebar.markdown("<div class='subsection-title'>Upload / refresh</div>", unsafe_allow_html=True)
    uploaded = st.sidebar.file_uploader("Upload new weekly report PDF/PPTX", type=["pdf", "pptx"], accept_multiple_files=True)
    if uploaded:
        with st.sidebar:
            with st.spinner("Parsing weekly report(s)..."):
                new_bundle = parse_uploaded_reports(uploaded)
        st.session_state["bundle"] = merge_bundles(st.session_state["bundle"], new_bundle)
        st.sidebar.success("Weekly report data loaded into the session.")
    cost_upload = st.sidebar.file_uploader("Upload monthly cost report XLSX/JSON", type=["xlsx", "json"], key="cost_report_upload")
    if cost_upload:
        _save_uploaded_cost_report(cost_upload)
    baseline_upload = st.sidebar.file_uploader("Upload schedule baseline JSON/PDF", type=["json", "pdf", "xer", "csv"], key="baseline_upload")
    if baseline_upload:
        _save_uploaded_baseline(baseline_upload)
    if st.sidebar.button("Save current session data", use_container_width=True):
        save_bundle(st.session_state["bundle"], DATA_PATH)
        try:
            cached_bundle.clear()
        except Exception:
            pass
        st.sidebar.success("Saved weekly data to data/weekly_data_bundle.json")
    return st.session_state["panel_choice"], int(selected_year), int(selected_week)


def render_header(bundle: Dict[str, Any], selected_label: str) -> None:
    sched_latest = latest_row(bundle.get("schedule", []))
    hse_latest = latest_row(bundle.get("hse", []))
    actual_date = _normalize_date_label(sched_latest.get("cutoff") or hse_latest.get("cutoff"))
    logo_src = logo_data_uri()
    logo_html = f"<span class='app-logo-inline'><img src='{logo_src}'></span>" if logo_src else ""
    periods = available_periods(st.session_state.get("bundle", {}))
    labels = [period_display(y, w) for y, w in periods]
    current_idx = labels.index(selected_label) if selected_label in labels else (len(labels) - 1 if labels else 0)
    prev_label = labels[max(0, current_idx - 1)] if labels else selected_label
    next_label = labels[min(len(labels)-1, current_idx + 1)] if labels else selected_label
    prev_cls = "disabled" if current_idx <= 0 else ""
    next_cls = "disabled" if not labels or current_idx >= len(labels)-1 else ""
    st.markdown(
        "<div class='hero-template'>"
        "<div class='hero-content'>"
        "<div class='hero-kicker'>Rail - Ponds - Roads</div>"
        f"<h1>{logo_html}Roger Campbell Scopes Control Center</h1>"
        "<div class='hero-meta'>"
        f"<span class='hero-chip actual-week'>Actual week: <b>{_html(selected_label)}</b><br><small>Cut-off: {_html(actual_date)}</small></span>"
        "</div></div></div>"
        f"<div class='floating-week-square'><span>Actual week</span><b>{_html(selected_label)}</b><div class='float-cutoff'>Cut-off: {_html(actual_date)}</div><div class='float-nav'><a class='{prev_cls}' href='?week={_html(prev_label)}'>Back</a><a class='{next_cls}' href='?week={_html(next_label)}'>Next</a></div></div>",
        unsafe_allow_html=True,
    )
    nav_cols = st.columns([0.10, 0.10, 0.80])
    with nav_cols[0]:
        st.button("Back", key="top_week_back", use_container_width=True, disabled=current_idx <= 0, on_click=_set_active_week_by_offset, args=(-1,))
    with nav_cols[1]:
        st.button("Next", key="top_week_next", use_container_width=True, disabled=(not labels or current_idx >= len(labels)-1), on_click=_set_active_week_by_offset, args=(1,))
    with nav_cols[2]:
        st.markdown(f"<div class='week-nav-strip'><span class='week-highlight'>Active week: {_html(selected_label)}</span><span class='week-note'>Cut-off: {_html(actual_date)}. Back / Next moves one loaded report week at a time.</span></div>", unsafe_allow_html=True)


def render_scope_matrix(records: List[Dict[str, Any]], selected_year: int, selected_week: int) -> None:
    st.markdown("<div class='section-title'>Executive control matrix</div>", unsafe_allow_html=True)
    cost_data, _active_label, _active_date = _active_cost_data("portfolio")
    cols = st.columns(3)
    for col, rec in zip(cols, records):
        with col:
            construction_dev = rec.get("construction_deviation")
            if construction_dev is None and rec.get("construction_actual") is not None and rec.get("construction_forecast") is not None:
                construction_dev = rec.get("construction_actual") - rec.get("construction_forecast")
            engineering_actual = rec.get("engineering_actual")
            engineering_forecast = rec.get("engineering_forecast") if rec.get("engineering_forecast") is not None else engineering_actual
            engineering_dev = rec.get("engineering_deviation")
            if engineering_dev is None and engineering_actual is not None and engineering_forecast is not None:
                engineering_dev = engineering_actual - engineering_forecast
            construction_etc = _baseline_etc_for_scope(rec["scope_id"], selected_year, selected_week, mode="final")
            engineering_etc = rec.get("engineering_etc") or _baseline_etc_for_scope(rec["scope_id"], selected_year, selected_week, mode="next")
            html_block = (
                "<div class='matrix-col'>"
                "<div class='matrix-head'>"
                f"<h3><span class='scope-symbol'>{_html(_scope_icon(rec['scope_id']))}</span>{_html(rec['name'])}</h3>"
                f"<span class='status-badge'>{_html(rec.get('status', 'Monitor'))}</span>"
                "</div>"
                f"{progress_bar_html('Construction progress', rec.get('construction_actual'), rec.get('construction_forecast'), construction_dev, construction_etc)}"
                f"{progress_bar_html('Engineering progress', engineering_actual, engineering_forecast, engineering_dev, engineering_etc)}"
                f"<div class='next-fc'><b>Next week FC</b>{_html(rec.get('next_week_fc') or 'Not published in selected-week data')}</div>"
                "<div class='gate-row'>"
                f"{_gate_pill_html('Open quality gates', len(rec.get('quality_items', [])), rec.get('quality_items', []))}"
                f"{_gate_pill_html('Open engineering gates', len(rec.get('engineering_items', [])), rec.get('engineering_items', []))}"
                "</div>"
                f"{_cost_plain_html(rec['scope_id'], cost_data)}"
                "</div>"
            )
            st.markdown(html_block, unsafe_allow_html=True)


def render_progress_trend(rec: Dict[str, Any], selected_year: Optional[int] = None, selected_week: Optional[int] = None) -> None:
    df = rec.get("progress_series", pd.DataFrame())
    if df is None or df.empty:
        st.info("No scope progress trend loaded for the selected period.")
        return
    df = df.sort_values("period_sort") if "period_sort" in df.columns else df
    rows = []
    for _, r in df.iterrows():
        actual = _safe_float(r.get("actual"))
        forecast = _safe_float(r.get("forecast"))
        deviation = _safe_float(r.get("deviation"))
        if deviation is None and actual is not None and forecast is not None:
            deviation = actual - forecast
        if actual is not None:
            rows.append({"Period": r.get("period_label"), "Progress type": "Actual", "Progress": actual, "Deviation": deviation, "Forecast": forecast, "Sort": r.get("period_sort")})
        if forecast is not None:
            rows.append({"Period": r.get("period_label"), "Progress type": "Forecast", "Progress": forecast, "Deviation": deviation, "Forecast": forecast, "Sort": r.get("period_sort")})
    chart_df = pd.DataFrame(rows)
    if chart_df.empty:
        st.info("No actual / forecast progress values loaded for this scope.")
        return
    chart_df = chart_df.sort_values("Sort")
    active_label = period_display(selected_year, selected_week) if selected_year and selected_week else None
    fig = px.line(chart_df, x="Period", y="Progress", color="Progress type", markers=True, title=f"{rec['name']} progress trend", hover_data={"Progress": ":.2f", "Forecast": ":.2f", "Deviation": ":+.2f", "Sort": False})
    for trace in fig.data:
        labels = []
        for x, y in zip(trace.x, trace.y):
            if trace.name == "Actual" and active_label and x == active_label:
                labels.append(f"{float(y):.2f}%")
            else:
                labels.append("")
        trace.text = labels
        trace.mode = "lines+markers+text"
        trace.textposition = "top center"
    if active_label and active_label in set(chart_df["Period"]):
        ymin = float(chart_df["Progress"].min()); ymax = float(chart_df["Progress"].max()); pad = max(0.15, (ymax-ymin)*0.10)
        fig.add_trace(go.Scatter(x=[active_label, active_label], y=[ymin-pad, ymax+pad], mode="lines", name="Active week", line=dict(color="#111111", dash="dash", width=2), hoverinfo="skip"))
    fig.update_layout(height=385, margin=dict(l=30, r=20, t=70, b=70), paper_bgcolor="rgba(0,0,0,0)", plot_bgcolor="rgba(0,0,0,0)", yaxis_title="Progress %", xaxis_title="Week / year", legend=dict(orientation="h", yanchor="top", y=-0.24, xanchor="left", x=0), title=dict(x=0.02, xanchor="left"))
    fig.update_xaxes(type="category")
    st.plotly_chart(fig, use_container_width=True)


def render_cost_overview(records: List[Dict[str, Any]]) -> None:
    st.markdown("<div class='section-title'>Cost Status</div>", unsafe_allow_html=True)
    cost_data = _select_cost_report("portfolio")
    active_month = st.session_state.get("monthly_cost_report_choice_portfolio") or _active_month_label_from_cost(cost_data)
    st.markdown(f"<div class='cost-section-head single'><span class='cost-active-pill month-only'>Active month: {_html(active_month)}</span></div>", unsafe_allow_html=True)
    st.markdown("<div class='cost-waterfall-note'>Waterfall/candle-bar sequence follows the Budget Forecast presentation logic: Budget - CO - Forecast - Potential exposure - Potential forecast.</div>", unsafe_allow_html=True)
    st.markdown("<div class='cost-status-grid'>", unsafe_allow_html=True)
    cols = st.columns(3)
    for col, rec in zip(cols, records):
        with col:
            st.markdown("<div class='cost-waterfall-wrap'>", unsafe_allow_html=True)
            st.plotly_chart(_cost_candle_figure(rec["scope_id"], cost_data, title=f"{rec['name']} - Cost Status"), use_container_width=True)
            nums = _cost_numbers(rec["scope_id"], cost_data)
            st.markdown(f"<div class='cost-waterfall-note'>{_html(compact_text(nums.get('display_note') or nums.get('basis'), 260))}</div>", unsafe_allow_html=True)
            st.markdown("</div>", unsafe_allow_html=True)
    st.markdown("</div>", unsafe_allow_html=True)


def render_scope_cost_section(rec: Dict[str, Any]) -> None:
    st.markdown("<div class='section-title'>Cost control - monthly cost report</div>", unsafe_allow_html=True)
    cost = _select_cost_report(rec["scope_id"])
    active_month = st.session_state.get(f"monthly_cost_report_choice_{rec['scope_id']}") or _active_month_label_from_cost(cost)
    cs = _cost_summary(rec["scope_id"], cost)
    if not cs:
        st.info("No monthly cost data loaded for this scope.")
        return
    nums = _cost_numbers(rec["scope_id"], cost)
    st.markdown(f"<div class='cost-section-head single'><span class='cost-active-pill month-only'>Active month: {_html(active_month)}</span></div>", unsafe_allow_html=True)
    st.markdown("<div class='cost-order-note'><b>Order:</b> Budget - CO - Forecast - Potential exposure - Potential forecast.</div>", unsafe_allow_html=True)
    st.plotly_chart(_cost_candle_figure(rec["scope_id"], cost, title=f"{rec['name']} - Cost Status"), use_container_width=True)
    metric_data = [
        ("Budget", nums["budget"], nums["basis"]),
        ("CO", nums["change_order"], "Approved / component change order"),
        ("Forecast", nums["forecast"], "Current EAC / forecast"),
        ("Potential exposure", nums["potential_exposure"], nums.get("display_note") if rec["scope_id"] == "roads" else f"{int(nums['high_exposure_count'])} high / {int(nums['exposure_count'])} total O&V items"),
        ("Potential forecast", nums["potential_forecast"], "Forecast plus active exposure"),
    ]
    mcols = st.columns(5)
    for col, (title, value, note) in zip(mcols, metric_data):
        with col:
            css = "bad" if title in {"Potential exposure", "Potential forecast"} else ("warn" if title == "CO" else "")
            st.markdown(f"<div class='cost-metric {css}'><span>{_html(title)}</span><b>{_html(_fmt_money(value))}</b><p style='margin:6px 0 0 0; font-size:.70rem; color:#667085; line-height:1.25;'>{_html(str(note or ''))}</p></div>", unsafe_allow_html=True)
    comp_rows = _scope_component_rows(rec["scope_id"], cost)
    if comp_rows:
        with st.expander("Scope cost split - component allocation", expanded=False):
            st.markdown(_rc_html_table(["Component", "Row label", "Package", "Revision", "Budget/TG5", "CO", "CAPEX", "Pending", "Potential", "Forecast / total", "Driver / allocation note"], comp_rows, numeric_cols={4,5,6,7,8,9}), unsafe_allow_html=True)
    pkg_rows = _scope_package_rows(rec["scope_id"], cost)
    if pkg_rows:
        with st.expander("Package drivers", expanded=False):
            st.markdown(_rc_html_table(["Package", "Description", "Supplier", "Budget", "CO", "Forecast", "Exposure", "Potential forecast", "Driver / note"], pkg_rows, numeric_cols={3,4,5,6,7}), unsafe_allow_html=True)
    exposures = _cost_exposures(rec["scope_id"], cost)
    if exposures:
        exp_rows = [[e.get("item_id"), e.get("package"), _fmt_money_full(e.get("amount")), e.get("criticality") or "", e.get("type") or "", e.get("description") or e.get("main_description"), e.get("pm") or "", _fmt_date_short(e.get("award_date"))] for e in exposures]
        with st.expander("Potential changes / O&V exposure items", expanded=False):
            st.markdown(_rc_html_table(["Item", "Package", "Amount", "Criticality", "Type", "Description", "Responsible", "Expected / award date"], exp_rows, numeric_cols={2}), unsafe_allow_html=True)


def render_milestone_timeline(
    records: List[Dict[str, Any]],
    scope_filter: Optional[str] = None,
    title: str = "Milestones",
    selected_year: Optional[int] = None,
    selected_week: Optional[int] = None,
    current_date: Optional[pd.Timestamp] = None,
) -> None:
    df = build_milestone_df(records, scope_filter=scope_filter, selected_year=selected_year, selected_week=selected_week)
    st.markdown(f"<div class='section-title'>{_html(title)}</div>", unsafe_allow_html=True)
    st.markdown("<div class='timeline-deviation-note'><span class='timeline-type-pill'>Weekly FC point</span> Points are weekly-report forecast/control dates sorted from earliest to latest. Hover shows whether each point is a start, finish/availability or control date and gives the baseline feedback.</div>", unsafe_allow_html=True)
    if df.empty:
        st.info("No dated forecast milestones loaded for this selected week.")
        return
    sy = selected_year or int(pd.Timestamp.today().isocalendar().year)
    sw = selected_week or int(pd.Timestamp.today().isocalendar().week)
    selected_week_start = iso_week_start(sy, sw).normalize()
    df = df.copy()
    df["Feedback"] = df.apply(_baseline_feedback_from_row, axis=1)
    df["Sort date"] = df["Forecast"].where(pd.notna(df["Forecast"]), df["Start / planned"])
    df = df.sort_values(["Sort date", "Scope", "Milestone"], na_position="last").reset_index(drop=True)
    df["Label"] = df.apply(lambda r: f"{r['Scope']} - {compact_text(str(r['Milestone']), 46)}" if not scope_filter else compact_text(str(r["Milestone"]), 70), axis=1)
    df["Y"] = list(range(len(df)))
    df["Plot date"] = df["Forecast"].where(df["Forecast"] >= selected_week_start, selected_week_start)
    df["Timing status"] = df["Forecast"].apply(lambda v: "Overdue / before selected week" if pd.notna(v) and pd.Timestamp(v).normalize() < selected_week_start else "Upcoming")
    df["FC text"] = df.apply(lambda r: ("Overdue<br>" if r["Timing status"].startswith("Overdue") else "") + pd.Timestamp(r["Forecast"]).strftime("%d %b %Y") + "<br>" + str(r["Forecast week"]), axis=1)
    symbol_map = {"Forecast start date": "triangle-up", "Forecast finish / availability date": "diamond", "Forecast control date": "circle"}
    fig = go.Figure()
    for basis, sdf in df.groupby("Date basis", sort=False):
        fig.add_trace(go.Scatter(
            x=sdf["Plot date"], y=sdf["Y"], mode="markers+text", text=sdf["FC text"], textposition="middle right", name=str(basis), marker=dict(size=13, symbol=symbol_map.get(str(basis), "circle")),
            customdata=sdf[["Scope", "Milestone", "Risk", "Start label", "Start week", "Forecast label", "Forecast week", "Timing status", "Date basis", "Baseline activity", "Baseline ID", "Baseline comparison basis", "Baseline comparison label", "Baseline comparison week", "Deviation label", "Feedback"]],
            hovertemplate=("<b>%{customdata[1]}</b><br>Scope: %{customdata[0]}<br>Risk: %{customdata[2]}<br>Weekly date type: %{customdata[8]}<br>Start / planned: %{customdata[3]} (%{customdata[4]})<br>Weekly FC: %{customdata[5]} (%{customdata[6]})<br>Status: %{customdata[7]}<br>Baseline match: %{customdata[9]}<br>Baseline ID: %{customdata[10]}<br>BL comparison basis: %{customdata[11]}<br>BL comparison date: %{customdata[12]} (%{customdata[13]})<br>Deviation: %{customdata[14]}<br>Feedback: %{customdata[15]}<extra></extra>")
        ))
    max_axis = max(df["Plot date"].max() + pd.Timedelta(days=14), selected_week_start + pd.Timedelta(days=42))
    tick_vals = list(pd.date_range(selected_week_start, max_axis, freq="W-MON"))
    if not tick_vals or tick_vals[0] != selected_week_start:
        tick_vals.insert(0, selected_week_start)
    tick_vals = sorted(set(pd.Timestamp(v).normalize() for v in tick_vals))
    tick_text = [f"{v.isocalendar().year} W{v.isocalendar().week:02d}<br>{v.strftime('%d %b')}" for v in tick_vals]
    fig.add_vline(x=selected_week_start, line_width=2, line_dash="dash", line_color="#111111")
    fig.add_annotation(x=selected_week_start, y=1.08, xref="x", yref="paper", text=f"Active {period_display(sy, sw)}", showarrow=False, font=dict(size=12, color="#111111"), bgcolor="#ffffff", bordercolor="#111111", borderwidth=1)
    fig.update_layout(title=f"{title} - weekly FC dates with BL comparison", height=max(410, 48*len(df)+145), margin=dict(l=30, r=35, t=78, b=62), paper_bgcolor="rgba(0,0,0,0)", plot_bgcolor="rgba(0,0,0,0)", xaxis_title="Date / ISO week", yaxis_title="", legend=dict(orientation="h", yanchor="bottom", y=1.02, xanchor="right", x=1))
    fig.update_yaxes(tickmode="array", tickvals=df["Y"].tolist(), ticktext=df["Label"].tolist(), autorange="reversed")
    fig.update_xaxes(range=[selected_week_start, max_axis], tickmode="array", tickvals=tick_vals, ticktext=tick_text, tickangle=-45, showgrid=True, tickfont=dict(size=9))
    st.plotly_chart(fig, use_container_width=True)


def render_scope_sections(rec: Dict[str, Any], selected_year: int, selected_week: int, current_date: Optional[pd.Timestamp] = None) -> None:
    selected_label = period_display(selected_year, selected_week)
    st.markdown(f"<div class='scope-banner'><h2>{_html(_scope_icon(rec['scope_id']))} {_html(rec['full_name'])} control panel</h2><p>{_html(compact_text(rec.get('insight', ''), 420))}</p></div>", unsafe_allow_html=True)
    col1, col2 = st.columns([1, 1])
    with col1:
        render_progress_gauge(rec)
    with col2:
        render_progress_trend(rec, selected_year, selected_week)
    render_milestone_timeline([rec], scope_filter=rec["scope_id"], title="Milestones", selected_year=selected_year, selected_week=selected_week, current_date=current_date)
    render_scope_baseline_section(rec, selected_year, selected_week)
    render_scope_cost_section(rec)
    render_action_table(f"{rec['name']} priority & high-exposure items - {selected_label}", rec.get("priority_items", []), selected_year, selected_week, rec.get("default_responsible", "TBC"), max_items=999, current_date=current_date)
    st.markdown("<div class='section-title'>Engineering / design</div>", unsafe_allow_html=True)
    engineering_actual = rec.get("engineering_actual")
    engineering_forecast = rec.get("engineering_forecast") if rec.get("engineering_forecast") is not None else engineering_actual
    engineering_dev = rec.get("engineering_deviation")
    if engineering_dev is None and engineering_actual is not None and engineering_forecast is not None:
        engineering_dev = engineering_actual - engineering_forecast
    st.markdown(progress_bar_html("Engineering progress", engineering_actual, engineering_forecast, engineering_dev, rec.get("engineering_etc") or _baseline_etc_for_scope(rec["scope_id"], selected_year, selected_week, mode="next")), unsafe_allow_html=True)
    st.markdown(f"<div class='item-card engineering'>{_html(rec.get('engineering_basis') or 'Scope-specific engineering basis not published.')}</div>", unsafe_allow_html=True)
    render_engineering_trend(rec, selected_year, selected_week)
    render_action_table("", rec.get("engineering_items", []), selected_year, selected_week, rec.get("default_responsible", "TBC"), max_items=12, current_date=current_date)
    st.markdown("<div class='section-title'>Quality / completion</div>", unsafe_allow_html=True)
    render_action_table("", rec.get("quality_items", []), selected_year, selected_week, rec.get("default_responsible", "TBC"), max_items=14, current_date=current_date)
    st.markdown("<div class='section-title'>Interface / commercial controls</div>", unsafe_allow_html=True)
    render_action_table("", rec.get("interface_items", []), selected_year, selected_week, rec.get("default_responsible", "TBC"), max_items=14, current_date=current_date)


def render_executive_overview(bundle: Dict[str, Any], profiles: Dict[str, Any], selected_year: int, selected_week: int, current_date: Optional[pd.Timestamp] = None) -> None:
    records = build_scope_records(bundle, profiles, selected_year, selected_week, scopes=CONTROL_SCOPES)
    selected_label = period_display(selected_year, selected_week)
    cutoff = current_date if current_date is not None else selected_cutoff_date(bundle)
    render_scope_matrix(records, selected_year, selected_week)
    render_cost_overview(records)
    render_executive_priority_delayed_near_table(records, selected_label, selected_year, selected_week, current_date=cutoff)
    render_milestone_timeline(records, title="Milestones", selected_year=selected_year, selected_week=selected_week, current_date=cutoff)



