def render_loading_overlay() -> None:
    src = logo_data_uri()
    if src:
        st.markdown(f"<div class='rc-load-overlay'><div class='rc-load-logo'><img src='{src}'></div></div>", unsafe_allow_html=True)


def _co_reconciliation_value(scope_id: str, cost_data: Optional[Dict[str, Any]] = None) -> Optional[float]:
    nums = _cost_numbers(scope_id, cost_data)
    budget = _safe_float(nums.get("budget"))
    forecast = _safe_float(nums.get("forecast"))
    if budget is not None and forecast is not None:
        return forecast - budget
    return _safe_float(nums.get("change_order"))


def _waterfall_numbers(scope_id: str, cost_data: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    nums = _cost_numbers(scope_id, cost_data)
    budget = _safe_float(nums.get("budget"))
    forecast = _safe_float(nums.get("forecast"))
    exposure = _safe_float(nums.get("potential_exposure"))
    potential_forecast = _safe_float(nums.get("potential_forecast"))
    if potential_forecast is None and forecast is not None and exposure is not None:
        potential_forecast = forecast + exposure
    co = _co_reconciliation_value(scope_id, cost_data)
    return {"budget": budget, "co": co, "forecast": forecast, "exposure": exposure, "potential_forecast": potential_forecast, "basis": nums.get("basis"), "note": nums.get("display_note")}


