def _period_slug(year: int, week: int) -> str:
    return f"{int(year)}-W{int(week):02d}"


def _period_from_slug(slug: Any, periods: List[Tuple[int, int]]) -> Optional[Tuple[int, int]]:
    text = str(slug or "").strip().replace(" ", "")
    m = re.match(r"^(20\d{2})-?W(\d{1,2})$", text, flags=re.I)
    if not m:
        return None
    val = (int(m.group(1)), int(m.group(2)))
    return val if val in periods else None


def _date_long(value: Any) -> str:
    ts = _parse_date(value)
    if pd.isna(ts):
        return "TBC"
    return pd.Timestamp(ts).strftime("%d %B %Y")


def _year_month_label(value: Any) -> str:
    raw = str(value or "").strip()
    if not raw:
        return "Active month"
    if re.match(r"^20\d{2}-\d{2}$", raw):
        dt = pd.to_datetime(raw + "-01", errors="coerce")
    else:
        dt = pd.to_datetime(raw, errors="coerce")
    if pd.isna(dt):
        return raw
    return pd.Timestamp(dt).strftime("%Y-%B")


def _display_scope_name(scope_id: str) -> str:
    return SCOPE_DISPLAY.get(scope_id, str(scope_id).title())


def _with_display_scope(rec: Dict[str, Any]) -> Dict[str, Any]:
    out = dict(rec)
    sid = out.get("scope_id")
    if sid in SCOPE_DISPLAY:
        out["name"] = SCOPE_DISPLAY[sid]
        out["full_name"] = SCOPE_DISPLAY[sid]
    return out


def tooltip_html(title: str, items: List[str], note: str = "Active-week items only.") -> str:
    if not items:
        items = ["No active items extracted for the selected week."]
    rows = "".join(f"<div class='tooltip-item'><b>{i+1}.</b>{_html(compact_text(item, 220))}</div>" for i, item in enumerate(items[:12]))
    return (
        "<div class='tooltip'>"
        f"<div class='tooltip-title'>{_html(title)}</div>"
        f"<div class='tooltip-note'>{_html(note)}</div>"
        f"<div class='tooltip-list'>{rows}</div>"
        "</div>"
    )


def _wrap_copyable_html_table(html_table: str, headers: List[str], rows: List[List[Any]], key_prefix: str = "tbl") -> str:
    raw = "\n".join(["\t".join(str(h or "") for h in headers)] + ["\t".join(str(c or "") for c in row) for row in rows])
    ident = "copy_" + hashlib.sha1(raw.encode("utf-8", "ignore")).hexdigest()[:10]
    # Inline JS works in local browser builds; if blocked by browser policy, the visible HTML table remains selectable.
    button = (
        f"<button class='copy-btn' onclick=\"navigator.clipboard.writeText(document.getElementById('{ident}').value).then(()=>this.innerText='Copied')\"></button>"
        f"<textarea id='{ident}' style='position:absolute;left:-9999px;top:-9999px;'>{_html(raw)}</textarea>"
    )
    return f"<div class='copy-table-wrap'>{button}{html_table}</div>"


def _rc_html_table(headers: List[str], rows: List[List[Any]], numeric_cols: Optional[set] = None) -> str:
    numeric_cols = numeric_cols or set()
    if not rows:
        return "<div class='action-empty'>No items loaded for this section.</div>"
    keep = _table_column_keep(headers, rows)
    headers2 = [headers[i] for i in keep]
    rows2 = [[row[i] if i < len(row) else "" for i in keep] for row in rows]
    numeric2 = {new_i for new_i, old_i in enumerate(keep) if old_i in numeric_cols}
    head = "".join(f"<th>{_html(h)}</th>" for h in headers2)
    body_parts = []
    for row in rows2:
        cells = []
        for i, val in enumerate(row):
            txt = str(val or "")
            long_cls = " wide-text" if len(txt) > 70 else ""
            if i == 0 and len(txt) > 45:
                long_cls += " driver-text"
            cls = " class='rc-num'" if i in numeric2 else (f" class='{long_cls.strip()}'" if long_cls.strip() else "")
            cells.append(f"<td{cls}>{_html(val)}</td>")
        body_parts.append("<tr>" + "".join(cells) + "</tr>")
    table = "<div class='rc-table-scroll'><table class='rc-table'><thead><tr>" + head + "</tr></thead><tbody>" + "".join(body_parts) + "</tbody></table></div>"
    return _wrap_copyable_html_table(table, headers2, rows2, "rc")


def action_table_html(
    items: List[Any],
    selected_year: int,
    selected_week: int,
    default_responsible: str = "TBC",
    max_items: int = 10,
    current_date: Optional[pd.Timestamp] = None,
) -> str:
    if not items:
        return "<div class='action-empty'>No active actions extracted for this section.</div>"
    sorted_items = sorted(items, key=lambda x: action_sort_key(x, selected_year, selected_week))
    headers = ["Action / issue", "Responsible", "Expected date", "Status"]
    rows_for_copy: List[List[Any]] = []
    parts = ["<div class='action-table-scroll'><div class='action-table'>"]
    parts.append("<div class='action-row action-head'><div class='action-cell'>Action / issue</div><div class='action-cell'>Responsible</div><div class='action-cell'>Expected date</div><div class='action-cell'>Status</div></div>")
    for item in sorted_items[:max_items]:
        if isinstance(item, dict):
            action = clean_action_text(item.get("issue") or item.get("action") or item.get("description") or "")
            responsible = item.get("owner") or item.get("responsible") or infer_responsible(action, default_responsible)
            expected = item.get("due_date") or item.get("expected_date") or infer_expected_date(action, selected_year, selected_week)
        else:
            action = clean_action_text(item)
            responsible = infer_responsible(action, default_responsible)
            expected = infer_expected_date(action, selected_year, selected_week)
        if is_closed_action(action):
            symbol, status, status_class = "OK", "Closed", "closed"
        else:
            symbol, status, status_class = action_status(expected, selected_year, selected_week, current_date=current_date)
        rows_for_copy.append([action, responsible or "TBC", expected or "TBC", f"{symbol} {status}"])
        parts.append(
            "<div class='action-row'>"
            f"<div class='action-cell action-main'>{_html(action)}</div>"
            f"<div class='action-cell action-resp'>{_html(responsible or 'TBC')}</div>"
            f"<div class='action-cell action-date'>{_html(expected or 'TBC')}</div>"
            f"<div class='action-cell'><span class='status-pill {status_class}'>{_html(symbol)} {_html(status)}</span></div>"
            "</div>"
        )
    parts.append("</div></div>")
    return _wrap_copyable_html_table("".join(parts), headers, rows_for_copy, "actions")


def _cost_active_date_label(cost_data: Dict[str, Any]) -> str:
    meta = cost_data.get("metadata") or {}
    raw = meta.get("cutoff_month") or meta.get("active_date") or meta.get("data_date") or meta.get("report_date")
    return _year_month_label(raw)


def _cost_reports() -> List[Dict[str, Any]]:
    pack = cached_monthly_cost_reports()
    reports = pack.get("reports", {}) or {}
    out: List[Dict[str, Any]] = []
    seen: Dict[str, int] = {}
    for rid, data in reports.items():
        active_date = _cost_active_date_label(data)
        seen[active_date] = seen.get(active_date, 0) + 1
        label = active_date if seen[active_date] == 1 else f"{active_date} ({seen[active_date]})"
        out.append({"id": rid, "label": label, "active_date": active_date, "data": data})
    if not out:
        data = cached_monthly_cost()
        out = [{"id": "active", "label": _cost_active_date_label(data), "active_date": _cost_active_date_label(data), "data": data}]
    return out


def _select_cost_report(scope_id: str = "portfolio") -> Dict[str, Any]:
    reports = _cost_reports()
    labels = [r["label"] for r in reports]
    key = f"monthly_cost_report_choice_{scope_id}"
    if key not in st.session_state or st.session_state.get(key) not in labels:
        st.session_state[key] = labels[-1] if labels else ""
    selected = st.selectbox("Monthly report to use", labels, key=key, help="Select the monthly cost report used by this section.") if labels else ""
    for report in reports:
        if report["label"] == selected:
            return report["data"]
    return reports[-1]["data"] if reports else cached_monthly_cost()


def _active_cost_data(scope_id: str = "portfolio") -> Tuple[Dict[str, Any], str, str]:
    reports = _cost_reports()
    labels = [r["label"] for r in reports]
    key = f"monthly_cost_report_choice_{scope_id}"
    selected = st.session_state.get(key) if st.session_state.get(key) in labels else (labels[-1] if labels else "")
    for report in reports:
        if report["label"] == selected:
            return report["data"], report["label"], report["active_date"]
    if reports:
        return reports[-1]["data"], reports[-1]["label"], reports[-1]["active_date"]
    data = cached_monthly_cost()
    return data, _cost_active_date_label(data), _cost_active_date_label(data)


def _cost_numbers(scope_id: str, cost_data: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    cost_data = cost_data or _monthly_cost_data()
    cs = _cost_summary(scope_id, cost_data)
    packages = _cost_packages(scope_id, cost_data)
    budget = _first_not_none(cs.get("budget"), cs.get("baseline_control_budget"), cs.get("approved_control_budget"))
    if budget is None and scope_id == "rail":
        budget = _sum_values(packages, ["baseline_control_budget"])
    # Ponds has published budget in the Initial Budget/Budget Forecast source even when the May pivot line has no contracted TG5.
    if budget is None and scope_id == "ponds":
        budget = 9132901.73
    forecast = _first_not_none(cs.get("forecast"), cs.get("eac"))
    exposure = _first_not_none(cs.get("potential_exposure"), cs.get("potential_deviation"), cs.get("exposure_total"), cs.get("potential_changes"))
    potential_forecast = cs.get("potential_forecast")
    if potential_forecast is None and _safe_float(forecast) is not None:
        potential_forecast = (_safe_float(forecast) or 0) + (_safe_float(exposure) or 0)
    # Make the waterfall/candle math coherent: Forecast = Budget + CO; Potential Forecast = Forecast + Exposure.
    co = None
    if _safe_float(forecast) is not None and _safe_float(budget) is not None:
        co = (_safe_float(forecast) or 0) - (_safe_float(budget) or 0)
    else:
        co = _first_not_none(cs.get("change_order"), cs.get("co"), cs.get("change_orders"))
    exposure_for_chart = None
    if _safe_float(potential_forecast) is not None and _safe_float(forecast) is not None:
        exposure_for_chart = (_safe_float(potential_forecast) or 0) - (_safe_float(forecast) or 0)
    elif exposure is not None:
        exposure_for_chart = exposure
    vowd = _first_not_none(cs.get("vowd"), cs.get("value_of_work_done"), cs.get("vowd_actual_cost"))
    return {
        "budget": budget,
        "change_order": co,
        "forecast": forecast,
        "potential_exposure": exposure_for_chart,
        "potential_forecast": potential_forecast,
        "vowd": vowd,
        "forecast_minus_vowd": (_safe_float(forecast) - _safe_float(vowd)) if _safe_float(forecast) is not None and _safe_float(vowd) is not None else None,
        "basis": cs.get("basis") or "Monthly cost report",
        "exposure_count": cs.get("exposure_count") or 0,
        "high_exposure_count": cs.get("high_exposure_count") or 0,
        "display_note": cs.get("display_note") or "Values are normalized for scope control. Shared package splits are shown as component allocations when available.",
    }


def _cost_plain_html(scope_id: str, cost_data: Optional[Dict[str, Any]] = None) -> str:
    nums = _cost_numbers(scope_id, cost_data)
    forecast = nums.get("forecast")
    vowd = nums.get("vowd")
    forecast_minus_vowd = nums.get("forecast_minus_vowd")
    values = [("Forecast", forecast), ("VOWD", vowd), ("Forecast - VOWD", forecast_minus_vowd)]
    cells = "".join(
        f"<div class='cost-plain-cell {'primary' if k == 'Forecast - VOWD' else ''}'><span>{_html(k)}</span><b>{_html(_fmt_money(v))}</b></div>"
        for k, v in values
    )
    note = compact_text(nums.get("display_note") or nums.get("basis") or "", 150)
    return f"<div class='cost-plain-card'><div class='cost-plain-title'>Cost position</div><div class='cost-plain-grid'>{cells}<div class='cost-plain-note'>{_html(note)}</div></div></div>"


def _waterfall_numbers(scope_id: str, cost_data: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    nums = _cost_numbers(scope_id, cost_data)
    budget = _safe_float(nums.get("budget"))
    forecast = _safe_float(nums.get("forecast"))
    potential_forecast = _safe_float(nums.get("potential_forecast"))
    co = _safe_float(nums.get("change_order"))
    exposure = _safe_float(nums.get("potential_exposure"))
    if co is None and budget is not None and forecast is not None:
        co = forecast - budget
    if exposure is None and forecast is not None and potential_forecast is not None:
        exposure = potential_forecast - forecast
    return {"budget": budget, "co": co, "forecast": forecast, "exposure": exposure, "potential_forecast": potential_forecast, "basis": nums.get("basis"), "note": nums.get("display_note")}


def _cost_candle_figure(scope_id: str, cost_data: Optional[Dict[str, Any]] = None, title: str = "Cost candle bar") -> go.Figure:
    vals = _waterfall_numbers(scope_id, cost_data)
    budget = vals.get("budget")
    co = vals.get("co")
    forecast = vals.get("forecast")
    exposure = vals.get("exposure")
    potential_forecast = vals.get("potential_forecast")
    labels = ["Budget", "CO", "Forecast", "Potential exposure", "Potential forecast"]
    y_vals = [budget or 0.0, co or 0.0, forecast or 0.0, exposure or 0.0, potential_forecast or 0.0]
    measures = ["absolute", "relative", "total", "relative", "total"]
    text_vals = [_fmt_money(v) if v is not None else "N/A" for v in [budget, co, forecast, exposure, potential_forecast]]
    fig = go.Figure(go.Waterfall(
        x=labels, y=y_vals, measure=measures, text=text_vals, textposition="outside",
        connector={"line": {"color": "#8f96a3", "width": 1}},
        increasing={"marker": {"color": "#007a45"}},
        decreasing={"marker": {"color": "#d00000"}},
        totals={"marker": {"color": "#c76df1"}},
        hovertemplate="%{x}<br>EUR %{y:,.0f}<extra></extra>",
    ))
    fig.update_layout(title=title, height=355, margin=dict(l=28, r=18, t=62, b=66), paper_bgcolor="rgba(0,0,0,0)", plot_bgcolor="rgba(0,0,0,0)", yaxis_title="EUR", showlegend=False)
    fig.update_xaxes(tickangle=-25)
    return fig


def progress_bar_html(label: str, actual: Any, forecast: Any, deviation: Any, etc: str = "To be provided", title: str = "Deviation vs Forecast") -> str:
    actual_pct = clamp_pct(actual)
    forecast_num = _safe_float(forecast)
    forecast_pct = clamp_pct(forecast_num if forecast_num is not None else actual_pct)
    dev = _safe_float(deviation)
    if dev is None and _safe_float(actual) is not None and forecast_num is not None:
        dev = _safe_float(actual) - forecast_num
    if dev is None:
        dev = 0.0
    return (
        "<div class='progress-box'>"
        "<div class='progress-top'>"
        f"<div class='progress-title'>{_html(label)}</div>"
        f"<div class='progress-value'>{_html(_fmt_pct(actual))}</div>"
        "</div>"
        "<div class='progress-track'>"
        f"<div class='progress-fill' style='width:{actual_pct:.2f}%;'></div>"
        f"<div class='progress-forecast' style='left:{forecast_pct:.2f}%;'></div>"
        "</div>"
        "<div class='progress-meta'>"
        f"<div><span>Forecast</span><b class='forecast-badge'>{_html(_fmt_pct(forecast_num if forecast_num is not None else actual))}</b></div>"
        f"<div class='dev-cell'>{deviation_badge(dev, title)}</div>"
        f"<div class='etc-line'><span>ETC</span><b>{_html(etc or 'To be provided')}</b></div>"
        "</div>"
        "</div>"
    )


def _baseline_etc_for_scope(scope_id: str, selected_year: int, selected_week: int, mode: str = "next") -> str:
    baseline = _baseline_data()
    df = _baseline_rows(scope_id, baseline, selected_year, selected_week, horizon_days=760, milestones_only=True)
    if df.empty:
        return "TBC"
    active_start = iso_week_start(selected_year, selected_week).normalize()
    future = df[df["Finish"] >= active_start].copy()
    if future.empty:
        item = df.sort_values("Finish").iloc[-1]
    elif mode == "final":
        item = future.sort_values("Finish").iloc[-1]
    else:
        item = future.sort_values("Finish").iloc[0]
    return _date_long(item.get("Finish"))


def render_header(bundle: Dict[str, Any], selected_label: str) -> None:
    sched_latest = latest_row(bundle.get("schedule", []))
    hse_latest = latest_row(bundle.get("hse", []))
    actual_date = _normalize_date_label(sched_latest.get("cutoff") or hse_latest.get("cutoff"))
    logo_src = logo_data_uri()
    logo_html = f"<span class='app-logo-inline'><img src='{logo_src}'></span>" if logo_src else ""
    loader_html = f"<div class='launch-loader'><div class='loader-box'><img src='{logo_src}'></div></div>" if logo_src and not st.session_state.get("loader_seen") else ""
    st.session_state["loader_seen"] = True
    periods = available_periods(st.session_state.get("bundle", {}))
    labels = [period_display(y, w) for y, w in periods]
    current_idx = labels.index(selected_label) if selected_label in labels else (len(labels) - 1 if labels else 0)
    prev_href = "#" if current_idx <= 0 else f"?active_week={_period_slug(*periods[current_idx-1])}"
    next_href = "#" if (not labels or current_idx >= len(labels) - 1) else f"?active_week={_period_slug(*periods[current_idx+1])}"
    prev_cls = "float-week-btn disabled" if current_idx <= 0 else "float-week-btn"
    next_cls = "float-week-btn disabled" if (not labels or current_idx >= len(labels) - 1) else "float-week-btn"
    st.markdown(
        loader_html +
        "<div class='hero-template'>"
        "<div class='hero-content'>"
        "<div class='hero-kicker'>Rail - Ponds - Roads</div>"
        f"<h1>{logo_html}Roger Campbell Scopes Control Center</h1>"
        "<div class='hero-meta'>"
        f"<span class='hero-chip actual-week'>Actual week: <b>{_html(selected_label)}</b><small>Cut-off: {_html(actual_date)}</small></span>"
        "</div></div></div>"
        f"<div class='floating-week-square'><span>Actual week</span><b>{_html(selected_label)}</b><small>Cut-off: {_html(actual_date)}</small><div class='float-week-actions'><a class='{prev_cls}' href='{prev_href}'>◀ Back</a><a class='{next_cls}' href='{next_href}'>Next ▶</a></div></div>",
        unsafe_allow_html=True,
    )


def render_sidebar(bundle: Dict[str, Any]) -> Tuple[str, int, int]:
    logo_src = logo_data_uri()
    if logo_src:
        st.sidebar.markdown(f"<div class='sidebar-logo'><img src='{logo_src}'><span>Scope controls</span></div>", unsafe_allow_html=True)
    st.sidebar.title("Control settings")

    periods = available_periods(st.session_state["bundle"])
