def render_sidebar(bundle: Dict[str, Any]) -> Tuple[str, int, int]:
    logo_src = logo_data_uri()
    if logo_src:
        st.sidebar.markdown(f"<div class='sidebar-logo'><img src='{logo_src}'><span>Scope controls</span></div>", unsafe_allow_html=True)
    st.sidebar.title("Control settings")

    periods = available_periods(st.session_state["bundle"])
    if not periods:
        selected_year, selected_week = (2026, 0)
    else:
        period_labels = [period_display(y, w) for y, w in periods]
        latest_y, latest_w = latest_period(st.session_state["bundle"])
        default_label = period_display(latest_y, latest_w)
        if default_label not in period_labels:
            default_label = period_labels[-1]
        if st.session_state.get("week_selector_value") not in period_labels:
            st.session_state["week_selector_value"] = default_label
        st.sidebar.markdown("<div class='subsection-title'>Week control</div>", unsafe_allow_html=True)
        selected_label = st.sidebar.selectbox(
            "Week to display",
            period_labels,
            key="week_selector_value",
            help="Select any loaded report week manually. The dashboard uses data up to the selected week and item lists from the selected week.",
        )
        current_idx = period_labels.index(selected_label)
        st.sidebar.caption(f"Selected week {current_idx + 1} of {len(period_labels)}")
        selected_year, selected_week = periods[current_idx]

    st.sidebar.markdown("---")
    st.sidebar.markdown("<div class='subsection-title'>Panel</div>", unsafe_allow_html=True)
    visible_panels = [p[0] for p in PANEL_OPTIONS if p[0] in {"Executive overview", "Rail On Site (ROS)", "Rail", "Ponds", "Roads"}]
    if "Rail" in visible_panels and "Rail On Site (ROS)" not in visible_panels:
        # Keep compatibility with older data while presenting the requested label.
        visible_panels = ["Rail On Site (ROS)" if p == "Rail" else p for p in visible_panels]
    if not visible_panels:
        visible_panels = ["Executive overview", "Rail On Site (ROS)", "Ponds", "Roads"]
    if "panel_choice" not in st.session_state or st.session_state.get("panel_choice") not in visible_panels:
        st.session_state["panel_choice"] = visible_panels[0]
    icons = {"Executive overview": "▦", "Rail On Site (ROS)": "🚆", "Rail": "🚆", "Ponds": "💧", "Roads": "🛣️"}
    for label in visible_panels:
        if st.sidebar.button(f"{icons.get(label, '•')} {label}", key=f"nav_v19_{label}", use_container_width=True):
            st.session_state["panel_choice"] = label
    st.sidebar.markdown(f"<div class='nav-active'>Current panel: {_html(st.session_state['panel_choice'])}</div>", unsafe_allow_html=True)
    st.sidebar.caption(f"Loaded {latest_period_label(st.session_state['bundle'])} - {source_count(st.session_state['bundle'])} source reports")
    st.sidebar.markdown("<div class='nav-hint'>Use the week selector to lock the dashboard to a historical report. Priority lists show only the active week. Milestones are timelines only.</div>", unsafe_allow_html=True)

    st.sidebar.markdown("---")
    st.sidebar.markdown("<div class='subsection-title'>Cost / baseline selectors</div>", unsafe_allow_html=True)
    cost_reports = _cost_reports()
    cost_labels = [r["label"] for r in cost_reports if r.get("label")]
    if cost_labels:
        if st.session_state.get("monthly_cost_report_choice_portfolio") not in cost_labels:
            st.session_state["monthly_cost_report_choice_portfolio"] = cost_labels[-1]
        st.sidebar.selectbox("Monthly report to use", cost_labels, key="monthly_cost_report_choice_portfolio")
        st.sidebar.markdown(f"<div class='cost-active-pill'>Active month: {_html(st.session_state['monthly_cost_report_choice_portfolio'])}</div>", unsafe_allow_html=True)
    baseline_reports = _baseline_reports()
    bl_labels = [r["label"] for r in baseline_reports if r.get("label")]
    if bl_labels:
        if st.session_state.get("baseline_choice") not in bl_labels:
            st.session_state["baseline_choice"] = bl_labels[-1]
        st.sidebar.selectbox("Baseline to use", bl_labels, key="baseline_choice")

    st.sidebar.markdown("---")
    st.sidebar.markdown("<div class='subsection-title'>Upload / refresh</div>", unsafe_allow_html=True)
    uploaded_weekly = st.sidebar.file_uploader(
        "Upload new weekly report PDF/PPTX",
        type=["pdf", "pptx"],
        accept_multiple_files=True,
        key="weekly_upload_v19",
        help="Upload one or more weekly reports. The parser merges new report weeks into the current session.",
    )
    if uploaded_weekly:
        key = _upload_list_hash(uploaded_weekly)
        if key != st.session_state.get("last_weekly_upload_key_v19"):
            with st.spinner("Parsing uploaded weekly report(s) and refreshing the control center..."):
                try:
                    incoming = parse_uploaded_reports(uploaded_weekly)
                    st.session_state["bundle"] = merge_bundles(st.session_state["bundle"], incoming)
                    st.session_state["last_weekly_upload_key_v19"] = key
                    st.sidebar.success(f"{len(uploaded_weekly)} weekly report(s) parsed and loaded.")
                except Exception as exc:
                    st.sidebar.error(f"Could not parse weekly upload: {exc}")

    uploaded_cost_reports = st.sidebar.file_uploader(
        "Upload monthly cost report XLSX",
        type=["xlsx"],
        accept_multiple_files=True,
        key="cost_upload_v19",
        help="Upload one or more monthly cost reports. Each report is normalized, stored and added to the monthly-report selector.",
    )
    if uploaded_cost_reports:
        key = _upload_list_hash(uploaded_cost_reports)
        if key != st.session_state.get("last_cost_upload_key_v19"):
            loaded = 0
            errors: List[str] = []
            for uploaded in uploaded_cost_reports:
                try:
                    _register_uploaded_cost_report(uploaded)
                    loaded += 1
                except Exception as exc:
                    errors.append(f"{uploaded.name}: {exc}")
            st.session_state["last_cost_upload_key_v19"] = key
            cached_monthly_cost_reports.clear()
            if loaded:
                # Select the latest loaded report after the cache refresh.
                refreshed = _cost_reports()
                if refreshed:
                    st.session_state["monthly_cost_report_choice_portfolio"] = refreshed[-1]["label"]
                st.sidebar.success(f"{loaded} cost report(s) uploaded and registered.")
            for msg in errors:
                st.sidebar.error(f"Could not parse cost report - {msg}")
            if loaded:
                _safe_rerun()

    uploaded_baselines = st.sidebar.file_uploader(
        "Upload schedule baseline PDF",
        type=["pdf"],
        accept_multiple_files=True,
        key="baseline_upload_v19",
        help="Upload one or more baseline PDFs. Parsed baselines are added to the baseline selector.",
    )
    if uploaded_baselines:
        key = _upload_list_hash(uploaded_baselines)
        if key != st.session_state.get("last_baseline_upload_key_v19"):
            loaded = 0
            errors: List[str] = []
            for uploaded in uploaded_baselines:
                try:
                    _register_uploaded_baseline(uploaded)
                    loaded += 1
                except Exception as exc:
                    errors.append(f"{uploaded.name}: {exc}")
            st.session_state["last_baseline_upload_key_v19"] = key
            try:
                cached_baseline_schedules.clear()
            except Exception:
                pass
            if loaded:
                refreshed = _baseline_reports()
                if refreshed:
                    st.session_state["baseline_choice"] = refreshed[-1]["label"]
                st.sidebar.success(f"{loaded} baseline file(s) uploaded and registered.")
            for msg in errors:
                st.sidebar.error(f"Could not parse baseline - {msg}")
            if loaded:
                _safe_rerun()

    if st.sidebar.button("Save current session data", use_container_width=True):
        save_bundle(st.session_state["bundle"], DATA_PATH)
        try:
            cached_bundle.clear()
        except Exception:
            pass
        st.sidebar.success("Saved weekly data to data/weekly_data_bundle.json")

    # Internally the data may still use the old 'Rail' key for panel routing.
    panel_choice = st.session_state["panel_choice"]
    if panel_choice == "Rail On Site (ROS)" and "Rail On Site (ROS)" not in SCOPE_PANEL_MAP:
        # main() expects the visible label to exist in SCOPE_PANEL_MAP for detail pages.
        SCOPE_PANEL_MAP["Rail On Site (ROS)"] = "rail"
    return panel_choice, int(selected_year), int(selected_week)



