def render_action_table(title: str, items: List[Any], selected_year: int, selected_week: int, default_responsible: str = "TBC", max_items: int = 10, current_date: Optional[pd.Timestamp] = None) -> None:
    if title:
        st.markdown(f"<div class='section-title'>{_html(title)}</div>", unsafe_allow_html=True)
    if not items:
        st.markdown("<div class='action-empty'>No active actions extracted for this section.</div>", unsafe_allow_html=True)
        return
    sorted_items = sorted(items, key=lambda x: action_sort_key(x, selected_year, selected_week))[:max_items]
    rows: List[List[Any]] = []
    for item in sorted_items:
        if isinstance(item, dict):
            action = clean_action_text(item.get("issue") or item.get("action") or item.get("description") or "")
            responsible = item.get("owner") or item.get("responsible") or infer_responsible(action, default_responsible)
            expected = item.get("due_date") or item.get("expected_date") or infer_expected_date(action, selected_year, selected_week)
        else:
            action = clean_action_text(item)
            responsible = infer_responsible(action, default_responsible)
            expected = infer_expected_date(action, selected_year, selected_week)
        if is_closed_action(action):
            status = "✅ Closed"
        else:
            symbol, stat, _cls = action_status(expected, selected_year, selected_week, current_date=current_date)
            status = f"{symbol} {stat}"
        rows.append([action, responsible or "TBC", expected or "TBC", status])
    _copyable_table_component(["Action / issue", "Responsible", "Expected date", "Status"], rows, key_prefix=title or "actions")


def _baseline_comparison_rows(rec: Dict[str, Any], selected_year: int, selected_week: int) -> List[List[Any]]:
    df = build_milestone_df([rec], scope_filter=rec["scope_id"], selected_year=selected_year, selected_week=selected_week)
    if df.empty:
        return []
    df["Sort date"] = df["Forecast"].where(pd.notna(df["Forecast"]), df["Start / planned"])
    df = df.sort_values(["Sort date", "Milestone"], na_position="last")
    rows: List[List[Any]] = []
    for _, r in df.iterrows():
        days = r.get("Deviation days")
        if days is None or pd.isna(days):
            status = "⚪ No BL match"
            variance = "N/A"
        else:
            days_int = int(days)
            if days_int > 14:
                status = "🔴 Delayed vs BL"
            elif days_int > 0:
                status = "🟠 Minor slip vs BL"
            elif days_int < 0:
                status = "🟢 Ahead of BL"
            else:
                status = "🟢 Aligned"
            variance = f"{days_int:+d} days"
        rows.append([r.get("Milestone"), r.get("Date basis"), r.get("Forecast label"), r.get("Forecast week"), r.get("Baseline comparison basis"), r.get("Baseline comparison label"), r.get("Baseline comparison week"), status, variance, r.get("Baseline activity")])
    return rows


def render_scope_baseline_section(rec: Dict[str, Any], selected_year: int, selected_week: int) -> None:
    baseline = _baseline_data()
    meta = baseline.get("metadata") or baseline.get("meta") or baseline
    baseline_name = meta.get("baseline_name") or baseline.get("baseline_name") or "Project Baseline BL CC E006"
    cutoff = meta.get("cutoff") or baseline.get("cutoff")
    print_date = meta.get("print_date") or baseline.get("print_date")
    df = _baseline_rows(rec["scope_id"], baseline, selected_year, selected_week, horizon_days=500, milestones_only=True)
    label = f"Schedule baseline control - {baseline_name} | Cut-off {_fmt_date_short(cutoff)}"
    with st.expander(label, expanded=False):
        st.markdown(
            f"<div class='baseline-expander-note'><b>Active baseline:</b> {_html(baseline_name)}. Cut-off {_html(_fmt_date_short(cutoff))}; print date {_html(_fmt_date_short(print_date))}. Activities are filtered to {_html(rec['name'])} and shown from the active week. The comparison table highlights variance between weekly-report FC/control dates and the matched baseline date.</div>",
            unsafe_allow_html=True,
        )
        rows = _baseline_comparison_rows(rec, selected_year, selected_week)
        if rows:
            _copyable_table_component(["Weekly milestone", "Weekly date type", "Weekly FC", "FC week", "BL comparison basis", "BL comparison date", "BL week", "Deviation", "Variance", "Matched BL activity"], rows, key_prefix=f"bl_{rec['scope_id']}")
        else:
            st.markdown("<div class='action-empty'>No weekly forecast milestones available for baseline comparison.</div>", unsafe_allow_html=True)
        st.markdown("<div class='subsection-title'>Baseline forecast timeline</div>", unsafe_allow_html=True)
        _baseline_timeline(df, selected_year, selected_week, f"{rec['name']} baseline forecast timeline", limit=48)


def render_scope_matrix(records: List[Dict[str, Any]], selected_year: int, selected_week: int) -> None:
    st.markdown("<div class='section-title'>Executive control matrix</div>", unsafe_allow_html=True)
    cost_data, _active_label, _active_date = _active_cost_data("portfolio")
    order = {"rail": 0, "ponds": 1, "roads": 2}
    records = [_with_display_scope(r) for r in records if r.get("scope_id") in order]
    records = sorted(records, key=lambda r: order.get(r.get("scope_id"), 99))
    cols = st.columns(3)
    for col, rec in zip(cols, records):
        with col:
            construction_dev = rec.get("construction_deviation")
            if construction_dev is None and rec.get("construction_actual") is not None and rec.get("construction_forecast") is not None:
                construction_dev = rec.get("construction_actual") - rec.get("construction_forecast")
            engineering_actual = rec.get("engineering_actual")
            engineering_forecast = rec.get("engineering_forecast") if rec.get("engineering_forecast") is not None else engineering_actual
            engineering_dev = rec.get("engineering_deviation")
            if engineering_dev is None and engineering_actual is not None and engineering_forecast is not None:
                engineering_dev = engineering_actual - engineering_forecast
            construction_etc = _baseline_etc_for_scope(rec["scope_id"], selected_year, selected_week, mode="final")
            engineering_etc = _date_only_etc(rec.get("engineering_etc") or _baseline_etc_for_scope(rec["scope_id"], selected_year, selected_week, mode="next"), fallback="TBC")
            driver = rec.get("status") or rec.get("insight") or "Monitor"
            icon = SCOPE_ICON.get(rec["scope_id"], "●")
            construction_next = _next_progress_label(rec, selected_year, selected_week, "construction")
            engineering_next = _next_progress_label(rec, selected_year, selected_week, "engineering")
            html_block = (
                "<div class='matrix-col'>"
                "<div class='matrix-head'>"
                f"<h3><span class='scope-icon'>{icon}</span>{_html(rec['name'])}</h3>"
                f"<span class='status-badge'>{_html(driver)}</span>"
                "</div>"
                f"{progress_bar_html('Construction progress', rec.get('construction_actual'), rec.get('construction_forecast'), construction_dev, construction_etc, next_week_forecast=construction_next)}"
                f"{progress_bar_html('Engineering progress', engineering_actual, engineering_forecast, engineering_dev, engineering_etc, next_week_forecast=engineering_next)}"
                f"<div class='next-fc'><b>Next week FC</b>{_html(rec.get('next_week_fc') or 'Not published in selected-week data')}</div>"
                "<div class='gate-row'>"
                f"{_gate_pill_html('Open quality gates', len(rec.get('quality_items', [])), rec.get('quality_items', []))}"
                f"{_gate_pill_html('Open engineering gates', len(rec.get('engineering_items', [])), rec.get('engineering_items', []))}"
                "</div>"
                f"{_cost_plain_html(rec['scope_id'], cost_data)}"
                "</div>"
            )
            st.markdown(html_block, unsafe_allow_html=True)


def render_cost_overview(records: List[Dict[str, Any]]) -> None:
    st.markdown("<div class='section-title'>Cost Status</div>", unsafe_allow_html=True)
    cost_data = _select_cost_report("portfolio")
    active_date = _cost_active_date_label(cost_data)
    meta = cost_data.get("metadata") or {}
    st.markdown(f"<div class='cost-section-head'><span class='cost-active-pill'>Active month: {_html(active_date)}</span><span class='cost-active-pill'>Currency: {_html(meta.get('currency') or 'EUR')}</span></div>", unsafe_allow_html=True)
    st.markdown("<div class='cost-waterfall-note'>Candle-bar / waterfall charts reconcile <b>Budget + CO = Forecast</b> and <b>Forecast + Potential exposure = Potential forecast</b>. Scope squares above show text only: Forecast, VOWD and ETC.</div>", unsafe_allow_html=True)
    order = {"rail": 0, "ponds": 1, "roads": 2}
    records = sorted([_with_display_scope(r) for r in records if r.get("scope_id") in order], key=lambda r: order.get(r.get("scope_id"), 99))
    cols = st.columns(3)
    for col, rec in zip(cols, records):
        with col:
            st.plotly_chart(_cost_candle_figure(rec["scope_id"], cost_data, title=f"{rec['name']} cost status"), use_container_width=True)
