def _scope_for_milestone_icon(scope_name: Any, scope_id: Any = None) -> str:
    sid = str(scope_id or "").lower()
    if sid in SCOPE_ICON:
        return SCOPE_ICON[sid]
    low = str(scope_name or "").lower()
    if "rail" in low:
        return SCOPE_ICON["rail"]
    if "pond" in low:
        return SCOPE_ICON["ponds"]
    if "road" in low:
        return SCOPE_ICON["roads"]
    return ""


def render_milestone_timeline(records: List[Dict[str, Any]], scope_filter: Optional[str] = None, title: str = "Milestones", selected_year: Optional[int] = None, selected_week: Optional[int] = None, current_date: Optional[pd.Timestamp] = None) -> None:
    df = build_milestone_df(records, scope_filter=scope_filter, selected_year=selected_year, selected_week=selected_week)
    st.markdown("<div class='section-title'>Milestones</div>", unsafe_allow_html=True)
    st.markdown("<div class='timeline-deviation-note'><span class='timeline-type-pill'>Weekly FC point</span> Points are weekly-report forecast/control dates. Y-axis is ordered by forecast/control date from earliest to latest. Hover includes baseline feedback where a reliable match exists.</div>", unsafe_allow_html=True)
    if df.empty:
        st.info("No dated forecast milestones loaded for this selected week.")
        return
    sy = selected_year or int(pd.Timestamp.today().isocalendar().year)
    sw = selected_week or int(pd.Timestamp.today().isocalendar().week)
    selected_week_start = iso_week_start(sy, sw).normalize()
    df = df.copy()
    df["Feedback"] = df.apply(_baseline_feedback_from_row, axis=1)
    df["Sort date"] = df["Forecast"].where(pd.notna(df["Forecast"]), df["Start / planned"])
    df = df.sort_values(["Sort date", "Scope", "Milestone"], na_position="last").reset_index(drop=True)
    df["Label"] = df.apply(lambda r: f"{_scope_for_milestone_icon(r.get('Scope'), r.get('Scope ID'))} {r['Scope']} - {compact_text(str(r['Milestone']), 46)}" if not scope_filter else compact_text(str(r["Milestone"]), 70), axis=1)
    df["Y"] = list(range(len(df)))
    df["Plot date"] = df["Forecast"].where(df["Forecast"] >= selected_week_start, selected_week_start)
    df["Timing status"] = df["Forecast"].apply(lambda v: "Overdue / before selected week" if pd.notna(v) and pd.Timestamp(v).normalize() < selected_week_start else "Upcoming")
    df["FC text"] = df.apply(lambda r: ("Overdue<br>" if r["Timing status"].startswith("Overdue") else "") + pd.Timestamp(r["Forecast"]).strftime("%d %b %Y") + "<br>" + str(r["Forecast week"]), axis=1)
    symbol_map = {"Forecast start date": "triangle-up", "Forecast finish / availability date": "diamond", "Forecast control date": "circle"}
    fig = go.Figure()
    for basis, sdf in df.groupby("Date basis", sort=False):
        fig.add_trace(go.Scatter(x=sdf["Plot date"], y=sdf["Y"], mode="markers+text", text=sdf["FC text"], textposition="middle right", name=str(basis), marker=dict(size=13, symbol=symbol_map.get(str(basis), "circle")), customdata=sdf[["Scope", "Milestone", "Risk", "Start label", "Start week", "Forecast label", "Forecast week", "Timing status", "Date basis", "Baseline comparison basis", "Baseline comparison label", "Baseline comparison week", "Deviation label", "Feedback"]], hovertemplate="<b>%{customdata[1]}</b><br>Scope: %{customdata[0]}<br>Risk / type: %{customdata[2]}<br>Weekly date type: %{customdata[8]}<br>Start / planned: %{customdata[3]} (%{customdata[4]})<br>Weekly FC/control date: %{customdata[5]} (%{customdata[6]})<br>Status: %{customdata[7]}<br>BL basis: %{customdata[9]}<br>BL date: %{customdata[10]} (%{customdata[11]})<br>Deviation: %{customdata[12]}<br>Feedback: %{customdata[13]}<extra></extra>"))
    max_axis = max(df["Plot date"].max() + pd.Timedelta(days=14), selected_week_start + pd.Timedelta(days=42))
    tick_vals = list(pd.date_range(selected_week_start, max_axis, freq="W-MON"))
    if not tick_vals or pd.Timestamp(tick_vals[0]).normalize() != selected_week_start:
        tick_vals.insert(0, selected_week_start)
    tick_vals = sorted(set(pd.Timestamp(v).normalize() for v in tick_vals))
    tick_text = [f"{v.isocalendar().year} W{v.isocalendar().week:02d}<br>{v.strftime('%d %b')}" for v in tick_vals]
    fig.add_vline(x=selected_week_start, line_width=2, line_dash="dash", line_color="#111111")
    fig.add_annotation(x=selected_week_start, y=1.08, xref="x", yref="paper", text=f"Active {period_display(sy, sw)}", showarrow=False, font=dict(size=12, color="#111111"), bgcolor="#ffffff", bordercolor="#111111", borderwidth=1)
    fig.update_layout(title="Milestones", height=max(410, 48 * len(df) + 145), margin=dict(l=30, r=35, t=78, b=62), paper_bgcolor="rgba(0,0,0,0)", plot_bgcolor="rgba(0,0,0,0)", xaxis_title="Date / ISO week", yaxis_title="", legend=dict(orientation="h", yanchor="bottom", y=1.02, xanchor="right", x=1))
    fig.update_yaxes(tickmode="array", tickvals=df["Y"].tolist(), ticktext=df["Label"].tolist(), autorange="reversed")
    fig.update_xaxes(range=[selected_week_start, max_axis], tickmode="array", tickvals=tick_vals, ticktext=tick_text, tickangle=-45, showgrid=True, tickfont=dict(size=9))
    st.markdown("<div class='timeline-note'>Timeline starts at the selected week. Y-axis is ordered from earliest forecast/control date to latest. Overdue items are pinned to the selected-week marker and keep their original FC/control date in hover.</div>", unsafe_allow_html=True)
    st.plotly_chart(fig, use_container_width=True)


def render_executive_priority_delayed_near_table(records: List[Dict[str, Any]], selected_label: str, selected_year: int, selected_week: int, current_date: Optional[pd.Timestamp]) -> None:
    st.markdown(f"<div class='section-title'>Priority & high-exposure items requiring action - {_html(selected_label)}</div>", unsafe_allow_html=True)
    rows = _build_exec_action_rows([r for r in records if r.get("scope_id") in {"rail", "ponds", "roads"}], selected_year, selected_week, current_date)
    if not rows:
        st.markdown("<div class='action-empty'>No delayed or near-due priority/high-exposure items identified for the active week.</div>", unsafe_allow_html=True)
        return
    table_rows = [[r['Scope'], r['Action'], r['Responsible'], r['Expected'], f"{r['Symbol']} {r['Status']}"] for r in rows]
    _copyable_table_component(["Scope", "Action / issue", "Responsible", "Expected date", "Status"], table_rows, key_prefix="exec_priority")


def render_scope_sections(rec: Dict[str, Any], selected_year: int, selected_week: int, current_date: Optional[pd.Timestamp] = None) -> None:
    rec = _with_display_scope(rec)
    selected_label = period_display(selected_year, selected_week)
    st.markdown(f"<div class='scope-banner'><h2><span class='scope-icon'>{SCOPE_ICON.get(rec.get('scope_id'), '')}</span>{_html(rec['full_name'])} control panel</h2><p>{_html(compact_text(rec.get('insight', ''), 420))}</p></div>", unsafe_allow_html=True)
    col1, col2 = st.columns([1, 1])
    with col1:
        render_progress_gauge(rec)
    with col2:
        render_progress_trend(rec, selected_year, selected_week)
    render_milestone_timeline([rec], scope_filter=rec["scope_id"], title="Milestones", selected_year=selected_year, selected_week=selected_week, current_date=current_date)
    render_scope_baseline_section(rec, selected_year, selected_week)
    render_scope_cost_section(rec)
    render_action_table(f"{rec['name']} priority & high-exposure items - {selected_label}", rec.get("priority_items", []), selected_year, selected_week, rec.get("default_responsible", "TBC"), max_items=999, current_date=current_date)
    st.markdown("<div class='section-title'>Engineering / design</div>", unsafe_allow_html=True)
    engineering_actual = rec.get("engineering_actual")
    engineering_forecast = rec.get("engineering_forecast") if rec.get("engineering_forecast") is not None else engineering_actual
    engineering_dev = rec.get("engineering_deviation")
    if engineering_dev is None and engineering_actual is not None and engineering_forecast is not None:
        engineering_dev = engineering_actual - engineering_forecast
    c1, c2 = st.columns([1, 1])
    with c1:
        st.markdown(progress_bar_html("Engineering progress", engineering_actual, engineering_forecast, engineering_dev, _date_only_etc(rec.get("engineering_etc") or _baseline_etc_for_scope(rec["scope_id"], selected_year, selected_week, mode="next"), fallback="TBC"), next_week_forecast=_next_progress_label(rec, selected_year, selected_week, "engineering")), unsafe_allow_html=True)
        st.markdown(f"<div class='item-card engineering'>{_html(rec.get('engineering_basis') or 'Scope-specific engineering basis not published.')}</div>", unsafe_allow_html=True)
    with c2:
        render_engineering_trend(rec, selected_year, selected_week)
    render_action_table("", rec.get("engineering_items", []), selected_year, selected_week, rec.get("default_responsible", "TBC"), max_items=12, current_date=current_date)
    st.markdown("<div class='section-title'>Quality / completion</div>", unsafe_allow_html=True)
    render_action_table("", rec.get("quality_items", []), selected_year, selected_week, rec.get("default_responsible", "TBC"), max_items=14, current_date=current_date)
    st.markdown("<div class='section-title'>Interface / commercial controls</div>", unsafe_allow_html=True)
    render_action_table("", rec.get("interface_items", []), selected_year, selected_week, rec.get("default_responsible", "TBC"), max_items=14, current_date=current_date)


def render_sidebar(bundle: Dict[str, Any]) -> Tuple[str, int, int]:
    logo_src = logo_mark_data_uri() or logo_data_uri()
    if logo_src:
        st.sidebar.markdown(f"<div class='sidebar-logo'><img src='{logo_src}'><span>Scope controls</span></div>", unsafe_allow_html=True)
    st.sidebar.title("Control settings")

    periods = available_periods(st.session_state["bundle"])
    if not periods:
        selected_year, selected_week = (2026, 0)
    else:
        period_labels = [period_display(y, w) for y, w in periods]
        latest_y, latest_w = latest_period(st.session_state["bundle"])
        default_label = period_display(latest_y, latest_w)
        if default_label not in period_labels:
            default_label = period_labels[-1]
        if st.session_state.get("week_selector_value") not in period_labels:
            st.session_state["week_selector_value"] = default_label
        st.sidebar.markdown("<div class='subsection-title'>Selections</div>", unsafe_allow_html=True)
        selected_label = st.sidebar.selectbox("Week to display", period_labels, key="week_selector_value", help="Select any loaded report week manually.")
        current_idx = period_labels.index(selected_label)
        selected_year, selected_week = periods[current_idx]
        st.sidebar.caption(f"Selected week {current_idx + 1} of {len(period_labels)}")

    cost_reports = _cost_reports()
    cost_labels = [r["label"] for r in cost_reports if r.get("label")]
    if cost_labels:
        if st.session_state.get("monthly_cost_report_choice_portfolio") not in cost_labels:
            st.session_state["monthly_cost_report_choice_portfolio"] = cost_labels[-1]
        st.sidebar.selectbox("Monthly report to use", cost_labels, key="monthly_cost_report_choice_portfolio")
        st.sidebar.markdown(f"<div class='cost-active-pill'>Active month: {_html(st.session_state['monthly_cost_report_choice_portfolio'])}</div>", unsafe_allow_html=True)
    baseline_reports = _baseline_reports()
    bl_labels = [r["label"] for r in baseline_reports if r.get("label")]
    if bl_labels:
        if st.session_state.get("baseline_choice") not in bl_labels:
            st.session_state["baseline_choice"] = bl_labels[-1]
        st.sidebar.selectbox("Baseline to use", bl_labels, key="baseline_choice")

    st.sidebar.markdown("---")
    st.sidebar.markdown("<div class='subsection-title'>Panel</div>", unsafe_allow_html=True)
    visible_panels = ["Executive overview", "Rail On Site (ROS)", "Ponds", "Roads"]
    if st.session_state.get("panel_choice") not in visible_panels:
        st.session_state["panel_choice"] = visible_panels[0]
    icons = {"Executive overview": "▦", "Rail On Site (ROS)": "🚆", "Ponds": "💧", "Roads": "🛣️"}
    for label in visible_panels:
        if st.sidebar.button(f"{icons.get(label, '•')} {label}", key=f"nav_v23_{label}", use_container_width=True):
            st.session_state["panel_choice"] = label
    st.sidebar.markdown(f"<div class='nav-active'>Current panel: {_html(st.session_state['panel_choice'])}</div>", unsafe_allow_html=True)
    st.sidebar.caption(f"Loaded {latest_period_label(st.session_state['bundle'])} - {source_count(st.session_state['bundle'])} source reports")
    st.sidebar.markdown("<div class='nav-hint'>Priority lists show only the active week. Milestones are shown as timelines. UGP is fully removed from this app.</div>", unsafe_allow_html=True)

    st.sidebar.markdown("---")
    st.sidebar.markdown("<div class='subsection-title'>Upload / refresh</div>", unsafe_allow_html=True)
    uploaded_weekly = st.sidebar.file_uploader("Upload new weekly report PDF/PPTX", type=["pdf", "pptx"], accept_multiple_files=True, key="weekly_upload_v23", help="Upload one or more weekly reports. The parser merges new report weeks into the current session.")
    if uploaded_weekly:
        key = _upload_list_hash(uploaded_weekly)
        if key != st.session_state.get("last_weekly_upload_key_v23"):
            with st.spinner("Parsing uploaded weekly report(s) and refreshing the control center..."):
                try:
                    incoming = parse_uploaded_reports(uploaded_weekly)
                    st.session_state["bundle"] = merge_bundles(st.session_state["bundle"], incoming)
                    st.session_state["last_weekly_upload_key_v23"] = key
                    st.sidebar.success(f"{len(uploaded_weekly)} weekly report(s) parsed and loaded.")
                except Exception as exc:
                    st.sidebar.error(f"Could not parse weekly upload: {exc}")
    uploaded_cost_reports = st.sidebar.file_uploader("Upload monthly cost report XLSX", type=["xlsx"], accept_multiple_files=True, key="cost_upload_v23", help="Upload one or more monthly cost reports. Each report is normalized, stored and added to the monthly-report selector.")
    if uploaded_cost_reports:
        key = _upload_list_hash(uploaded_cost_reports)
        if key != st.session_state.get("last_cost_upload_key_v23"):
            loaded = 0; errors: List[str] = []
            for uploaded in uploaded_cost_reports:
                try:
                    _register_uploaded_cost_report(uploaded)
                    loaded += 1
                except Exception as exc:
                    errors.append(f"{uploaded.name}: {exc}")
            st.session_state["last_cost_upload_key_v23"] = key
            try: cached_monthly_cost_reports.clear()
            except Exception: pass
            if loaded:
                refreshed = _cost_reports()
                if refreshed:
                    st.session_state["monthly_cost_report_choice_portfolio"] = refreshed[-1]["label"]
                st.sidebar.success(f"{loaded} cost report(s) uploaded and registered.")
            for msg in errors:
                st.sidebar.error(f"Could not parse cost report - {msg}")
            if loaded: _safe_rerun()
    uploaded_baselines = st.sidebar.file_uploader("Upload schedule baseline PDF", type=["pdf"], accept_multiple_files=True, key="baseline_upload_v23", help="Upload one or more baseline PDFs. Parsed baselines are added to the baseline selector.")
    if uploaded_baselines:
        key = _upload_list_hash(uploaded_baselines)
        if key != st.session_state.get("last_baseline_upload_key_v23"):
            loaded = 0; errors: List[str] = []
            for uploaded in uploaded_baselines:
                try:
                    _register_uploaded_baseline(uploaded)
                    loaded += 1
                except Exception as exc:
                    errors.append(f"{uploaded.name}: {exc}")
            st.session_state["last_baseline_upload_key_v23"] = key
            try: cached_baseline_schedules.clear()
            except Exception: pass
            if loaded:
                refreshed = _baseline_reports()
                if refreshed:
                    st.session_state["baseline_choice"] = refreshed[-1]["label"]
                st.sidebar.success(f"{loaded} baseline file(s) uploaded and registered.")
            for msg in errors:
                st.sidebar.error(f"Could not parse baseline - {msg}")
            if loaded: _safe_rerun()
    if st.sidebar.button("Save current session data", use_container_width=True):
        save_bundle(st.session_state["bundle"], DATA_PATH)
        try: cached_bundle.clear()
        except Exception: pass
        st.sidebar.success("Saved weekly data to data/weekly_data_bundle.json")
    return st.session_state["panel_choice"], int(selected_year), int(selected_week)


