def _next_progress_label(rec: Dict[str, Any], selected_year: int, selected_week: int, kind: str = "construction") -> str:
    """Return the next loaded week forecast percentage for this scope/discipline."""
    next_start = iso_week_start(selected_year, selected_week) + pd.Timedelta(days=7)
    ny, nw = int(next_start.isocalendar().year), int(next_start.isocalendar().week)
    target_label = period_display(ny, nw)
    df = rec.get("engineering_series") if kind == "engineering" else rec.get("progress_series")
    if df is None or not hasattr(df, "empty") or df.empty:
        return f"{target_label}: not published"
    try:
        candidates = []
        for _, row in df.iterrows():
            y = row.get("year") or row.get("period_year")
            w = row.get("week") or row.get("period_week")
            label = str(row.get("period_label") or "")
            if not y or not w:
                m = re.search(r"(20\d{2})\s*W(\d{1,2})", label)
                if m:
                    y, w = int(m.group(1)), int(m.group(2))
            try:
                y, w = int(y), int(w)
            except Exception:
                continue
            if (y, w) == (ny, nw):
                val = _safe_float(row.get("forecast"))
                if val is not None:
                    return f"{target_label}: {_fmt_pct(val)}"
            if (y, w) > (selected_year, selected_week):
                val = _safe_float(row.get("forecast"))
                if val is not None:
                    candidates.append(((y, w), val))
        if candidates:
            (fy, fw), val = sorted(candidates)[0]
            return f"{period_display(fy, fw)}: {_fmt_pct(val)}"
    except Exception:
        pass
    return f"{target_label}: not published"


def _cost_plain_html(scope_id: str, cost_data: Optional[Dict[str, Any]] = None) -> str:
    nums = _cost_numbers(scope_id, cost_data)
    values = [("Forecast", nums.get("forecast")), ("VOWD", nums.get("vowd")), ("ETC", nums.get("forecast_minus_vowd"))]
    cells = "".join(
        f"<div class='cost-plain-cell {'primary' if k == 'ETC' else ''}'><span>{_html(k)}</span><b>{_html(_fmt_money(v))}</b></div>"
        for k, v in values
    )
    return f"<div class='cost-plain-card'><div class='cost-plain-title'>Cost position</div><div class='cost-plain-grid'>{cells}</div></div>"


def _cost_candle_figure(scope_id: str, cost_data: Optional[Dict[str, Any]] = None, title: str = "Cost Status") -> go.Figure:
    vals = _waterfall_numbers(scope_id, cost_data)
    budget = vals.get("budget") or 0.0
    co = vals.get("co") or 0.0
    forecast = vals.get("forecast") or (budget + co)
    exposure = vals.get("exposure") or 0.0
    potential_forecast = vals.get("potential_forecast") or (forecast + exposure)
    labels = ["Budget", "CO", "Forecast", "Potential exposure", "Potential forecast"]
    y_vals = [budget, co, forecast, exposure, potential_forecast]
    measures = ["absolute", "relative", "total", "relative", "total"]
    running = [budget, budget + co, forecast, forecast + exposure, potential_forecast]
    text_vals = [_fmt_money(v) for v in y_vals]
    custom = [[labels[i], _fmt_money_full(y_vals[i]), _fmt_money_full(running[i])] for i in range(len(labels))]
    fig = go.Figure(go.Waterfall(
        x=labels,
        y=y_vals,
        measure=measures,
        text=text_vals,
        textposition="outside",
        customdata=custom,
        connector={"line": {"color": "#9aa1ad", "width": 1}},
        increasing={"marker": {"color": "#007a45"}},
        decreasing={"marker": {"color": "#c73535"}},
        totals={"marker": {"color": "#c76df1"}},
        hovertemplate="<b>%{customdata[0]}</b><br>Step value: %{customdata[1]}<br>Cost position after step: %{customdata[2]}<extra></extra>",
    ))
    fig.update_layout(
        title={"text": title, "x": 0.02, "xanchor": "left", "font": {"size": 16}},
        height=350,
        margin=dict(l=34, r=24, t=58, b=72),
        paper_bgcolor="rgba(0,0,0,0)",
        plot_bgcolor="rgba(0,0,0,0)",
        yaxis_title="EUR",
        xaxis_title="",
        showlegend=False,
        hovermode="closest",
    )
    fig.update_xaxes(tickangle=-22)
    return fig


def progress_bar_html(label: str, actual: Any, forecast: Any, deviation: Any, etc: str = "To be provided", title: str = "Deviation vs Forecast", next_week_forecast: Optional[str] = None) -> str:
    actual_pct = clamp_pct(actual)
    forecast_num = _safe_float(forecast)
    forecast_pct = clamp_pct(forecast_num if forecast_num is not None else actual_pct)
    dev = _safe_float(deviation)
    if dev is None and _safe_float(actual) is not None and forecast_num is not None:
        dev = _safe_float(actual) - forecast_num
    if dev is None:
        dev = 0.0
    dev_class = _deviation_class(dev)
    next_html = ""
    if next_week_forecast:
        next_html = f"<div class='next-week-mini'><span>Next week forecast</span><b>{_html(next_week_forecast)}</b></div>"
    return (
        "<div class='progress-box'>"
        "<div class='progress-top'>"
        f"<div class='progress-title'>{_html(label)}</div>"
        f"<div class='progress-value'>{_html(_fmt_pct(actual))}</div>"
        "</div>"
        "<div class='progress-track'>"
        f"<div class='progress-fill' style='width:{actual_pct:.2f}%;'></div>"
        f"<div class='progress-forecast' style='left:{forecast_pct:.2f}%;'></div>"
        "</div>"
        "<div class='progress-meta'>"
        f"<div class='progress-mini-card'><span>Forecast</span><b>{_html(_fmt_pct(forecast_num if forecast_num is not None else actual))}</b></div>"
        f"<div class='progress-mini-card dev {dev_class}'><span>{_html(title)}</span><b>{_html(_fmt_deviation(dev))}</b></div>"
        f"{next_html}"
        f"<div class='progress-mini-card etc'><span>ETC</span><b>{_html(_date_only_etc(etc, fallback='TBC'))}</b></div>"
        "</div></div>"
    )


def _matrix_driver(rec: Dict[str, Any]) -> str:
    driver = rec.get("status") or rec.get("insight") or "Monitor"
    return compact_text(driver, 160)


def render_scope_matrix(records: List[Dict[str, Any]], selected_year: int, selected_week: int) -> None:
    st.markdown("<div class='section-title'>Executive control matrix</div>", unsafe_allow_html=True)
    cost_data, _active_label, _active_date = _active_cost_data("portfolio")
    order = {"rail": 0, "ponds": 1, "roads": 2}
    records = [_with_display_scope(r) for r in records if r.get("scope_id") in order]
    records = sorted(records, key=lambda r: order.get(r.get("scope_id"), 99))
    cols = st.columns(3)
    for col, rec in zip(cols, records):
        with col:
            construction_dev = rec.get("construction_deviation")
            if construction_dev is None and rec.get("construction_actual") is not None and rec.get("construction_forecast") is not None:
                construction_dev = rec.get("construction_actual") - rec.get("construction_forecast")
            engineering_actual = rec.get("engineering_actual")
            engineering_forecast = rec.get("engineering_forecast") if rec.get("engineering_forecast") is not None else engineering_actual
            engineering_dev = rec.get("engineering_deviation")
            if engineering_dev is None and engineering_actual is not None and engineering_forecast is not None:
                engineering_dev = engineering_actual - engineering_forecast
            construction_etc = _date_only_etc(_baseline_etc_for_scope(rec["scope_id"], selected_year, selected_week, mode="final"), fallback="TBC")
            engineering_etc = _date_only_etc(rec.get("engineering_etc") or _baseline_etc_for_scope(rec["scope_id"], selected_year, selected_week, mode="next"), fallback="TBC")
            icon = SCOPE_ICON.get(rec["scope_id"], "●")
            html_block = (
                "<div class='matrix-col'>"
                "<div class='matrix-head'>"
                f"<h3><span class='scope-icon'>{icon}</span>{_html(rec['name'])}</h3>"
                f"<span class='status-badge'>{_html(_matrix_driver(rec))}</span>"
                "</div>"
                f"{progress_bar_html('Construction progress', rec.get('construction_actual'), rec.get('construction_forecast'), construction_dev, construction_etc, next_week_forecast=_next_progress_label(rec, selected_year, selected_week, 'construction'))}"
                f"{progress_bar_html('Engineering progress', engineering_actual, engineering_forecast, engineering_dev, engineering_etc, next_week_forecast=_next_progress_label(rec, selected_year, selected_week, 'engineering'))}"
                f"<div class='next-fc'><b>Next week FC</b>{_html(rec.get('next_week_fc') or 'Not published in selected-week data')}</div>"
                "<div class='gate-row'>"
                f"{_gate_pill_html('Open quality gates', len(rec.get('quality_items', [])), rec.get('quality_items', []))}"
                f"{_gate_pill_html('Open engineering gates', len(rec.get('engineering_items', [])), rec.get('engineering_items', []))}"
                "</div>"
                f"{_cost_plain_html(rec['scope_id'], cost_data)}"
                "</div>"
            )
            st.markdown(html_block, unsafe_allow_html=True)


def _preferred_col_widths(headers: List[str]) -> List[int]:
    lower = [str(h).lower() for h in headers]
    n = len(headers)
    if n == 5 and "scope" in lower[0] and "action" in lower[1]:
        return [9, 51, 18, 12, 10]
    if n == 4 and "action" in lower[0]:
        return [58, 20, 12, 10]
    if n >= 8 and any("driver" in h for h in lower):
        # Package/exposure tables: keep narrative columns wider but avoid blank horizontal space.
        base = [9, 20, 10, 8, 8, 8, 8, 9, 20]
        if n == len(base):
            return base
    if n == 8 and "description" in lower[5]:
        return [8, 10, 9, 9, 9, 35, 10, 10]
    return [max(8, int(100 / max(1, n)))] * n


def _estimate_component_height(headers: List[str], rows: List[List[Any]]) -> int:
    widths = _preferred_col_widths(headers)
    total = 74
    for row in rows:
        max_lines = 1
        for i, cell in enumerate(row):
            text = str(cell or "")
            width_pct = widths[i] if i < len(widths) else 12
            chars_per_line = max(12, int(width_pct * 1.75))
            lines = max(1, math.ceil(len(text) / chars_per_line))
            max_lines = max(max_lines, min(9, lines))
        total += 30 + max_lines * 15
    return max(150, min(4200, total))


def _copyable_table_component(headers: List[str], rows: List[List[Any]], numeric_cols: Optional[set] = None, key_prefix: str = "tbl") -> None:
    numeric_cols = numeric_cols or set()
    if not rows:
        st.markdown("<div class='action-empty'>No rows available for this active selection.</div>", unsafe_allow_html=True)
        return
    keep = _table_column_keep(headers, rows)
    headers2 = [headers[i] for i in keep]
    rows2 = [[row[i] if i < len(row) else "" for i in keep] for row in rows]
    numeric2 = {new_i for new_i, old_i in enumerate(keep) if old_i in numeric_cols}
    tsv = "\n".join(["\t".join(str(h or "") for h in headers2)] + ["\t".join(str(c or "") for c in row) for row in rows2])
    widths = _preferred_col_widths(headers2)
    if len(widths) != len(headers2):
        widths = [int(100 / len(headers2))] * len(headers2)
    colgroup = "".join(f"<col style='width:{w}%;'>" for w in widths)
    table_head = "".join(f"<th>{html.escape(str(h or ''))}</th>" for h in headers2)
    body = []
    for ri, row in enumerate(rows2):
        cells = []
        for ci, val in enumerate(row):
            cls = "num" if ci in numeric2 else ""
            cells.append(f"<td class='{cls}'>{html.escape(str(val or ''))}</td>")
        body.append(f"<tr>{''.join(cells)}</tr>")
    ident = "tbl_" + hashlib.sha1((key_prefix + tsv).encode("utf-8", "ignore")).hexdigest()[:12]
    doc = f"""
<!doctype html>
<html><head><meta charset='utf-8'>
<style>
body{{margin:0;font-family:Inter,Segoe UI,Arial,sans-serif;color:#1f2937;background:transparent;}}
.copybar{{display:flex;gap:8px;align-items:center;margin:0 0 8px 0;}}
.copybar button{{border:1px solid #d9c3ee;background:#fff;color:#39135c;border-radius:999px;padding:6px 11px;font-weight:850;font-size:12px;cursor:pointer;}}
.copybar .msg{{font-size:12px;color:#667085;}}
.table-wrap{{width:100%;border:1px solid #e7e2ed;border-radius:15px;overflow:hidden;background:#fff;box-shadow:0 1px 8px rgba(17,17,17,.04);}}
table{{width:100%;border-collapse:collapse;table-layout:fixed;}}
th{{background:#f7f7fa;color:#111;font-size:11px;letter-spacing:.06em;text-transform:uppercase;font-weight:900;line-height:1.18;padding:9px 8px;text-align:left;border-bottom:1px solid #e7e2ed;border-left:1px solid #eee8f4;white-space:normal;overflow-wrap:anywhere;}}
th:first-child{{border-left:0;}}
td{{font-size:12px;line-height:1.30;padding:8px 8px;vertical-align:top;border-top:1px solid #eee8f4;border-left:1px solid #eee8f4;white-space:normal;overflow-wrap:anywhere;word-break:normal;hyphens:auto;}}
td:first-child{{border-left:0;}}
tbody tr:nth-child(even){{background:#fbfafc;}}
td.num{{text-align:right;font-weight:800;white-space:nowrap;}}
textarea{{position:absolute;left:-9999px;top:-9999px;}}
</style></head><body>
<div class='copybar'><button id='{ident}_btn'>Copy table</button><span id='{ident}_msg' class='msg'>Copies as a tab-separated table.</span></div>
<textarea id='{ident}_tsv' readonly>{html.escape(tsv)}</textarea>
<div class='table-wrap'><table><colgroup>{colgroup}</colgroup><thead><tr>{table_head}</tr></thead><tbody>{''.join(body)}</tbody></table></div>
<script>
const t = document.getElementById('{ident}_tsv');
const m = document.getElementById('{ident}_msg');
function legacyCopy() {{
  t.style.cssText='position:fixed;left:0;top:0;width:2px;height:2px;opacity:0;';
  t.focus(); t.select();
  try {{ document.execCommand('copy'); m.textContent='Copied. Paste into Excel/Teams as a table.'; return true; }}
  catch(e) {{ return false; }}
}}
document.getElementById('{ident}_btn').addEventListener('click', async function(){{
  try {{ await navigator.clipboard.writeText(t.value); m.textContent='Copied. Paste into Excel/Teams as a table.'; }}
  catch(e) {{ if(!legacyCopy()) {{ m.textContent='Clipboard blocked by browser. Select table rows and press Ctrl+C.'; }} }}
}});
</script>
</body></html>
"""
    height = _estimate_component_height(headers2, rows2)
    components.html(doc, height=height, scrolling=False)


def render_action_table(title: str, items: List[Any], selected_year: int, selected_week: int, default_responsible: str = "TBC", max_items: int = 10, current_date: Optional[pd.Timestamp] = None) -> None:
    if title:
        st.markdown(f"<div class='section-title'>{_html(title)}</div>", unsafe_allow_html=True)
    if not items:
        st.markdown("<div class='action-empty'>No active actions extracted for this section.</div>", unsafe_allow_html=True)
        return
    sorted_items = sorted(items, key=lambda x: action_sort_key(x, selected_year, selected_week))[:max_items]
    rows: List[List[Any]] = []
    for item in sorted_items:
        if isinstance(item, dict):
            action = clean_action_text(item.get("issue") or item.get("action") or item.get("description") or "")
            responsible = item.get("owner") or item.get("responsible") or infer_responsible(action, default_responsible)
            expected = item.get("due_date") or item.get("expected_date") or infer_expected_date(action, selected_year, selected_week)
        else:
            action = clean_action_text(item)
            responsible = infer_responsible(action, default_responsible)
            expected = infer_expected_date(action, selected_year, selected_week)
        if is_closed_action(action):
            status = "✅ Closed"
        else:
            symbol, stat, _cls = action_status(expected, selected_year, selected_week, current_date=current_date)
            status = f"{symbol} {stat}"
        rows.append([action, responsible or "TBC", expected or "TBC", status])
    _copyable_table_component(["Action / issue", "Responsible", "Expected date", "Status"], rows, key_prefix=title or "actions")


def _progress_trend_figure(rec: Dict[str, Any], selected_year: Optional[int], selected_week: Optional[int], df: pd.DataFrame, y_col: str, title: str, y_title: str) -> Optional[go.Figure]:
    if df is None or df.empty:
        return None
    df = df.sort_values("period_sort") if "period_sort" in df.columns else df
    rows = []
    for _, r in df.iterrows():
        actual = _safe_float(r.get("actual"))
        forecast = _safe_float(r.get("forecast"))
        deviation = _safe_float(r.get("deviation"))
        if deviation is None and actual is not None and forecast is not None:
            deviation = actual - forecast
        if actual is not None:
            rows.append({"Period": r.get("period_label"), "Progress type": "Actual", y_col: actual, "Forecast": forecast, "Deviation": deviation, "Sort": r.get("period_sort")})
        if forecast is not None:
            rows.append({"Period": r.get("period_label"), "Progress type": "Forecast", y_col: forecast, "Forecast": forecast, "Deviation": deviation, "Sort": r.get("period_sort")})
    chart_df = pd.DataFrame(rows)
    if chart_df.empty:
        return None
    chart_df = chart_df.sort_values("Sort")
    fig = px.line(chart_df, x="Period", y=y_col, color="Progress type", markers=True, title=title, hover_data={y_col: ":.2f", "Forecast": ":.2f", "Deviation": "+.2f", "Sort": False})
    active_label = period_display(selected_year, selected_week) if selected_year and selected_week else None
    for trace in fig.data:
        labels = []
        for x, y in zip(trace.x, trace.y):
            labels.append(f"{float(y):.2f}%" if active_label and str(x) == active_label and trace.name == "Actual" else "")
        trace.text = labels
        trace.mode = "lines+markers+text"
        trace.textposition = "top center"
    if active_label and active_label in set(chart_df["Period"]):
        ymin = float(chart_df[y_col].min())
        ymax = float(chart_df[y_col].max())
        pad = max(0.15, (ymax - ymin) * 0.10)
        fig.add_trace(go.Scatter(x=[active_label, active_label], y=[ymin - pad, ymax + pad], mode="lines", name="Active week", line=dict(color="#111111", dash="dash", width=2), hoverinfo="skip", showlegend=True))
        active_points = chart_df[chart_df["Period"] == active_label]
        fig.add_trace(go.Scatter(x=active_points["Period"], y=active_points[y_col], mode="markers", name="Active values", marker=dict(size=13, symbol="diamond-open", color="#111111", line=dict(width=2)), customdata=active_points[["Progress type", "Forecast", "Deviation"]], hovertemplate="<b>Active week</b><br>%{customdata[0]}: %{y:.2f}%<br>Forecast: %{customdata[1]:.2f}%<br>Deviation: %{customdata[2]:+.2f}%<extra></extra>"))
    fig.update_layout(height=360, margin=dict(l=30, r=20, t=86, b=62), paper_bgcolor="rgba(0,0,0,0)", plot_bgcolor="rgba(0,0,0,0)", yaxis_title=y_title, xaxis_title="Week / year", legend=dict(orientation="h", yanchor="bottom", y=1.04, xanchor="right", x=1), title=dict(font=dict(size=15), x=0.02, xanchor="left", y=0.98))
    fig.update_xaxes(type="category", tickangle=-45)
    return fig


