def _render_metric_gauge(rec: Dict[str, Any], actual: Any, forecast: Any, deviation: Any, title: str, label_name: str) -> None:
    if actual is None and forecast is None:
        st.markdown(f"<div class='mini-kpi'><h4>{_html(label_name)} publication</h4><div class='value'>No % published</div><p>This scope is controlled through gates and forecast milestones until a reliable percentage is published.</p></div>", unsafe_allow_html=True)
        return
    if deviation is None and actual is not None and forecast is not None:
        deviation = actual - forecast
    actual_value = actual if actual is not None else 0.0
    forecast_value = forecast if forecast is not None else actual_value
    dev_class = _deviation_class(deviation)
    fig = go.Figure(go.Indicator(
        mode="gauge+number",
        value=actual_value,
        number={"suffix": "%", "font": {"size": 32}},
        title={"text": title, "font": {"size": 15}},
        domain={"x": [0.08, 0.92], "y": [0.14, 1]},
        gauge={"axis": {"range": [0, 100], "tickwidth": 1}, "bar": {"color": "#6f2da8", "thickness": 0.26}, "bgcolor": "white", "borderwidth": 1, "bordercolor": "#e7e2ed", "steps": [{"range": [0, 50], "color": "#f0edf5"}, {"range": [50, 80], "color": "#e5d5f4"}, {"range": [80, 100], "color": "#d6c0eb"}], "threshold": {"line": {"color": "#111111", "width": 4}, "thickness": 0.82, "value": forecast_value}},
    ))
    fig.update_layout(height=286, margin=dict(l=22, r=22, t=48, b=0), paper_bgcolor="rgba(0,0,0,0)")
    st.plotly_chart(fig, use_container_width=True)
    st.markdown("<div class='gauge-footer'>" f"<div class='gf-cell'><span>Actual</span><b>{_html(_fmt_pct(actual))}</b></div>" f"<div class='gf-cell'><span>Forecast</span><b>{_html(_fmt_pct(forecast))}</b></div>" f"<div class='gf-cell gf-dev {dev_class}'><span>Deviation vs Forecast</span><b>{_html(_fmt_deviation(deviation))}</b></div>" "</div>", unsafe_allow_html=True)


