        with st.expander("Package drivers", expanded=False):
            _copyable_table_component(["Package", "Description", "Supplier", "Budget", "CO", "Forecast", "Exposure", "Potential forecast", "Driver / note"], pkg_rows, numeric_cols={3,4,5,6,7}, key_prefix=f"pkg_{rec['scope_id']}")
