def _clean_engineering_note_text(value: Any) -> Any:
    if not isinstance(value, str):
        return value
    patterns = [
        r"\bSWECO Engineering Management scope readiness chart,?\s*20\d{2}\s*W\d{1,2}:?\s*",
        r"\bLatest loaded SWECO Engineering Management scope readiness chart,?\s*20\d{2}\s*W\d{1,2}:?\s*",
        r"\bSWECO Engineering Management chart history:\s*",
        r"\bScope-specific values are taken from the SWECO Engineering Management discipline chart where available;?\s*",
        r"\bThe app will use the next uploaded report when a SWECO Engineering Management chart is detected\.?\s*",
    ]
    out = value
    for pat in patterns:
        out = re.sub(pat, "", out, flags=re.I)
    out = re.sub(r"\s+", " ", out).strip(" -.;")
    return out


def _clean_engineering_notes_in_item(item: Any) -> Optional[Any]:
    if isinstance(item, dict):
        out = {}
        for k, v in item.items():
            if isinstance(v, str):
                cv = _clean_engineering_note_text(v)
                if not cv and k.lower() in {"issue", "action", "description", "basis"}:
                    continue
                out[k] = cv
            else:
                out[k] = v
        if not out:
            return None
        joined = " ".join(str(v) for v in out.values())
        if re.search(r"SWECO Engineering Management", joined, re.I):
            return None
        return out
    if isinstance(item, str):
        cv = _clean_engineering_note_text(item)
        if not cv or re.search(r"SWECO Engineering Management", cv, re.I):
            return None
        return cv
    return item


def _clean_engineering_notes_list(values: Any) -> List[Any]:
    if not values:
        return []
    out = []
    for item in values:
        ci = _clean_engineering_notes_in_item(item)
        if ci is not None:
            out.append(ci)
    return out


_with_display_scope_v23_base = _with_display_scope

def _with_display_scope(rec: Dict[str, Any]) -> Dict[str, Any]:
    out = _with_display_scope_v23_base(rec)
    for field in ["engineering_basis", "basis", "engineering_etc", "construction_etc", "insight", "status"]:
        if field in out and isinstance(out.get(field), str):
            out[field] = _clean_engineering_note_text(out[field])
    for field in ["engineering_items", "quality_items", "priority_items", "interface_items", "milestones"]:
        if field in out:
            out[field] = _clean_engineering_notes_list(out.get(field))
    return out


def _cost_report_month_key(cost_data: Dict[str, Any]) -> str:
    meta = cost_data.get("metadata") or {}
    raw = meta.get("cutoff_month") or meta.get("active_date") or meta.get("data_date") or ""
    text = str(raw).strip()
    if re.match(r"^20\d{2}-\d{2}$", text):
        return text
    dt = pd.to_datetime(text, errors="coerce")
    if pd.notna(dt):
        return pd.Timestamp(dt).strftime("%Y-%m")
    return text


def _cost_reports_sorted_v23() -> List[Dict[str, Any]]:
    reports = _cost_reports()
    def sort_key(r: Dict[str, Any]) -> str:
        data = r.get("data") if isinstance(r, dict) else {}
        return _cost_report_month_key(data if isinstance(data, dict) else {}) or str(r.get("label", ""))
    return sorted(reports, key=sort_key)


def _cost_history_html(scope_id: str, metric_key: str, active_cost_data: Optional[Dict[str, Any]] = None, months: int = 3) -> str:
    active_key = _cost_report_month_key(active_cost_data or {})
    reports = _cost_reports_sorted_v23()
    normalized: List[Tuple[str, Dict[str, Any]]] = []
    for r in reports:
        data = r.get("data") if isinstance(r, dict) else {}
        if not isinstance(data, dict):
            continue
        key = _cost_report_month_key(data)
        if not key:
            continue
        vals = _waterfall_numbers(scope_id, data)
        value = vals.get(metric_key)
        if _safe_float(value) is not None:
            normalized.append((key, data))
    if not normalized:
        return "No monthly history loaded"
    if active_key:
        upto = [(k, d) for k, d in normalized if k <= active_key]
        selected = upto[-months:] if upto else normalized[-months:]
    else:
        selected = normalized[-months:]
    rows = []
    for key, data in selected:
        label = _active_month_label_from_cost(data)
        vals = _waterfall_numbers(scope_id, data)
        rows.append(f"{label}: {_fmt_money_full(vals.get(metric_key))}")
    return "<br>".join(rows)


def _cost_candle_figure(scope_id: str, cost_data: Optional[Dict[str, Any]] = None, title: str = "Cost Status") -> go.Figure:
    vals = _waterfall_numbers(scope_id, cost_data)
    budget = vals.get("budget") or 0.0
    co = vals.get("co") or 0.0
    forecast = vals.get("forecast") if vals.get("forecast") is not None else (budget + co)
    exposure = vals.get("exposure") or 0.0
    potential_forecast = vals.get("potential_forecast") if vals.get("potential_forecast") is not None else (forecast + exposure)
    labels = ["Budget", "CO", "Forecast", "Potential exposure", "Potential forecast"]
    keys = ["budget", "co", "forecast", "exposure", "potential_forecast"]
    y_vals = [budget, co, forecast, exposure, potential_forecast]
    measures = ["absolute", "relative", "total", "relative", "total"]
    running = [budget, budget + co, forecast, forecast + exposure, potential_forecast]
    text_vals = [_fmt_money(v) for v in y_vals]
    custom = []
    for i, label in enumerate(labels):
        hist = _cost_history_html(scope_id, keys[i], cost_data, months=3)
        custom.append([label, _fmt_money_full(y_vals[i]), _fmt_money_full(running[i]), hist])
    fig = go.Figure(go.Waterfall(
        x=labels,
        y=y_vals,
        measure=measures,
        text=text_vals,
        textposition="outside",
        customdata=custom,
        connector={"line": {"color": "#9aa1ad", "width": 1}},
        increasing={"marker": {"color": "#007a45"}},
        decreasing={"marker": {"color": "#c73535"}},
        totals={"marker": {"color": "#c76df1"}},
        hovertemplate=(
            "<b>%{customdata[0]}</b><br>"
            "Actual selected report: %{customdata[1]}<br>"
            "Cost position after step: %{customdata[2]}<br>"
            "<br><b>Last 3 monthly reports</b><br>%{customdata[3]}"
            "<extra></extra>"
        ),
    ))
    fig.update_layout(
        title={"text": title, "x": 0.02, "xanchor": "left", "font": {"size": 17}},
        height=362,
        margin=dict(l=34, r=24, t=60, b=72),
        paper_bgcolor="rgba(0,0,0,0)",
        plot_bgcolor="rgba(0,0,0,0)",
        yaxis_title="EUR",
        xaxis_title="",
        showlegend=False,
        hovermode="closest",
    )
    fig.update_xaxes(tickangle=-22)
    return fig


def _table_column_keep(headers: List[str], rows: List[List[Any]]) -> List[int]:
    keep = []
    for i, h in enumerate(headers):
        htxt = str(h or "").strip()
        col_vals = [str(row[i] if i < len(row) else "").strip() for row in rows]
        if htxt or any(v for v in col_vals):
            keep.append(i)
    return keep


def _col_widths_for_headers(headers: List[str]) -> List[str]:
    joined = " | ".join(headers).lower()
    widths = []
    for h in headers:
        l = h.lower()
        if "action" in l or "issue" in l or "description" in l or "driver" in l:
            widths.append("44%" if "scope" in joined and len(headers) <= 5 else "32%")
        elif "scope" in l:
            widths.append("11%")
        elif "responsible" in l or "supplier" in l:
            widths.append("13%")
        elif "expected" in l or "date" in l:
            widths.append("12%")
        elif "status" in l or "criticality" in l or "type" in l:
            widths.append("10%")
        elif "budget" in l or "forecast" in l or "co" == l.strip() or "amount" in l or "exposure" in l:
            widths.append("10%")
        elif "package" in l or "item" in l:
            widths.append("10%")
        else:
            widths.append("12%")
    # Normalize roughly to 100% using CSS accepted percentages as guidance.
    return widths


def _copyable_table_component(headers: List[str], rows: List[List[Any]], numeric_cols: Optional[set] = None, key_prefix: str = "tbl") -> None:
    numeric_cols = numeric_cols or set()
    if not rows:
        st.markdown("<div class='action-empty'>No rows available for this active selection.</div>", unsafe_allow_html=True)
        return
    keep = _table_column_keep(headers, rows)
    headers2 = [headers[i] for i in keep]
    rows2 = [[row[i] if i < len(row) else "" for i in keep] for row in rows]
    numeric2 = {new_i for new_i, old_i in enumerate(keep) if old_i in numeric_cols}
    tsv = "\n".join(["\t".join(str(h or "") for h in headers2)] + ["\t".join(str(c or "") for c in row) for row in rows2])
    csv = "\n".join([",".join('"' + str(h or "").replace('"','""') + '"' for h in headers2)] + [",".join('"' + str(c or "").replace('"','""') + '"' for c in row) for row in rows2])
    widths = _col_widths_for_headers(headers2)
    colgroup = "".join(f"<col style='width:{w}'>" for w in widths)
    head = "".join(f"<th>{html.escape(str(h or ''))}</th>" for h in headers2)
    body_rows = []
    for row in rows2:
        cells = []
        for ci, val in enumerate(row):
            cls = "num" if ci in numeric2 else ""
            cells.append(f"<td class='{cls}'>{html.escape(str(val or ''))}</td>")
        body_rows.append(f"<tr>{''.join(cells)}</tr>")
    table_html = f"<table><colgroup>{colgroup}</colgroup><thead><tr>{head}</tr></thead><tbody>{''.join(body_rows)}</tbody></table>"
    ident = "tbl_" + hashlib.sha1((key_prefix + tsv).encode("utf-8", "ignore")).hexdigest()[:12]
    doc = f"""
<!doctype html>
<html><head><meta charset='utf-8'>
<style>
body{{margin:0;font-family:Inter,Segoe UI,Arial,sans-serif;color:#1f2937;background:transparent;}}
.copybar{{display:flex;gap:8px;align-items:center;margin:0 0 8px 0;}}
.copybar button{{border:1px solid #d9c3ee;background:#fff;color:#39135c;border-radius:999px;padding:7px 12px;font-weight:900;font-size:12px;cursor:pointer;}}
.copybar button:hover{{background:#f2e7fb;}}
.copybar .msg{{font-size:12px;color:#667085;}}
.table-wrap{{width:100%;border:1px solid #e7e2ed;border-radius:15px;overflow:hidden;background:#fff;box-shadow:0 1px 8px rgba(17,17,17,.04);}}
table{{width:100%;border-collapse:collapse;table-layout:fixed;}}
th{{background:#f7f7fa;color:#111;font-size:11px;letter-spacing:.06em;text-transform:uppercase;font-weight:950;line-height:1.18;padding:9px 8px;text-align:left;border-bottom:1px solid #e7e2ed;border-left:1px solid #eee8f4;}}
th:first-child{{border-left:0;}}
td{{font-size:12px;line-height:1.30;padding:8px 8px;vertical-align:top;border-top:1px solid #eee8f4;border-left:1px solid #eee8f4;white-space:normal;overflow-wrap:break-word;word-break:normal;hyphens:auto;}}
td:first-child{{border-left:0;}}
tbody tr:nth-child(even){{background:#fbfafc;}}
td.num{{text-align:right;font-weight:850;white-space:nowrap;}}
textarea{{position:absolute;left:-9999px;top:-9999px;}}
</style></head><body>
<div class='copybar'><button id='{ident}_btn'>Copy table</button><span id='{ident}_msg' class='msg'>Copies formatted HTML table with Excel-compatible tab-separated fallback.</span></div>
<textarea id='{ident}_tsv' readonly>{html.escape(tsv)}</textarea>
<textarea id='{ident}_csv' readonly>{html.escape(csv)}</textarea>
<div id='{ident}_html' class='table-wrap'>{table_html}</div>
<script>
const msg = document.getElementById('{ident}_msg');
const tsv = document.getElementById('{ident}_tsv').value;
const htmlTable = document.getElementById('{ident}_html').innerHTML;
async function copyTable() {{
  try {{
    if (navigator.clipboard && window.ClipboardItem) {{
      const item = new ClipboardItem({{
        'text/html': new Blob([htmlTable], {{type:'text/html'}}),
        'text/plain': new Blob([tsv], {{type:'text/plain'}})
      }});
      await navigator.clipboard.write([item]);
      msg.textContent = 'Copied as a formatted table. Paste into Excel, Word, Teams or email.';
      return;
    }}
    await navigator.clipboard.writeText(tsv);
    msg.textContent = 'Copied as tab-separated data. Paste into Excel to form columns.';
  }} catch(e) {{
    const ta = document.getElementById('{ident}_tsv');
    ta.style.cssText='position:static;width:100%;height:120px;margin:8px 0;font-family:monospace;font-size:12px;';
    ta.focus(); ta.select();
    msg.textContent='Browser blocked clipboard. Press Ctrl+C, then paste into Excel.';
  }}
}}
document.getElementById('{ident}_btn').addEventListener('click', copyTable);
</script>
</body></html>
"""
    height = max(165, min(2300, 62 + len(rows2) * 48))
    components.html(doc, height=height, scrolling=False)


def render_engineering_trend(rec: Dict[str, Any], selected_year: Optional[int] = None, selected_week: Optional[int] = None) -> None:
    rec = _with_display_scope(rec)
    fig = _progress_trend_figure(rec, selected_year, selected_week, rec.get("engineering_series", pd.DataFrame()), "Readiness", f"{rec['name']} engineering / design progress trend", "Engineering readiness %")
    if fig is None:
        st.info("No weekly scope-specific engineering readiness history loaded for this scope.")
        return
    st.plotly_chart(fig, use_container_width=True)


def render_cost_overview(records: List[Dict[str, Any]]) -> None:
    st.markdown("<div class='section-title'>Cost Status</div>", unsafe_allow_html=True)
    cost_data = _select_cost_report("portfolio")
    active_month = st.session_state.get("monthly_cost_report_choice_portfolio") or _active_month_label_from_cost(cost_data)
    st.markdown(f"<div class='cost-section-head single'><span class='cost-active-pill month-only'>Active month: {_html(active_month)}</span></div>", unsafe_allow_html=True)
    order = {"rail": 0, "ponds": 1, "roads": 2}
    records = sorted([_with_display_scope(r) for r in records if r.get("scope_id") in order], key=lambda r: order.get(r.get("scope_id"), 99))
    cols = st.columns(3)
    for col, rec in zip(cols, records):
        with col:
            st.plotly_chart(_cost_candle_figure(rec["scope_id"], cost_data, title=f"{rec['name']} cost status"), use_container_width=True)


def render_scope_cost_section(rec: Dict[str, Any]) -> None:
    rec = _with_display_scope(rec)
    st.markdown("<div class='section-title'>Cost control - monthly cost report</div>", unsafe_allow_html=True)
    cost = _select_cost_report(rec["scope_id"])
    active_month = st.session_state.get("monthly_cost_report_choice_portfolio") or _active_month_label_from_cost(cost)
    cs = _cost_summary(rec["scope_id"], cost)
    if not cs:
        st.info("No monthly cost data loaded for this scope.")
        return
    nums = _cost_numbers(rec["scope_id"], cost)
    st.markdown(f"<div class='cost-section-head single'><span class='cost-active-pill month-only'>Active month: {_html(active_month)}</span></div>", unsafe_allow_html=True)
    st.plotly_chart(_cost_candle_figure(rec["scope_id"], cost, title=f"{rec['name']} cost status"), use_container_width=True)
    metric_data = [
        ("Budget", nums["budget"]),
        ("CO", nums["change_order"]),
        ("Forecast", nums["forecast"]),
        ("Potential exposure", nums["potential_exposure"]),
        ("Potential forecast", nums["potential_forecast"]),
    ]
    mcols = st.columns(5)
    for col, (title, value) in zip(mcols, metric_data):
        with col:
            css = "bad" if title in {"Potential exposure", "Potential forecast"} else ("warn" if title == "CO" else "")
            st.markdown(f"<div class='cost-metric {css}'><span>{_html(title)}</span><b>{_html(_fmt_money(value))}</b></div>", unsafe_allow_html=True)
    # Keep detailed drivers expandable, but remove the old component-allocation table.
    exposures = _cost_exposures(rec["scope_id"], cost)
    if exposures:
        exp_rows = [[e.get("item_id"), e.get("package"), _fmt_money_full(e.get("amount")), e.get("criticality") or "", e.get("type") or "", e.get("description") or e.get("main_description"), e.get("pm") or "", _fmt_date_short(e.get("award_date"))] for e in exposures]
        with st.expander("Potential changes / O&V exposure items", expanded=False):
            _copyable_table_component(["Item", "Package", "Amount", "Criticality", "Type", "Description", "Responsible", "Expected / award date"], exp_rows, numeric_cols={2}, key_prefix=f"exp_{rec['scope_id']}")


