    render_milestone_timeline([rec], scope_filter=rec["scope_id"], title="Milestones", selected_year=selected_year, selected_week=selected_week, current_date=current_date)
    render_scope_baseline_section(rec, selected_year, selected_week)
    render_scope_cost_section(rec)
