def _cost_report_sort_key(report: Dict[str, Any]) -> str:
    data = report.get("data") if isinstance(report, dict) else None
    meta = (data or {}).get("metadata") if isinstance(data, dict) else {}
    raw = (meta or {}).get("cutoff_month") or (meta or {}).get("active_date") or (meta or {}).get("data_date") or report.get("active_date") or report.get("label") or ""
    dt = pd.to_datetime(str(raw) + ("-01" if re.match(r"^20\d{2}-\d{2}$", str(raw)) else ""), errors="coerce")
    if pd.notna(dt):
        return pd.Timestamp(dt).strftime("%Y-%m-%d")
    return str(raw)


def _cost_reports() -> List[Dict[str, Any]]:
    pack = cached_monthly_cost_reports()
    raw_reports = pack.get("reports", {}) if isinstance(pack, dict) else {}
    labels_map = pack.get("labels", {}) if isinstance(pack, dict) else {}
    seen: Dict[str, Dict[str, Any]] = {}
    for rid, report in (raw_reports or {}).items():
        if not isinstance(report, dict):
            continue
        label = _active_month_label_from_cost(report)
        if not label or label == "Active month":
            raw_label = labels_map.get(rid, rid)
            label = str(raw_label).split(" - ")[0] if raw_label else str(rid)
        meta = report.get("metadata") or {}
        sort_key = meta.get("cutoff_month") or meta.get("active_date") or meta.get("data_date") or label
        item = {"id": rid, "label": label, "active_date": label, "data": report, "_sort": sort_key}
        # Keep the richest report per month if duplicates exist.
        prev = seen.get(label)
        if prev is None or len(json.dumps(report, default=str)) >= len(json.dumps(prev.get("data", {}), default=str)):
            seen[label] = item
    if not seen:
        fallback = cached_monthly_cost()
        fallback_label = _active_month_label_from_cost(fallback)
        seen[fallback_label] = {"id": "active", "label": fallback_label, "active_date": fallback_label, "data": fallback, "_sort": fallback_label}
    out = list(seen.values())
    out.sort(key=_cost_report_sort_key)
    return out


def _cost_history_for_scope(scope_id: str, active_cost_data: Optional[Dict[str, Any]] = None, max_months: int = 3) -> List[Tuple[str, Dict[str, Any]]]:
    reports = _cost_reports()
    active_label = _active_month_label_from_cost(active_cost_data or _select_cost_report("portfolio"))
    labels = [r.get("label") for r in reports]
    idx = labels.index(active_label) if active_label in labels else len(reports) - 1
    start = max(0, idx - max_months + 1)
    selected = reports[start:idx + 1]
    out: List[Tuple[str, Dict[str, Any]]] = []
    for r in selected:
        data = r.get("data") if isinstance(r, dict) else None
        if isinstance(data, dict):
            out.append((r.get("label") or _active_month_label_from_cost(data), _waterfall_numbers(scope_id, data)))
    return out


def _history_hover_text(scope_id: str, metric_key: str, active_cost_data: Optional[Dict[str, Any]]) -> str:
    hist = _cost_history_for_scope(scope_id, active_cost_data, max_months=3)
    if not hist:
        return "No cost history loaded"
    label_map = {
        "budget": "Budget",
        "co": "CO",
        "forecast": "Forecast",
        "exposure": "Potential exposure",
        "potential_forecast": "Potential forecast",
    }
    lines = [f"{label}: {_fmt_money_full((vals or {}).get(metric_key))}" for label, vals in hist]
    return "<br>".join(lines)


def _cost_candle_figure(scope_id: str, cost_data: Optional[Dict[str, Any]] = None, title: str = "Cost Status") -> go.Figure:
    cost_data = cost_data or _select_cost_report("portfolio")
    vals = _waterfall_numbers(scope_id, cost_data)
    budget = vals.get("budget") or 0.0
    co = vals.get("co") or 0.0
    forecast = vals.get("forecast") or (budget + co)
    exposure = vals.get("exposure") or 0.0
    potential_forecast = vals.get("potential_forecast") or (forecast + exposure)
    labels = ["Budget", "CO", "Forecast", "Potential exposure", "Potential forecast"]
    metric_keys = ["budget", "co", "forecast", "exposure", "potential_forecast"]
    y_vals = [budget, co, forecast, exposure, potential_forecast]
    measures = ["absolute", "relative", "total", "relative", "total"]
    running = [budget, budget + co, forecast, forecast + exposure, potential_forecast]
    text_vals = [_fmt_money(v) for v in y_vals]
    active_month = _active_month_label_from_cost(cost_data)
    custom = []
    for i, label in enumerate(labels):
        hist_html = _history_hover_text(scope_id, metric_keys[i], cost_data)
        custom.append([label, _fmt_money_full(y_vals[i]), _fmt_money_full(running[i]), active_month, hist_html])
    fig = go.Figure(go.Waterfall(
        x=labels,
        y=y_vals,
        measure=measures,
        text=text_vals,
        textposition="outside",
        customdata=custom,
        connector={"line": {"color": "#9aa1ad", "width": 1}},
        increasing={"marker": {"color": "#007a45"}},
        decreasing={"marker": {"color": "#c73535"}},
        totals={"marker": {"color": "#c76df1"}},
        hovertemplate=(
            "<b>%{customdata[0]}</b><br>"
            "Active month: %{customdata[3]}<br>"
            "Step value: %{customdata[1]}<br>"
            "Cost position after step: %{customdata[2]}<br><br>"
            "<b>Last 3 loaded months</b><br>%{customdata[4]}<extra></extra>"
        ),
    ))
    fig.update_layout(
        title={"text": title, "x": 0.02, "xanchor": "left", "font": {"size": 16}},
        height=372,
        margin=dict(l=34, r=24, t=62, b=78),
        paper_bgcolor="rgba(0,0,0,0)",
        plot_bgcolor="rgba(0,0,0,0)",
        yaxis_title="EUR",
        xaxis_title="",
        showlegend=False,
        hovermode="closest",
    )
    fig.update_xaxes(tickangle=-22)
    return fig


