# Sidebar panels for v24. Cost is a standalone section/panel; UGP remains deleted.
PANEL_OPTIONS = [
    ("Executive overview", "Executive overview", "portfolio"),
    ("Cost Status", "Cost Status", "cost"),
    ("Rail On Site (ROS)", "Rail On Site (ROS)", "train"),
    ("Ponds", "Ponds", "drop"),
    ("Roads", "Roads", "road"),
]
SCOPE_PANEL_MAP = {"Rail On Site (ROS)": "rail", "Ponds": "ponds", "Roads": "roads"}
COST_SCOPE_LABELS = {
    "portfolio": "Portfolio total",
    "rail": "Rail On Site (ROS)",
    "ponds": "Ponds",
    "roads": "Roads",
}
COST_LABEL_TO_SCOPE = {v: k for k, v in COST_SCOPE_LABELS.items()}


def _num0(value: Any) -> float:
    num = _safe_float(value)
    return float(num) if num is not None else 0.0


def _cost_numbers_v24(scope_id: str, cost_data: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    """Return cost numbers for a scope or portfolio aggregate."""
    cost_data = cost_data or _select_cost_report("portfolio")
    if scope_id != "portfolio":
        nums = _cost_numbers(scope_id, cost_data)
        out = dict(nums)
        out["change_order"] = _num0(out.get("forecast")) - _num0(out.get("budget"))
        out["potential_forecast"] = _num0(out.get("forecast")) + _num0(out.get("potential_exposure"))
        out["forecast_minus_vowd"] = _num0(out.get("forecast")) - _num0(out.get("vowd"))
        return out
    total = {
        "budget": 0.0,
        "change_order": 0.0,
        "forecast": 0.0,
        "vowd": 0.0,
        "forecast_minus_vowd": 0.0,
        "potential_exposure": 0.0,
        "potential_forecast": 0.0,
        "basis": "Portfolio sum: Rail On Site (ROS), Ponds and Roads",
        "display_note": "Portfolio sum across Rail On Site (ROS), Ponds and Roads. UGP is excluded.",
    }
    for sid in ["rail", "ponds", "roads"]:
        nums = _cost_numbers(sid, cost_data)
        budget = _num0(nums.get("budget"))
        forecast = _num0(nums.get("forecast"))
        exposure = _num0(nums.get("potential_exposure"))
        vowd = _num0(nums.get("vowd"))
        total["budget"] += budget
        total["forecast"] += forecast
        total["change_order"] += forecast - budget
        total["vowd"] += vowd
        total["forecast_minus_vowd"] += forecast - vowd
        total["potential_exposure"] += exposure
        total["potential_forecast"] += forecast + exposure
    return total


def _cost_history_all(scope_id: str) -> List[Dict[str, Any]]:
    reports = _cost_reports()
    history: List[Dict[str, Any]] = []
    for report in reports:
        data = report.get("data") if isinstance(report, dict) else None
        if not isinstance(data, dict):
            continue
        label = report.get("label") or _active_month_label_from_cost(data)
        nums = _cost_numbers_v24(scope_id, data)
        history.append({
            "label": label,
            "data": data,
            "budget": _safe_float(nums.get("budget")),
            "co": _safe_float(nums.get("change_order")),
            "forecast": _safe_float(nums.get("forecast")),
            "vowd": _safe_float(nums.get("vowd")),
            "etc": _safe_float(nums.get("forecast_minus_vowd")),
            "exposure": _safe_float(nums.get("potential_exposure")),
            "potential_forecast": _safe_float(nums.get("potential_forecast")),
        })
    return history


def _active_cost_label() -> str:
    reports = _cost_reports()
    labels = [r.get("label") for r in reports if r.get("label")]
    selected = st.session_state.get("monthly_cost_report_choice_portfolio")
    if selected in labels:
        return selected
    return labels[-1] if labels else _active_month_label_from_cost(_select_cost_report("portfolio"))


def _active_cost_index(history: List[Dict[str, Any]], active_label: Optional[str] = None) -> int:
    if not history:
        return -1
    active_label = active_label or _active_cost_label()
    labels = [h.get("label") for h in history]
    return labels.index(active_label) if active_label in labels else len(history) - 1


def _money_delta_text(cur: Optional[float], prev: Optional[float]) -> str:
    if cur is None or prev is None:
        return "No previous month"
    delta = cur - prev
    sign = "+" if delta >= 0 else ""
    return f"{sign}{_fmt_money(delta)} vs previous month"


def _pct_ratio(numer: Optional[float], denom: Optional[float]) -> str:
    if numer is None or denom in (None, 0):
        return "N/A"
    return f"{(float(numer) / float(denom)) * 100:.1f}%"


def _metric_trend(history: List[Dict[str, Any]], metric_key: str) -> List[Tuple[str, Optional[float]]]:
    return [(h.get("label", ""), h.get(metric_key)) for h in history]


def _sparkline_svg(points: List[Tuple[str, Optional[float]]], active_idx: int) -> str:
    vals = [v for _label, v in points if _safe_float(v) is not None]
    if len(vals) < 2:
        return "<div style='color:#cbd5e1;font-size:12px;'>No trend history loaded</div>"
    vmin, vmax = min(vals), max(vals)
    if abs(vmax - vmin) < 1e-9:
        vmax = vmin + 1
    n = len(points)
    coords = []
    for i, (_label, val) in enumerate(points):
        x = 4 + (92 * i / max(1, n - 1))
        if _safe_float(val) is None:
            y = 25
        else:
            y = 42 - (34 * (float(val) - vmin) / (vmax - vmin))
        coords.append((x, y, val))
    poly = " ".join(f"{x:.1f},{y:.1f}" for x, y, val in coords if _safe_float(val) is not None)
    circles = []
    for i, (x, y, val) in enumerate(coords):
        if _safe_float(val) is None:
            continue
        if i == active_idx:
            circles.append(f"<circle cx='{x:.1f}' cy='{y:.1f}' r='4.0' fill='#d8b4fe' stroke='#fff' stroke-width='1.6'/>")
        else:
            circles.append(f"<circle cx='{x:.1f}' cy='{y:.1f}' r='2.1' fill='#9ca3af'/>")
    return (
        "<svg viewBox='0 0 100 50' preserveAspectRatio='none'>"
        "<line x1='4' y1='44' x2='96' y2='44' stroke='rgba(255,255,255,.18)' stroke-width='1'/>"
        f"<polyline points='{poly}' fill='none' stroke='#d8b4fe' stroke-width='2.2' stroke-linecap='round' stroke-linejoin='round'/>"
        + "".join(circles) +
        "</svg>"
    )


def _cost_kpi_card(label: str, metric_key: str, history: List[Dict[str, Any]], active_idx: int, tone: str = "") -> str:
    if not history:
        return ""
    active = history[active_idx] if 0 <= active_idx < len(history) else history[-1]
    prev = history[active_idx - 1] if active_idx > 0 else None
    first = history[0]
    cur_val = active.get(metric_key)
    prev_val = prev.get(metric_key) if prev else None
    first_val = first.get(metric_key)
    delta_text = _money_delta_text(cur_val, prev_val)
    since_text = _money_delta_text(cur_val, first_val).replace("vs previous month", "since first loaded month") if first is not active else "First loaded month"
    points = _metric_trend(history, metric_key)
    spark = _sparkline_svg(points, active_idx)
    rows = []
    for i, (m, v) in enumerate(points):
        cls = "hist-row active" if i == active_idx else "hist-row"
        rows.append(f"<div class='{cls}'><span>{_html(m)}</span><b>{_html(_fmt_money(v))}</b></div>")
    tone_class = f" {tone}" if tone else ""
    return (
        f"<div class='cost-kpi-card{tone_class}'>"
        f"<div class='k-title'>{_html(label)}</div>"
        f"<div class='k-value'>{_html(_fmt_money(cur_val))}</div>"
        f"<div class='k-sub'><b>{_html(delta_text)}</b><br>{_html(since_text)}</div>"
        "<div class='cost-kpi-tooltip'>"
        f"<div class='spark-title'><b>{_html(label)} history</b><span>{_html(active.get('label',''))}</span></div>"
        f"{spark}"
        + "".join(rows) +
        "</div></div>"
    )


def _cost_kpi_grid(history: List[Dict[str, Any]], active_idx: int) -> None:
    items = [
        ("Budget", "budget", ""),
        ("CO", "co", "warn"),
        ("Forecast", "forecast", ""),
        ("VOWD / actual", "vowd", "good"),
        ("ETC", "etc", ""),
        ("Potential exposure", "exposure", "bad"),
        ("Potential forecast", "potential_forecast", "bad"),
        ("Forecast vs budget", "co", "warn"),
    ]
    cards = "".join(_cost_kpi_card(label, key, history, active_idx, tone) for label, key, tone in items)
    st.markdown(f"<div class='cost-kpi-grid'>{cards}</div>", unsafe_allow_html=True)


def _waterfall_numbers_v24(scope_id: str, cost_data: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    nums = _cost_numbers_v24(scope_id, cost_data)
    return {
        "budget": _safe_float(nums.get("budget")),
        "co": _safe_float(nums.get("change_order")),
        "forecast": _safe_float(nums.get("forecast")),
        "exposure": _safe_float(nums.get("potential_exposure")),
        "potential_forecast": _safe_float(nums.get("potential_forecast")),
        "vowd": _safe_float(nums.get("vowd")),
        "etc": _safe_float(nums.get("forecast_minus_vowd")),
        "basis": nums.get("basis"),
        "note": nums.get("display_note"),
    }


def _cost_candle_figure_v24(scope_id: str, cost_data: Optional[Dict[str, Any]] = None, title: str = "Cost Status") -> go.Figure:
    cost_data = cost_data or _select_cost_report("portfolio")
    vals = _waterfall_numbers_v24(scope_id, cost_data)
    budget = vals.get("budget") or 0.0
    co = vals.get("co") or 0.0
    forecast = vals.get("forecast") or (budget + co)
    exposure = vals.get("exposure") or 0.0
    potential_forecast = vals.get("potential_forecast") or (forecast + exposure)
    labels = ["Budget", "CO", "Forecast", "Potential exposure", "Potential forecast"]
    y_vals = [budget, co, forecast, exposure, potential_forecast]
    measures = ["absolute", "relative", "total", "relative", "total"]
    running = [budget, budget + co, forecast, forecast + exposure, potential_forecast]
    active_month = _active_month_label_from_cost(cost_data)
    custom = [[labels[i], _fmt_money_full(y_vals[i]), _fmt_money_full(running[i]), active_month] for i in range(len(labels))]
    fig = go.Figure(go.Waterfall(
        x=labels,
        y=y_vals,
        measure=measures,
        text=[_fmt_money(v) for v in y_vals],
        textposition="outside",
        customdata=custom,
        connector={"line": {"color": "#9aa1ad", "width": 1}},
        increasing={"marker": {"color": "#007a45"}},
        decreasing={"marker": {"color": "#c73535"}},
        totals={"marker": {"color": "#c76df1"}},
        hovertemplate=(
            "<b>%{customdata[0]}</b><br>"
            "Active month: %{customdata[3]}<br>"
            "Step value: %{customdata[1]}<br>"
            "Cost position after step: %{customdata[2]}<extra></extra>"
        ),
    ))
    fig.update_layout(
        title={"text": title, "x": 0.02, "xanchor": "left", "font": {"size": 18}},
        height=420,
        margin=dict(l=34, r=24, t=64, b=78),
        paper_bgcolor="rgba(0,0,0,0)",
        plot_bgcolor="rgba(0,0,0,0)",
        yaxis_title="EUR",
        xaxis_title="",
        showlegend=False,
        hovermode="closest",
    )
    fig.update_xaxes(tickangle=-22)
    return fig


def _cost_history_figure(scope_id: str, history: List[Dict[str, Any]], active_idx: int) -> go.Figure:
    labels = [h.get("label") for h in history]
    fig = go.Figure()
    metrics = [
        ("Budget", "budget"),
        ("Forecast", "forecast"),
        ("VOWD / actual", "vowd"),
        ("ETC", "etc"),
        ("Potential exposure", "exposure"),
        ("Potential forecast", "potential_forecast"),
    ]
    for name, key in metrics:
        y = [h.get(key) for h in history]
        fig.add_trace(go.Scatter(
            x=labels,
            y=y,
            mode="lines+markers",
            name=name,
            customdata=[[name, _fmt_money_full(v), lab] for lab, v in zip(labels, y)],
            hovertemplate="<b>%{customdata[0]}</b><br>Month: %{customdata[2]}<br>Value: %{customdata[1]}<extra></extra>",
        ))
    if 0 <= active_idx < len(history):
        active_label = labels[active_idx]
        fig.add_vline(x=active_label, line_width=2, line_dash="dash", line_color="#111111", annotation_text="Active month", annotation_position="top")
        # Highlight active VOWD/actual value explicitly.
        active_vowd = history[active_idx].get("vowd")
        fig.add_trace(go.Scatter(
            x=[active_label], y=[active_vowd], mode="markers+text", name="Active actual value",
            marker={"symbol": "diamond-open", "size": 15, "color": "#111111", "line": {"width": 2}},
            text=[_fmt_money(active_vowd)], textposition="top center",
            hovertemplate="<b>Active actual / VOWD</b><br>Month: %{x}<br>Value: %{text}<extra></extra>",
        ))
    fig.update_layout(
        title={"text": f"{COST_SCOPE_LABELS.get(scope_id, scope_id)} cost history", "x": 0.02, "xanchor": "left", "font": {"size": 18}},
        height=420,
        margin=dict(l=44, r=20, t=64, b=70),
        paper_bgcolor="rgba(0,0,0,0)",
        plot_bgcolor="rgba(0,0,0,0)",
        yaxis_title="EUR",
        xaxis_title="Month",
        legend_title="Cost metric",
        hovermode="x unified",
    )
    fig.update_xaxes(tickangle=-25)
    return fig


def _cost_delta_figure(scope_id: str, history: List[Dict[str, Any]], active_idx: int) -> go.Figure:
    labels = [h.get("label") for h in history]
    forecast_delta = []
    exposure_delta = []
    for i, h in enumerate(history):
        if i == 0:
            forecast_delta.append(0)
            exposure_delta.append(0)
        else:
            forecast_delta.append(_num0(h.get("forecast")) - _num0(history[i - 1].get("forecast")))
            exposure_delta.append(_num0(h.get("exposure")) - _num0(history[i - 1].get("exposure")))
    fig = go.Figure()
    fig.add_trace(go.Bar(x=labels, y=forecast_delta, name="Forecast monthly movement", customdata=[_fmt_money_full(v) for v in forecast_delta], hovertemplate="<b>Forecast movement</b><br>%{x}: %{customdata}<extra></extra>"))
    fig.add_trace(go.Bar(x=labels, y=exposure_delta, name="Exposure monthly movement", customdata=[_fmt_money_full(v) for v in exposure_delta], hovertemplate="<b>Exposure movement</b><br>%{x}: %{customdata}<extra></extra>"))
    if 0 <= active_idx < len(labels):
        fig.add_vline(x=labels[active_idx], line_width=2, line_dash="dash", line_color="#111111")
    fig.update_layout(
        title={"text": "Monthly movement", "x": 0.02, "xanchor": "left", "font": {"size": 17}},
        barmode="group",
        height=340,
        margin=dict(l=44, r=20, t=58, b=76),
        paper_bgcolor="rgba(0,0,0,0)",
        plot_bgcolor="rgba(0,0,0,0)",
        yaxis_title="EUR",
        xaxis_title="Month",
        legend_title="Movement",
        hovermode="x unified",
    )
    fig.update_xaxes(tickangle=-25)
    return fig


def _cost_history_table_rows(history: List[Dict[str, Any]]) -> List[List[Any]]:
    rows = []
    prev_forecast = None
    for h in history:
        forecast = h.get("forecast")
        exposure = h.get("exposure")
        vowd = h.get("vowd")
        rows.append([
            h.get("label"),
            _fmt_money_full(h.get("budget")),
            _fmt_money_full(h.get("co")),
            _fmt_money_full(forecast),
            _fmt_money_full(vowd),
            _fmt_money_full(h.get("etc")),
            _fmt_money_full(exposure),
            _fmt_money_full(h.get("potential_forecast")),
            _money_delta_text(forecast, prev_forecast) if prev_forecast is not None else "First loaded month",
            _pct_ratio(exposure, forecast),
            _pct_ratio(vowd, forecast),
        ])
        prev_forecast = forecast
    return rows


def _cost_package_rows_v24(scope_id: str, cost_data: Dict[str, Any]) -> List[List[Any]]:
    scopes = ["rail", "ponds", "roads"] if scope_id == "portfolio" else [scope_id]
    rows: List[List[Any]] = []
    for sid in scopes:
        for row in _scope_package_rows(sid, cost_data):
            # Current row shape: Package, Description, Supplier, Budget, CO, Forecast, Exposure, Potential forecast, Driver/note.
            rows.append([COST_SCOPE_LABELS.get(sid, sid)] + row)
    return rows


def _cost_exposure_rows_v24(scope_id: str, cost_data: Dict[str, Any]) -> List[List[Any]]:
    scopes = ["rail", "ponds", "roads"] if scope_id == "portfolio" else [scope_id]
    rows: List[List[Any]] = []
    for sid in scopes:
        exposures = _cost_exposures(sid, cost_data)
        for e in exposures:
            rows.append([
                COST_SCOPE_LABELS.get(sid, sid),
                e.get("item_id") or "",
                e.get("package") or "",
                _fmt_money_full(e.get("amount")),
                e.get("criticality") or "",
                e.get("type") or "",
                e.get("description") or e.get("main_description") or "",
                e.get("pm") or "",
                _fmt_date_short(e.get("award_date")),
            ])
    # Sort by amount descending where possible.
    def amt(row: List[Any]) -> float:
        return _num0(str(row[3]).replace("€", "").replace(",", ""))
    return sorted(rows, key=amt, reverse=True)


def _pm_cost_insights(scope_id: str, history: List[Dict[str, Any]], active_idx: int) -> None:
    if not history:
        return
    cur = history[active_idx if active_idx >= 0 else -1]
    prev = history[active_idx - 1] if active_idx > 0 else None
    forecast = cur.get("forecast")
    exposure = cur.get("exposure")
    potential = cur.get("potential_forecast")
    vowd = cur.get("vowd")
    etc = cur.get("etc")
    f_delta = (forecast - prev.get("forecast")) if prev and forecast is not None and prev.get("forecast") is not None else None
    exposure_ratio = _pct_ratio(exposure, forecast)
    burn_ratio = _pct_ratio(vowd, forecast)
    cards = [
        ("Current forecast movement", _fmt_money_full(f_delta) if f_delta is not None else "No previous month", "Month-over-month movement in current forecast for the selected scope."),
        ("Exposure pressure", f"{_fmt_money(exposure)} / {exposure_ratio}", "Potential exposure as a share of current forecast; this is the PM pressure point to challenge."),
        ("Actualized cost position", f"VOWD {burn_ratio}", f"VOWD is {_fmt_money(vowd)} and remaining ETC is {_fmt_money(etc)} against forecast."),
    ]
    html_cards = "".join(f"<div class='pm-insight-card'><span>{_html(t)}</span><b>{_html(v)}</b><p>{_html(p)}</p></div>" for t, v, p in cards)
    st.markdown(f"<div class='pm-insight-grid'>{html_cards}</div>", unsafe_allow_html=True)


def render_cost_control_center(records: Optional[List[Dict[str, Any]]] = None) -> None:
    active_cost = _select_cost_report("portfolio")
    active_month = _active_cost_label()
    meta = active_cost.get("metadata") or {}
    default_label = st.session_state.get("cost_scope_visualization_v24") or "Portfolio total"
    if default_label not in COST_LABEL_TO_SCOPE:
        default_label = "Portfolio total"
    st.markdown("<div class='cost-one-section'>", unsafe_allow_html=True)
    st.markdown(
        "<div class='cost-only-hero'>"
        "<div>"
        "<h2>Cost Status</h2>"
        "<p>One dedicated cost-control view for Rail On Site (ROS), Ponds and Roads. It shows the selected active month, all loaded monthly history, current cost KPIs, forecast movement, VOWD / actual position, ETC, potential exposure and the package / exposure drivers a Project Manager needs for stakeholder discussions.</p>"
        f"<div class='cost-pill-row'><span class='cost-pill-v24'>Active month: {_html(active_month)}</span><span class='cost-pill-v24'>Currency: {_html(meta.get('currency') or 'EUR')}</span><span class='cost-pill-v24'>Historical reports: {len(_cost_reports())}</span></div>"
        "</div>"
        f"<div class='cost-scope-select-wrap'><span>Scope visualized</span><b>{_html(default_label)}</b></div>"
        "</div>",
        unsafe_allow_html=True,
    )
    labels = ["Portfolio total", "Rail On Site (ROS)", "Ponds", "Roads"]
    selected_label = st.selectbox("Scope to visualize", labels, key="cost_scope_visualization_v24", help="Select which scope drives the Cost Status section.")
    scope_id = COST_LABEL_TO_SCOPE.get(selected_label, "portfolio")
    history = _cost_history_all(scope_id)
    active_idx = _active_cost_index(history, active_month)
    if not history:
        st.info("No monthly cost data loaded yet.")
        st.markdown("</div>", unsafe_allow_html=True)
        return
    _cost_kpi_grid(history, active_idx)
    _pm_cost_insights(scope_id, history, active_idx)
    col1, col2 = st.columns([1.0, 1.42])
    with col1:
        st.plotly_chart(_cost_candle_figure_v24(scope_id, active_cost, title=f"{selected_label} - active month waterfall"), use_container_width=True)
    with col2:
        st.plotly_chart(_cost_history_figure(scope_id, history, active_idx), use_container_width=True)
    st.plotly_chart(_cost_delta_figure(scope_id, history, active_idx), use_container_width=True)
    st.markdown("<div class='section-title'>Historical cost register</div>", unsafe_allow_html=True)
    hist_rows = _cost_history_table_rows(history)
    _copyable_table_component(
        ["Month", "Budget", "CO", "Forecast", "VOWD / actual", "ETC", "Potential exposure", "Potential forecast", "Forecast movement", "Exposure / forecast", "VOWD / forecast"],
        hist_rows,
        key_prefix=f"cost_history_v24_{scope_id}",
    )
    st.markdown("<div class='section-title'>Package drivers - active month</div>", unsafe_allow_html=True)
    package_rows = _cost_package_rows_v24(scope_id, active_cost)
    if package_rows:
        _copyable_table_component(
            ["Scope", "Package", "Description", "Supplier", "Budget", "CO", "Forecast", "Exposure", "Potential forecast", "Driver / note"],
            package_rows,
            key_prefix=f"cost_pkg_v24_{scope_id}",
        )
    else:
        st.markdown("<div class='action-empty'>No package-driver rows loaded for the selected scope/month.</div>", unsafe_allow_html=True)
    st.markdown("<div class='section-title'>Potential exposure / O&V drivers - active month</div>", unsafe_allow_html=True)
    exposure_rows = _cost_exposure_rows_v24(scope_id, active_cost)
    if exposure_rows:
        _copyable_table_component(
            ["Scope", "Item", "Package", "Amount", "Criticality", "Type", "Description", "Responsible", "Expected / award date"],
            exposure_rows,
            key_prefix=f"cost_exp_v24_{scope_id}",
        )
    else:
        st.markdown("<div class='action-empty'>No potential-exposure rows loaded for the selected scope/month.</div>", unsafe_allow_html=True)
    st.markdown("</div>", unsafe_allow_html=True)


def render_cost_overview(records: List[Dict[str, Any]]) -> None:
    # v24: cost is shown once in the dedicated Cost Status panel, not repeated in Executive overview.
    render_cost_control_center(records)


def render_scope_matrix(records: List[Dict[str, Any]], selected_year: int, selected_week: int) -> None:
    st.markdown("<div class='section-title'>Executive control matrix</div>", unsafe_allow_html=True)
    order = {"rail": 0, "ponds": 1, "roads": 2}
    records = [_with_display_scope(r) for r in records if r.get("scope_id") in order]
    records = sorted(records, key=lambda r: order.get(r.get("scope_id"), 99))
    cols = st.columns(3)
    for col, rec in zip(cols, records):
        with col:
            construction_dev = rec.get("construction_deviation")
            if construction_dev is None and rec.get("construction_actual") is not None and rec.get("construction_forecast") is not None:
                construction_dev = rec.get("construction_actual") - rec.get("construction_forecast")
            engineering_actual = rec.get("engineering_actual")
            engineering_forecast = rec.get("engineering_forecast") if rec.get("engineering_forecast") is not None else engineering_actual
            engineering_dev = rec.get("engineering_deviation")
            if engineering_dev is None and engineering_actual is not None and engineering_forecast is not None:
                engineering_dev = engineering_actual - engineering_forecast
            construction_etc = _date_only_etc(_baseline_etc_for_scope(rec["scope_id"], selected_year, selected_week, mode="final"), fallback="TBC")
            engineering_etc = _date_only_etc(rec.get("engineering_etc") or _baseline_etc_for_scope(rec["scope_id"], selected_year, selected_week, mode="next"), fallback="TBC")
            icon = SCOPE_ICON.get(rec["scope_id"], "●")
            html_block = (
                "<div class='matrix-col no-cost'>"
                "<div class='matrix-head'>"
                f"<h3><span class='scope-icon'>{icon}</span>{_html(rec['name'])}</h3>"
                f"<span class='status-badge'>{_html(_matrix_driver(rec))}</span>"
                "</div>"
                f"{progress_bar_html('Construction progress', rec.get('construction_actual'), rec.get('construction_forecast'), construction_dev, construction_etc, next_week_forecast=_next_progress_label(rec, selected_year, selected_week, 'construction'))}"
                f"{progress_bar_html('Engineering progress', engineering_actual, engineering_forecast, engineering_dev, engineering_etc, next_week_forecast=_next_progress_label(rec, selected_year, selected_week, 'engineering'))}"
                f"<div class='next-fc'><b>Next week FC</b>{_html(rec.get('next_week_fc') or 'Not published in selected-week data')}</div>"
                "<div class='gate-row'>"
                f"{_gate_pill_html('Open quality gates', len(rec.get('quality_items', [])), rec.get('quality_items', []))}"
                f"{_gate_pill_html('Open engineering gates', len(rec.get('engineering_items', [])), rec.get('engineering_items', []))}"
                "</div>"
                "</div>"
            )
            st.markdown(html_block, unsafe_allow_html=True)


def render_executive_overview(bundle: Dict[str, Any], profiles: Dict[str, Any], selected_year: int, selected_week: int, current_date: Optional[pd.Timestamp] = None) -> None:
    records = build_scope_records(bundle, profiles, selected_year, selected_week, scopes=CONTROL_SCOPES)
    selected_label = period_display(selected_year, selected_week)
    cutoff = current_date if current_date is not None else selected_cutoff_date(bundle)
    render_scope_matrix(records, selected_year, selected_week)
    render_executive_priority_delayed_near_table(records, selected_label, selected_year, selected_week, current_date=cutoff)
    render_milestone_timeline(records, title="Milestones", selected_year=selected_year, selected_week=selected_week, current_date=cutoff)


def render_scope_sections(rec: Dict[str, Any], selected_year: int, selected_week: int, current_date: Optional[pd.Timestamp] = None) -> None:
    rec = _with_display_scope(rec)
    selected_label = period_display(selected_year, selected_week)
    st.markdown(f"<div class='scope-banner'><h2><span class='scope-icon'>{SCOPE_ICON.get(rec.get('scope_id'), '')}</span>{_html(rec['full_name'])} control panel</h2><p>{_html(compact_text(rec.get('insight', ''), 420))}</p></div>", unsafe_allow_html=True)
    col1, col2 = st.columns([1, 1])
    with col1:
        render_progress_gauge(rec)
    with col2:
        render_progress_trend(rec, selected_year, selected_week)
    render_milestone_timeline([rec], scope_filter=rec["scope_id"], title="Milestones", selected_year=selected_year, selected_week=selected_week, current_date=current_date)
    render_scope_baseline_section(rec, selected_year, selected_week)
    # Cost intentionally removed from scope panels in v24. Use the dedicated Cost Status panel.
    render_action_table(f"{rec['name']} priority & high-exposure items - {selected_label}", rec.get("priority_items", []), selected_year, selected_week, rec.get("default_responsible", "TBC"), max_items=999, current_date=current_date)
    st.markdown("<div class='section-title'>Engineering / design</div>", unsafe_allow_html=True)
    e1, e2 = st.columns([1, 1])
    with e1:
        render_engineering_gauge(rec, selected_year, selected_week)
    with e2:
        render_engineering_trend(rec, selected_year, selected_week)
    render_action_table("", rec.get("engineering_items", []), selected_year, selected_week, rec.get("default_responsible", "TBC"), max_items=999, current_date=current_date)
    st.markdown("<div class='section-title'>Quality / completion</div>", unsafe_allow_html=True)
    render_action_table("", rec.get("quality_items", []), selected_year, selected_week, rec.get("default_responsible", "TBC"), max_items=999, current_date=current_date)
    st.markdown("<div class='section-title'>Interface / commercial controls</div>", unsafe_allow_html=True)
    render_action_table("", rec.get("interface_items", []), selected_year, selected_week, rec.get("default_responsible", "TBC"), max_items=999, current_date=current_date)


def render_sidebar(bundle: Dict[str, Any]) -> Tuple[str, int, int]:
    logo_src = logo_mark_data_uri() or logo_data_uri()
    if logo_src:
        st.sidebar.markdown(f"<div class='sidebar-logo'><img src='{logo_src}'><span>Scope controls</span></div>", unsafe_allow_html=True)
    st.sidebar.title("Control settings")

    periods = available_periods(st.session_state["bundle"])
    if not periods:
        selected_year, selected_week = (2026, 0)
        period_labels = []
    else:
        period_labels = [period_display(y, w) for y, w in periods]
        latest_y, latest_w = latest_period(st.session_state["bundle"])
        default_label = period_display(latest_y, latest_w)
        if default_label not in period_labels:
            default_label = period_labels[-1]
        if st.session_state.get("week_selector_value") not in period_labels:
            st.session_state["week_selector_value"] = default_label
        st.sidebar.markdown("<div class='subsection-title'>Selections</div>", unsafe_allow_html=True)
        selected_label = st.sidebar.selectbox("Week to display", period_labels, key="week_selector_value", help="Select any loaded report week manually.")
        current_idx = period_labels.index(selected_label)
        selected_year, selected_week = periods[current_idx]
        st.sidebar.caption(f"Selected week {current_idx + 1} of {len(period_labels)}")

    cost_reports = _cost_reports()
    cost_labels = [r["label"] for r in cost_reports if r.get("label")]
    if cost_labels:
        if st.session_state.get("monthly_cost_report_choice_portfolio") not in cost_labels:
            st.session_state["monthly_cost_report_choice_portfolio"] = cost_labels[-1]
        st.sidebar.selectbox("Monthly report to use", cost_labels, key="monthly_cost_report_choice_portfolio")
        st.sidebar.markdown(f"<div class='cost-active-pill'>Active month: {_html(st.session_state['monthly_cost_report_choice_portfolio'])}</div>", unsafe_allow_html=True)
    baseline_reports = _baseline_reports()
    bl_labels = [r["label"] for r in baseline_reports if r.get("label")]
    if bl_labels:
        if st.session_state.get("baseline_choice") not in bl_labels:
            st.session_state["baseline_choice"] = bl_labels[-1]
        st.sidebar.selectbox("Baseline to use", bl_labels, key="baseline_choice")

    st.sidebar.markdown("---")
    st.sidebar.markdown("<div class='subsection-title'>Panel</div>", unsafe_allow_html=True)
    visible_panels = ["Executive overview", "Cost Status", "Rail On Site (ROS)", "Ponds", "Roads"]
    if st.session_state.get("panel_choice") not in visible_panels:
        st.session_state["panel_choice"] = visible_panels[0]
    icons = {"Executive overview": "▦", "Cost Status": "€", "Rail On Site (ROS)": "🚆", "Ponds": "💧", "Roads": "🛣️"}
    for label in visible_panels:
        if st.sidebar.button(f"{icons.get(label, '•')} {label}", key=f"nav_v24_{label}", use_container_width=True):
            st.session_state["panel_choice"] = label
    st.sidebar.markdown(f"<div class='nav-active'>Current panel: {_html(st.session_state['panel_choice'])}</div>", unsafe_allow_html=True)
    st.sidebar.caption(f"Loaded {latest_period_label(st.session_state['bundle'])} - {source_count(st.session_state['bundle'])} source reports")
    st.sidebar.markdown("<div class='nav-hint'>Cost is now consolidated in one Cost Status panel. UGP is fully removed from this app.</div>", unsafe_allow_html=True)

    st.sidebar.markdown("---")
    st.sidebar.markdown("<div class='subsection-title'>Upload / refresh</div>", unsafe_allow_html=True)
    uploaded_weekly = st.sidebar.file_uploader("Upload new weekly report PDF/PPTX", type=["pdf", "pptx"], accept_multiple_files=True, key="weekly_upload_v24", help="Upload one or more weekly reports. The parser merges new report weeks into the current session.")
    if uploaded_weekly:
        key = _upload_list_hash(uploaded_weekly)
        if key != st.session_state.get("last_weekly_upload_key_v24"):
            with st.spinner("Parsing uploaded weekly report(s) and refreshing the control center..."):
                try:
                    incoming = parse_uploaded_reports(uploaded_weekly)
                    st.session_state["bundle"] = merge_bundles(st.session_state["bundle"], incoming)
                    st.session_state["last_weekly_upload_key_v24"] = key
                    st.sidebar.success(f"{len(uploaded_weekly)} weekly report(s) parsed and loaded.")
                except Exception as exc:
                    st.sidebar.error(f"Could not parse weekly upload: {exc}")
    uploaded_cost_reports = st.sidebar.file_uploader("Upload monthly cost report XLSX", type=["xlsx"], accept_multiple_files=True, key="cost_upload_v24", help="Upload one or more monthly cost reports. Each report is normalized, stored and added to the monthly-report selector.")
    if uploaded_cost_reports:
        key = _upload_list_hash(uploaded_cost_reports)
        if key != st.session_state.get("last_cost_upload_key_v24"):
            loaded = 0; errors: List[str] = []
            for uploaded in uploaded_cost_reports:
                try:
                    data = normalize_uploaded_cost_report(uploaded)
                    rid, label = save_normalized_cost_report(data, uploaded.name)
                    loaded += 1
                    st.session_state["monthly_cost_report_choice_portfolio"] = label
                except Exception as exc:
                    errors.append(f"{uploaded.name}: {exc}")
            cached_monthly_cost_reports.clear()
            st.session_state["last_cost_upload_key_v24"] = key
            if loaded:
                st.sidebar.success(f"{loaded} monthly cost report(s) loaded.")
            for err in errors:
                st.sidebar.error(err)
    uploaded_baselines = st.sidebar.file_uploader("Upload schedule baseline PDF", type=["pdf"], accept_multiple_files=True, key="baseline_upload_v24", help="Upload one or more time-schedule baseline PDFs. They are registered for baseline selection.")
    if uploaded_baselines:
        key = _upload_list_hash(uploaded_baselines)
        if key != st.session_state.get("last_baseline_upload_key_v24"):
            loaded = 0; errors = []
            for uploaded in uploaded_baselines:
                try:
                    data = parse_uploaded_baseline_pdf(uploaded)
                    rid, label = save_normalized_baseline(data, uploaded.name)
                    st.session_state["baseline_choice"] = label
                    loaded += 1
                except Exception as exc:
                    errors.append(f"{uploaded.name}: {exc}")
            cached_baseline_schedules.clear()
            st.session_state["last_baseline_upload_key_v24"] = key
            if loaded:
                st.sidebar.success(f"{loaded} baseline file(s) loaded.")
            for err in errors:
                st.sidebar.error(err)
    if st.sidebar.button("Save current session data", key="save_session_v24", use_container_width=True):
        DATA_PATH.write_text(json.dumps(st.session_state["bundle"], indent=2, default=str), encoding="utf-8")
        st.sidebar.success("Session data saved to data/weekly_data_bundle.json")
    return st.session_state.get("panel_choice", "Executive overview"), selected_year, selected_week


def main() -> None:
    render_loading_overlay()
    if "bundle" not in st.session_state:
        st.session_state["bundle"] = cached_bundle(DATA_PATH.stat().st_mtime_ns)
    profiles = cached_profiles()
    panel_choice, selected_year, selected_week = render_sidebar(st.session_state["bundle"])
    view_bundle = filter_bundle_until(st.session_state["bundle"], selected_year, selected_week)
    selected_label = period_display(selected_year, selected_week)
    render_header(view_bundle, selected_label)
    selected_cutoff = selected_cutoff_date(view_bundle)
    if panel_choice == "Executive overview":
        render_executive_overview(st.session_state["bundle"], profiles, selected_year, selected_week, current_date=selected_cutoff)
    elif panel_choice == "Cost Status":
        render_cost_control_center()
    else:
        render_scope_panel(st.session_state["bundle"], profiles, SCOPE_PANEL_MAP[panel_choice], selected_year, selected_week, current_date=selected_cutoff)
    st.markdown(
        "<div class='footer-note'>Data source: uploaded weekly reports, the Rail On Site May 2026 reference presentation, the BL CC E006 time-schedule baseline, the Budget Forecast Roads-Rail-Ponds presentation, and selectable monthly cost reports. This app is focused only on Rail On Site (ROS), Ponds and Roads. UGP is fully removed. Cost is consolidated in one dedicated Cost Status panel. Week labels include year to support 2024, 2025, 2026 and future history uploads.</div>",
        unsafe_allow_html=True,
    )


