COST_SCOPE_OPTIONS = {
    "all": "All scopes",
    "rail": "Rail On Site (ROS)",
    "ponds": "Ponds",
    "roads": "Roads",
}
COST_SCOPE_ICON = {"all": "▦", "rail": "🚆", "ponds": "💧", "roads": "🛣️"}
COST_METRICS = [
    ("budget", "Budget"),
    ("change_order", "CO"),
    ("forecast", "Forecast"),
    ("vowd", "VOWD"),
    ("forecast_minus_vowd", "ETC"),
    ("potential_exposure", "Potential exposure"),
    ("potential_forecast", "Potential forecast"),
]


def _cost_month_key_from_data(cost_data: Dict[str, Any]) -> str:
    meta = cost_data.get("metadata") or {}
    raw = str(meta.get("cutoff_month") or meta.get("active_date") or meta.get("data_date") or meta.get("report_date") or "").strip()
    if re.match(r"^20\d{2}-\d{2}$", raw):
        return raw
    dt = pd.to_datetime(raw, errors="coerce")
    if pd.notna(dt):
        return pd.Timestamp(dt).strftime("%Y-%m")
    return raw


def _cost_month_ts_from_data(cost_data: Dict[str, Any], label: str = "") -> pd.Timestamp:
    key = _cost_month_key_from_data(cost_data)
    if key:
        if re.match(r"^20\d{2}-\d{2}$", key):
            return pd.to_datetime(key + "-01", errors="coerce")
        return pd.to_datetime(key, errors="coerce")
    return pd.to_datetime(label, errors="coerce")


def _active_cost_report() -> Dict[str, Any]:
    reports = _cost_reports()
    labels = [r.get("label") for r in reports]
    choice = st.session_state.get("monthly_cost_report_choice_portfolio")
    if choice in labels:
        return next((r for r in reports if r.get("label") == choice), reports[-1] if reports else {"data": cached_monthly_cost(), "label": "Active month"})
    return reports[-1] if reports else {"data": cached_monthly_cost(), "label": "Active month"}


def _cost_report_rows(scope_id: str, through_active: bool = True) -> List[Dict[str, Any]]:
    active = _active_cost_report()
    active_ts = _cost_month_ts_from_data(active.get("data") or {}, active.get("label", ""))
    rows: List[Dict[str, Any]] = []
    for report in _cost_reports():
        data = report.get("data") or {}
        if not isinstance(data, dict):
            continue
        ts = report.get("sort_date") or _cost_month_ts_from_data(data, report.get("label", ""))
        if through_active and pd.notna(active_ts) and pd.notna(ts) and ts > active_ts:
            continue
        nums = _cost_numbers(scope_id, data)
        rows.append({
            "label": report.get("label") or _active_month_label_from_cost(data),
            "date": ts,
            "month_key": _cost_month_key_from_data(data),
            "data": data,
            "numbers": nums,
        })
    rows.sort(key=lambda r: (pd.Timestamp.max if pd.isna(r.get("date")) else r.get("date"), str(r.get("label") or "")))
    return rows


def _cost_metric_value(nums: Dict[str, Any], metric: str) -> Optional[float]:
    if metric == "change_order":
        # Reconciled delta from budget to forecast, not the raw CO field.
        budget = _safe_float(nums.get("budget")) or 0.0
        forecast = _safe_float(nums.get("forecast"))
        if forecast is not None:
            return forecast - budget
    if metric == "forecast_minus_vowd":
        return _safe_float(nums.get("forecast_minus_vowd"))
    return _safe_float(nums.get(metric))


def _scope_cost_history_df(scope_id: str) -> pd.DataFrame:
    data_rows = []
    for r in _cost_report_rows(scope_id, through_active=True):
        nums = r.get("numbers") or {}
        row = {"Month": r.get("label"), "Date": r.get("date"), "Month key": r.get("month_key")}
        for metric, label in COST_METRICS:
            row[label] = _cost_metric_value(nums, metric)
        budget = _safe_float(row.get("Budget")) or 0.0
        co = _safe_float(row.get("CO")) or 0.0
        forecast = _safe_float(row.get("Forecast"))
        exposure = _safe_float(row.get("Potential exposure")) or 0.0
        potential_forecast = _safe_float(row.get("Potential forecast"))
        row["Budget + CO check"] = (budget + co) - forecast if forecast is not None else None
        row["Forecast + exposure check"] = ((forecast or 0.0) + exposure) - potential_forecast if potential_forecast is not None else None
        data_rows.append(row)
    return pd.DataFrame(data_rows)


def _portfolio_cost_history_df() -> pd.DataFrame:
    # Align by month and sum all active scopes.
    report_map: Dict[str, Dict[str, Any]] = {}
    active = _active_cost_report()
    active_ts = _cost_month_ts_from_data(active.get("data") or {}, active.get("label", ""))
    for report in _cost_reports():
        data = report.get("data") or {}
        ts = report.get("sort_date") or _cost_month_ts_from_data(data, report.get("label", ""))
        if pd.notna(active_ts) and pd.notna(ts) and ts > active_ts:
            continue
        key = report.get("label") or _active_month_label_from_cost(data)
        report_map[key] = {"label": key, "date": ts, "data": data}
    rows = []
    for key, report in sorted(report_map.items(), key=lambda kv: (pd.Timestamp.max if pd.isna(kv[1].get("date")) else kv[1].get("date"), kv[0])):
        row = {"Month": key, "Date": report.get("date"), "Month key": _cost_month_key_from_data(report.get("data") or {})}
        for metric, label in COST_METRICS:
            total = 0.0
            any_val = False
            for sid in ["rail", "ponds", "roads"]:
                nums = _cost_numbers(sid, report.get("data") or {})
                val = _cost_metric_value(nums, metric)
                if val is not None:
                    total += val
                    any_val = True
            row[label] = total if any_val else None
        budget = _safe_float(row.get("Budget")) or 0.0
        co = _safe_float(row.get("CO")) or 0.0
        forecast = _safe_float(row.get("Forecast"))
        exposure = _safe_float(row.get("Potential exposure")) or 0.0
        potential_forecast = _safe_float(row.get("Potential forecast"))
        row["Budget + CO check"] = (budget + co) - forecast if forecast is not None else None
        row["Forecast + exposure check"] = ((forecast or 0.0) + exposure) - potential_forecast if potential_forecast is not None else None
        rows.append(row)
    return pd.DataFrame(rows)


def _history_for_scope(scope_id: str) -> pd.DataFrame:
    return _portfolio_cost_history_df() if scope_id == "all" else _scope_cost_history_df(scope_id)


def _active_history_row(scope_id: str) -> Dict[str, Any]:
    df = _history_for_scope(scope_id)
    if df.empty:
        return {}
    active_label = (_active_cost_report().get("label") or "")
    match = df[df["Month"] == active_label]
    if not match.empty:
        return match.iloc[-1].to_dict()
    return df.iloc[-1].to_dict()


def _svg_sparkline(points: List[Tuple[str, Optional[float]]], active_label: str) -> str:
    clean = [(label, _safe_float(val)) for label, val in points if _safe_float(val) is not None]
    if len(clean) < 1:
        return "<div style='font-size:.72rem;color:#e5e7eb'>No monthly history loaded.</div>"
    vals = [v for _, v in clean]
    lo, hi = min(vals), max(vals)
    if abs(hi - lo) < 1e-9:
        hi = lo + 1.0
    width, height = 226, 78
    left, right, top, bottom = 16, 12, 12, 18
    usable_w, usable_h = width - left - right, height - top - bottom
    coords = []
    for i, (label, val) in enumerate(clean):
        x = left + (usable_w * i / max(1, len(clean) - 1))
        y = top + usable_h - ((val - lo) / (hi - lo)) * usable_h
        coords.append((label, val, x, y))
    poly = " ".join(f"{x:.1f},{y:.1f}" for _, _, x, y in coords)
    elems = [f"<svg viewBox='0 0 {width} {height}' aria-label='Cost history sparkline'>",
             "<line x1='16' y1='60' x2='214' y2='60' stroke='rgba(255,255,255,.20)' stroke-width='1'/>",
             f"<polyline points='{poly}' fill='none' stroke='#c76df1' stroke-width='2.5' stroke-linecap='round' stroke-linejoin='round'/>" ]
    for label, val, x, y in coords:
        active = label == active_label
        radius = 5.5 if active else 3.5
        fill = "#ffffff" if active else "#c76df1"
        stroke = "#c76df1" if active else "#ffffff"
        elems.append(f"<circle cx='{x:.1f}' cy='{y:.1f}' r='{radius}' fill='{fill}' stroke='{stroke}' stroke-width='2'/>")
        if active:
            elems.append(f"<text x='{x:.1f}' y='{max(10,y-8):.1f}' text-anchor='middle' font-size='9' fill='#fff' font-weight='900'>{html.escape(_fmt_money(val))}</text>")
    elems.append("</svg>")
    return "".join(elems)


def _cost_kpi_hover(scope_id: str, metric_key: str, metric_label: str, active_label: str) -> str:
    df = _history_for_scope(scope_id)
    if df.empty or metric_label not in df.columns:
        return "<div class='cost-kpi-tip'><h4>No history available</h4></div>"
    # Hover uses the latest three months up to the active report; full history is visible below in charts/tables.
    if active_label in set(df["Month"].astype(str)):
        active_idx = df.index[df["Month"].astype(str) == active_label].tolist()[-1]
        subset = df.loc[:active_idx].tail(3)
    else:
        subset = df.tail(3)
    points = [(str(r["Month"]), r.get(metric_label)) for _, r in subset.iterrows()]
    svg = _svg_sparkline(points, active_label)
    rows = []
    for label, val in points:
        cls = "hist-row active" if label == active_label else "hist-row"
        rows.append(f"<div class='{cls}'><span>{_html(label)}</span><b>{_html(_fmt_money(val))}</b></div>")
    return f"<div class='cost-kpi-tip'><h4>{_html(metric_label)} - recent history</h4>{svg}<div class='active-line'>Actual selected month highlighted.</div>{''.join(rows)}</div>"


def _render_cost_kpi_cards(scope_id: str) -> None:
    active = _active_cost_report()
    active_label = active.get("label") or _active_month_label_from_cost(active.get("data") or {})
    row = _active_history_row(scope_id)
    if not row:
        st.info("No cost KPI data loaded for this selection.")
        return
    cards = []
    for metric_key, label in COST_METRICS:
        value = row.get(label)
        cls = "primary" if label in {"Forecast", "ETC"} else ("bad" if label in {"Potential exposure", "Potential forecast"} else ("warn" if label == "CO" else ""))
        tip = _cost_kpi_hover(scope_id, metric_key, label, active_label)
        sub = "selected month" if label not in {"ETC"} else "Forecast minus VOWD"
        cards.append(
            f"<div class='cost-kpi-card {cls}'>"
            f"<div class='cost-kpi-label'>{_html(label)}</div>"
            f"<div class='cost-kpi-value'>{_html(_fmt_money(value))}</div>"
            f"<div class='cost-kpi-sub'>{_html(sub)}</div>"
            f"{tip}</div>"
        )
    st.markdown("<div class='cost-kpi-grid'>" + "".join(cards) + "</div>", unsafe_allow_html=True)


def _cost_waterfall_figure_v24(scope_id: str, cost_data: Optional[Dict[str, Any]] = None, title: str = "Cost waterfall") -> go.Figure:
    cost_data = cost_data or (_active_cost_report().get("data") or cached_monthly_cost())
    if scope_id == "all":
        row = _active_history_row("all")
        budget = _safe_float(row.get("Budget")) or 0.0
        co = _safe_float(row.get("CO")) or 0.0
        forecast = _safe_float(row.get("Forecast")) if row.get("Forecast") is not None else budget + co
        exposure = _safe_float(row.get("Potential exposure")) or 0.0
        potential_forecast = _safe_float(row.get("Potential forecast")) if row.get("Potential forecast") is not None else (forecast or 0) + exposure
    else:
        nums = _cost_numbers(scope_id, cost_data)
        budget = _safe_float(nums.get("budget")) or 0.0
        forecast = _safe_float(nums.get("forecast"))
        co = (forecast - budget) if forecast is not None else (_safe_float(nums.get("change_order")) or 0.0)
        forecast = forecast if forecast is not None else budget + co
        exposure = _safe_float(nums.get("potential_exposure")) or 0.0
        potential_forecast = _safe_float(nums.get("potential_forecast")) if nums.get("potential_forecast") is not None else forecast + exposure
    labels = ["Budget", "CO", "Forecast", "Potential exposure", "Potential forecast"]
    y_vals = [budget, co, forecast, exposure, potential_forecast]
    running = [budget, budget + co, forecast, forecast + exposure, potential_forecast]
    measures = ["absolute", "relative", "total", "relative", "total"]
    active_label = _active_cost_report().get("label") or "Active month"
    custom = []
    df = _history_for_scope(scope_id)
    for label, val, run in zip(labels, y_vals, running):
        hist = []
        if not df.empty and label in df.columns:
            sub = df[["Month", label]].tail(3)
            hist = [f"{r['Month']}: {_fmt_money(r[label])}" for _, r in sub.iterrows()]
        custom.append([label, _fmt_money_full(val), _fmt_money_full(run), active_label, "<br>".join(hist)])
    fig = go.Figure(go.Waterfall(
        x=labels,
        y=y_vals,
        measure=measures,
        text=[_fmt_money(v) for v in y_vals],
        textposition="outside",
        connector={"line": {"color": "#9aa1ad", "width": 1}},
        increasing={"marker": {"color": "#007a45"}},
        decreasing={"marker": {"color": "#c73535"}},
        totals={"marker": {"color": "#c76df1"}},
        customdata=custom,
        hovertemplate=(
            "<b>%{customdata[0]}</b><br>"
            "Active month: %{customdata[3]}<br>"
            "Step value: %{customdata[1]}<br>"
            "Cost position after step: %{customdata[2]}<br><br>"
            "<b>Recent history</b><br>%{customdata[4]}<extra></extra>"
        ),
    ))
    fig.update_layout(
        title={"text": title, "x": 0.02, "xanchor": "left", "font": {"size": 18}},
        height=410,
        margin=dict(l=34, r=24, t=62, b=78),
        paper_bgcolor="rgba(0,0,0,0)",
        plot_bgcolor="rgba(0,0,0,0)",
        yaxis_title="EUR",
        showlegend=False,
        hovermode="closest",
    )
    fig.update_xaxes(tickangle=-22)
    return fig


def _cost_history_trend_figure(scope_id: str) -> go.Figure:
    df = _history_for_scope(scope_id)
    fig = go.Figure()
    if df.empty:
        return fig
    metrics = ["Budget", "Forecast", "VOWD", "ETC", "Potential exposure", "Potential forecast"]
    active_label = _active_cost_report().get("label") or ""
    for metric in metrics:
        if metric not in df.columns:
            continue
        custom = []
        for _, r in df.iterrows():
            custom.append([r.get("Month"), _fmt_money_full(r.get(metric)), "Active month" if str(r.get("Month")) == active_label else "History"])
        fig.add_trace(go.Scatter(
            x=df["Month"],
            y=df[metric],
            mode="lines+markers",
            name=metric,
            customdata=custom,
            hovertemplate="<b>%{fullData.name}</b><br>Month: %{customdata[0]}<br>Value: %{customdata[1]}<br>%{customdata[2]}<extra></extra>",
        ))
    if active_label in set(df["Month"].astype(str)):
        fig.add_vline(x=active_label, line_width=2, line_dash="dash", line_color="#111111")
    # Overlay larger diamond markers for active month values.
    active_df = df[df["Month"].astype(str) == active_label]
    if not active_df.empty:
        for metric in metrics:
            if metric in active_df.columns:
                fig.add_trace(go.Scatter(x=[active_label], y=[active_df.iloc[-1][metric]], mode="markers", marker_symbol="diamond-open", marker_size=13, marker_line_width=2, name=f"{metric} active", showlegend=False, hoverinfo="skip"))
    fig.update_layout(
        title={"text": "Cost history trend", "x": 0.02, "font": {"size": 18}},
        height=430,
        margin=dict(l=40, r=26, t=62, b=70),
        paper_bgcolor="rgba(0,0,0,0)",
        plot_bgcolor="rgba(0,0,0,0)",
        yaxis_title="EUR",
        xaxis_title="Monthly report",
        legend_title="Metric",
        hovermode="x unified",
    )
    fig.update_xaxes(tickangle=-30)
    return fig


def _cost_scope_comparison_figure() -> go.Figure:
    active = _active_cost_report()
    data = active.get("data") or cached_monthly_cost()
    rows = []
    for sid, label in [("rail", "Rail On Site (ROS)"), ("ponds", "Ponds"), ("roads", "Roads")]:
        nums = _cost_numbers(sid, data)
        rows.append({"Scope": label, "Forecast": _safe_float(nums.get("forecast")), "VOWD": _safe_float(nums.get("vowd")), "ETC": _safe_float(nums.get("forecast_minus_vowd")), "Potential forecast": _safe_float(nums.get("potential_forecast"))})
    df = pd.DataFrame(rows)
    fig = go.Figure()
    for metric in ["Forecast", "VOWD", "ETC", "Potential forecast"]:
        fig.add_trace(go.Bar(x=df["Scope"], y=df[metric], name=metric, text=[_fmt_money(v) for v in df[metric]], textposition="outside", hovertemplate=f"<b>{metric}</b><br>Scope: %{{x}}<br>Value: %{{y:,.0f}} EUR<extra></extra>"))
    fig.update_layout(
        title={"text": "Active-month cost position by scope", "x": 0.02, "font": {"size": 18}},
        height=430,
        margin=dict(l=40, r=26, t=62, b=70),
        barmode="group",
        paper_bgcolor="rgba(0,0,0,0)",
        plot_bgcolor="rgba(0,0,0,0)",
        yaxis_title="EUR",
        xaxis_title="",
        legend_title="Metric",
    )
    return fig


def _cost_health_cards(scope_id: str) -> None:
    row = _active_history_row(scope_id)
    if not row:
        return
    check1 = _safe_float(row.get("Budget + CO check"))
    check2 = _safe_float(row.get("Forecast + exposure check"))
    forecast = _safe_float(row.get("Forecast"))
    budget = _safe_float(row.get("Budget"))
    exposure = _safe_float(row.get("Potential exposure"))
    etc = _safe_float(row.get("ETC"))
    vs_budget = (forecast - budget) if forecast is not None and budget is not None else None
    exp_pct = (exposure / forecast * 100.0) if exposure is not None and forecast not in (None, 0) else None
    items = [
        ("Forecast vs budget", vs_budget, "bad" if (vs_budget or 0) > 0 else "good"),
        ("Exposure as % forecast", f"{exp_pct:.1f}%" if exp_pct is not None else "N/A", "warn" if (exp_pct or 0) > 15 else "good"),
        ("ETC", _fmt_money(etc), "primary"),
        ("Cost check", "OK" if abs(check1 or 0) < 1 and abs(check2 or 0) < 1 else "Check", "good" if abs(check1 or 0) < 1 and abs(check2 or 0) < 1 else "bad"),
    ]
    html_cards = []
    for label, value, cls in items:
        val = _fmt_money(value) if isinstance(value, (int, float)) else str(value)
        html_cards.append(f"<div class='cost-health-card {cls}'><span>{_html(label)}</span><b>{_html(val)}</b></div>")
    st.markdown("<div class='cost-health-row'>" + "".join(html_cards) + "</div>", unsafe_allow_html=True)


def _cost_history_table_rows(scope_id: str) -> List[List[Any]]:
    df = _history_for_scope(scope_id)
    if df.empty:
        return []
    rows = []
    for _, r in df.iterrows():
        rows.append([
            r.get("Month"),
            _fmt_money_full(r.get("Budget")),
            _fmt_money_full(r.get("CO")),
            _fmt_money_full(r.get("Forecast")),
            _fmt_money_full(r.get("VOWD")),
            _fmt_money_full(r.get("ETC")),
            _fmt_money_full(r.get("Potential exposure")),
            _fmt_money_full(r.get("Potential forecast")),
            _fmt_money_full(r.get("Budget + CO check")),
            _fmt_money_full(r.get("Forecast + exposure check")),
        ])
    return rows


def _active_scope_summary_rows() -> List[List[Any]]:
    data = _active_cost_report().get("data") or cached_monthly_cost()
    rows = []
    for sid, label in [("rail", "Rail On Site (ROS)"), ("ponds", "Ponds"), ("roads", "Roads")]:
        nums = _cost_numbers(sid, data)
        rows.append([
            label,
            _fmt_money_full(nums.get("budget")),
            _fmt_money_full(_co_reconciliation_value(sid, data) if "_co_reconciliation_value" in globals() else (_safe_float(nums.get("forecast") or 0) - _safe_float(nums.get("budget") or 0))),
            _fmt_money_full(nums.get("forecast")),
            _fmt_money_full(nums.get("vowd")),
            _fmt_money_full(nums.get("forecast_minus_vowd")),
            _fmt_money_full(nums.get("potential_exposure")),
            _fmt_money_full(nums.get("potential_forecast")),
        ])
    return rows


def _cost_driver_rows(scope_id: str) -> List[List[Any]]:
    cost = _active_cost_report().get("data") or cached_monthly_cost()
    pkg_rows = _scope_package_rows(scope_id, cost)
    # Keep the driver table concise but useful; remove blank columns in copyable component.
    return pkg_rows or []


def _cost_exposure_rows(scope_id: str) -> List[List[Any]]:
    cost = _active_cost_report().get("data") or cached_monthly_cost()
    exposures = _cost_exposures(scope_id, cost)
    rows = []
    for e in exposures:
        rows.append([
            e.get("item_id"),
            e.get("package"),
            _fmt_money_full(e.get("amount")),
            e.get("criticality") or "",
            e.get("type") or "",
            e.get("description") or e.get("main_description") or "",
            e.get("pm") or "",
            _fmt_date_short(e.get("award_date")),
        ])
    return rows


def render_cost_panel(bundle: Dict[str, Any], profiles: Dict[str, Any], selected_year: int, selected_week: int, current_date: Optional[pd.Timestamp] = None) -> None:
    active_report = _active_cost_report()
    active_month = active_report.get("label") or _active_month_label_from_cost(active_report.get("data") or {})
    meta = (active_report.get("data") or {}).get("metadata") or {}
    st.markdown(
        "<div class='cost-control-hero'>"
        "<h2>Cost Status</h2>"
        "<p>Single cost-control section for Rail On Site (ROS), Ponds and Roads. Select a scope to review active-month KPIs, historical trends, reconciliation, package drivers and potential exposure.</p>"
        "</div>",
        unsafe_allow_html=True,
    )
    st.markdown(f"<div class='cost-selector-row'><span class='cost-pill'>Active month: {_html(active_month)}</span><span class='cost-pill'>Currency: {_html(meta.get('currency') or 'EUR')}</span><span class='cost-pill'>Loaded cost reports: {len(_cost_reports())}</span></div>", unsafe_allow_html=True)
    labels = list(COST_SCOPE_OPTIONS.values())
    label_to_id = {v: k for k, v in COST_SCOPE_OPTIONS.items()}
    if st.session_state.get("cost_scope_visual_selector") not in labels:
        st.session_state["cost_scope_visual_selector"] = "All scopes"
    selected_scope_label = st.selectbox("Scope to visualize", labels, key="cost_scope_visual_selector", help="Select the cost view scope. Executive and scope panels stay focused on progress, actions and milestones; cost is consolidated here.")
    scope_id = label_to_id.get(selected_scope_label, "all")
    st.markdown(f"<div class='section-title'>{_html(COST_SCOPE_ICON.get(scope_id,'▦'))} {_html(selected_scope_label)} - cost control dashboard</div>", unsafe_allow_html=True)
    _render_cost_kpi_cards(scope_id)
    _cost_health_cards(scope_id)
    if scope_id == "all":
        left, right = st.columns([1.05, 1.35])
        with left:
            st.markdown("<div class='cost-chart-card'><h3>Active month comparison</h3><p>Forecast, VOWD, ETC and potential forecast by scope.</p>", unsafe_allow_html=True)
            st.plotly_chart(_cost_scope_comparison_figure(), use_container_width=True)
            st.markdown("</div>", unsafe_allow_html=True)
        with right:
            st.markdown("<div class='cost-chart-card'><h3>Portfolio historical trend</h3><p>All loaded monthly cost reports up to the selected active month.</p>", unsafe_allow_html=True)
            st.plotly_chart(_cost_history_trend_figure("all"), use_container_width=True)
            st.markdown("</div>", unsafe_allow_html=True)
        st.markdown("<div class='cost-full-card'><h3>Active-month scope summary</h3>", unsafe_allow_html=True)
        _copyable_table_component(["Scope", "Budget", "CO", "Forecast", "VOWD", "ETC", "Potential exposure", "Potential forecast"], _active_scope_summary_rows(), key_prefix="cost_scope_summary_v24")
        st.markdown("</div>", unsafe_allow_html=True)
    else:
        left, right = st.columns([1.0, 1.35])
        with left:
            st.markdown("<div class='cost-chart-card'><h3>Waterfall / candle bar</h3><p>Budget + CO = Forecast; Forecast + potential exposure = Potential forecast.</p>", unsafe_allow_html=True)
            st.plotly_chart(_cost_waterfall_figure_v24(scope_id, active_report.get("data"), title=f"{selected_scope_label} waterfall"), use_container_width=True)
            st.markdown("</div>", unsafe_allow_html=True)
        with right:
            st.markdown("<div class='cost-chart-card'><h3>Historical cost trend</h3><p>All loaded monthly cost reports, with the active month highlighted.</p>", unsafe_allow_html=True)
            st.plotly_chart(_cost_history_trend_figure(scope_id), use_container_width=True)
            st.markdown("</div>", unsafe_allow_html=True)
        st.markdown("<div class='cost-full-card'><h3>Monthly history</h3>", unsafe_allow_html=True)
        _copyable_table_component(["Month", "Budget", "CO", "Forecast", "VOWD", "ETC", "Potential exposure", "Potential forecast", "Budget + CO check", "Forecast + exposure check"], _cost_history_table_rows(scope_id), key_prefix=f"cost_hist_{scope_id}_v24")
        st.markdown("</div>", unsafe_allow_html=True)
        drivers = _cost_driver_rows(scope_id)
        if drivers:
            st.markdown("<div class='cost-full-card'><h3>Package drivers - active month</h3>", unsafe_allow_html=True)
            _copyable_table_component(["Package", "Description", "Supplier", "Budget", "CO", "Forecast", "Exposure", "Potential forecast", "Driver / note"], drivers, numeric_cols={3,4,5,6,7}, key_prefix=f"cost_drivers_{scope_id}_v24")
            st.markdown("</div>", unsafe_allow_html=True)
        exposures = _cost_exposure_rows(scope_id)
        if exposures:
            st.markdown("<div class='cost-full-card'><h3>Potential exposure / O&V items - active month</h3>", unsafe_allow_html=True)
            _copyable_table_component(["Item", "Package", "Amount", "Criticality", "Type", "Description", "Responsible", "Expected / award date"], exposures, numeric_cols={2}, key_prefix=f"cost_exposures_{scope_id}_v24")
            st.markdown("</div>", unsafe_allow_html=True)
    st.markdown("<div class='cost-full-card'><h3>All monthly cost history - selected view</h3>", unsafe_allow_html=True)
    _copyable_table_component(["Month", "Budget", "CO", "Forecast", "VOWD", "ETC", "Potential exposure", "Potential forecast", "Budget + CO check", "Forecast + exposure check"], _cost_history_table_rows(scope_id), key_prefix=f"cost_full_history_{scope_id}_v24")
    st.markdown("</div>", unsafe_allow_html=True)


def render_scope_matrix(records: List[Dict[str, Any]], selected_year: int, selected_week: int) -> None:
    st.markdown("<div class='section-title'>Executive control matrix</div>", unsafe_allow_html=True)
    order = {"rail": 0, "ponds": 1, "roads": 2}
    records = sorted([_with_display_scope(r) for r in records if r.get("scope_id") in order], key=lambda r: order.get(r.get("scope_id"), 99))
    cols = st.columns(3)
    for col, rec in zip(cols, records):
        with col:
            construction_actual = rec.get("construction_actual")
            construction_forecast = rec.get("construction_forecast") if rec.get("construction_forecast") is not None else construction_actual
            construction_dev = rec.get("construction_deviation")
            if construction_dev is None and construction_actual is not None and construction_forecast is not None:
                construction_dev = construction_actual - construction_forecast
            engineering_actual = rec.get("engineering_actual")
            engineering_forecast = rec.get("engineering_forecast") if rec.get("engineering_forecast") is not None else engineering_actual
            engineering_dev = rec.get("engineering_deviation")
            if engineering_dev is None and engineering_actual is not None and engineering_forecast is not None:
                engineering_dev = engineering_actual - engineering_forecast
            construction_etc = _baseline_etc_for_scope(rec["scope_id"], selected_year, selected_week, mode="final")
            engineering_etc = rec.get("engineering_etc") or _baseline_etc_for_scope(rec["scope_id"], selected_year, selected_week, mode="next")
            driver = rec.get("status") or rec.get("insight") or "Monitor"
            icon = SCOPE_ICON.get(rec["scope_id"], COST_SCOPE_ICON.get(rec["scope_id"], "●"))
            html_block = (
                "<div class='matrix-col'>"
                "<div class='matrix-head'>"
                f"<h3><span class='scope-icon'>{icon}</span>{_html(rec['name'])}</h3>"
                f"<span class='status-badge'>{_html(driver)}</span>"
                "</div>"
                f"{progress_bar_html('Construction progress', construction_actual, construction_forecast, construction_dev, construction_etc)}"
                f"{progress_bar_html('Engineering progress', engineering_actual, engineering_forecast, engineering_dev, engineering_etc)}"
                f"<div class='next-fc'><b>Next week FC</b>{_html(rec.get('next_week_fc') or 'Not published in selected-week data')}</div>"
                "<div class='gate-row'>"
                f"{_gate_pill_html('Open quality gates', len(rec.get('quality_items', [])), rec.get('quality_items', []))}"
                f"{_gate_pill_html('Open engineering gates', len(rec.get('engineering_items', [])), rec.get('engineering_items', []))}"
                "</div>"
                "</div>"
            )
            st.markdown(html_block, unsafe_allow_html=True)


def render_executive_overview(bundle: Dict[str, Any], profiles: Dict[str, Any], selected_year: int, selected_week: int, current_date: Optional[pd.Timestamp] = None) -> None:
    records = build_scope_records(bundle, profiles, selected_year, selected_week, scopes=CONTROL_SCOPES)
    selected_label = period_display(selected_year, selected_week)
    cutoff = current_date if current_date is not None else selected_cutoff_date(bundle)
    render_scope_matrix(records, selected_year, selected_week)
    render_executive_priority_delayed_near_table(records, selected_label, selected_year, selected_week, current_date=cutoff)
    render_milestone_timeline(records, title="Milestones", selected_year=selected_year, selected_week=selected_week, current_date=cutoff)


def render_scope_sections(rec: Dict[str, Any], selected_year: int, selected_week: int, current_date: Optional[pd.Timestamp] = None) -> None:
    rec = _with_display_scope(rec)
    selected_label = period_display(selected_year, selected_week)
    st.markdown(f"<div class='scope-banner'><h2><span class='scope-icon'>{SCOPE_ICON.get(rec.get('scope_id'), '')}</span>{_html(rec['full_name'])} control panel</h2><p>{_html(compact_text(rec.get('insight', ''), 420))}</p></div>", unsafe_allow_html=True)
    col1, col2 = st.columns([1, 1])
    with col1:
        render_progress_gauge(rec)
    with col2:
        render_progress_trend(rec, selected_year, selected_week)
    render_milestone_timeline([rec], scope_filter=rec["scope_id"], title="Milestones", selected_year=selected_year, selected_week=selected_week, current_date=current_date)
    render_scope_baseline_section(rec, selected_year, selected_week)
    render_action_table(f"{rec['name']} priority & high-exposure items - {selected_label}", rec.get("priority_items", []), selected_year, selected_week, rec.get("default_responsible", "TBC"), max_items=999, current_date=current_date)
    st.markdown("<div class='section-title'>Engineering / design</div>", unsafe_allow_html=True)
    e1, e2 = st.columns([1, 1])
    with e1:
        render_engineering_gauge(rec, selected_year, selected_week)
    with e2:
        render_engineering_trend(rec, selected_year, selected_week)
    render_action_table("", rec.get("engineering_items", []), selected_year, selected_week, rec.get("default_responsible", "TBC"), max_items=999, current_date=current_date)
    st.markdown("<div class='section-title'>Quality / completion</div>", unsafe_allow_html=True)
    render_action_table("", rec.get("quality_items", []), selected_year, selected_week, rec.get("default_responsible", "TBC"), max_items=999, current_date=current_date)
    st.markdown("<div class='section-title'>Interface / commercial controls</div>", unsafe_allow_html=True)
    render_action_table("", rec.get("interface_items", []), selected_year, selected_week, rec.get("default_responsible", "TBC"), max_items=999, current_date=current_date)


def render_sidebar(bundle: Dict[str, Any]) -> Tuple[str, int, int]:
    logo_src = logo_data_uri()
    if logo_src:
        st.sidebar.markdown(f"<div class='sidebar-logo'><img src='{logo_src}'><span>Scope controls</span></div>", unsafe_allow_html=True)
    st.sidebar.title("Control settings")
    st.sidebar.markdown("<div class='subsection-title'>Selectors</div>", unsafe_allow_html=True)
    periods = available_periods(st.session_state["bundle"])
    if not periods:
        selected_year, selected_week = (2026, 0)
    else:
        period_labels = [period_display(y, w) for y, w in periods]
        latest_y, latest_w = latest_period(st.session_state["bundle"])
        default_label = period_display(latest_y, latest_w)
        if default_label not in period_labels:
            default_label = period_labels[-1]
        if st.session_state.get("week_selector_value") not in period_labels:
            st.session_state["week_selector_value"] = default_label
        selected_label = st.sidebar.selectbox(
            "Week to display",
            period_labels,
            key="week_selector_value",
            help="Select any loaded report week manually. The dashboard uses data up to the selected week and item lists from the selected week.",
        )
        current_idx = period_labels.index(selected_label)
        st.sidebar.caption(f"Selected week {current_idx + 1} of {len(period_labels)}")
        selected_year, selected_week = periods[current_idx]

    cost_reports = _cost_reports()
    cost_labels = [r["label"] for r in cost_reports if r.get("label")]
    if cost_labels:
        if st.session_state.get("monthly_cost_report_choice_portfolio") not in cost_labels:
            st.session_state["monthly_cost_report_choice_portfolio"] = cost_labels[-1]
        st.sidebar.selectbox("Monthly report to use", cost_labels, key="monthly_cost_report_choice_portfolio")
        st.sidebar.markdown(f"<div class='cost-active-pill'>Active month: {_html(st.session_state['monthly_cost_report_choice_portfolio'])}</div>", unsafe_allow_html=True)
    baseline_reports = _baseline_reports()
    bl_labels = [r["label"] for r in baseline_reports if r.get("label")]
    if bl_labels:
        if st.session_state.get("baseline_choice") not in bl_labels:
            st.session_state["baseline_choice"] = bl_labels[-1]
        st.sidebar.selectbox("Baseline to use", bl_labels, key="baseline_choice")

    st.sidebar.markdown("---")
    st.sidebar.markdown("<div class='subsection-title'>Panel</div>", unsafe_allow_html=True)
    visible_panels = ["Executive overview", COST_PANEL_LABEL, "Rail On Site (ROS)", "Ponds", "Roads"]
    if "panel_choice" not in st.session_state or st.session_state.get("panel_choice") not in visible_panels:
        st.session_state["panel_choice"] = visible_panels[0]
    icons = {"Executive overview": "▦", COST_PANEL_LABEL: "€", "Rail On Site (ROS)": "🚆", "Ponds": "💧", "Roads": "🛣️"}
    for label in visible_panels:
        if st.sidebar.button(f"{icons.get(label, '•')} {label}", key=f"nav_v24_{label}", use_container_width=True):
            st.session_state["panel_choice"] = label
    st.sidebar.markdown(f"<div class='nav-active'>Current panel: {_html(st.session_state['panel_choice'])}</div>", unsafe_allow_html=True)
    st.sidebar.caption(f"Loaded {latest_period_label(st.session_state['bundle'])} - {source_count(st.session_state['bundle'])} source reports")
    st.sidebar.markdown("<div class='nav-hint'>Selectors first, panel second, uploads below. Cost is consolidated in one Cost Status panel.</div>", unsafe_allow_html=True)

    st.sidebar.markdown("---")
    st.sidebar.markdown("<div class='subsection-title'>Upload / refresh</div>", unsafe_allow_html=True)
    uploaded_weekly = st.sidebar.file_uploader(
        "Upload new weekly report PDF/PPTX",
        type=["pdf", "pptx"],
        accept_multiple_files=True,
        key="weekly_upload_v24",
        help="Upload one or more weekly reports. The parser merges new report weeks into the current session.",
    )
    if uploaded_weekly:
        key = _upload_list_hash(uploaded_weekly)
        if key != st.session_state.get("last_weekly_upload_key_v24"):
            with st.spinner("Parsing uploaded weekly report(s) and refreshing the control center..."):
                try:
                    incoming = parse_uploaded_reports(uploaded_weekly)
                    st.session_state["bundle"] = merge_bundles(st.session_state["bundle"], incoming)
                    st.session_state["last_weekly_upload_key_v24"] = key
                    st.sidebar.success(f"{len(uploaded_weekly)} weekly report(s) parsed and loaded.")
                except Exception as exc:
                    st.sidebar.error(f"Could not parse weekly upload: {exc}")
    uploaded_cost_reports = st.sidebar.file_uploader(
        "Upload monthly cost report XLSX",
        type=["xlsx"],
        accept_multiple_files=True,
        key="cost_upload_v24",
        help="Upload one or more monthly cost reports. Each report is normalized, stored and added to the monthly-report selector.",
    )
    if uploaded_cost_reports:
        key = _upload_list_hash(uploaded_cost_reports)
        if key != st.session_state.get("last_cost_upload_key_v24"):
            loaded = 0
            errors: List[str] = []
            for uploaded in uploaded_cost_reports:
                try:
                    _register_uploaded_cost_report(uploaded)
                    loaded += 1
                except Exception as exc:
                    errors.append(f"{uploaded.name}: {exc}")
            st.session_state["last_cost_upload_key_v24"] = key
            try:
                cached_monthly_cost_reports.clear()
            except Exception:
                pass
            if loaded:
                refreshed = _cost_reports()
                if refreshed:
                    st.session_state["monthly_cost_report_choice_portfolio"] = refreshed[-1]["label"]
                st.sidebar.success(f"{loaded} cost report(s) uploaded and registered.")
            for msg in errors:
                st.sidebar.error(f"Could not parse cost report - {msg}")
            if loaded:
                _safe_rerun()
    uploaded_baselines = st.sidebar.file_uploader(
        "Upload schedule baseline PDF",
        type=["pdf"],
        accept_multiple_files=True,
        key="baseline_upload_v24",
        help="Upload one or more baseline PDFs. Parsed baselines are added to the baseline selector.",
    )
    if uploaded_baselines:
        key = _upload_list_hash(uploaded_baselines)
        if key != st.session_state.get("last_baseline_upload_key_v24"):
            loaded = 0
            errors: List[str] = []
            for uploaded in uploaded_baselines:
                try:
                    _register_uploaded_baseline(uploaded)
                    loaded += 1
                except Exception as exc:
                    errors.append(f"{uploaded.name}: {exc}")
            st.session_state["last_baseline_upload_key_v24"] = key
            try:
                cached_baseline_schedules.clear()
            except Exception:
                pass
            if loaded:
                refreshed = _baseline_reports()
                if refreshed:
                    st.session_state["baseline_choice"] = refreshed[-1]["label"]
                st.sidebar.success(f"{loaded} baseline file(s) uploaded and registered.")
            for msg in errors:
                st.sidebar.error(f"Could not parse baseline - {msg}")
            if loaded:
                _safe_rerun()
    if st.sidebar.button("Save current session data", use_container_width=True):
        save_bundle(st.session_state["bundle"], DATA_PATH)
        try:
            cached_bundle.clear()
        except Exception:
            pass
        st.sidebar.success("Saved weekly data to data/weekly_data_bundle.json")
    return st.session_state["panel_choice"], int(selected_year), int(selected_week)


def main() -> None:
    render_loading_overlay()
    if "bundle" not in st.session_state:
        st.session_state["bundle"] = cached_bundle(DATA_PATH.stat().st_mtime_ns)
    profiles = cached_profiles()
    panel_choice, selected_year, selected_week = render_sidebar(st.session_state["bundle"])
    view_bundle = filter_bundle_until(st.session_state["bundle"], selected_year, selected_week)
    selected_label = period_display(selected_year, selected_week)
    render_header(view_bundle, selected_label)
    selected_cutoff = selected_cutoff_date(view_bundle)
    if panel_choice == "Executive overview":
        render_executive_overview(st.session_state["bundle"], profiles, selected_year, selected_week, current_date=selected_cutoff)
    elif panel_choice == COST_PANEL_LABEL:
        render_cost_panel(st.session_state["bundle"], profiles, selected_year, selected_week, current_date=selected_cutoff)
    else:
        render_scope_panel(st.session_state["bundle"], profiles, SCOPE_PANEL_MAP[panel_choice], selected_year, selected_week, current_date=selected_cutoff)
    st.markdown(
        "<div class='footer-note'>Data source: uploaded weekly reports, the Rail On Site May 2026 reference presentation, BL CC E006 schedule baseline, Budget Forecast Roads-Rail-Ponds reference presentation, and selectable monthly cost reports. This app is focused only on Rail On Site (ROS), Ponds and Roads. Week labels include year to support 2024, 2025, 2026 and future history uploads. The upload parser is tuned to the current weekly-report template; major layout changes may require updating scripts/extract_weekly_data.py.</div>",
        unsafe_allow_html=True,
    )


