def _cost_month_ts_v24(report: Dict[str, Any], label: str = "") -> pd.Timestamp:
    data = report.get("data", report) if isinstance(report, dict) else {}
    meta = data.get("metadata") if isinstance(data, dict) else {}
    raw = ""
    if isinstance(meta, dict):
        raw = meta.get("cutoff_month") or meta.get("active_date") or meta.get("data_date") or meta.get("report_date") or ""
    raw = str(raw or label or "").strip()
    if re.match(r"^20\d{2}-\d{2}$", raw):
        raw = raw + "-01"
    ts = pd.to_datetime(raw, errors="coerce")
    if pd.isna(ts):
        # Label is usually YYYY-Month.
        ts = pd.to_datetime(str(label or "").replace("_", "-"), errors="coerce")
    return pd.Timestamp(ts) if pd.notna(ts) else pd.NaT


def _cost_reports() -> List[Dict[str, Any]]:
    pack = cached_monthly_cost_reports()
    raw_reports = pack.get("reports", {}) if isinstance(pack, dict) else {}
    labels_map = pack.get("labels", {}) if isinstance(pack, dict) else {}
    reports: List[Dict[str, Any]] = []
    for rid, report in (raw_reports or {}).items():
        if not isinstance(report, dict):
            continue
        label = _active_month_label_from_cost(report)
        if not label or label == "Active month":
            raw_label = labels_map.get(rid, rid)
            label = str(raw_label).split(" - ")[0]
        ts = _cost_month_ts_v24(report, label)
        reports.append({"id": rid, "label": label, "active_date": label, "sort_date": ts, "data": report})
    if not reports:
        fallback = cached_monthly_cost()
        label = _active_month_label_from_cost(fallback)
        reports.append({"id": "active", "label": label, "active_date": label, "sort_date": _cost_month_ts_v24(fallback, label), "data": fallback})
    # One visible item per month label; keep the latest registered object for duplicate labels.
    by_label: Dict[str, Dict[str, Any]] = {}
    for r in reports:
        by_label[str(r.get("label"))] = r
    reports = list(by_label.values())
    reports.sort(key=lambda r: (pd.Timestamp.max if pd.isna(r.get("sort_date")) else r.get("sort_date"), str(r.get("label"))))
    return reports


def _cost_report_by_label_v24(label: str) -> Dict[str, Any]:
    reports = _cost_reports()
    if not reports:
        return cached_monthly_cost()
    for r in reports:
        if r.get("label") == label:
            data = r.get("data")
            return data if isinstance(data, dict) else cached_monthly_cost()
    data = reports[-1].get("data")
    return data if isinstance(data, dict) else cached_monthly_cost()


def _selected_cost_label_v24() -> str:
    reports = _cost_reports()
    labels = [r.get("label") for r in reports if r.get("label")]
    if not labels:
        return ""
    selected = st.session_state.get("monthly_cost_report_choice_portfolio")
    if selected not in labels:
        selected = labels[-1]
        st.session_state["monthly_cost_report_choice_portfolio"] = selected
    return str(selected)


def _cost_numbers_clean_v24(scope_id: str, cost_data: Dict[str, Any]) -> Dict[str, Optional[float]]:
    nums = _cost_numbers(scope_id, cost_data)
    budget = _safe_float(nums.get("budget"))
    forecast = _safe_float(nums.get("forecast"))
    vowd = _safe_float(nums.get("vowd"))
    exposure = _safe_float(nums.get("potential_exposure"))
    potential_forecast = _safe_float(nums.get("potential_forecast"))
    if forecast is not None and budget is not None:
        co = forecast - budget
    else:
        co = _safe_float(nums.get("change_order"))
    if potential_forecast is None and forecast is not None:
        potential_forecast = forecast + (exposure or 0.0)
    if exposure is None and potential_forecast is not None and forecast is not None:
        exposure = potential_forecast - forecast
    etc = forecast - vowd if forecast is not None and vowd is not None else _safe_float(nums.get("forecast_minus_vowd"))
    return {
        "budget": budget,
        "change_order": co,
        "forecast": forecast,
        "vowd": vowd,
        "etc": etc,
        "potential_exposure": exposure,
        "potential_forecast": potential_forecast,
        "forecast_deviation": (forecast - budget) if forecast is not None and budget is not None else None,
        "potential_deviation": (potential_forecast - budget) if potential_forecast is not None and budget is not None else None,
    }


def _cost_scope_numbers_v24(scope_id: str, cost_data: Dict[str, Any]) -> Dict[str, Optional[float]]:
    if scope_id != "portfolio":
        return _cost_numbers_clean_v24(scope_id, cost_data)
    totals: Dict[str, float] = {k: 0.0 for k in ["budget", "change_order", "forecast", "vowd", "etc", "potential_exposure", "potential_forecast", "forecast_deviation", "potential_deviation"]}
    seen: Dict[str, bool] = {k: False for k in totals}
    for sid in ["rail", "ponds", "roads"]:
        nums = _cost_numbers_clean_v24(sid, cost_data)
        for k, v in nums.items():
            fv = _safe_float(v)
            if fv is not None:
                totals[k] += fv
                seen[k] = True
    return {k: (totals[k] if seen[k] else None) for k in totals}


def _cost_history_df_v24(scope_id: str) -> pd.DataFrame:
    rows = []
    for report in _cost_reports():
        label = str(report.get("label") or "")
        data = report.get("data") if isinstance(report.get("data"), dict) else {}
        nums = _cost_scope_numbers_v24(scope_id, data)
        rows.append({
            "Label": label,
            "Date": report.get("sort_date") if not pd.isna(report.get("sort_date")) else _cost_month_ts_v24(data, label),
            "Budget": nums.get("budget"),
            "CO": nums.get("change_order"),
            "Forecast": nums.get("forecast"),
            "VOWD": nums.get("vowd"),
            "ETC": nums.get("etc"),
            "Potential exposure": nums.get("potential_exposure"),
            "Potential forecast": nums.get("potential_forecast"),
            "Forecast deviation vs budget": nums.get("forecast_deviation"),
            "Potential deviation vs budget": nums.get("potential_deviation"),
        })
    df = pd.DataFrame(rows)
    if not df.empty:
        df = df.sort_values("Date", na_position="last").reset_index(drop=True)
    return df


def _fmt_delta_v24(value: Any) -> Tuple[str, str]:
    fv = _safe_float(value)
    if fv is None or abs(fv) < 1:
        return "Δ vs previous: 0", "neutral"
    return f"Δ vs previous: {_fmt_money(fv)}", "bad" if fv > 0 else "good"


def _cost_history_svg_v24(df: pd.DataFrame, metric: str, active_label: str, width: int = 300, height: int = 74) -> str:
    if df.empty or metric not in df.columns:
        return "<svg></svg>"
    tmp = df[["Label", metric]].copy()
    tmp[metric] = pd.to_numeric(tmp[metric], errors="coerce")
    tmp = tmp.dropna()
    if tmp.empty:
        return "<svg></svg>"
    vals = tmp[metric].tolist()
    n = len(vals)
    vmin, vmax = min(vals), max(vals)
    if abs(vmax - vmin) < 1e-9:
        vmax = vmin + 1.0
    pad_x, pad_y = 18, 12
    pts = []
    for i, v in enumerate(vals):
        x = pad_x if n == 1 else pad_x + i * ((width - 2 * pad_x) / (n - 1))
        y = height - pad_y - ((v - vmin) / (vmax - vmin)) * (height - 2 * pad_y)
        pts.append((x, y, tmp.iloc[i]["Label"], v))
    line = " ".join(f"{x:.1f},{y:.1f}" for x, y, _l, _v in pts)
    circles = []
    for x, y, label, v in pts:
        active = str(label) == str(active_label)
        fill = "#ffffff" if active else "#c76df1"
        stroke = "#ffffff" if active else "#c76df1"
        r = 5 if active else 3
        circles.append(f"<circle cx='{x:.1f}' cy='{y:.1f}' r='{r}' fill='{fill}' stroke='{stroke}' stroke-width='1.5'></circle>")
        if active:
            circles.append(f"<text x='{x:.1f}' y='{max(10, y-10):.1f}' text-anchor='middle' fill='#fff' font-size='10' font-weight='800'>{html.escape(_fmt_money(v))}</text>")
    return f"<svg viewBox='0 0 {width} {height}' preserveAspectRatio='none'><line x1='{pad_x}' y1='{height-pad_y}' x2='{width-pad_x}' y2='{height-pad_y}' stroke='rgba(255,255,255,.25)' stroke-width='1'/><polyline points='{line}' fill='none' stroke='#c76df1' stroke-width='2.3'/>{''.join(circles)}</svg>"


def _cost_kpi_card_v24(label: str, metric: str, df: pd.DataFrame, active_label: str) -> str:
    if df.empty:
        value = None
        delta = None
    else:
        row = df[df["Label"] == active_label]
        if row.empty:
            row = df.tail(1)
        value = row.iloc[0].get(metric) if metric in row.columns else None
        idx = int(row.index[-1]) if not row.empty else len(df) - 1
        prev = df.iloc[idx - 1].get(metric) if idx > 0 and metric in df.columns else None
        delta = (_safe_float(value) - _safe_float(prev)) if _safe_float(value) is not None and _safe_float(prev) is not None else None
    dtext, dclass = _fmt_delta_v24(delta)
    svg = _cost_history_svg_v24(df, metric, active_label)
    hist_rows = []
    for _, r in df.iterrows():
        active = str(r.get("Label")) == str(active_label)
        hist_rows.append(f"<div class='{ 'active' if active else ''}'><span>{_html(r.get('Label'))}</span><b>{_html(_fmt_money(r.get(metric)))}</b></div>")
    return (
        "<div class='cost-kpi-card'>"
        f"<div class='cost-kpi-label'>{_html(label)}</div>"
        f"<div class='cost-kpi-value'>{_html(_fmt_money(value))}</div>"
        f"<div class='cost-kpi-delta {dclass}'>{_html(dtext)}</div>"
        "<div class='cost-kpi-tooltip'>"
        f"<div class='cost-kpi-tooltip-title'>{_html(label)} history - active {_html(active_label)}</div>"
        f"{svg}<div class='cost-kpi-history'>{''.join(hist_rows)}</div>"
        "</div></div>"
    )


def _cost_waterfall_v24(scope_id: str, cost_data: Dict[str, Any], scope_label: str, active_label: str) -> go.Figure:
    nums = _cost_scope_numbers_v24(scope_id, cost_data)
    labels = ["Budget", "CO", "Forecast", "Potential exposure", "Potential forecast"]
    metrics = ["Budget", "CO", "Forecast", "Potential exposure", "Potential forecast"]
    vals = [nums.get("budget") or 0.0, nums.get("change_order") or 0.0, nums.get("forecast") or 0.0, nums.get("potential_exposure") or 0.0, nums.get("potential_forecast") or 0.0]
    measures = ["absolute", "relative", "total", "relative", "total"]
    running = [vals[0], vals[0] + vals[1], vals[2], vals[2] + vals[3], vals[4]]
    df = _cost_history_df_v24(scope_id)
    custom = []
    for i, metric in enumerate(metrics):
        hist = _cost_history_records_text_v24(df, metric, active_label, months=3)
        custom.append([metric, active_label, _fmt_money_full(vals[i]), _fmt_money_full(running[i]), hist])
    fig = go.Figure(go.Waterfall(
        x=labels,
        y=vals,
        measure=measures,
        text=[_fmt_money(v) for v in vals],
        textposition="outside",
        customdata=custom,
        connector={"line": {"color": "#9aa1ad", "width": 1}},
        increasing={"marker": {"color": "#007a45"}},
        decreasing={"marker": {"color": "#c73535"}},
        totals={"marker": {"color": "#c76df1"}},
        hovertemplate=(
            "<b>%{customdata[0]}</b><br>"
            "Scope: " + _html(scope_label) + "<br>"
            "Active month: %{customdata[1]}<br>"
            "Actual value: %{customdata[2]}<br>"
            "Cost position after step: %{customdata[3]}<br><br>"
            "Last 3 loaded months:<br>%{customdata[4]}<extra></extra>"
        ),
    ))
    fig.update_layout(
        title={"text": f"{scope_label} - cost waterfall", "x": 0.02, "xanchor": "left", "font": {"size": 18}},
        height=420,
        margin=dict(l=38, r=28, t=68, b=76),
        paper_bgcolor="rgba(0,0,0,0)",
        plot_bgcolor="rgba(0,0,0,0)",
        yaxis_title="EUR",
        showlegend=False,
        hovermode="closest",
    )
    fig.update_xaxes(tickangle=-20)
    return fig


def _cost_history_records_text_v24(df: pd.DataFrame, metric: str, active_label: str, months: int = 3) -> str:
    if df.empty or metric not in df.columns:
        return "No monthly history loaded."
    if active_label in set(df["Label"]):
        active_idx = int(df.index[df["Label"] == active_label][-1])
        start = max(0, active_idx - months + 1)
        tmp = df.iloc[start:active_idx + 1]
    else:
        tmp = df.tail(months)
    lines = []
    for _, r in tmp.iterrows():
        bullet = "●" if str(r.get("Label")) == str(active_label) else "•"
        lines.append(f"{bullet} {r.get('Label')}: {_fmt_money(r.get(metric))}")
    return "<br>".join(lines)


def _cost_history_line_figure_v24(df: pd.DataFrame, active_label: str, title: str, metrics: List[str]) -> go.Figure:
    fig = go.Figure()
    if df.empty:
        fig.update_layout(title=title, height=360)
        return fig
    x = df["Label"].astype(str).tolist()
    for metric in metrics:
        if metric not in df.columns:
            continue
        y = pd.to_numeric(df[metric], errors="coerce")
        fig.add_trace(go.Scatter(
            x=x,
            y=y,
            mode="lines+markers",
            name=metric,
            customdata=df[["Label"]],
            hovertemplate=f"<b>{metric}</b><br>Month: %{{x}}<br>Value: €%{{y:,.0f}}<extra></extra>",
        ))
    if active_label in x:
        active_rows = df[df["Label"] == active_label]
        ymax = pd.to_numeric(df[metrics].stack(), errors="coerce").max() if set(metrics).issubset(df.columns) else None
        ymin = pd.to_numeric(df[metrics].stack(), errors="coerce").min() if set(metrics).issubset(df.columns) else None
        fig.add_vline(x=active_label, line_dash="dash", line_color="#111111", line_width=2)
        for metric in metrics:
            if metric in active_rows.columns:
                val = _safe_float(active_rows.iloc[0].get(metric))
                if val is not None:
                    fig.add_trace(go.Scatter(x=[active_label], y=[val], mode="markers+text", marker=dict(symbol="diamond-open", size=15, color="#111111", line=dict(width=2)), text=[_fmt_money(val)], textposition="top center", name=f"Active {metric}", showlegend=False, hovertemplate=f"<b>Active {metric}</b><br>{active_label}<br>€%{{y:,.0f}}<extra></extra>"))
    fig.update_layout(
        title={"text": title, "x": 0.02, "xanchor": "left", "font": {"size": 17}},
        height=405,
        margin=dict(l=40, r=24, t=66, b=70),
        paper_bgcolor="rgba(0,0,0,0)",
        plot_bgcolor="rgba(0,0,0,0)",
        yaxis_title="EUR",
        xaxis_title="Monthly report",
        hovermode="x unified",
        legend=dict(orientation="h", yanchor="bottom", y=1.02, xanchor="right", x=1),
    )
    fig.update_xaxes(tickangle=-30, type="category")
    return fig


def _cost_scope_comparison_figure_v24(cost_data: Dict[str, Any], active_label: str) -> go.Figure:
    scopes = [("rail", "Rail On Site (ROS)"), ("ponds", "Ponds"), ("roads", "Roads")]
    metrics = ["Forecast", "VOWD", "ETC", "Potential forecast"]
    fig = go.Figure()
    for metric in metrics:
        vals = []
        custom = []
        for sid, label in scopes:
            nums = _cost_scope_numbers_v24(sid, cost_data)
            key = {"Forecast":"forecast", "VOWD":"vowd", "ETC":"etc", "Potential forecast":"potential_forecast"}[metric]
            val = nums.get(key)
            vals.append(val)
            hist = _cost_history_records_text_v24(_cost_history_df_v24(sid), metric, active_label, months=3)
            custom.append([label, metric, _fmt_money_full(val), hist])
        fig.add_trace(go.Bar(x=[label for _sid, label in scopes], y=vals, name=metric, customdata=custom, hovertemplate="<b>%{customdata[0]}</b><br>%{customdata[1]}: %{customdata[2]}<br>Last 3 months:<br>%{customdata[3]}<extra></extra>"))
    fig.update_layout(
        title={"text": "Active month cost position by scope", "x": 0.02, "xanchor": "left", "font": {"size": 17}},
        barmode="group",
        height=405,
        margin=dict(l=42, r=22, t=66, b=62),
        paper_bgcolor="rgba(0,0,0,0)",
        plot_bgcolor="rgba(0,0,0,0)",
        yaxis_title="EUR",
        legend=dict(orientation="h", yanchor="bottom", y=1.02, xanchor="right", x=1),
    )
    return fig


def _cost_history_table_rows_v24(scope_id: str, active_label: str) -> Tuple[List[str], List[List[Any]]]:
    headers = ["Month", "Scope", "Budget", "CO", "Forecast", "VOWD", "ETC", "Potential exposure", "Potential forecast", "Forecast deviation", "Potential deviation"]
    rows: List[List[Any]] = []
    scopes = [("portfolio", "All scopes")] if scope_id == "portfolio" else [(scope_id, _scope_name(scope_id))]
    if scope_id == "portfolio":
        scopes = [("rail", "Rail On Site (ROS)"), ("ponds", "Ponds"), ("roads", "Roads"), ("portfolio", "Portfolio total")]
    for sid, slabel in scopes:
        df = _cost_history_df_v24(sid)
        for _, r in df.iterrows():
            rows.append([
                r.get("Label"),
                slabel,
                _fmt_money_full(r.get("Budget")),
                _fmt_money_full(r.get("CO")),
                _fmt_money_full(r.get("Forecast")),
                _fmt_money_full(r.get("VOWD")),
                _fmt_money_full(r.get("ETC")),
                _fmt_money_full(r.get("Potential exposure")),
                _fmt_money_full(r.get("Potential forecast")),
                _fmt_money_full(r.get("Forecast deviation vs budget")),
                _fmt_money_full(r.get("Potential deviation vs budget")),
            ])
    return headers, rows


def _cost_pm_insight_cards_v24(scope_id: str, df: pd.DataFrame, active_label: str, cost_data: Dict[str, Any]) -> str:
    if df.empty:
        return ""
    row = df[df["Label"] == active_label]
    if row.empty:
        row = df.tail(1)
    r = row.iloc[0]
    forecast = _safe_float(r.get("Forecast"))
    budget = _safe_float(r.get("Budget"))
    potential = _safe_float(r.get("Potential forecast"))
    exposure = _safe_float(r.get("Potential exposure"))
    vowd = _safe_float(r.get("VOWD"))
    etc = _safe_float(r.get("ETC"))
    forecast_delta = forecast - budget if forecast is not None and budget is not None else None
    potential_delta = potential - budget if potential is not None and budget is not None else None
    burn_pct = (vowd / forecast * 100) if vowd is not None and forecast not in (None, 0) else None
    exposure_pct = (exposure / forecast * 100) if exposure is not None and forecast not in (None, 0) else None
    cards = [
        ("Forecast vs budget", _fmt_money(forecast_delta), "Current forecast position against baseline budget."),
        ("Potential exposure", _fmt_money(exposure), f"Potential exposure equals {exposure_pct:.1f}% of current forecast." if exposure_pct is not None else "Potential exposure not published for this selection."),
        ("VOWD / ETC", f"{burn_pct:.1f}% / {_fmt_money(etc)}" if burn_pct is not None else _fmt_money(etc), "Value of work done versus remaining estimate to complete."),
        ("Potential deviation", _fmt_money(potential_delta), "Potential forecast against budget if identified exposure materializes."),
        ("History loaded", f"{len(df)} months", f"{df['Label'].iloc[0]} to {df['Label'].iloc[-1]}" if len(df) else "No history."),
        ("Active month", active_label, "Use the sidebar to change the active monthly cost report."),
    ]
    return "<div class='cost-pm-insights'>" + "".join(f"<div class='cost-insight-card'><span>{_html(t)}</span><b>{_html(v)}</b><p>{_html(desc)}</p></div>" for t, v, desc in cards) + "</div>"


def render_cost_overview(records: List[Dict[str, Any]]) -> None:
    st.markdown("<div class='section-title'>Cost Status</div>", unsafe_allow_html=True)
    active_label = _selected_cost_label_v24()
    cost_data = _cost_report_by_label_v24(active_label)
    meta = cost_data.get("metadata") or {}
    st.markdown(
        f"<div class='cost-v24-controls'><span class='cost-v24-pill'>Active month: {_html(active_label)}</span><span class='cost-v24-pill'>Currency: {_html(meta.get('currency') or 'EUR')}</span><span class='cost-v24-pill'>Reports loaded: {len(_cost_reports())}</span></div>",
        unsafe_allow_html=True,
    )
    st.markdown("<div class='cost-v24-note'>One consolidated cost section. Use the selector below to switch between portfolio and individual scope views. Historical KPIs, trends and tables use every loaded monthly cost report.</div>", unsafe_allow_html=True)

    choices = list(COST_SCOPE_SELECT.keys())
    if st.session_state.get("cost_scope_visual_v24") not in choices:
        st.session_state["cost_scope_visual_v24"] = choices[0]
    st.markdown("<div class='cost-scope-select'>", unsafe_allow_html=True)
    choice = st.selectbox("Scope to visualize", choices, key="cost_scope_visual_v24")
    st.markdown("</div>", unsafe_allow_html=True)
    scope_id = COST_SCOPE_SELECT.get(choice, "portfolio")
    scope_label = choice if scope_id == "portfolio" else _scope_name(scope_id)
    df = _cost_history_df_v24(scope_id)
    kpis = [
        ("Budget", "Budget"),
        ("CO", "CO"),
        ("Forecast", "Forecast"),
        ("VOWD", "VOWD"),
        ("ETC", "ETC"),
        ("Potential exposure", "Potential exposure"),
        ("Potential forecast", "Potential forecast"),
        ("Potential deviation", "Potential deviation vs budget"),
    ]
    st.markdown("<div class='cost-kpi-grid'>" + "".join(_cost_kpi_card_v24(title, metric, df, active_label) for title, metric in kpis) + "</div>", unsafe_allow_html=True)
    st.markdown(_cost_pm_insight_cards_v24(scope_id, df, active_label, cost_data), unsafe_allow_html=True)

    c1, c2 = st.columns([1, 1])
    with c1:
        st.markdown("<div class='cost-chart-card'>", unsafe_allow_html=True)
        st.plotly_chart(_cost_waterfall_v24(scope_id, cost_data, scope_label, active_label), use_container_width=True)
        st.markdown("</div>", unsafe_allow_html=True)
    with c2:
        st.markdown("<div class='cost-chart-card'>", unsafe_allow_html=True)
        if scope_id == "portfolio":
            st.plotly_chart(_cost_scope_comparison_figure_v24(cost_data, active_label), use_container_width=True)
        else:
            st.plotly_chart(_cost_history_line_figure_v24(df, active_label, f"{scope_label} - forecast / VOWD / ETC history", ["Forecast", "VOWD", "ETC", "Potential forecast"]), use_container_width=True)
        st.markdown("</div>", unsafe_allow_html=True)

    c3, c4 = st.columns([1, 1])
    with c3:
        st.markdown("<div class='cost-chart-card'>", unsafe_allow_html=True)
        st.plotly_chart(_cost_history_line_figure_v24(df, active_label, f"{scope_label} - budget / forecast trend", ["Budget", "Forecast", "Potential forecast"]), use_container_width=True)
        st.markdown("</div>", unsafe_allow_html=True)
    with c4:
        st.markdown("<div class='cost-chart-card'>", unsafe_allow_html=True)
        st.plotly_chart(_cost_history_line_figure_v24(df, active_label, f"{scope_label} - changes and exposure trend", ["CO", "Potential exposure", "Forecast deviation vs budget", "Potential deviation vs budget"]), use_container_width=True)
        st.markdown("</div>", unsafe_allow_html=True)

    st.markdown("<div class='cost-history-title'>Monthly cost history</div>", unsafe_allow_html=True)
    headers, rows = _cost_history_table_rows_v24(scope_id, active_label)
    _copyable_table_component(headers, rows, numeric_cols=set(range(2, len(headers))), key_prefix=f"cost_hist_{scope_id}_{active_label}")

    if scope_id != "portfolio":
        pkg_rows = _scope_package_rows(scope_id, cost_data)
        if pkg_rows:
            st.markdown("<div class='cost-history-title'>Active-month package drivers</div>", unsafe_allow_html=True)
            _copyable_table_component(["Package", "Description", "Supplier", "Budget", "CO", "Forecast", "Exposure", "Potential forecast", "Driver / note"], pkg_rows, numeric_cols={3,4,5,6,7}, key_prefix=f"cost_pkg_{scope_id}_{active_label}")
        exposures = _cost_exposures(scope_id, cost_data)
        if exposures:
            st.markdown("<div class='cost-history-title'>Potential changes / exposure items</div>", unsafe_allow_html=True)
            exp_rows = [[e.get("item_id"), e.get("package"), _fmt_money_full(e.get("amount")), e.get("criticality") or "", e.get("type") or "", e.get("description") or e.get("main_description"), e.get("pm") or "", _fmt_date_short(e.get("award_date"))] for e in exposures]
            _copyable_table_component(["Item", "Package", "Amount", "Criticality", "Type", "Description", "Responsible", "Expected / award date"], exp_rows, numeric_cols={2}, key_prefix=f"cost_exp_{scope_id}_{active_label}")
    else:
        st.markdown("<div class='cost-history-title'>Active-month exposure summary by scope</div>", unsafe_allow_html=True)
        exp_rows = []
        for sid in ["rail", "ponds", "roads"]:
            for e in _cost_exposures(sid, cost_data):
                exp_rows.append([_scope_name(sid), e.get("item_id"), e.get("package"), _fmt_money_full(e.get("amount")), e.get("criticality") or "", e.get("type") or "", e.get("description") or e.get("main_description"), e.get("pm") or "", _fmt_date_short(e.get("award_date"))])
        if exp_rows:
            _copyable_table_component(["Scope", "Item", "Package", "Amount", "Criticality", "Type", "Description", "Responsible", "Expected / award date"], exp_rows, numeric_cols={3}, key_prefix=f"cost_exp_portfolio_{active_label}")
        else:
            st.markdown("<div class='action-empty'>No active potential exposure item rows loaded for the active month.</div>", unsafe_allow_html=True)


def render_scope_cost_section(rec: Dict[str, Any]) -> None:
    # Cost is intentionally consolidated in the Executive overview Cost Status section.
    # This keeps one cost-control area in the app while preserving scope/detail panels
    # for schedule, engineering, quality, milestones and actions.
    return


def render_scope_matrix(records: List[Dict[str, Any]], selected_year: int, selected_week: int) -> None:
    st.markdown("<div class='section-title'>Executive control matrix</div>", unsafe_allow_html=True)
    order = {"rail": 0, "ponds": 1, "roads": 2}
    records = [_with_display_scope(r) for r in records if r.get("scope_id") in order]
    records = sorted(records, key=lambda r: order.get(r.get("scope_id"), 99))
    cols = st.columns(3)
    for col, rec in zip(cols, records):
        with col:
            construction_dev = rec.get("construction_deviation")
            if construction_dev is None and rec.get("construction_actual") is not None and rec.get("construction_forecast") is not None:
                construction_dev = rec.get("construction_actual") - rec.get("construction_forecast")
            engineering_actual = rec.get("engineering_actual")
            engineering_forecast = rec.get("engineering_forecast") if rec.get("engineering_forecast") is not None else engineering_actual
            engineering_dev = rec.get("engineering_deviation")
            if engineering_dev is None and engineering_actual is not None and engineering_forecast is not None:
                engineering_dev = engineering_actual - engineering_forecast
            construction_etc = _date_only_etc(_baseline_etc_for_scope(rec["scope_id"], selected_year, selected_week, mode="final"), fallback="TBC")
            engineering_etc = _date_only_etc(rec.get("engineering_etc") or _baseline_etc_for_scope(rec["scope_id"], selected_year, selected_week, mode="next"), fallback="TBC")
            icon = SCOPE_ICON.get(rec["scope_id"], "●")
            html_block = (
                "<div class='matrix-col'>"
                "<div class='matrix-head'>"
                f"<h3><span class='scope-icon'>{icon}</span>{_html(rec['name'])}</h3>"
                f"<span class='status-badge'>{_html(_matrix_driver(rec))}</span>"
                "</div>"
                f"{progress_bar_html('Construction progress', rec.get('construction_actual'), rec.get('construction_forecast'), construction_dev, construction_etc, next_week_forecast=_next_progress_label(rec, selected_year, selected_week, 'construction'))}"
                f"{progress_bar_html('Engineering progress', engineering_actual, engineering_forecast, engineering_dev, engineering_etc, next_week_forecast=_next_progress_label(rec, selected_year, selected_week, 'engineering'))}"
                f"<div class='next-fc'><b>Next week FC</b>{_html(rec.get('next_week_fc') or 'Not published in selected-week data')}</div>"
                "<div class='gate-row'>"
                f"{_gate_pill_html('Open quality gates', len(rec.get('quality_items', [])), rec.get('quality_items', []))}"
                f"{_gate_pill_html('Open engineering gates', len(rec.get('engineering_items', [])), rec.get('engineering_items', []))}"
                "</div>"
                "</div>"
            )
            st.markdown(html_block, unsafe_allow_html=True)


def render_executive_overview(bundle: Dict[str, Any], profiles: Dict[str, Any], selected_year: int, selected_week: int, current_date: Optional[pd.Timestamp] = None) -> None:
    records = build_scope_records(bundle, profiles, selected_year, selected_week, scopes=CONTROL_SCOPES)
    selected_label = period_display(selected_year, selected_week)
    cutoff = current_date if current_date is not None else selected_cutoff_date(bundle)
    render_scope_matrix(records, selected_year, selected_week)
    render_cost_overview(records)
    render_executive_priority_delayed_near_table(records, selected_label, selected_year, selected_week, current_date=cutoff)
    render_milestone_timeline(records, title="Milestones", selected_year=selected_year, selected_week=selected_week, current_date=cutoff)



