def render_loading_overlay() -> None:
    """v26: no loading picture/overlay."""
    return


def _selected_cutoff_label_for_header(bundle: Dict[str, Any]) -> str:
    try:
        view = filter_bundle_until(bundle, *_selected_week_tuple_from_state(bundle))
        dt = selected_cutoff_date(view)
    except Exception:
        try:
            dt = selected_cutoff_date(bundle)
        except Exception:
            dt = None
    return _normalize_date_label(dt) if dt is not None else "TBC"


def _selected_week_tuple_from_state(bundle: Dict[str, Any]) -> Tuple[int, int]:
    periods = available_periods(bundle)
    if not periods:
        return (2026, 0)
    labels = [period_display(y, w) for y, w in periods]
    selected = st.session_state.get("week_selector_value")
    if selected not in labels:
        y, w = latest_period(bundle)
        selected = period_display(y, w)
        if selected not in labels:
            selected = labels[-1]
        st.session_state["week_selector_value"] = selected
    return periods[labels.index(st.session_state["week_selector_value"])]


def _set_active_week_by_offset_v26(offset: int) -> None:
    periods = available_periods(st.session_state.get("bundle", {}))
    labels = [period_display(y, w) for y, w in periods]
    if not labels:
        return
    current = st.session_state.get("week_selector_value")
    idx = labels.index(current) if current in labels else len(labels) - 1
    idx = max(0, min(len(labels) - 1, idx + int(offset)))
    st.session_state["week_selector_value"] = labels[idx]


def render_top_control_center(bundle: Dict[str, Any]) -> Tuple[int, int]:
    """Floating title/control box containing week, cost month and baseline selectors."""
    periods = available_periods(bundle)
    if not periods:
        period_labels = []
        selected_year, selected_week = 2026, 0
    else:
        period_labels = [period_display(y, w) for y, w in periods]
        latest_y, latest_w = latest_period(bundle)
        default_label = period_display(latest_y, latest_w)
        if default_label not in period_labels:
            default_label = period_labels[-1]
        if st.session_state.get("week_selector_value") not in period_labels:
            st.session_state["week_selector_value"] = default_label
        selected_label_pre = st.session_state["week_selector_value"]
        selected_year, selected_week = periods[period_labels.index(selected_label_pre)]

    logo_src = logo_mark_data_uri() or logo_data_uri()
    with st.container(key="rc_top_control_center_v26"):
        if logo_src:
            st.markdown(
                f"<div class='rc-subtitle'>Rail On Site (ROS) - Ponds - Roads</div>"
                f"<div class='rc-title-row'><div class='rc-title-logo'><img src='{logo_src}'></div><h1>Roger Campbell Scopes Control Center</h1></div>",
                unsafe_allow_html=True,
            )
        else:
            st.markdown("<div class='rc-subtitle'>Rail On Site (ROS) - Ponds - Roads</div><h1>Roger Campbell Scopes Control Center</h1>", unsafe_allow_html=True)
        c_week, c_back, c_next, c_cutoff, c_cost, c_baseline = st.columns([1.18, .42, .42, .95, 1.05, 1.18], gap="small")
        with c_week:
            st.markdown("<div class='rc-control-label'>Actual week</div>", unsafe_allow_html=True)
            if period_labels:
                selected_label = st.selectbox("Actual week", period_labels, key="week_selector_value", label_visibility="collapsed")
                selected_year, selected_week = periods[period_labels.index(selected_label)]
            else:
                st.markdown("<div class='rc-cutoff'>No weeks loaded</div>", unsafe_allow_html=True)
        current_idx = period_labels.index(st.session_state["week_selector_value"]) if period_labels and st.session_state.get("week_selector_value") in period_labels else 0
        with c_back:
            st.markdown("<div class='rc-control-label'>&nbsp;</div>", unsafe_allow_html=True)
            st.button("◀ Back", key="top_week_back_v26", use_container_width=True, disabled=(current_idx <= 0), on_click=_set_active_week_by_offset_v26, args=(-1,))
        with c_next:
            st.markdown("<div class='rc-control-label'>&nbsp;</div>", unsafe_allow_html=True)
            st.button("Next ▶", key="top_week_next_v26", use_container_width=True, disabled=(not period_labels or current_idx >= len(period_labels)-1), on_click=_set_active_week_by_offset_v26, args=(1,))
        cutoff_label = _normalize_date_label(selected_cutoff_date(filter_bundle_until(bundle, selected_year, selected_week))) if period_labels else "TBC"
        with c_cutoff:
            st.markdown("<div class='rc-control-label'>Cut-off date</div>", unsafe_allow_html=True)
            st.markdown(f"<div class='rc-cutoff'><span>Cut-off:</span>{_html(cutoff_label)}</div>", unsafe_allow_html=True)
        cost_reports = _cost_reports()
        cost_labels = [r["label"] for r in cost_reports if r.get("label")]
        with c_cost:
            st.markdown("<div class='rc-control-label'>Active month</div>", unsafe_allow_html=True)
            if cost_labels:
                if st.session_state.get("monthly_cost_report_choice_portfolio") not in cost_labels:
                    st.session_state["monthly_cost_report_choice_portfolio"] = cost_labels[-1]
                st.selectbox("Active month", cost_labels, key="monthly_cost_report_choice_portfolio", label_visibility="collapsed")
            else:
                st.markdown("<div class='rc-cutoff'>No cost report</div>", unsafe_allow_html=True)
        baseline_reports = _baseline_reports()
        bl_labels = [r["label"] for r in baseline_reports if r.get("label")]
        with c_baseline:
            st.markdown("<div class='rc-control-label'>Active baseline</div>", unsafe_allow_html=True)
            if bl_labels:
                if st.session_state.get("baseline_choice") not in bl_labels:
                    st.session_state["baseline_choice"] = bl_labels[-1]
                st.selectbox("Active baseline", bl_labels, key="baseline_choice", label_visibility="collapsed")
            else:
                st.markdown("<div class='rc-cutoff'>No baseline</div>", unsafe_allow_html=True)
    return int(selected_year), int(selected_week)


def _gate_popover_rows(items: List[Any]) -> str:
    if not items:
        return "<div class='gate-popover-empty'>No open gates extracted for this active week.</div>"
    rows = []
    for i, item in enumerate(items, 1):
        text = clean_action_text(item.get("issue") or item.get("action") or item.get("description") or item if isinstance(item, dict) else item)
        rows.append(f"<div class='gate-popover-row'><b>{i}.</b> {_html(text)}</div>")
    return "".join(rows)


def _gate_pill_html(title: str, count: int, items: List[str]) -> str:
    token = hashlib.sha1((title + str(count) + "|".join(map(str, items[:20]))).encode("utf-8", "ignore")).hexdigest()[:12]
    pid = f"gate_pop_{token}"
    return (
        "<div class='gate-pill'>"
        f"<button type='button' class='gate-click-surface' popovertarget='{pid}' popovertargetaction='toggle'>"
        f"<span>{_html(title)}</span><b>{int(count)}</b><small>Click to open list</small></button>"
        f"<div id='{pid}' class='gate-popover' popover><div class='gate-popover-inner'>"
        f"<div class='gate-popover-title'>{_html(title)} - active week</div>{_gate_popover_rows(items)}"
        "</div></div></div>"
    )


def _next_week_fc_html(text: Any) -> str:
    raw = str(text or "Not published in selected-week data").strip()
    # Split into individual activities while keeping week prefix readable.
    parts = []
    if raw and raw.lower() not in {"not published", "not published in selected-week data"}:
        # normalize bullets/newlines/semicolons into separate items
        normalized = re.sub(r"\s*[•▪]\s*", "\n", raw)
        chunks = []
        for line in re.split(r"\n+", normalized):
            chunks.extend(re.split(r";\s+(?=[A-Z0-9])", line))
        parts = [compact_text(c.strip(" -•"), 190) for c in chunks if c.strip(" -•")]
    if not parts:
        parts = ["Not published in selected-week data"]
    lis = "".join(f"<li>{_html(p)}</li>" for p in parts)
    return f"<div class='next-fc'><b>Next week FC</b><ul>{lis}</ul></div>"


def _cost_history_sorted_df(scope_id: str, latest_first: bool = False) -> pd.DataFrame:
    df = _history_for_scope(scope_id)
    if df is None or df.empty:
        return pd.DataFrame()
    df = df.copy()
    def _ts(label: Any) -> pd.Timestamp:
        return pd.to_datetime(str(label), errors="coerce")
    df["_sort_month"] = df["Month"].apply(_ts)
    df = df.sort_values(["_sort_month", "Month"], ascending=[not latest_first, not latest_first], na_position="last")
    return df.drop(columns=["_sort_month"], errors="ignore")


def _cost_kpi_hover(scope_id: str, metric_key: str, metric_label: str, active_label: str) -> str:
    df = _history_for_scope(scope_id)
    if df.empty or metric_label not in df.columns:
        return "<div class='cost-kpi-tip'><h4>No history available</h4></div>"
    if active_label in set(df["Month"].astype(str)):
        active_idx = df.index[df["Month"].astype(str) == active_label].tolist()[-1]
        subset = df.loc[:active_idx].tail(3)
    else:
        subset = df.tail(3)
    points = [(str(r["Month"]), r.get(metric_label)) for _, r in subset.iterrows()]
    svg = _svg_sparkline(points, active_label)
    rows = []
    for label, val in reversed(points):
        cls = "hist-row latest" if label == active_label else "hist-row"
        rows.append(f"<div class='{cls}'><span>{_html(label)}</span><b>{_html(_fmt_money(val))}</b></div>")
    return f"<div class='cost-kpi-tip'><h4>{_html(metric_label)} - last 3 months</h4>{svg}<div class='active-line'>Latest first; active month highlighted.</div>{''.join(rows)}</div>"


def _history_lines_latest_first(scope_id: str, label: str, active_label: str, months: int = 3) -> str:
    df = _history_for_scope(scope_id)
    if df is None or df.empty or label not in df.columns:
        return "No history"
    if active_label in set(df["Month"].astype(str)):
        active_idx = df.index[df["Month"].astype(str) == active_label].tolist()[-1]
        sub = df.loc[:active_idx].tail(months)
    else:
        sub = df.tail(months)
    lines = []
    for _, r in sub.iloc[::-1].iterrows():
        prefix = "<b>" if str(r.get("Month")) == active_label else ""
        suffix = "</b>" if str(r.get("Month")) == active_label else ""
        lines.append(f"{prefix}{_html(r.get('Month'))}: {_html(_fmt_money(r.get(label)))}{suffix}")
    return "<br>".join(lines)


def _cost_waterfall_v24(scope_id: str, cost_data: Dict[str, Any], scope_label: str, active_label: str) -> go.Figure:
    """Waterfall/candle chart with corrected latest-to-oldest hover history."""
    if scope_id == "all":
        row = _active_history_row("all")
        budget = _safe_float(row.get("Budget")) or 0.0
        co = _safe_float(row.get("CO")) or 0.0
        forecast = _safe_float(row.get("Forecast")) if row.get("Forecast") is not None else budget + co
        exposure = _safe_float(row.get("Potential exposure")) or 0.0
        potential_forecast = _safe_float(row.get("Potential forecast")) if row.get("Potential forecast") is not None else (forecast or 0) + exposure
    else:
        nums = _cost_numbers(scope_id, cost_data)
        budget = _safe_float(nums.get("budget")) or 0.0
        forecast = _safe_float(nums.get("forecast"))
        co = (forecast - budget) if forecast is not None else (_safe_float(nums.get("change_order")) or 0.0)
        forecast = forecast if forecast is not None else budget + co
        exposure = _safe_float(nums.get("potential_exposure")) or 0.0
        potential_forecast = _safe_float(nums.get("potential_forecast")) if nums.get("potential_forecast") is not None else forecast + exposure
    labels = ["Budget", "CO", "Forecast", "Potential exposure", "Potential forecast"]
    y_vals = [budget, co, forecast, exposure, potential_forecast]
    running = [budget, budget + co, forecast, forecast + exposure, potential_forecast]
    measures = ["absolute", "relative", "total", "relative", "total"]
    hist_label_map = {"Budget":"Budget", "CO":"CO", "Forecast":"Forecast", "Potential exposure":"Potential exposure", "Potential forecast":"Potential forecast"}
    custom = []
    for label, val, run in zip(labels, y_vals, running):
        hist = _history_lines_latest_first(scope_id, hist_label_map[label], active_label, months=3)
        custom.append([label, _fmt_money_full(val), _fmt_money_full(run), active_label, hist])
    fig = go.Figure(go.Waterfall(
        x=labels, y=y_vals, measure=measures, text=[_fmt_money(v) for v in y_vals], textposition="outside",
        connector={"line": {"color": "#9aa1ad", "width": 1}},
        increasing={"marker": {"color": "#007a45"}}, decreasing={"marker": {"color": "#c73535"}}, totals={"marker": {"color": "#c76df1"}},
        customdata=custom,
        hovertemplate=("<b>%{customdata[0]}</b><br>Active month: %{customdata[3]}<br>Step value: %{customdata[1]}<br>Cost position after step: %{customdata[2]}<br><br><b>History, latest to oldest</b><br>%{customdata[4]}<extra></extra>"),
    ))
    fig.update_layout(title={"text": f"{scope_label} cost waterfall - {active_label}", "x": 0.02, "xanchor": "left", "font": {"size": 18}}, height=430, margin=dict(l=40, r=24, t=64, b=82), paper_bgcolor="rgba(0,0,0,0)", plot_bgcolor="rgba(0,0,0,0)", yaxis_title="EUR", showlegend=False, hovermode="closest")
    fig.update_xaxes(tickangle=-22)
    return fig


def _cost_history_table_rows(scope_id: str) -> List[List[Any]]:
    df = _cost_history_sorted_df(scope_id, latest_first=True)
    if df.empty:
        return []
    rows = []
    for _, r in df.iterrows():
        rows.append([
            r.get("Month"), _fmt_money_full(r.get("Budget")), _fmt_money_full(r.get("CO")), _fmt_money_full(r.get("Forecast")), _fmt_money_full(r.get("VOWD")), _fmt_money_full(r.get("ETC")), _fmt_money_full(r.get("Potential exposure")), _fmt_money_full(r.get("Potential forecast")), _fmt_money_full(r.get("Budget + CO check")), _fmt_money_full(r.get("Forecast + exposure check")),
        ])
    return rows


def _cost_history_table_rows_v24(scope_id: str, active_label: str) -> Tuple[List[str], List[List[Any]]]:
    headers = ["Month", "Budget", "CO", "Forecast", "VOWD", "ETC", "Potential exposure", "Potential forecast", "Budget + CO check", "Forecast + exposure check"]
    return headers, _cost_history_table_rows(scope_id)


def _preferred_col_widths(headers: List[str]) -> List[int]:
    lower = [str(h).lower() for h in headers]
    n = len(headers)
    if n == 5 and "scope" in lower[0] and "action" in lower[1]:
        return [8, 50, 19, 12, 11]
    if n == 4 and "action" in lower[0]:
        return [62, 18, 11, 9]
    if n >= 9 and lower[0] == "month":
        return [11, 10, 9, 10, 10, 10, 13, 13, 12, 12][:n]
    if n >= 8 and any("driver" in h for h in lower):
        base = [8, 20, 9, 8, 8, 8, 8, 9, 22]
        return base[:n] if n <= len(base) else [8, 18, 9, 8, 8, 8, 8, 9, 22] + [8]*(n-9)
    if n == 8 and "description" in lower[5]:
        return [8, 10, 9, 9, 8, 36, 10, 10]
    return [max(8, int(100 / max(1, n)))] * n


def _copyable_table_component(headers: List[str], rows: List[List[Any]], numeric_cols: Optional[set] = None, key_prefix: str = "tbl") -> None:
    """Copy real HTML table first; fall back to TSV. Latest cost-history row is bold."""
    numeric_cols = numeric_cols or set()
    if not rows:
        st.markdown("<div class='action-empty'>No rows available for this active selection.</div>", unsafe_allow_html=True)
        return
    keep = _table_column_keep(headers, rows)
    headers2 = [headers[i] for i in keep]
    rows2 = [[row[i] if i < len(row) else "" for i in keep] for row in rows]
    numeric2 = {new_i for new_i, old_i in enumerate(keep) if old_i in numeric_cols}
    tsv = "\n".join(["\t".join(str(h or "") for h in headers2)] + ["\t".join(str(c or "") for c in row) for row in rows2])
    widths = _preferred_col_widths(headers2)
    if len(widths) != len(headers2):
        widths = [int(100 / max(1, len(headers2)))] * len(headers2)
    colgroup = "".join(f"<col style='width:{w}%;'>" for w in widths)
    table_head = "".join(f"<th>{html.escape(str(h or ''))}</th>" for h in headers2)
    bold_first = bool(re.search(r"cost_(full_)?hist|cost_history|scope_cost_hist", str(key_prefix), re.I))
    body = []
    for ri, row in enumerate(rows2):
        tr_cls = " class='latest-row'" if bold_first and ri == 0 else ""
        cells = []
        for ci, val in enumerate(row):
            cls = "num" if ci in numeric2 else ""
            cells.append(f"<td class='{cls}'>{html.escape(str(val or ''))}</td>")
        body.append(f"<tr{tr_cls}>{''.join(cells)}</tr>")
    ident = "tbl_" + hashlib.sha1((key_prefix + tsv).encode("utf-8", "ignore")).hexdigest()[:12]
    html_table = f"<table><colgroup>{colgroup}</colgroup><thead><tr>{table_head}</tr></thead><tbody>{''.join(body)}</tbody></table>"
    js_tsv = json.dumps(tsv)
    js_html = json.dumps("<html><body>" + html_table + "</body></html>")
    doc = f"""
<!doctype html><html><head><meta charset='utf-8'>
<style>
body{{margin:0;font-family:Inter,Segoe UI,Arial,sans-serif;color:#1f2937;background:transparent;}}
.copybar{{display:flex;gap:8px;align-items:center;margin:0 0 8px 0;}}
.copybar button{{border:1px solid #d9c3ee;background:#fff;color:#39135c;border-radius:999px;padding:7px 13px;font-weight:900;font-size:12px;cursor:pointer;}}
.copybar .msg{{font-size:12px;color:#667085;}}
.table-wrap{{width:100%;border:1px solid #e7e2ed;border-radius:15px;overflow:hidden;background:#fff;box-shadow:0 1px 8px rgba(17,17,17,.04);}}
table{{width:100%;border-collapse:collapse;table-layout:fixed;}}
th{{background:#f7f7fa;color:#111;font-size:11.5px;letter-spacing:.05em;text-transform:uppercase;font-weight:950;line-height:1.18;padding:9px 8px;text-align:left;border-bottom:1px solid #e7e2ed;border-left:1px solid #eee8f4;white-space:normal;overflow-wrap:anywhere;}}
th:first-child{{border-left:0;}}
td{{font-size:12.5px;line-height:1.32;padding:8px 8px;vertical-align:top;border-top:1px solid #eee8f4;border-left:1px solid #eee8f4;white-space:normal;overflow-wrap:anywhere;word-break:normal;hyphens:auto;}}
td:first-child{{border-left:0;}}
tbody tr:nth-child(even){{background:#fbfafc;}}
tr.latest-row td{{font-weight:950 !important;}}
td.num{{text-align:right;font-weight:850;white-space:nowrap;}}
textarea{{position:absolute;left:-9999px;top:-9999px;}}
</style></head><body>
<div class='copybar'><button id='{ident}_btn'>Copy table</button><span id='{ident}_msg' class='msg'>Copies a formatted Excel-ready table.</span></div>
<textarea id='{ident}_tsv' readonly></textarea>
<div id='{ident}_wrap' class='table-wrap'>{html_table}</div>
<script>
const TSV = {js_tsv};
const HTML_TABLE = {js_html};
const ta = document.getElementById('{ident}_tsv');
ta.value = TSV;
const msg = document.getElementById('{ident}_msg');
async function clipboardItemCopy() {{
  if (navigator.clipboard && window.ClipboardItem) {{
    await navigator.clipboard.write([new ClipboardItem({{'text/html': new Blob([HTML_TABLE], {{type:'text/html'}}), 'text/plain': new Blob([TSV], {{type:'text/plain'}})}})]);
    return true;
  }}
  return false;
}}
function selectionHtmlCopy() {{
  const table = document.querySelector('#{ident}_wrap table');
  const range = document.createRange();
  range.selectNode(table);
  const sel = window.getSelection();
  sel.removeAllRanges(); sel.addRange(range);
  const handler = function(e) {{ e.clipboardData.setData('text/html', HTML_TABLE); e.clipboardData.setData('text/plain', TSV); e.preventDefault(); }};
  document.addEventListener('copy', handler);
  let ok = false;
  try {{ ok = document.execCommand('copy'); }} catch(err) {{ ok = false; }}
  document.removeEventListener('copy', handler);
  sel.removeAllRanges();
  return ok;
}}
function textCopy() {{
  try {{ ta.style.cssText='position:fixed;left:0;top:0;width:2px;height:2px;opacity:0;'; ta.focus(); ta.select(); return document.execCommand('copy'); }} catch(e) {{ return false; }}
}}
document.getElementById('{ident}_btn').addEventListener('click', async function(){{
  try {{ if (selectionHtmlCopy()) {{ msg.textContent='Copied as table. Paste into Excel / Teams.'; return; }} }} catch(e) {{}}
  try {{ if (await clipboardItemCopy()) {{ msg.textContent='Copied as table. Paste into Excel / Teams.'; return; }} }} catch(e) {{}}
  if (textCopy()) {{ msg.textContent='Copied as Excel-ready table text.'; }} else {{ msg.textContent='Clipboard blocked. Select the table and press Ctrl+C.'; }}
}});
</script></body></html>
"""
    height = max(180, min(16000, _estimate_component_height(headers2, rows2) + 18))
    components.html(doc, height=height, scrolling=False)


def render_scope_matrix(records: List[Dict[str, Any]], selected_year: int, selected_week: int) -> None:
    st.markdown("<div class='section-title'>Executive control matrix</div>", unsafe_allow_html=True)
    order = {"rail": 0, "ponds": 1, "roads": 2}
    records = sorted([_with_display_scope(r) for r in records if r.get("scope_id") in order], key=lambda r: order.get(r.get("scope_id"), 99))
    cols = st.columns(3)
    for col, rec in zip(cols, records):
        with col:
            construction_actual = rec.get("construction_actual")
            construction_forecast = rec.get("construction_forecast") if rec.get("construction_forecast") is not None else construction_actual
            construction_dev = rec.get("construction_deviation")
            if construction_dev is None and construction_actual is not None and construction_forecast is not None:
                construction_dev = construction_actual - construction_forecast
            engineering_actual = rec.get("engineering_actual")
            engineering_forecast = rec.get("engineering_forecast") if rec.get("engineering_forecast") is not None else engineering_actual
            engineering_dev = rec.get("engineering_deviation")
            if engineering_dev is None and engineering_actual is not None and engineering_forecast is not None:
                engineering_dev = engineering_actual - engineering_forecast
            construction_etc = _baseline_etc_for_scope(rec["scope_id"], selected_year, selected_week, mode="final")
            engineering_etc = rec.get("engineering_etc") or _baseline_etc_for_scope(rec["scope_id"], selected_year, selected_week, mode="next")
            icon = SCOPE_ICON.get(rec["scope_id"], COST_SCOPE_ICON.get(rec["scope_id"], "●"))
            html_block = (
                "<div class='matrix-col'>"
                "<div class='matrix-head'>"
                f"<h3><span class='scope-icon'>{icon}</span>{_html(rec['name'])}</h3>"
                f"<span class='status-badge'>{_html(_matrix_driver(rec))}</span>"
                "</div>"
                f"{progress_bar_html('Construction progress', construction_actual, construction_forecast, construction_dev, construction_etc, next_week_forecast=_next_progress_label(rec, selected_year, selected_week, 'construction'))}"
                f"{progress_bar_html('Engineering progress', engineering_actual, engineering_forecast, engineering_dev, engineering_etc, next_week_forecast=_next_progress_label(rec, selected_year, selected_week, 'engineering'))}"
                "<div class='gate-row'>"
                f"{_gate_pill_html('Open quality gates', len(rec.get('quality_items', [])), rec.get('quality_items', []))}"
                f"{_gate_pill_html('Open engineering gates', len(rec.get('engineering_items', [])), rec.get('engineering_items', []))}"
                "</div>"
                f"{_cost_plain_card_html_v25(rec['scope_id'], 'Cost position') if '_cost_plain_card_html_v25' in globals() else _cost_plain_html(rec['scope_id'])}"
                f"{_next_week_fc_html(rec.get('next_week_fc'))}"
                "</div>"
            )
            st.markdown(html_block, unsafe_allow_html=True)


def render_sidebar(bundle: Dict[str, Any]) -> str:
    logo_src = logo_mark_data_uri() or logo_data_uri()
    if logo_src:
        st.sidebar.markdown(f"<div class='sidebar-logo'><img src='{logo_src}'><span>Scope controls</span></div>", unsafe_allow_html=True)
    st.sidebar.title("Control settings")
    st.sidebar.markdown("<div class='subsection-title'>Panel</div>", unsafe_allow_html=True)
    visible_panels = ["Executive overview", COST_PANEL_LABEL, "Rail On Site (ROS)", "Ponds", "Roads"]
    if "panel_choice" not in st.session_state or st.session_state.get("panel_choice") not in visible_panels:
        st.session_state["panel_choice"] = visible_panels[0]
    icons = {"Executive overview":"▦", COST_PANEL_LABEL:"€", "Rail On Site (ROS)":"🚆", "Ponds":"💧", "Roads":"🛣️"}
    for label in visible_panels:
        if st.sidebar.button(f"{icons.get(label, '•')} {label}", key=f"nav_v26_{label}", use_container_width=True):
            st.session_state["panel_choice"] = label
    st.sidebar.markdown(f"<div class='nav-active'>Current panel: {_html(st.session_state['panel_choice'])}</div>", unsafe_allow_html=True)
    st.sidebar.caption(f"Loaded {latest_period_label(st.session_state['bundle'])} - {source_count(st.session_state['bundle'])} source reports")
    st.sidebar.markdown("<div class='nav-hint'>Week, cost month and baseline selectors are in the floating header. Upload files below.</div>", unsafe_allow_html=True)
    st.sidebar.markdown("---")
    st.sidebar.markdown("<div class='subsection-title'>Upload / refresh</div>", unsafe_allow_html=True)
    uploaded_weekly = st.sidebar.file_uploader("Upload new weekly report PDF/PPTX", type=["pdf", "pptx"], accept_multiple_files=True, key="weekly_upload_v26", help="Upload one or more weekly reports. The parser merges new report weeks into the current session.")
    if uploaded_weekly:
        key = _upload_list_hash(uploaded_weekly)
        if key != st.session_state.get("last_weekly_upload_key_v26"):
            with st.spinner("Parsing uploaded weekly report(s) and refreshing the control center..."):
                try:
                    incoming = parse_uploaded_reports(uploaded_weekly)
                    st.session_state["bundle"] = merge_bundles(st.session_state["bundle"], incoming)
                    st.session_state["last_weekly_upload_key_v26"] = key
                    st.sidebar.success(f"{len(uploaded_weekly)} weekly report(s) parsed and loaded.")
                except Exception as exc:
                    st.sidebar.error(f"Could not parse weekly upload: {exc}")
    uploaded_cost_reports = st.sidebar.file_uploader("Upload monthly cost report XLSX", type=["xlsx"], accept_multiple_files=True, key="cost_upload_v26", help="Upload one or more monthly cost reports. Each report is normalized, stored and added to the active-month selector.")
    if uploaded_cost_reports:
        key = _upload_list_hash(uploaded_cost_reports)
        if key != st.session_state.get("last_cost_upload_key_v26"):
            loaded = 0; errors: List[str] = []
            for uploaded in uploaded_cost_reports:
                try:
                    _register_uploaded_cost_report(uploaded)
                    loaded += 1
                except Exception as exc:
                    errors.append(f"{uploaded.name}: {exc}")
            st.session_state["last_cost_upload_key_v26"] = key
            try: cached_monthly_cost_reports.clear()
            except Exception: pass
            if loaded:
                refreshed = _cost_reports()
                if refreshed:
                    st.session_state["monthly_cost_report_choice_portfolio"] = refreshed[-1]["label"]
                st.sidebar.success(f"{loaded} cost report(s) uploaded and registered.")
            for msg in errors:
                st.sidebar.error(f"Could not parse cost report - {msg}")
            if loaded: _safe_rerun()
    uploaded_baselines = st.sidebar.file_uploader("Upload schedule baseline PDF", type=["pdf"], accept_multiple_files=True, key="baseline_upload_v26", help="Upload one or more baseline PDFs. Parsed baselines are added to the active-baseline selector.")
    if uploaded_baselines:
        key = _upload_list_hash(uploaded_baselines)
        if key != st.session_state.get("last_baseline_upload_key_v26"):
            loaded = 0; errors: List[str] = []
            for uploaded in uploaded_baselines:
                try:
                    _register_uploaded_baseline(uploaded)
                    loaded += 1
                except Exception as exc:
                    errors.append(f"{uploaded.name}: {exc}")
            st.session_state["last_baseline_upload_key_v26"] = key
            try: cached_baseline_schedules.clear()
            except Exception: pass
            if loaded:
                refreshed = _baseline_reports()
                if refreshed:
                    st.session_state["baseline_choice"] = refreshed[-1]["label"]
                st.sidebar.success(f"{loaded} baseline file(s) uploaded and registered.")
            for msg in errors:
                st.sidebar.error(f"Could not parse baseline - {msg}")
            if loaded: _safe_rerun()
    if st.sidebar.button("Save current session data", use_container_width=True):
        save_bundle(st.session_state["bundle"], DATA_PATH)
        try: cached_bundle.clear()
        except Exception: pass
        st.sidebar.success("Saved weekly data to data/weekly_data_bundle.json")
    return st.session_state["panel_choice"]


