# Delete the loading picture completely.
def render_loading_overlay() -> None:
    return None


def _selector_defaults_v26(bundle: Dict[str, Any]) -> None:
    periods = available_periods(bundle)
    labels = [period_display(y, w) for y, w in periods]
    if labels and st.session_state.get("week_selector_value") not in labels:
        st.session_state["week_selector_value"] = labels[-1]
    cost_labels = [r.get("label") for r in _cost_reports() if r.get("label")]
    if cost_labels and st.session_state.get("monthly_cost_report_choice_portfolio") not in cost_labels:
        st.session_state["monthly_cost_report_choice_portfolio"] = cost_labels[-1]
    bl_labels = [r.get("label") for r in _baseline_reports() if r.get("label")]
    if bl_labels and st.session_state.get("baseline_choice") not in bl_labels:
        st.session_state["baseline_choice"] = bl_labels[-1]


def _selected_period_from_state_v26(bundle: Dict[str, Any]) -> Tuple[int, int]:
    periods = available_periods(bundle)
    if not periods:
        return 2026, 0
    labels = [period_display(y, w) for y, w in periods]
    choice = st.session_state.get("week_selector_value")
    if choice not in labels:
        choice = labels[-1]
        st.session_state["week_selector_value"] = choice
    return periods[labels.index(choice)]


def _set_active_week_by_offset(offset: int) -> None:
    periods = available_periods(st.session_state.get("bundle", {}))
    labels = [period_display(y, w) for y, w in periods]
    if not labels:
        return
    current = st.session_state.get("week_selector_value")
    idx = labels.index(current) if current in labels else len(labels) - 1
    idx = max(0, min(len(labels) - 1, idx + int(offset)))
    st.session_state["week_selector_value"] = labels[idx]


def render_header(bundle: Dict[str, Any], selected_label: str) -> Tuple[int, int]:
    """Sticky top control center: title + week/month/baseline selectors + week nav."""
    sched_latest = latest_row(bundle.get("schedule", []))
    hse_latest = latest_row(bundle.get("hse", []))
    actual_date = _normalize_date_label(sched_latest.get("cutoff") or hse_latest.get("cutoff"))
    periods = available_periods(st.session_state.get("bundle", bundle))
    labels = [period_display(y, w) for y, w in periods]
    if labels and st.session_state.get("week_selector_value") not in labels:
        st.session_state["week_selector_value"] = labels[-1]
    current_idx = labels.index(st.session_state.get("week_selector_value")) if labels and st.session_state.get("week_selector_value") in labels else max(0, len(labels)-1)
    cost_labels = [r.get("label") for r in _cost_reports() if r.get("label")]
    baseline_labels = [r.get("label") for r in _baseline_reports() if r.get("label")]
    logo_src = logo_mark_data_uri() or logo_data_uri()
    logo_html = f"<div class='rc-logo-box'><img src='{logo_src}'></div>" if logo_src else ""
    try:
        header = st.container(key="top_control_header_v26")
    except TypeError:
        header = st.container()
    with header:
        st.markdown(
            "<div class='rc-title-row'>"
            f"{logo_html}"
            "<div><div class='rc-subtitle'>Rail - Ponds - Roads</div>"
            "<h1>Roger Campbell Scopes Control Center</h1></div>"
            "</div>",
            unsafe_allow_html=True,
        )
        cols = st.columns([1.12, 1.02, 1.16, .62, .62, 1.08], gap="small")
        with cols[0]:
            if labels:
                selected_week_label = st.selectbox("Actual week", labels, key="week_selector_value", label_visibility="visible")
            else:
                selected_week_label = selected_label
                st.markdown(f"<div class='actual-cutoff-pill'>Actual week: {_html(selected_week_label)}</div>", unsafe_allow_html=True)
        with cols[1]:
            if cost_labels:
                st.selectbox("Active month", cost_labels, key="monthly_cost_report_choice_portfolio", label_visibility="visible")
            else:
                st.markdown("<div class='actual-cutoff-pill'>Active month: N/A</div>", unsafe_allow_html=True)
        with cols[2]:
            if baseline_labels:
                st.selectbox("Active baseline", baseline_labels, key="baseline_choice", label_visibility="visible")
            else:
                st.markdown("<div class='actual-cutoff-pill'>Baseline: N/A</div>", unsafe_allow_html=True)
        with cols[3]:
            st.markdown("<div style='height:1.46rem'></div>", unsafe_allow_html=True)
            st.button("◀ Back", key="week_back_v26", use_container_width=True, disabled=current_idx <= 0, on_click=_set_active_week_by_offset, args=(-1,))
        with cols[4]:
            st.markdown("<div style='height:1.46rem'></div>", unsafe_allow_html=True)
            st.button("Next ▶", key="week_next_v26", use_container_width=True, disabled=(not labels or current_idx >= len(labels) - 1), on_click=_set_active_week_by_offset, args=(1,))
        with cols[5]:
            st.markdown("<div style='height:1.48rem'></div>", unsafe_allow_html=True)
            st.markdown(f"<div class='actual-cutoff-pill'><span>Cut-off:</span><small>{_html(actual_date)}</small></div>", unsafe_allow_html=True)
    return _selected_period_from_state_v26(st.session_state.get("bundle", bundle))


def render_sidebar(bundle: Dict[str, Any]) -> Tuple[str, int, int]:
    """Sidebar now only contains navigation and uploads; selectors live in the sticky header."""
    logo_src = logo_mark_data_uri() or logo_data_uri()
    if logo_src:
        st.sidebar.markdown(f"<div class='sidebar-logo'><img src='{logo_src}'><span>Scope controls</span></div>", unsafe_allow_html=True)
    st.sidebar.title("Control settings")
    st.sidebar.markdown("<div class='subsection-title'>Panel</div>", unsafe_allow_html=True)
    panel_labels = ["Executive overview", "Cost Status", "Rail On Site (ROS)", "Ponds", "Roads"]
    if st.session_state.get("panel_choice") not in panel_labels:
        st.session_state["panel_choice"] = "Executive overview"
    icons = {"Executive overview":"▦", "Cost Status":"€", "Rail On Site (ROS)":"🚆", "Ponds":"💧", "Roads":"🛣️"}
    for label in panel_labels:
        if st.sidebar.button(f"{icons.get(label,'•')} {label}", key=f"nav_v26_{label}", use_container_width=True):
            st.session_state["panel_choice"] = label
    st.sidebar.markdown(f"<div class='nav-active'>Current panel: {_html(st.session_state['panel_choice'])}</div>", unsafe_allow_html=True)
    st.sidebar.caption(f"Loaded {latest_period_label(st.session_state['bundle'])} - {source_count(st.session_state['bundle'])} source reports")

    st.sidebar.markdown("---")
    st.sidebar.markdown("<div class='subsection-title'>Upload / refresh</div>", unsafe_allow_html=True)
    uploaded_weekly = st.sidebar.file_uploader(
        "Upload new weekly report PDF/PPTX", type=["pdf", "pptx"], accept_multiple_files=True, key="weekly_upload_v26",
        help="Upload one or more weekly reports. The parser merges new report weeks into the current session.")
    if uploaded_weekly:
        key = _upload_list_hash(uploaded_weekly)
        if key != st.session_state.get("last_weekly_upload_key_v26"):
            with st.spinner("Parsing uploaded weekly report(s) and refreshing the control center..."):
                try:
                    incoming = parse_uploaded_reports(uploaded_weekly)
                    st.session_state["bundle"] = merge_bundles(st.session_state["bundle"], incoming)
                    st.session_state["last_weekly_upload_key_v26"] = key
                    st.sidebar.success(f"{len(uploaded_weekly)} weekly report(s) parsed and loaded.")
                    _safe_rerun()
                except Exception as exc:
                    st.sidebar.error(f"Could not parse weekly upload: {exc}")
    uploaded_cost_reports = st.sidebar.file_uploader(
        "Upload monthly cost report XLSX", type=["xlsx"], accept_multiple_files=True, key="cost_upload_v26",
        help="Upload one or more monthly cost reports. Each report is normalized, stored and added to the active-month selector.")
    if uploaded_cost_reports:
        key = _upload_list_hash(uploaded_cost_reports)
        if key != st.session_state.get("last_cost_upload_key_v26"):
            loaded = 0; errors: List[str] = []
            for uploaded in uploaded_cost_reports:
                try:
                    _register_uploaded_cost_report(uploaded); loaded += 1
                except Exception as exc:
                    errors.append(f"{uploaded.name}: {exc}")
            st.session_state["last_cost_upload_key_v26"] = key
            try: cached_monthly_cost_reports.clear()
            except Exception: pass
            if loaded:
                refreshed = _cost_reports()
                if refreshed: st.session_state["monthly_cost_report_choice_portfolio"] = refreshed[-1]["label"]
                st.sidebar.success(f"{loaded} cost report(s) uploaded and registered.")
            for msg in errors: st.sidebar.error(f"Could not parse cost report - {msg}")
            if loaded: _safe_rerun()
    uploaded_baselines = st.sidebar.file_uploader(
        "Upload schedule baseline PDF", type=["pdf"], accept_multiple_files=True, key="baseline_upload_v26",
        help="Upload one or more baseline PDFs. Parsed baselines are added to the baseline selector.")
    if uploaded_baselines:
        key = _upload_list_hash(uploaded_baselines)
        if key != st.session_state.get("last_baseline_upload_key_v26"):
            loaded = 0; errors: List[str] = []
            for uploaded in uploaded_baselines:
                try:
                    _register_uploaded_baseline(uploaded); loaded += 1
                except Exception as exc:
                    errors.append(f"{uploaded.name}: {exc}")
            st.session_state["last_baseline_upload_key_v26"] = key
            try: cached_baseline_schedules.clear()
            except Exception: pass
            if loaded:
                refreshed = _baseline_reports()
                if refreshed: st.session_state["baseline_choice"] = refreshed[-1]["label"]
                st.sidebar.success(f"{loaded} baseline file(s) uploaded and registered.")
            for msg in errors: st.sidebar.error(f"Could not parse baseline - {msg}")
            if loaded: _safe_rerun()
    if st.sidebar.button("Save current session data", use_container_width=True):
        save_bundle(st.session_state["bundle"], DATA_PATH)
        try: cached_bundle.clear()
        except Exception: pass
        st.sidebar.success("Saved weekly data to data/weekly_data_bundle.json")
    y, w = _selected_period_from_state_v26(st.session_state.get("bundle", bundle))
    return st.session_state["panel_choice"], int(y), int(w)


def _split_fc_items(value: Any) -> List[str]:
    text = str(value or "").strip()
    if not text:
        return []
    parts = re.split(r"\s*[;•]\s*|\s+\|\s+", text)
    clean = [p.strip(" -") for p in parts if p and p.strip(" -")]
    return clean or [text]


def _next_week_fc_box_html(rec: Dict[str, Any]) -> str:
    items = _split_fc_items(rec.get("next_week_fc"))
    if not items:
        items = ["Not published in selected-week data"]
    body = "".join(f"<li>{_html(item)}</li>" for item in items[:8])
    return f"<div class='next-fc'><b>Next week FC</b><ul>{body}</ul></div>"


def _gate_details_html(title: str, count: int, items: List[Any]) -> str:
    if not items:
        body = "<div><span class='idx'>--</span>No active-week items extracted.</div>"
    else:
        body = "".join(f"<div><span class='idx'>{i:02d}</span>{_html(clean_action_text(it.get('issue') or it.get('action') or it.get('description') or '') if isinstance(it, dict) else str(it))}</div>" for i, it in enumerate(items[:30], start=1))
    return (
        "<details class='gate-details'>"
        f"<summary><span>{_html(title)}</span><b>{int(count)}</b></summary>"
        f"<div class='gate-panel'><div class='gate-row-list'>{body}</div></div>"
        "</details>"
    )


def render_scope_matrix(records: List[Dict[str, Any]], selected_year: int, selected_week: int) -> None:
    st.markdown("<div class='section-title'>Executive control matrix</div>", unsafe_allow_html=True)
    cost_data = _active_cost_report().get("data") if "_active_cost_report" in globals() else _select_cost_report("portfolio")
    order = {"rail": 0, "ponds": 1, "roads": 2}
    records = sorted([_with_display_scope(r) for r in records if r.get("scope_id") in order], key=lambda r: order.get(r.get("scope_id"), 99))
    cols = st.columns(3, gap="large")
    for col, rec in zip(cols, records):
        with col:
            construction_actual = rec.get("construction_actual")
            construction_forecast = rec.get("construction_forecast") if rec.get("construction_forecast") is not None else construction_actual
            construction_dev = rec.get("construction_deviation")
            if construction_dev is None and construction_actual is not None and construction_forecast is not None:
                construction_dev = construction_actual - construction_forecast
            engineering_actual = rec.get("engineering_actual")
            engineering_forecast = rec.get("engineering_forecast") if rec.get("engineering_forecast") is not None else engineering_actual
            engineering_dev = rec.get("engineering_deviation")
            if engineering_dev is None and engineering_actual is not None and engineering_forecast is not None:
                engineering_dev = engineering_actual - engineering_forecast
            construction_etc = _baseline_etc_for_scope(rec["scope_id"], selected_year, selected_week, mode="final")
            engineering_etc = rec.get("engineering_etc") or _baseline_etc_for_scope(rec["scope_id"], selected_year, selected_week, mode="next")
            icon = SCOPE_ICON.get(rec["scope_id"], COST_SCOPE_ICON.get(rec["scope_id"], "●"))
            html_block = (
                "<div class='matrix-col'>"
                "<div class='matrix-head'>"
                f"<h3><span class='scope-icon'>{icon}</span>{_html(rec['name'])}</h3>"
                f"<span class='status-badge'>{_html(_matrix_driver(rec))}</span>"
                "</div>"
                f"{progress_bar_html('Construction progress', construction_actual, construction_forecast, construction_dev, construction_etc, next_week_forecast=_next_progress_label(rec, selected_year, selected_week, 'construction'))}"
                f"{progress_bar_html('Engineering progress', engineering_actual, engineering_forecast, engineering_dev, engineering_etc, next_week_forecast=_next_progress_label(rec, selected_year, selected_week, 'engineering'))}"
                f"{_next_week_fc_box_html(rec)}"
                "<div class='gate-row'>"
                f"{_gate_details_html('Open quality gates', len(rec.get('quality_items', [])), rec.get('quality_items', []))}"
                f"{_gate_details_html('Open engineering gates', len(rec.get('engineering_items', [])), rec.get('engineering_items', []))}"
                "</div>"
                f"{_cost_plain_html(rec['scope_id'], cost_data)}"
                "</div>"
            )
            st.markdown(html_block, unsafe_allow_html=True)


def _history_hover_text(scope_id: str, metric_key: str, active_cost_data: Optional[Dict[str, Any]]) -> str:
    hist = _cost_history_for_scope(scope_id, active_cost_data, max_months=3) if "_cost_history_for_scope" in globals() else []
    if not hist:
        return "No cost history loaded"
    # Latest first in hover list.
    active_label = _active_month_label_from_cost(active_cost_data or {})
    lines = []
    for label, vals in reversed(hist):
        val = (vals or {}).get(metric_key)
        strong_open = "<b>" if str(label) == str(active_label) else ""
        strong_close = "</b>" if str(label) == str(active_label) else ""
        lines.append(f"{strong_open}{_html(label)}: {_html(_fmt_money_full(val))}{strong_close}")
    return "<br>".join(lines)


def _cost_kpi_hover(scope_id: str, metric_key: str, metric_label: str, active_label: str) -> str:
    df = _history_for_scope(scope_id)
    if df.empty or metric_label not in df.columns:
        return "<div class='cost-kpi-tip'><h4>No history available</h4></div>"
    if active_label in set(df["Month"].astype(str)):
        active_idx = df.index[df["Month"].astype(str) == active_label].tolist()[-1]
        subset = df.loc[:active_idx].tail(6)
    else:
        subset = df.tail(6)
    chronological = [(str(r["Month"]), r.get(metric_label)) for _, r in subset.iterrows()]
    svg = _svg_sparkline(chronological, active_label)
    rows = []
    for label, val in reversed(chronological):
        cls = "hist-row active" if label == active_label else "hist-row"
        rows.append(f"<div class='{cls}'><span>{_html(label)}</span><b>{_html(_fmt_money(val))}</b></div>")
    return f"<div class='cost-kpi-tip'><h4>{_html(metric_label)} - recent history</h4>{svg}<div class='active-line'>Active value highlighted. List shown latest to oldest.</div>{''.join(rows)}</div>"


def _cost_waterfall_figure_v24(scope_id: str, cost_data: Optional[Dict[str, Any]] = None, title: str = "Cost waterfall") -> go.Figure:
    cost_data = cost_data or (_active_cost_report().get("data") or cached_monthly_cost())
    if scope_id == "all":
        row = _active_history_row("all")
        budget = _safe_float(row.get("Budget")) or 0.0
        co = _safe_float(row.get("CO")) or 0.0
        forecast = _safe_float(row.get("Forecast")) if row.get("Forecast") is not None else budget + co
        exposure = _safe_float(row.get("Potential exposure")) or 0.0
        potential_forecast = _safe_float(row.get("Potential forecast")) if row.get("Potential forecast") is not None else (forecast or 0) + exposure
    else:
        nums = _cost_numbers(scope_id, cost_data)
        budget = _safe_float(nums.get("budget")) or 0.0
        forecast = _safe_float(nums.get("forecast"))
        co = (forecast - budget) if forecast is not None else (_safe_float(nums.get("change_order")) or 0.0)
        forecast = forecast if forecast is not None else budget + co
        exposure = _safe_float(nums.get("potential_exposure")) or 0.0
        potential_forecast = _safe_float(nums.get("potential_forecast")) if nums.get("potential_forecast") is not None else forecast + exposure
    labels = ["Budget", "CO", "Forecast", "Potential exposure", "Potential forecast"]
    y_vals = [budget, co, forecast, exposure, potential_forecast]
    running = [budget, budget + co, forecast, forecast + exposure, potential_forecast]
    measures = ["absolute", "relative", "total", "relative", "total"]
    active_label = _active_cost_report().get("label") or _active_month_label_from_cost(cost_data)
    metric_map = {"Budget":"Budget", "CO":"CO", "Forecast":"Forecast", "Potential exposure":"Potential exposure", "Potential forecast":"Potential forecast"}
    custom = []
    df = _history_for_scope(scope_id)
    for label, val, run in zip(labels, y_vals, running):
        hist_lines = []
        if not df.empty and metric_map[label] in df.columns:
            sub = df[["Month", metric_map[label]]].tail(3)
            for _, r in sub.iloc[::-1].iterrows():
                strong_open = "<b>" if str(r["Month"]) == str(active_label) else ""
                strong_close = "</b>" if str(r["Month"]) == str(active_label) else ""
                hist_lines.append(f"{strong_open}{r['Month']}: {_fmt_money(r[metric_map[label]])}{strong_close}")
        custom.append([label, _fmt_money_full(val), _fmt_money_full(run), active_label, "<br>".join(hist_lines)])
    fig = go.Figure(go.Waterfall(
        x=labels, y=y_vals, measure=measures, text=[_fmt_money(v) for v in y_vals], textposition="outside",
        connector={"line":{"color":"#9aa1ad","width":1}}, increasing={"marker":{"color":"#007a45"}}, decreasing={"marker":{"color":"#c73535"}}, totals={"marker":{"color":"#c76df1"}},
        customdata=custom,
        hovertemplate=("<b>%{customdata[0]}</b><br>Active month: %{customdata[3]}<br>Step value: %{customdata[1]}<br>Cost position after step: %{customdata[2]}<br><br><b>Last 3 monthly values</b><br>%{customdata[4]}<extra></extra>"),
    ))
    fig.update_layout(title={"text": title, "x":0.02, "xanchor":"left", "font":{"size":18}}, height=410, margin=dict(l=34,r=24,t=62,b=78), paper_bgcolor="rgba(0,0,0,0)", plot_bgcolor="rgba(0,0,0,0)", yaxis_title="EUR", showlegend=False, hovermode="closest")
    fig.update_xaxes(tickangle=-22)
    return fig


def _cost_history_table_rows(scope_id: str) -> List[List[Any]]:
    df = _history_for_scope(scope_id)
    if df.empty:
        return []
    # Latest to oldest.
    sort_col = "Date" if "Date" in df.columns else None
    if sort_col:
        df = df.sort_values(sort_col, ascending=False, na_position="last")
    else:
        df = df.iloc[::-1]
    rows = []
    for _, r in df.iterrows():
        rows.append([
            r.get("Month"),
            _fmt_money_full(r.get("Budget")),
            _fmt_money_full(r.get("CO")),
            _fmt_money_full(r.get("Forecast")),
            _fmt_money_full(r.get("VOWD")),
            _fmt_money_full(r.get("ETC")),
            _fmt_money_full(r.get("Potential exposure")),
            _fmt_money_full(r.get("Potential forecast")),
            _fmt_money_full(r.get("Budget + CO check")),
            _fmt_money_full(r.get("Forecast + exposure check")),
        ])
    return rows


def _preferred_col_widths(headers: List[str]) -> List[int]:
    lower = [str(h).lower() for h in headers]
    n = len(headers)
    if n == 5 and "scope" in lower[0] and "action" in lower[1]:
        return [9, 52, 18, 11, 10]
    if n == 4 and "action" in lower[0]:
        return [60, 18, 12, 10]
    if n == 10 and "month" in lower[0]:
        return [10,9,8,10,9,9,12,13,10,10]
    if n >= 8 and any("driver" in h or "description" in h for h in lower):
        return [9,18,9,8,8,8,8,10,22][:n]
    if n == 8 and "description" in lower[5]:
        return [8,10,9,9,8,36,10,10]
    return [max(8, int(100 / max(1, n)))] * n


def _estimate_component_height(headers: List[str], rows: List[List[Any]]) -> int:
    widths = _preferred_col_widths(headers)
    total = 88
    for row in rows:
        max_lines = 1
        for i, cell in enumerate(row):
            text = str(cell or "")
            width_pct = widths[i] if i < len(widths) else 12
            chars_per_line = max(10, int(width_pct * 1.70))
            lines = max(1, math.ceil(len(text) / chars_per_line))
            max_lines = max(max_lines, min(18, lines))
        total += 34 + max_lines * 17
    return max(190, min(18000, total + 25))


def _copyable_table_component(headers: List[str], rows: List[List[Any]], numeric_cols: Optional[set] = None, key_prefix: str = "tbl") -> None:
    numeric_cols = numeric_cols or set()
    if not rows:
        st.markdown("<div class='action-empty'>No rows available for this active selection.</div>", unsafe_allow_html=True)
        return
    keep = _table_column_keep(headers, rows)
    headers2 = [headers[i] for i in keep]
    rows2 = [[row[i] if i < len(row) else "" for i in keep] for row in rows]
    numeric2 = {new_i for new_i, old_i in enumerate(keep) if old_i in numeric_cols}
    tsv = "\n".join(["\t".join(str(h or "") for h in headers2)] + ["\t".join(str(c or "") for c in row) for row in rows2])
    widths = _preferred_col_widths(headers2)
    if len(widths) != len(headers2):
        widths = [int(100 / max(1, len(headers2)))] * len(headers2)
    colgroup = "".join(f"<col style='width:{w}%;'>" for w in widths)
    table_head = "".join(f"<th>{html.escape(str(h or ''))}</th>" for h in headers2)
    is_cost_history = "cost" in str(key_prefix).lower() and headers2 and str(headers2[0]).lower().startswith("month")
    body = []
    for ri, row in enumerate(rows2):
        row_class = "latest-row" if is_cost_history and ri == 0 else ""
        cells = []
        for ci, val in enumerate(row):
            cls = "num" if ci in numeric2 else ""
            cells.append(f"<td class='{cls}'>{html.escape(str(val or ''))}</td>")
        body.append(f"<tr class='{row_class}'>{''.join(cells)}</tr>")
    ident = "tbl_" + hashlib.sha1((key_prefix + tsv).encode("utf-8", "ignore")).hexdigest()[:12]
    html_table = f"<table><colgroup>{colgroup}</colgroup><thead><tr>{table_head}</tr></thead><tbody>{''.join(body)}</tbody></table>"
    js_tsv = json.dumps(tsv)
    js_html = json.dumps("<html><head><meta charset='utf-8'></head><body>" + html_table + "</body></html>")
    doc = f"""
<!doctype html><html><head><meta charset='utf-8'>
<style>
body{{margin:0;font-family:Inter,Segoe UI,Arial,sans-serif;color:#1f2937;background:transparent;}}
.copybar{{display:flex;gap:8px;align-items:center;margin:0 0 8px 0;}}
.copybar button{{border:1px solid #d9c3ee;background:#fff;color:#39135c;border-radius:999px;padding:7px 13px;font-weight:900;font-size:12px;cursor:pointer;}}
.copybar button:hover{{background:#f8f3fd;border-color:#6f2da8;}}
.copybar .msg{{font-size:12px;color:#667085;}}
.table-wrap{{width:100%;border:1px solid #e7e2ed;border-radius:15px;overflow:hidden;background:#fff;box-shadow:0 1px 8px rgba(17,17,17,.04);}}
table{{width:100%;border-collapse:collapse;table-layout:fixed;}}
th{{background:#f7f7fa;color:#111;font-size:11px;letter-spacing:.06em;text-transform:uppercase;font-weight:900;line-height:1.18;padding:9px 8px;text-align:left;border-bottom:1px solid #e7e2ed;border-left:1px solid #eee8f4;white-space:normal;overflow-wrap:anywhere;}}
th:first-child{{border-left:0;}}
td{{font-size:12.5px;line-height:1.32;padding:8px 8px;vertical-align:top;border-top:1px solid #eee8f4;border-left:1px solid #eee8f4;white-space:normal;overflow-wrap:anywhere;word-break:normal;hyphens:auto;}}
td:first-child{{border-left:0;}}
tbody tr:nth-child(even){{background:#fbfafc;}}
tbody tr.latest-row td:first-child{{font-weight:950!important;background:#f8f3fd!important;color:#111!important;}}
tbody tr.latest-row td:not(:first-child){{font-weight:400!important;background:inherit!important;color:#1f2937!important;}}
td.num{{text-align:right;font-weight:850;white-space:nowrap;}}
textarea{{position:absolute;left:-9999px;top:-9999px;}}
</style></head><body>
<div class='copybar'><button id='{ident}_btn'>Copy table</button><span id='{ident}_msg' class='msg'>Copies an Excel-ready table.</span></div>
<textarea id='{ident}_tsv' readonly></textarea>
<div id='{ident}_wrap' class='table-wrap'>{html_table}</div>
<script>
const TSV = {js_tsv};
const HTML_TABLE = {js_html};
const ta = document.getElementById('{ident}_tsv');
ta.value = TSV;
const msg = document.getElementById('{ident}_msg');
function selectRenderedTable() {{
  const table = document.querySelector('#{ident}_wrap table');
  const range = document.createRange();
  range.selectNode(table);
  const sel = window.getSelection();
  sel.removeAllRanges();
  sel.addRange(range);
}}
async function richClipboard() {{
  if (navigator.clipboard && window.ClipboardItem) {{
    const item = new ClipboardItem({{'text/html': new Blob([HTML_TABLE], {{type:'text/html'}}),'text/plain': new Blob([TSV], {{type:'text/plain'}})}});
    await navigator.clipboard.write([item]);
    return true;
  }}
  return false;
}}
function execCopyTable() {{
  try {{ selectRenderedTable(); const ok = document.execCommand('copy'); window.getSelection().removeAllRanges(); return ok; }} catch(e) {{ return false; }}
}}
function execCopyText() {{
  try {{ ta.style.cssText='position:fixed;left:0;top:0;width:2px;height:2px;opacity:0;'; ta.focus(); ta.select(); return document.execCommand('copy'); }} catch(e) {{ return false; }}
}}
document.getElementById('{ident}_btn').addEventListener('click', async function(){{
  if (execCopyTable()) {{ msg.textContent='Copied as a real table. Paste into Excel / Teams.'; return; }}
  try {{ if (await richClipboard()) {{ msg.textContent='Copied as formatted table. Paste into Excel / Teams.'; return; }} }} catch(e) {{}}
  if (execCopyText()) {{ msg.textContent='Copied as tab-separated table. Paste into Excel.'; return; }}
  msg.textContent='Clipboard blocked. Select the table and press Ctrl+C.';
}});
</script></body></html>
"""
    height = _estimate_component_height(headers2, rows2)
    components.html(doc, height=height, scrolling=False)


def render_cost_panel(bundle: Dict[str, Any], profiles: Dict[str, Any], selected_year: int, selected_week: int, current_date: Optional[pd.Timestamp] = None) -> None:
    active_report = _active_cost_report()
    active_month = active_report.get("label") or _active_month_label_from_cost(active_report.get("data") or {})
    cost_data = active_report.get("data") or cached_monthly_cost()
    meta = cost_data.get("metadata") or {}
    st.markdown(
        "<div class='cost-status-top'><h2>Cost Status</h2>"
        "<p>Dedicated cost-control view for Rail On Site (ROS), Ponds and Roads. Cost history is shown latest to oldest; the latest month is bold in monthly tables and the active value is highlighted in KPI hover timelines and charts.</p>"
        f"<div class='cost-v24-controls'><span class='cost-v24-pill'>Active month: {_html(active_month)}</span><span class='cost-v24-pill'>Currency: {_html(meta.get('currency') or 'EUR')}</span><span class='cost-v24-pill'>Reports loaded: {len(_cost_reports())}</span></div>"
        "</div>", unsafe_allow_html=True)
