    scope_id = label_to_id.get(selected_scope_label, "all")
    st.markdown(f"<div class='section-title'>{_html(COST_SCOPE_ICON.get(scope_id,'▦'))} {_html(selected_scope_label)} - cost control dashboard</div>", unsafe_allow_html=True)
