def render_header(bundle: Dict[str, Any], selected_label: str) -> Tuple[int, int]:
    """Sticky top control center: title + all dropdown selectors + week nav."""
    sched_latest = latest_row(bundle.get("schedule", []))
    hse_latest = latest_row(bundle.get("hse", []))
    actual_date = _normalize_date_label(sched_latest.get("cutoff") or hse_latest.get("cutoff"))
    periods = available_periods(st.session_state.get("bundle", bundle))
    labels = [period_display(y, w) for y, w in periods]
    if labels and st.session_state.get("week_selector_value") not in labels:
        st.session_state["week_selector_value"] = labels[-1]
    current_idx = labels.index(st.session_state.get("week_selector_value")) if labels and st.session_state.get("week_selector_value") in labels else max(0, len(labels)-1)
    cost_labels = [r.get("label") for r in _cost_reports() if r.get("label")]
    baseline_labels = [r.get("label") for r in _baseline_reports() if r.get("label")]
    scope_labels = list(COST_SCOPE_OPTIONS.values()) if "COST_SCOPE_OPTIONS" in globals() else ["All scopes", "Rail On Site (ROS)", "Ponds", "Roads"]
    if st.session_state.get("cost_scope_visual_selector") not in scope_labels:
        st.session_state["cost_scope_visual_selector"] = scope_labels[0]
    logo_src = logo_mark_data_uri() or logo_data_uri()
    logo_html = f"<div class='rc-logo-box'><img src='{logo_src}'></div>" if logo_src else ""
    try:
        header = st.container(key="top_control_header_v26")
    except TypeError:
        header = st.container()
    with header:
        st.markdown(
            "<div class='rc-title-row'>"
            f"{logo_html}"
            "<div><div class='rc-subtitle'>Rail - Ponds - Roads</div>"
            "<h1>Roger Campbell Scopes Control Center</h1></div>"
            "</div>",
            unsafe_allow_html=True,
        )
        cols = st.columns([1.05, .92, .98, 1.08, .56, .56, .94], gap="small")
        with cols[0]:
            if labels:
                st.selectbox("Actual week", labels, key="week_selector_value", label_visibility="visible")
            else:
                st.markdown(f"<div class='actual-cutoff-pill'>Actual week: {_html(selected_label)}</div>", unsafe_allow_html=True)
        with cols[1]:
            if cost_labels:
                st.selectbox("Active month", cost_labels, key="monthly_cost_report_choice_portfolio", label_visibility="visible")
            else:
                st.markdown("<div class='actual-cutoff-pill'>Active month: N/A</div>", unsafe_allow_html=True)
        with cols[2]:
            st.markdown("<div class='cost-scope-compact'>", unsafe_allow_html=True)
            st.selectbox("Cost scope", scope_labels, key="cost_scope_visual_selector", label_visibility="visible")
            st.markdown("</div>", unsafe_allow_html=True)
        with cols[3]:
            if baseline_labels:
                st.selectbox("Active baseline", baseline_labels, key="baseline_choice", label_visibility="visible")
            else:
                st.markdown("<div class='actual-cutoff-pill'>Baseline: N/A</div>", unsafe_allow_html=True)
        with cols[4]:
            st.markdown("<div style='height:1.46rem'></div>", unsafe_allow_html=True)
            st.button("< Back", key="week_back_v261", use_container_width=True, disabled=current_idx <= 0, on_click=_set_active_week_by_offset, args=(-1,))
        with cols[5]:
            st.markdown("<div style='height:1.46rem'></div>", unsafe_allow_html=True)
            st.button("Next >", key="week_next_v261", use_container_width=True, disabled=(not labels or current_idx >= len(labels) - 1), on_click=_set_active_week_by_offset, args=(1,))
        with cols[6]:
            st.markdown("<div style='height:1.48rem'></div>", unsafe_allow_html=True)
            st.markdown(f"<div class='actual-cutoff-pill'><span>Cut-off:</span><small>{_html(actual_date)}</small></div>", unsafe_allow_html=True)
    return _selected_period_from_state_v26(st.session_state.get("bundle", bundle))


def render_cost_panel(bundle: Dict[str, Any], profiles: Dict[str, Any], selected_year: int, selected_week: int, current_date: Optional[pd.Timestamp] = None) -> None:
    active_report = _active_cost_report()
    active_month = active_report.get("label") or _active_month_label_from_cost(active_report.get("data") or {})
    cost_data = active_report.get("data") or cached_monthly_cost()
    meta = cost_data.get("metadata") or {}
    st.markdown(
        "<div class='cost-status-top'><h2>Cost Status</h2>"
        "<p>Dedicated cost-control view for Rail On Site (ROS), Ponds and Roads. Cost history is shown latest to oldest; the latest month cell is bold in monthly tables and the active value is highlighted in KPI hover timelines and charts.</p>"
        f"<div class='cost-v24-controls'><span class='cost-v24-pill'>Active month: {_html(active_month)}</span><span class='cost-v24-pill'>Currency: {_html(meta.get('currency') or 'EUR')}</span><span class='cost-v24-pill'>Reports loaded: {len(_cost_reports())}</span></div>"
        "</div>", unsafe_allow_html=True)
    labels = list(COST_SCOPE_OPTIONS.values()) if "COST_SCOPE_OPTIONS" in globals() else ["All scopes", "Rail On Site (ROS)", "Ponds", "Roads"]
    label_to_id = {v: k for k, v in COST_SCOPE_OPTIONS.items()} if "COST_SCOPE_OPTIONS" in globals() else {"All scopes":"all","Rail On Site (ROS)":"rail","Ponds":"ponds","Roads":"roads"}
    selected_scope_label = st.session_state.get("cost_scope_visual_selector", "All scopes")
    if selected_scope_label not in labels:
        selected_scope_label = labels[0]
        st.session_state["cost_scope_visual_selector"] = selected_scope_label
    scope_id = label_to_id.get(selected_scope_label, "all")
    st.markdown(f"<div class='cost-scope-current-pill'>Scope visualized: {_html(selected_scope_label)}</div>", unsafe_allow_html=True)
    st.markdown(f"<div class='section-title'>{_html(COST_SCOPE_ICON.get(scope_id,'*'))} {_html(selected_scope_label)} - cost control dashboard</div>", unsafe_allow_html=True)
    try:
        _render_cost_kpi_cards(scope_id)
    except Exception:
        pass
    try:
        _cost_health_cards(scope_id)
    except Exception:
        pass
    if scope_id == "all":
        left, right = st.columns([1.0, 1.35], gap="large")
        with left:
            with st.container(border=True):
                st.markdown("**Active month comparison**")
                st.plotly_chart(_cost_scope_comparison_figure(), use_container_width=True)
        with right:
            with st.container(border=True):
                st.markdown("**Portfolio historical trend**")
                st.plotly_chart(_cost_history_trend_figure("all"), use_container_width=True)
        with st.container(border=True):
            st.markdown("**Active-month scope summary**")
            _copyable_table_component(["Scope", "Budget", "CO", "Forecast", "VOWD", "ETC", "Potential exposure", "Potential forecast"], _active_scope_summary_rows(), key_prefix="cost_scope_summary_v261")
    else:
        left, right = st.columns([1.0, 1.35], gap="large")
        with left:
            with st.container(border=True):
                st.markdown("**Waterfall / candle bar**")
                st.plotly_chart(_cost_waterfall_figure_v24(scope_id, cost_data, title=f"{selected_scope_label} waterfall"), use_container_width=True)
        with right:
            with st.container(border=True):
                st.markdown("**Historical cost trend**")
                st.plotly_chart(_cost_history_trend_figure(scope_id), use_container_width=True)
        drivers = _cost_driver_rows(scope_id) if "_cost_driver_rows" in globals() else []
        if drivers:
            with st.container(border=True):
                st.markdown("**Package drivers - active month**")
                _copyable_table_component(["Package", "Description", "Supplier", "Budget", "CO", "Forecast", "Exposure", "Potential forecast", "Driver / note"], drivers, numeric_cols={3,4,5,6,7}, key_prefix=f"cost_drivers_{scope_id}_v261")
        exposures = _cost_exposure_rows(scope_id) if "_cost_exposure_rows" in globals() else []
        if exposures:
            with st.container(border=True):
                st.markdown("**Potential exposure / O&V items - active month**")
                _copyable_table_component(["Item", "Package", "Amount", "Criticality", "Type", "Description", "Responsible", "Expected / award date"], exposures, numeric_cols={2}, key_prefix=f"cost_exposures_{scope_id}_v261")
    with st.container(border=True):
        st.markdown("**Monthly cost history**")
        _copyable_table_component(["Month", "Budget", "CO", "Forecast", "VOWD", "ETC", "Potential exposure", "Potential forecast", "Budget + CO check", "Forecast + exposure check"], _cost_history_table_rows(scope_id), numeric_cols={1,2,3,4,5,6,7,8,9}, key_prefix=f"cost_monthly_history_{scope_id}_v261")



# v26.2: gate lists use native popover, so they stay open for review and close on outside click.
def _gate_details_html(title: str, count: int, items: List[Any]) -> str:
    token = hashlib.sha1((title + str(count) + "|" + "|".join(map(str, items[:30]))).encode("utf-8", "ignore")).hexdigest()[:12]
    pid = f"gate_pop_{token}"
    if not items:
        body = "<div class='gate-popover-empty'>No active-week items extracted.</div>"
    else:
        rows = []
        for i, it in enumerate(items[:40], start=1):
            text = clean_action_text(it.get("issue") or it.get("action") or it.get("description") or "") if isinstance(it, dict) else str(it)
            rows.append(f"<div class='gate-popover-row'><b>{i:02d}</b>&nbsp;&nbsp;{_html(text)}</div>")
        body = "".join(rows)
    return (
        "<div class='gate-pill'>"
        f"<button type='button' class='gate-click-surface' popovertarget='{pid}' popovertargetaction='toggle'>"
        f"<span>{_html(title)}</span><b>{int(count)}</b><small>Click to open list</small></button>"
        f"<div id='{pid}' class='gate-popover' popover><div class='gate-popover-inner'>"
        f"<div class='gate-popover-title'>{_html(title)} - active week</div>{body}"
        "</div></div></div>"
    )



