def render_executive_overview(bundle: Dict[str, Any], profiles: Dict[str, Any], selected_year: int, selected_week: int, current_date: Optional[pd.Timestamp] = None) -> None:
    records = build_scope_records(bundle, profiles, selected_year, selected_week, scopes=CONTROL_SCOPES)
    selected_label = period_display(selected_year, selected_week)
    cutoff = current_date if current_date is not None else selected_cutoff_date(bundle)
    render_scope_matrix(records, selected_year, selected_week)
    render_executive_priority_delayed_near_table(records, selected_label, selected_year, selected_week, current_date=cutoff)
    render_milestone_timeline(records, title="Milestones", selected_year=selected_year, selected_week=selected_week, current_date=cutoff)


def main() -> None:
    if "bundle" not in st.session_state:
        st.session_state["bundle"] = cached_bundle(DATA_PATH.stat().st_mtime_ns)
    profiles = cached_profiles()
    _selector_defaults_v27(st.session_state["bundle"])
    panel_choice, _sy, _sw = render_sidebar(st.session_state["bundle"])
    sy0, sw0 = _selected_period_from_state_v27(st.session_state["bundle"])
    view_bundle_initial = filter_bundle_until(st.session_state["bundle"], sy0, sw0)
    selected_label_initial = period_display(sy0, sw0)
    selected_year, selected_week = render_header(view_bundle_initial, selected_label_initial, panel_choice=panel_choice)
    view_bundle = filter_bundle_until(st.session_state["bundle"], selected_year, selected_week)
    selected_cutoff = selected_cutoff_date(view_bundle)
    if panel_choice == "Executive overview":
        render_executive_overview(st.session_state["bundle"], profiles, selected_year, selected_week, current_date=selected_cutoff)
    elif panel_choice in {"Cost Status", globals().get("COST_PANEL_LABEL", "Cost Status")}:
        render_cost_panel(st.session_state["bundle"], profiles, selected_year, selected_week, current_date=selected_cutoff)
    else:
        render_scope_panel(st.session_state["bundle"], profiles, SCOPE_PANEL_MAP[panel_choice], selected_year, selected_week, current_date=selected_cutoff)
    st.markdown(
        "<div class='footer-note'>Data source: uploaded weekly reports, the Rail On Site May 2026 reference presentation, BL CC E006 schedule baseline, Budget Forecast Roads-Rail-Ponds reference presentation, and selectable monthly cost reports. This app is focused only on Rail On Site (ROS), Ponds and Roads. Week labels include year to support 2024, 2025, 2026 and future history uploads.</div>",
        unsafe_allow_html=True,
    )


# v27.1: use native Streamlit bordered containers for cost charts so charts visibly stay inside cards.
def render_cost_panel(bundle: Dict[str, Any], profiles: Dict[str, Any], selected_year: int, selected_week: int, current_date: Optional[pd.Timestamp] = None) -> None:
    active_report = _active_cost_report()
    active_month = active_report.get("label") or _active_month_label_from_cost(active_report.get("data") or {})
    cost_data = active_report.get("data") or cached_monthly_cost()
    meta = cost_data.get("metadata") or {}
    labels = list(COST_SCOPE_OPTIONS.values()) if "COST_SCOPE_OPTIONS" in globals() else ["All scopes", "Rail On Site (ROS)", "Ponds", "Roads"]
    label_to_id = {v: k for k, v in COST_SCOPE_OPTIONS.items()} if "COST_SCOPE_OPTIONS" in globals() else {"All scopes":"all", "Rail On Site (ROS)":"rail", "Ponds":"ponds", "Roads":"roads"}
    selected_scope_label = st.session_state.get("cost_scope_visual_selector", "All scopes")
    if selected_scope_label not in labels:
        selected_scope_label = labels[0]
        st.session_state["cost_scope_visual_selector"] = selected_scope_label
    scope_id = label_to_id.get(selected_scope_label, "all")
    st.markdown(
        f"<div class='cost-detail-card'><div class='cost-detail-grid'>"
        f"<div class='cost-detail-cell'><span>Active month</span><b>{_html(active_month)}</b></div>"
        f"<div class='cost-detail-cell'><span>Currency</span><b>{_html(meta.get('currency') or 'EUR')}</b></div>"
        f"<div class='cost-detail-cell'><span>Reports loaded</span><b>{len(_cost_reports())}</b></div>"
        f"<div class='cost-detail-cell'><span>Scope view</span><b>{_html(selected_scope_label)}</b></div>"
        "</div></div>", unsafe_allow_html=True)
    try:
        _render_cost_kpi_cards(scope_id)
    except Exception:
        pass
    try:
        _cost_health_cards(scope_id)
    except Exception:
        pass
    if scope_id == "all":
        left, right = st.columns([1.0, 1.35], gap="large")
        with left:
            with st.container(border=True):
                st.markdown("**Active month comparison**")
                st.plotly_chart(_cost_scope_comparison_figure(), use_container_width=True)
        with right:
            with st.container(border=True):
                st.markdown("**Portfolio historical trend**")
                st.plotly_chart(_cost_history_trend_figure("all"), use_container_width=True)
        with st.container(border=True):
            st.markdown("**Active-month scope summary**")
            _copyable_table_component(["Scope", "Budget", "CO", "Forecast", "VOWD", "ETC", "Potential exposure", "Potential forecast"], _active_scope_summary_rows(), key_prefix="cost_scope_summary_v271")
    else:
        left, right = st.columns([1.0, 1.35], gap="large")
        with left:
            with st.container(border=True):
                st.markdown("**Waterfall / candle bar**")
                st.plotly_chart(_cost_waterfall_figure_v24(scope_id, cost_data, title=f"{selected_scope_label} waterfall"), use_container_width=True)
        with right:
            with st.container(border=True):
                st.markdown("**Historical cost trend**")
                st.plotly_chart(_cost_history_trend_figure(scope_id), use_container_width=True)
        drivers = _cost_driver_rows(scope_id) if "_cost_driver_rows" in globals() else []
        if drivers:
            with st.expander("Package drivers - active month", expanded=False):
                _copyable_table_component(["Package", "Description", "Supplier", "Budget", "CO", "Forecast", "Exposure", "Potential forecast", "Driver / note"], drivers, numeric_cols={3,4,5,6,7}, key_prefix=f"cost_drivers_{scope_id}_v271")
        exposures = _cost_exposure_rows(scope_id) if "_cost_exposure_rows" in globals() else []
        if exposures:
            with st.expander("Potential exposure / O&V items - active month", expanded=False):
                _copyable_table_component(["Item", "Package", "Amount", "Criticality", "Type", "Description", "Responsible", "Expected / award date"], exposures, numeric_cols={2}, key_prefix=f"cost_exposures_{scope_id}_v271")
    with st.container(border=True):
        st.markdown("**Monthly cost history**")
        _copyable_table_component(["Month", "Budget", "CO", "Forecast", "VOWD", "ETC", "Potential exposure", "Potential forecast", "Budget + CO check", "Forecast + exposure check"], _cost_history_table_rows(scope_id), numeric_cols={1,2,3,4,5,6,7,8,9}, key_prefix=f"cost_monthly_history_{scope_id}_v271")


