# v27.2: waterfall/candle chart includes a real monthly history timeline inside the same chart.
def _cost_waterfall_figure_v24(scope_id: str, cost_data: Optional[Dict[str, Any]] = None, title: str = "Cost waterfall") -> go.Figure:
    from plotly.subplots import make_subplots
    cost_data = cost_data or (_active_cost_report().get("data") or cached_monthly_cost())
    if scope_id == "all":
        row = _active_history_row("all")
        budget = _safe_float(row.get("Budget")) or 0.0
        co = _safe_float(row.get("CO")) or 0.0
        forecast = _safe_float(row.get("Forecast")) if row.get("Forecast") is not None else budget + co
        exposure = _safe_float(row.get("Potential exposure")) or 0.0
        potential_forecast = _safe_float(row.get("Potential forecast")) if row.get("Potential forecast") is not None else (forecast or 0.0) + exposure
    else:
        nums = _cost_numbers(scope_id, cost_data)
        budget = _safe_float(nums.get("budget")) or 0.0
        forecast = _safe_float(nums.get("forecast"))
        co = (forecast - budget) if forecast is not None else (_safe_float(nums.get("change_order")) or 0.0)
        forecast = forecast if forecast is not None else budget + co
        exposure = _safe_float(nums.get("potential_exposure")) or 0.0
        potential_forecast = _safe_float(nums.get("potential_forecast")) if nums.get("potential_forecast") is not None else forecast + exposure
    labels = ["Budget", "CO", "Forecast", "Potential exposure", "Potential forecast"]
    y_vals = [budget, co, forecast, exposure, potential_forecast]
    running = [budget, budget + co, forecast, forecast + exposure, potential_forecast]
    measures = ["absolute", "relative", "total", "relative", "total"]
    active_label = _active_cost_report().get("label") or _active_month_label_from_cost(cost_data)
    custom = []
    for label, val, run in zip(labels, y_vals, running):
        spark, hist_lines = _cost_recent_history_payload(scope_id, label, active_label, months=3)
        custom.append([label, _fmt_money_full(val), _fmt_money_full(run), active_label, spark, hist_lines])
    fig = make_subplots(
        rows=2,
        cols=1,
        row_heights=[0.64, 0.36],
        vertical_spacing=0.16,
        subplot_titles=(title, "Monthly history - active month highlighted"),
    )
    fig.add_trace(go.Waterfall(
        x=labels,
        y=y_vals,
        measure=measures,
        text=[_fmt_money(v) for v in y_vals],
        textposition="outside",
        connector={"line": {"color": "#9aa1ad", "width": 1}},
        increasing={"marker": {"color": "#007a45"}},
        decreasing={"marker": {"color": "#c73535"}},
        totals={"marker": {"color": "#c76df1"}},
        customdata=custom,
        hovertemplate=(
            "<b>%{customdata[0]}</b><br>"
            "Active month: %{customdata[3]}<br>"
            "Step value: %{customdata[1]}<br>"
            "Cost position after step: %{customdata[2]}<br><br>"
            "<b>Last 3 months, latest to oldest</b><br>"
            "%{customdata[4]}<br>%{customdata[5]}<br><br>"
            "Full monthly history is charted below.<extra></extra>"
        ),
        name="Active month",
    ), row=1, col=1)
    try:
        df = _history_for_scope(scope_id).copy()
    except Exception:
        df = pd.DataFrame()
    if not df.empty and "Month" in df.columns:
        df["_sort_date"] = pd.to_datetime(df["Month"].astype(str), errors="coerce")
        df = df.sort_values(["_sort_date", "Month"], na_position="last").drop(columns=["_sort_date"], errors="ignore")
        history_metrics = ["Forecast", "VOWD", "ETC", "Potential forecast"]
        colors = {"Forecast":"#0b66c3", "VOWD":"#111111", "ETC":"#6f2da8", "Potential forecast":"#c76df1"}
        x_vals = df["Month"].astype(str).tolist()
        for metric in history_metrics:
            if metric not in df.columns:
                continue
            y_hist = [_safe_float(v) for v in df[metric].tolist()]
            fig.add_trace(go.Scatter(
                x=x_vals,
                y=y_hist,
                mode="lines+markers",
                name=metric,
                line=dict(color=colors.get(metric, "#667085"), width=2.2),
                marker=dict(size=6),
                hovertemplate=f"<b>{metric}</b><br>%{{x}}<br>%{{y:,.0f}} EUR<extra></extra>",
            ), row=2, col=1)
            if active_label in x_vals:
                idx = x_vals.index(active_label)
                active_val = y_hist[idx]
                if active_val is not None:
                    fig.add_trace(go.Scatter(
                        x=[active_label],
                        y=[active_val],
                        mode="markers",
                        name=f"Active {metric}",
                        showlegend=False,
                        marker=dict(symbol="diamond", size=13, color="#ffffff", line=dict(color=colors.get(metric, "#111111"), width=2.6)),
                        hovertemplate=f"<b>Active {metric}</b><br>{active_label}<br>%{{y:,.0f}} EUR<extra></extra>",
                    ), row=2, col=1)
    fig.update_layout(
        height=590,
        margin=dict(l=42, r=24, t=72, b=72),
        paper_bgcolor="rgba(0,0,0,0)",
        plot_bgcolor="rgba(0,0,0,0)",
        showlegend=True,
        legend=dict(orientation="h", yanchor="bottom", y=1.0, xanchor="right", x=1.0, font=dict(size=10)),
        hovermode="closest",
    )
    fig.update_xaxes(tickangle=-22, row=1, col=1)
    fig.update_xaxes(tickangle=-28, title_text="Month", row=2, col=1)
    fig.update_yaxes(title_text="EUR", row=1, col=1)
    fig.update_yaxes(title_text="EUR", row=2, col=1)
    return fig



