st.markdown(V30_PM_CSS, unsafe_allow_html=True)


def action_status(expected_label: Any, selected_year: int, selected_week: int, current_date: Optional[pd.Timestamp] = None) -> Tuple[str, str, str]:
    due = parse_expected_date_label(expected_label, selected_year, selected_week)
    if pd.isna(due):
        return ("", "TBC", "tbc")
    ref = pd.Timestamp(current_date).normalize() if current_date is not None and pd.notna(current_date) else iso_week_start(selected_year, selected_week)
    days = int((pd.Timestamp(due).normalize() - ref).days)
    if days < 0:
        return ("", "Delayed", "delayed")
    if days <= 14:
        return ("", "Near due", "near")
    return ("", "On track", "ontrack")


def _status_for_action_text(action: str, selected_year: int, selected_week: int, current_date: Optional[pd.Timestamp] = None) -> Tuple[str, str, str, str]:
    expected = infer_expected_date(action, selected_year, selected_week)
    if is_closed_action(action):
        return "", "Closed", "closed", expected
    symbol, status, cls = action_status(expected, selected_year, selected_week, current_date=current_date)
    return symbol, status, cls, expected


def render_action_table(title: str, items: List[Any], selected_year: int, selected_week: int, default_responsible: str = "TBC", max_items: int = 10, current_date: Optional[pd.Timestamp] = None) -> None:
    if title:
        st.markdown(f"<div class='section-title'>{_html(title)}</div>", unsafe_allow_html=True)
    if not items:
        st.markdown("<div class='action-empty'>No active actions extracted for this section.</div>", unsafe_allow_html=True)
        return
    rows: List[List[Any]] = []
    for item in sorted(items, key=lambda x: action_sort_key(x, selected_year, selected_week))[:max_items]:
        if isinstance(item, dict):
            action = clean_action_text(item.get("issue") or item.get("action") or item.get("description") or "")
            responsible = item.get("owner") or item.get("responsible") or infer_responsible(action, default_responsible)
            expected = item.get("due_date") or item.get("expected_date") or infer_expected_date(action, selected_year, selected_week)
        else:
            action = clean_action_text(item)
            responsible = infer_responsible(action, default_responsible)
            expected = infer_expected_date(action, selected_year, selected_week)
        status = "Closed" if is_closed_action(action) else action_status(expected, selected_year, selected_week, current_date=current_date)[1]
        rows.append([action, responsible or "TBC", expected or "TBC", status])
    _copyable_table_component(["Action / issue", "Responsible", "Expected date", "Status"], rows, key_prefix=title or "actions")


def _pm_pct(value: Any) -> str:
    num = _safe_float(value)
    return "N/A" if num is None else f"{num:.1f}%"


def _pm_pp(value: Any) -> str:
    num = _safe_float(value)
    return "N/A" if num is None else f"{num:+.1f} pp"


def _pm_ratio(numer: Optional[float], denom: Optional[float]) -> Optional[float]:
    if numer is None or denom in (None, 0):
        return None
    return float(numer) / float(denom) * 100.0


def _pm_action_counts(rec: Dict[str, Any], selected_year: int, selected_week: int, current_date: Optional[pd.Timestamp]) -> Dict[str, Any]:
    counts: Dict[str, Any] = {"Delayed": 0, "Near due": 0, "On track": 0, "TBC": 0, "Closed": 0, "first_delayed": ""}
    for item in rec.get("priority_items", []) or []:
        if isinstance(item, dict):
            action = clean_action_text(item.get("issue") or item.get("action") or item.get("description") or "")
            expected = item.get("due_date") or item.get("expected_date") or infer_expected_date(action, selected_year, selected_week)
        else:
            action = clean_action_text(item)
            expected = infer_expected_date(action, selected_year, selected_week)
        if not action:
            continue
        status = "Closed" if is_closed_action(action) else action_status(expected, selected_year, selected_week, current_date=current_date)[1]
        counts[status] = int(counts.get(status, 0)) + 1
        if status == "Delayed" and not counts.get("first_delayed"):
            counts["first_delayed"] = action
    return counts


def _pm_baseline_metrics(rec: Dict[str, Any], selected_year: int, selected_week: int) -> Dict[str, Any]:
    delays: List[int] = []
    matched = 0
    try:
        rows = _baseline_comparison_rows(rec, selected_year, selected_week)
    except Exception:
        rows = []
    for row in rows:
        if len(row) >= 9:
            matched += 1
            m = re.search(r"([+-]\d+)", str(row[8]))
            if m:
                delays.append(int(m.group(1)))
    positive = [d for d in delays if d > 0]
    return {"matched": matched, "slipped": len(positive), "max_delay": max(positive) if positive else 0, "best_gain": min(delays) if delays else 0}


def _pm_cost_metrics(scope_id: str) -> Dict[str, Any]:
    try:
        cost_data = (_active_cost_report().get("data") or cached_monthly_cost())
    except Exception:
        cost_data = {}
    try:
        nums = _cost_numbers(scope_id, cost_data)
    except Exception:
        nums = {}
    try:
        row = _active_history_row(scope_id)
    except Exception:
        row = {}
    budget = _safe_float(nums.get("budget") if nums.get("budget") is not None else row.get("Budget"))
    forecast = _safe_float(nums.get("forecast") if nums.get("forecast") is not None else row.get("Forecast"))
    exposure = _safe_float(nums.get("potential_exposure") if nums.get("potential_exposure") is not None else row.get("Potential exposure"))
    vowd = _safe_float(nums.get("vowd") if nums.get("vowd") is not None else row.get("VOWD"))
    etc = _safe_float(nums.get("forecast_minus_vowd") if nums.get("forecast_minus_vowd") is not None else row.get("ETC"))
    return {"budget": budget, "forecast": forecast, "forecast_vs_budget": (forecast - budget) if forecast is not None and budget is not None else None, "exposure": exposure, "exposure_pct": _pm_ratio(exposure, forecast), "vowd_pct": _pm_ratio(vowd, forecast), "etc": etc}


def _pm_scope_assessment(rec: Dict[str, Any], selected_year: int, selected_week: int, current_date: Optional[pd.Timestamp]) -> Dict[str, Any]:
    rec = _with_display_scope(rec)
    actions = _pm_action_counts(rec, selected_year, selected_week, current_date)
    baseline = _pm_baseline_metrics(rec, selected_year, selected_week)
    cost = _pm_cost_metrics(rec.get("scope_id", ""))
    construction_dev = _safe_float(rec.get("construction_deviation"))
    engineering_dev = _safe_float(rec.get("engineering_deviation"))
    open_gates = len(rec.get("quality_items", []) or []) + len(rec.get("engineering_items", []) or [])
    score = int(actions.get("Delayed", 0)) * 3 + int(actions.get("Near due", 0))
    score += 3 if construction_dev is not None and construction_dev < -5 else (2 if construction_dev is not None and construction_dev < -2 else 0)
    score += 3 if engineering_dev is not None and engineering_dev < -5 else (2 if engineering_dev is not None and engineering_dev < -2 else 0)
    score += 2 if baseline.get("max_delay", 0) > 14 else (1 if baseline.get("max_delay", 0) > 0 else 0)
    score += 2 if open_gates >= 12 else (1 if open_gates >= 6 else 0)
    exposure_pct = cost.get("exposure_pct")
    score += 2 if exposure_pct is not None and exposure_pct > 15 else (1 if exposure_pct is not None and exposure_pct > 5 else 0)
    if cost.get("forecast_vs_budget") is not None and cost.get("forecast_vs_budget") > 0:
        score += 1
    tone, label = ("critical", "Intervention") if score >= 7 else (("watch", "Watch") if score >= 3 else ("good", "Controlled"))
    return {"scope": rec.get("name") or rec.get("full_name") or "Scope", "scope_id": rec.get("scope_id"), "tone": tone, "label": label, "score": score, "actions": actions, "baseline": baseline, "cost": cost, "construction_dev": construction_dev, "engineering_dev": engineering_dev, "open_gates": open_gates, "first_delayed": actions.get("first_delayed") or ""}


def _pm_signal_html(label: str, value: str) -> str:
    return f"<div class='pm-signal'><span>{_html(label)}</span><b>{_html(value)}</b></div>"


def _pm_scope_card_html(a: Dict[str, Any]) -> str:
    actions, baseline, cost = a["actions"], a["baseline"], a["cost"]
    signals = [
        _pm_signal_html("Actions", f"{actions.get('Delayed', 0)} delayed / {actions.get('Near due', 0)} near due"),
        _pm_signal_html("Progress", f"Construction {_pm_pp(a.get('construction_dev'))}; Engineering {_pm_pp(a.get('engineering_dev'))}"),
        _pm_signal_html("Baseline", f"{baseline.get('slipped', 0)} slipped / max +{baseline.get('max_delay', 0)} days"),
        _pm_signal_html("Cost", f"Exposure {_pm_pct(cost.get('exposure_pct'))}; ETC {_fmt_money(cost.get('etc'))}"),
    ]
    if a.get("first_delayed"):
        signals.append(_pm_signal_html("First late", compact_text(a["first_delayed"], 105)))
    return f"<div class='pm-scope-card'><h3>{_html(a['scope'])}</h3><span class='pm-status {a['tone']}'>{_html(a['label'])}</span><div class='pm-signal-list'>{''.join(signals)}</div></div>"


def render_pm_control_health(records: List[Dict[str, Any]], selected_year: int, selected_week: int, current_date: Optional[pd.Timestamp]) -> None:
    assessments = [_pm_scope_assessment(r, selected_year, selected_week, current_date) for r in records if r.get("scope_id") in {"rail", "ponds", "roads"}]
    if not assessments:
        return
    total_delayed = sum(int(a["actions"].get("Delayed", 0)) for a in assessments)
    total_near = sum(int(a["actions"].get("Near due", 0)) for a in assessments)
    intervention = sum(1 for a in assessments if a["tone"] == "critical")
    watch = sum(1 for a in assessments if a["tone"] == "watch")
    devs = [(a.get("scope"), a.get("construction_dev")) for a in assessments if a.get("construction_dev") is not None]
    worst_scope, worst_dev = min(devs, key=lambda x: x[1]) if devs else ("N/A", None)
    baseline_max = max((int(a["baseline"].get("max_delay", 0)) for a in assessments), default=0)
    exposure_pairs = [(a.get("scope"), a["cost"].get("exposure_pct")) for a in assessments if a["cost"].get("exposure_pct") is not None]
    exp_scope, exp_pct = max(exposure_pairs, key=lambda x: x[1]) if exposure_pairs else ("N/A", None)
    posture_tone = "critical" if intervention else ("watch" if watch or total_delayed else "good")
    action_tone = "critical" if total_delayed else ("watch" if total_near else "good")
    variance_tone = "critical" if worst_dev is not None and worst_dev < -5 else ("watch" if worst_dev is not None and worst_dev < -2 else "good")
    baseline_tone = "critical" if baseline_max > 14 else ("watch" if baseline_max > 0 else "primary")
    st.markdown("<div class='pm-health-grid'>" +
        f"<div class='pm-health-card {posture_tone}'><span>Portfolio posture</span><b>{_html(str(intervention))}</b><p>intervention scopes; {watch} watch scopes</p></div>" +
        f"<div class='pm-health-card {action_tone}'><span>Action pressure</span><b>{total_delayed}/{total_near}</b><p>delayed / near-due active items</p></div>" +
        f"<div class='pm-health-card {variance_tone}'><span>Worst construction variance</span><b>{_html(_pm_pp(worst_dev))}</b><p>{_html(str(worst_scope))}</p></div>" +
        f"<div class='pm-health-card {baseline_tone}'><span>Baseline / exposure check</span><b>+{baseline_max}d</b><p>max BL slip; exposure {_html(_pm_pct(exp_pct))} on {_html(str(exp_scope))}</p></div></div>", unsafe_allow_html=True)
    st.markdown("<div class='pm-scope-grid'>" + "".join(_pm_scope_card_html(a) for a in assessments) + "</div>", unsafe_allow_html=True)


def render_pm_scope_summary(rec: Dict[str, Any], selected_year: int, selected_week: int, current_date: Optional[pd.Timestamp]) -> None:
    a = _pm_scope_assessment(rec, selected_year, selected_week, current_date)
    actions, baseline, cost = a["actions"], a["baseline"], a["cost"]
    st.markdown("<div class='pm-scope-summary'><div class='pm-scope-summary-grid'>" +
        f"<div class='pm-scope-summary-cell'><span class='label'>PM control status</span><b><span class='pm-status {a['tone']}'>{_html(a['label'])}</span></b><p>{_html(compact_text(a.get('first_delayed') or _matrix_driver(rec), 130))}</p></div>" +
        f"<div class='pm-scope-summary-cell'><span class='label'>Actions</span><b>{actions.get('Delayed', 0)} delayed</b><p>{actions.get('Near due', 0)} near due; {actions.get('TBC', 0)} TBC</p></div>" +
        f"<div class='pm-scope-summary-cell'><span class='label'>Progress variance</span><b>{_html(_pm_pp(a.get('construction_dev')))}</b><p>construction; engineering {_html(_pm_pp(a.get('engineering_dev')))}</p></div>" +
        f"<div class='pm-scope-summary-cell'><span class='label'>Baseline variance</span><b>+{baseline.get('max_delay', 0)} days</b><p>{baseline.get('slipped', 0)} slipped milestone matches</p></div>" +
        f"<div class='pm-scope-summary-cell'><span class='label'>Cost exposure</span><b>{_html(_pm_pct(cost.get('exposure_pct')))}</b><p>ETC {_html(_fmt_money(cost.get('etc')))}</p></div></div></div>", unsafe_allow_html=True)


def render_scope_sections(rec: Dict[str, Any], selected_year: int, selected_week: int, current_date: Optional[pd.Timestamp] = None) -> None:
    rec = _with_display_scope(rec)
    selected_label = period_display(selected_year, selected_week)
    st.markdown(f"<div class='scope-banner'><h2><span class='scope-icon'>{SCOPE_ICON.get(rec.get('scope_id'), '')}</span>{_html(rec['full_name'])} control panel</h2><p>{_html(compact_text(rec.get('insight', ''), 420))}</p></div>", unsafe_allow_html=True)
    render_pm_scope_summary(rec, selected_year, selected_week, current_date)
    col1, col2 = st.columns([1, 1])
    with col1:
        render_progress_gauge(rec)
    with col2:
        render_progress_trend(rec, selected_year, selected_week)
    render_milestone_timeline([rec], scope_filter=rec["scope_id"], title="Milestones", selected_year=selected_year, selected_week=selected_week, current_date=current_date)
    render_scope_baseline_section(rec, selected_year, selected_week)
    render_scope_cost_section(rec)
    render_action_table(f"{rec['name']} priority & high-exposure items - {selected_label}", rec.get("priority_items", []), selected_year, selected_week, rec.get("default_responsible", "TBC"), max_items=999, current_date=current_date)
    st.markdown("<div class='section-title'>Engineering / design</div>", unsafe_allow_html=True)
    e1, e2 = st.columns([1, 1])
    with e1:
        render_engineering_gauge(rec, selected_year, selected_week)
    with e2:
        render_engineering_trend(rec, selected_year, selected_week)
    render_action_table("", rec.get("engineering_items", []), selected_year, selected_week, rec.get("default_responsible", "TBC"), max_items=999, current_date=current_date)
    st.markdown("<div class='section-title'>Quality / completion</div>", unsafe_allow_html=True)
    render_action_table("", rec.get("quality_items", []), selected_year, selected_week, rec.get("default_responsible", "TBC"), max_items=999, current_date=current_date)
    st.markdown("<div class='section-title'>Interface / commercial controls</div>", unsafe_allow_html=True)
    render_action_table("", rec.get("interface_items", []), selected_year, selected_week, rec.get("default_responsible", "TBC"), max_items=999, current_date=current_date)


def _cost_month_delta(scope_id: str, metric_label: str) -> Optional[float]:
    try:
        df = _history_for_scope(scope_id)
    except Exception:
        return None
    if df.empty or metric_label not in df.columns:
        return None
    active_label = _active_month_label_v29() if "_active_month_label_v29" in globals() else str(df.iloc[-1].get("Month"))
    subset = df.loc[:df.index[df["Month"].astype(str) == active_label].tolist()[-1]] if active_label in set(df["Month"].astype(str)) else df
    clean = pd.to_numeric(subset[metric_label], errors="coerce").dropna()
    return float(clean.iloc[-1] - clean.iloc[-2]) if len(clean) >= 2 else None


def _cost_health_cards(scope_id: str) -> None:
    row = _active_history_row(scope_id)
    if not row:
        return
    check1 = _safe_float(row.get("Budget + CO check")); check2 = _safe_float(row.get("Forecast + exposure check"))
    forecast = _safe_float(row.get("Forecast")); budget = _safe_float(row.get("Budget")); exposure = _safe_float(row.get("Potential exposure")); vowd = _safe_float(row.get("VOWD"))
    vs_budget = (forecast - budget) if forecast is not None and budget is not None else None
    exp_pct = _pm_ratio(exposure, forecast); vowd_pct = _pm_ratio(vowd, forecast); forecast_delta = _cost_month_delta(scope_id, "Forecast")
    balanced = abs(check1 or 0) < 1 and abs(check2 or 0) < 1
    items = [("Forecast vs budget", _fmt_money(vs_budget), "bad" if (vs_budget or 0) > 0 else "good"), ("Exposure as % forecast", f"{exp_pct:.1f}%" if exp_pct is not None else "N/A", "warn" if (exp_pct or 0) > 15 else "good"), ("VOWD / Forecast", f"{vowd_pct:.1f}%" if vowd_pct is not None else "N/A", "primary"), ("Forecast MoM", _fmt_money(forecast_delta), "bad" if (forecast_delta or 0) > 0 else "good"), ("Cost check", "Balanced" if balanced else "Review", "good" if balanced else "bad")]
    st.markdown("<div class='cost-health-row'>" + "".join(f"<div class='cost-health-card {cls}'><span>{_html(label)}</span><b>{_html(value)}</b></div>" for label, value, cls in items) + "</div>", unsafe_allow_html=True)


def render_executive_overview(bundle: Dict[str, Any], profiles: Dict[str, Any], selected_year: int, selected_week: int, current_date: Optional[pd.Timestamp] = None) -> None:
    records = build_scope_records(bundle, profiles, selected_year, selected_week, scopes=CONTROL_SCOPES)
    selected_label = period_display(selected_year, selected_week)
    cutoff = current_date if current_date is not None else selected_cutoff_date(bundle)
    render_pm_control_health(records, selected_year, selected_week, cutoff)
    render_scope_matrix(records, selected_year, selected_week)
    render_executive_priority_delayed_near_table(records, selected_label, selected_year, selected_week, current_date=cutoff)
    render_milestone_timeline(records, title="Milestones", selected_year=selected_year, selected_week=selected_week, current_date=cutoff)


