def _pm_status_rank(status: str) -> int:
    return {"Delayed": 3, "Near due": 2, "TBC": 1, "On track": 0, "Closed": 0}.get(str(status), 0)


def _pm_visual_scores(a: Dict[str, Any]) -> Dict[str, float]:
    actions = a.get("actions") or {}
    baseline = a.get("baseline") or {}
    cost = a.get("cost") or {}
    action_score = min(10.0, float(actions.get("Delayed", 0)) * 3.0 + float(actions.get("Near due", 0)) * 1.2 + float(actions.get("TBC", 0)) * 0.35)
    progress_score = 0.0
    for dev in [a.get("construction_dev"), a.get("engineering_dev")]:
        dev_num = _safe_float(dev)
        if dev_num is not None and dev_num < 0:
            progress_score += min(5.0, abs(dev_num) / 1.5)
    gate_score = min(10.0, float(a.get("open_gates") or 0) / 1.5)
    baseline_score = min(10.0, float(baseline.get("max_delay") or 0) / 2.0)
    exposure_pct = _safe_float(cost.get("exposure_pct"))
    cost_score = min(10.0, (exposure_pct or 0.0) / 2.0)
    total = min(10.0, action_score * .30 + progress_score * .24 + gate_score * .14 + baseline_score * .17 + cost_score * .15)
    return {"Actions": action_score, "Progress": progress_score, "Gates": gate_score, "Baseline": baseline_score, "Cost": cost_score, "Total": total}


def _pm_theme_figure(fig: go.Figure, height: int = 360) -> go.Figure:
    fig.update_layout(
        height=height,
        margin=dict(l=38, r=20, t=34, b=44),
        paper_bgcolor="rgba(0,0,0,0)",
        plot_bgcolor="rgba(0,0,0,0)",
        font=dict(family="Segoe UI, Arial, sans-serif", color="#1f2937", size=12),
        hoverlabel=dict(bgcolor="#111111", font_size=12, font_color="#ffffff"),
        legend=dict(orientation="h", yanchor="bottom", y=1.02, xanchor="right", x=1),
    )
    fig.update_xaxes(showgrid=False, zeroline=False, linecolor="#e7e2ed", tickfont=dict(size=11))
    fig.update_yaxes(showgrid=True, gridcolor="#f0edf5", zeroline=False, linecolor="#e7e2ed", tickfont=dict(size=11))
    return fig


def _pm_heatmap_figure(assessments: List[Dict[str, Any]]) -> go.Figure:
    metrics = ["Actions", "Progress", "Gates", "Baseline", "Cost", "Total"]
    scopes = [str(a.get("scope") or "Scope") for a in assessments]
    z = [[_pm_visual_scores(a)[m] for m in metrics] for a in assessments]
    text = [[f"{val:.1f}" for val in row] for row in z]
    fig = go.Figure(data=go.Heatmap(
        z=z,
        x=metrics,
        y=scopes,
        text=text,
        texttemplate="%{text}",
        zmin=0,
        zmax=10,
        colorscale=[[0, "#e7f7ee"], [.45, "#fff5df"], [1, "#fdeaea"]],
        colorbar=dict(title="Pressure", len=.76),
        hovertemplate="<b>%{y}</b><br>%{x}: %{z:.1f}/10<extra></extra>",
    ))
    fig.update_yaxes(autorange="reversed")
    return _pm_theme_figure(fig, height=320)


def _pm_action_variance_figure(assessments: List[Dict[str, Any]]) -> go.Figure:
    scopes = [str(a.get("scope") or "Scope") for a in assessments]
    delayed = [int((a.get("actions") or {}).get("Delayed", 0)) for a in assessments]
    near = [int((a.get("actions") or {}).get("Near due", 0)) for a in assessments]
    construction = [_safe_float(a.get("construction_dev")) or 0.0 for a in assessments]
    engineering = [_safe_float(a.get("engineering_dev")) or 0.0 for a in assessments]
    fig = go.Figure()
    fig.add_trace(go.Bar(name="Delayed actions", x=scopes, y=delayed, marker_color="#c73535", yaxis="y"))
    fig.add_trace(go.Bar(name="Near due", x=scopes, y=near, marker_color="#b87000", yaxis="y"))
    fig.add_trace(go.Scatter(name="Construction variance", x=scopes, y=construction, mode="lines+markers+text", text=[_pm_pp(v) for v in construction], textposition="bottom center", marker=dict(color="#111111", size=9), line=dict(color="#111111", width=2), yaxis="y2"))
    fig.add_trace(go.Scatter(name="Engineering variance", x=scopes, y=engineering, mode="lines+markers", marker=dict(color="#6f2da8", size=8), line=dict(color="#6f2da8", width=2, dash="dot"), yaxis="y2"))
    fig.update_layout(
        barmode="stack",
        yaxis=dict(title="Action count", rangemode="tozero", showgrid=True, gridcolor="#f0edf5"),
        yaxis2=dict(title="Variance (pp)", overlaying="y", side="right", zeroline=True, zerolinecolor="#98a2b3", showgrid=False),
    )
    return _pm_theme_figure(fig, height=320)


def _pm_cost_exposure_figure(assessments: List[Dict[str, Any]]) -> go.Figure:
    scopes = [str(a.get("scope") or "Scope") for a in assessments]
    exposure = [_safe_float((a.get("cost") or {}).get("exposure_pct")) or 0.0 for a in assessments]
    etc = [_safe_float((a.get("cost") or {}).get("etc")) or 0.0 for a in assessments]
    colors = ["#c73535" if v > 15 else "#b87000" if v > 5 else "#058b55" for v in exposure]
    fig = go.Figure()
    fig.add_trace(go.Bar(name="Exposure / forecast", x=scopes, y=exposure, marker_color=colors, text=[f"{v:.1f}%" for v in exposure], textposition="outside", hovertemplate="<b>%{x}</b><br>Exposure: %{y:.1f}%<extra></extra>"))
    fig.add_trace(go.Scatter(name="ETC", x=scopes, y=etc, mode="lines+markers", marker=dict(color="#6f2da8", size=9), line=dict(color="#6f2da8", width=2), yaxis="y2", hovertemplate="<b>%{x}</b><br>ETC: %{y:,.0f} EUR<extra></extra>"))
    fig.update_layout(
        yaxis=dict(title="Exposure %", rangemode="tozero", ticksuffix="%"),
        yaxis2=dict(title="ETC EUR", overlaying="y", side="right", showgrid=False),
    )
    return _pm_theme_figure(fig, height=320)


def render_pm_visuals(records: List[Dict[str, Any]], selected_year: int, selected_week: int, current_date: Optional[pd.Timestamp]) -> None:
    assessments = [_pm_scope_assessment(r, selected_year, selected_week, current_date) for r in records if r.get("scope_id") in {"rail", "ponds", "roads"}]
    if not assessments:
        return
    st.markdown("<div class='section-title'>PM analysis visuals</div>", unsafe_allow_html=True)
    left, right = st.columns([1.08, .92], gap="large")
    with left:
        st.markdown("<div class='pm-visual-card'><h3>Control pressure heatmap</h3><p>0 is controlled; 10 needs management attention.</p>", unsafe_allow_html=True)
        st.plotly_chart(_pm_heatmap_figure(assessments), use_container_width=True)
        st.markdown("</div>", unsafe_allow_html=True)
    with right:
        st.markdown("<div class='pm-visual-card'><h3>Action pressure vs progress variance</h3><p>Bars show action pressure; lines show variance against forecast.</p>", unsafe_allow_html=True)
        st.plotly_chart(_pm_action_variance_figure(assessments), use_container_width=True)
        st.markdown("</div>", unsafe_allow_html=True)
    st.markdown("<div class='pm-visual-card'><h3>Cost exposure and ETC</h3><p>Exposure is normalized against forecast; ETC remains in EUR.</p>", unsafe_allow_html=True)
    st.plotly_chart(_pm_cost_exposure_figure(assessments), use_container_width=True)
    st.markdown("</div>", unsafe_allow_html=True)


