SCOPE_CANONICAL_LABELS = {"rail": "Rail On Site (ROS)", "ponds": "Ponds", "roads": "Roads"}
SCOPE_PANEL_BY_ID = {"rail": "Rail On Site (ROS)", "ponds": "Ponds", "roads": "Roads"}


def _scope_label_v32(scope_id: str) -> str:
    return SCOPE_CANONICAL_LABELS.get(str(scope_id or "").lower(), _scope_label(scope_id) if "_scope_label" in globals() else str(scope_id or "Scope").title())


def _scope_link_v32(scope_id: str, label: str = "Open detail") -> str:
    panel = SCOPE_PANEL_BY_ID.get(str(scope_id or "").lower())
    if not panel:
        return ""
    token = hashlib.sha1((panel + label).encode("utf-8", "ignore")).hexdigest()[:10]
    return f"<a class='scope-detail-link' href='?panel={quote_plus(panel)}&nav={token}' target='_self'>{_html(label)}</a>"


def _apply_url_panel_v32() -> None:
    try:
        raw = st.query_params.get("panel")
    except Exception:
        raw = None
    if isinstance(raw, list):
        raw = raw[0] if raw else None
    if raw in {"Executive overview", "Cost Status", "Rail On Site (ROS)", "Ponds", "Roads"}:
        st.session_state["panel_choice"] = raw


def _latest_defaults_v32(bundle: Dict[str, Any]) -> None:
    periods = available_periods(bundle)
    week_labels = [period_display(y, w) for y, w in periods]
    if week_labels:
        latest_week = week_labels[-1]
        if st.session_state.get("_latest_week_applied_v32") != latest_week:
            st.session_state["week_selector_value"] = latest_week
            st.session_state["_latest_week_applied_v32"] = latest_week
        elif st.session_state.get("week_selector_value") not in week_labels:
            st.session_state["week_selector_value"] = latest_week
    cost_labels = _month_labels_v29() if "_month_labels_v29" in globals() else [r.get("label") for r in _cost_reports() if r.get("label")]
    if cost_labels:
        latest_month = cost_labels[-1]
        if st.session_state.get("_latest_month_applied_v32") != latest_month:
            st.session_state["monthly_cost_report_choice_portfolio"] = latest_month
            st.session_state["_latest_month_applied_v32"] = latest_month
        elif st.session_state.get("monthly_cost_report_choice_portfolio") not in cost_labels:
            st.session_state["monthly_cost_report_choice_portfolio"] = latest_month
    bl_labels = [r.get("label") for r in _baseline_reports() if r.get("label")]
    if bl_labels:
        latest_baseline = bl_labels[-1]
        if st.session_state.get("_latest_baseline_applied_v32") != latest_baseline:
            st.session_state["baseline_choice"] = latest_baseline
            st.session_state["_latest_baseline_applied_v32"] = latest_baseline
        elif st.session_state.get("baseline_choice") not in bl_labels:
            st.session_state["baseline_choice"] = latest_baseline


def _selected_period_from_state_v32(bundle: Dict[str, Any]) -> Tuple[int, int]:
    _latest_defaults_v32(bundle)
    return _selected_period_from_state_v29(bundle) if "_selected_period_from_state_v29" in globals() else _selected_period_from_state_v27(bundle)


def _as_action_records_v32(items: List[Any], selected_year: int, selected_week: int, default_responsible: str = "TBC", current_date: Optional[pd.Timestamp] = None) -> List[Dict[str, Any]]:
    rows: List[Dict[str, Any]] = []
    for item in items or []:
        if isinstance(item, dict):
            action = clean_action_text(item.get("issue") or item.get("action") or item.get("description") or "")
            responsible = item.get("owner") or item.get("responsible") or infer_responsible(action, default_responsible)
            expected = item.get("due_date") or item.get("expected_date") or infer_expected_date(action, selected_year, selected_week)
        else:
            action = clean_action_text(item)
            responsible = infer_responsible(action, default_responsible)
            expected = infer_expected_date(action, selected_year, selected_week)
        if not action:
            continue
        if is_closed_action(action):
            status = "Closed"
            cls = "closed"
        else:
            _, status, cls = action_status(expected, selected_year, selected_week, current_date=current_date)
        rows.append({"action": action, "responsible": responsible or "TBC", "expected": expected or "TBC", "status": status, "class": cls})
    return rows


def _action_rows_html_v32(rows: List[Dict[str, Any]]) -> str:
    if not rows:
        return "<div class='pm-empty-list'>No active items extracted for this selection.</div>"
    body = []
    for i, row in enumerate(rows[:80], start=1):
        body.append(
            "<div class='action-pop-row'>"
            f"<i>{i:02d}</i><span>{_html(row.get('action'))}"
            f"<small>Responsible: {_html(row.get('responsible'))} | Expected: {_html(row.get('expected'))} | Status: {_html(row.get('status'))}</small></span></div>"
        )
    return "".join(body)


def _action_popover_button_v32(title: str, rows: List[Dict[str, Any]], count: int, label: Optional[str] = None, class_name: str = "action-count-button") -> str:
    token = hashlib.sha1((title + str(count) + "|".join(r.get("action", "") for r in rows[:30])).encode("utf-8", "ignore")).hexdigest()[:12]
    pid = f"action_v32_{token}"
    body = _action_rows_html_v32(rows)
    button_label = label or f"{count} items"
    return (
        f"<button type='button' class='{class_name}' popovertarget='{pid}' popovertargetaction='toggle'>{_html(button_label)}</button>"
        f"<div id='{pid}' class='action-popover-v32' popover><div class='action-pop-head'><b>{_html(title)}</b>"
        f"<span>{int(count)} item(s). Click outside this list to close.</span></div><div class='action-pop-body'>{body}</div></div>"
    )


def _filter_action_rows_v32(rows: List[Dict[str, Any]], statuses: Optional[set] = None) -> List[Dict[str, Any]]:
    if not statuses:
        return rows
    return [r for r in rows if r.get("status") in statuses]


def _scope_all_action_rows_v32(rec: Dict[str, Any], selected_year: int, selected_week: int, current_date: Optional[pd.Timestamp]) -> List[Dict[str, Any]]:
    rows: List[Dict[str, Any]] = []
    sections = [
        ("Priority", rec.get("priority_items", [])),
        ("Engineering", rec.get("engineering_items", [])),
        ("Quality", rec.get("quality_items", [])),
        ("Interface", rec.get("interface_items", [])),
    ]
    for section, items in sections:
        for row in _as_action_records_v32(items, selected_year, selected_week, rec.get("default_responsible", "TBC"), current_date):
            row["section"] = section
            rows.append(row)
    return rows


def _pm_action_counts(rec: Dict[str, Any], selected_year: int, selected_week: int, current_date: Optional[pd.Timestamp]) -> Dict[str, Any]:
    rows = _scope_all_action_rows_v32(rec, selected_year, selected_week, current_date)
    counts: Dict[str, Any] = {"Delayed": 0, "Near due": 0, "On track": 0, "TBC": 0, "Closed": 0, "first_delayed": "", "rows": rows}
    for row in rows:
        status = row.get("status") or "TBC"
        counts[status] = int(counts.get(status, 0)) + 1
        if status == "Delayed" and not counts.get("first_delayed"):
            counts["first_delayed"] = row.get("action", "")
    return counts


def _pm_pp(value: Any) -> str:
    num = _safe_float(value)
    return "N/A" if num is None else f"{num:+.1f}%"


def _progress_target_gap_v32(value: Any, monthly_target: float = 10.0) -> float:
    num = _safe_float(value)
    if num is None:
        return monthly_target
    return max(0.0, monthly_target - max(0.0, num))


def _pm_visual_scores(a: Dict[str, Any]) -> Dict[str, float]:
    actions = a.get("actions") or {}
    baseline = a.get("baseline") or {}
    cost = a.get("cost") or {}
    action_score = min(10.0, float(actions.get("Delayed", 0)) * 2.2 + float(actions.get("Near due", 0)) * 1.1 + float(actions.get("TBC", 0)) * 0.25)
    target_gap = float(a.get("progress_target_gap") or 0.0)
    progress_score = min(10.0, target_gap * 0.75)
    for dev in [a.get("construction_dev"), a.get("engineering_dev")]:
        dev_num = _safe_float(dev)
        if dev_num is not None and dev_num < 0:
            progress_score = min(10.0, progress_score + abs(dev_num) / 3.0)
    gate_score = min(10.0, float(a.get("open_gates") or 0) / 1.5)
    baseline_score = min(10.0, float(baseline.get("max_delay") or 0) / 2.0)
    exposure_pct = _safe_float(cost.get("exposure_pct"))
    cost_score = min(10.0, (exposure_pct or 0.0) / 2.0)
    total = min(10.0, action_score * .26 + progress_score * .30 + gate_score * .12 + baseline_score * .16 + cost_score * .16)
    return {"Actions": action_score, "Progress": progress_score, "Gates": gate_score, "Baseline": baseline_score, "Cost": cost_score, "Total": total}


def _pm_scope_assessment(rec: Dict[str, Any], selected_year: int, selected_week: int, current_date: Optional[pd.Timestamp]) -> Dict[str, Any]:
    rec = _with_display_scope(rec)
    scope_id = rec.get("scope_id", "")
    actions = _pm_action_counts(rec, selected_year, selected_week, current_date)
    baseline = _pm_baseline_metrics(rec, selected_year, selected_week)
    cost = _pm_cost_metrics(scope_id)
    construction_actual = _safe_float(rec.get("construction_actual"))
    engineering_actual = _safe_float(rec.get("engineering_actual"))
    construction_dev = _safe_float(rec.get("construction_deviation"))
    engineering_dev = _safe_float(rec.get("engineering_deviation"))
    open_gates = len(rec.get("quality_items", []) or []) + len(rec.get("engineering_items", []) or [])
    construction_gap = _progress_target_gap_v32(construction_actual)
    engineering_gap = _progress_target_gap_v32(engineering_actual)
    target_gap = max(construction_gap, engineering_gap)
    score = int(actions.get("Delayed", 0)) * 2 + int(actions.get("Near due", 0))
    score += 3 if target_gap >= 8 else (2 if target_gap >= 4 else (1 if target_gap > 0 else 0))
    score += 3 if construction_dev is not None and construction_dev < -5 else (2 if construction_dev is not None and construction_dev < -2 else 0)
    score += 3 if engineering_dev is not None and engineering_dev < -5 else (2 if engineering_dev is not None and engineering_dev < -2 else 0)
    score += 2 if baseline.get("max_delay", 0) > 14 else (1 if baseline.get("max_delay", 0) > 0 else 0)
    score += 2 if open_gates >= 12 else (1 if open_gates >= 6 else 0)
    exposure_pct = cost.get("exposure_pct")
    score += 2 if exposure_pct is not None and exposure_pct > 15 else (1 if exposure_pct is not None and exposure_pct > 5 else 0)
    if cost.get("forecast_vs_budget") is not None and cost.get("forecast_vs_budget") > 0:
        score += 1
    tone, label = ("critical", "Intervention") if score >= 7 else (("watch", "Watch") if score >= 3 else ("good", "Controlled"))
    return {
        "scope": _scope_label_v32(scope_id), "scope_id": scope_id, "tone": tone, "label": label, "score": score,
        "actions": actions, "baseline": baseline, "cost": cost, "construction_dev": construction_dev,
        "engineering_dev": engineering_dev, "construction_actual": construction_actual, "engineering_actual": engineering_actual,
        "progress_target_gap": target_gap, "open_gates": open_gates, "first_delayed": actions.get("first_delayed") or "",
    }


def _pm_scope_card_html(a: Dict[str, Any]) -> str:
    actions, baseline, cost = a["actions"], a["baseline"], a["cost"]
    all_rows = actions.get("rows") or []
    delayed_rows = _filter_action_rows_v32(all_rows, {"Delayed"})
    near_rows = _filter_action_rows_v32(all_rows, {"Near due"})
    title = f"{a['scope']} action list"
    action_button = _action_popover_button_v32(title, delayed_rows + near_rows, int(actions.get("Delayed", 0)) + int(actions.get("Near due", 0)), label=f"{actions.get('Delayed', 0)} delayed / {actions.get('Near due', 0)} near due", class_name="pm-click-signal")
    signals = [
        f"<div class='pm-signal click-wrap'><span>Actions</span><b>{action_button}</b><em class='click-hint'>Click count to view list</em></div>",
        _pm_signal_html("Progress", f"Construction {_pm_pp(a.get('construction_dev'))}; Engineering {_pm_pp(a.get('engineering_dev'))}; target gap {a.get('progress_target_gap', 0):.1f}%"),
        _pm_signal_html("Baseline", f"{baseline.get('slipped', 0)} slipped / max +{baseline.get('max_delay', 0)} days"),
        _pm_signal_html("Cost", f"Exposure {_pm_pct(cost.get('exposure_pct'))}; ETC {_fmt_money(cost.get('etc'))}"),
    ]
    if a.get("first_delayed"):
        signals.append(_pm_signal_html("First late", compact_text(a["first_delayed"], 105)))
    return f"<div class='pm-scope-card'><h3>{_html(a['scope'])}{_scope_link_v32(a.get('scope_id'))}</h3><span class='pm-status {a['tone']}'>{_html(a['label'])}</span><div class='pm-signal-list'>{''.join(signals)}</div></div>"


def render_pm_control_health(records: List[Dict[str, Any]], selected_year: int, selected_week: int, current_date: Optional[pd.Timestamp]) -> None:
    assessments = [_pm_scope_assessment(r, selected_year, selected_week, current_date) for r in records if r.get("scope_id") in {"rail", "ponds", "roads"}]
    if not assessments:
        return
    all_rows = [row for a in assessments for row in ((a.get("actions") or {}).get("rows") or [])]
    delayed_rows = _filter_action_rows_v32(all_rows, {"Delayed"})
    near_rows = _filter_action_rows_v32(all_rows, {"Near due"})
    total_delayed = len(delayed_rows)
    total_near = len(near_rows)
    intervention = sum(1 for a in assessments if a["tone"] == "critical")
    watch = sum(1 for a in assessments if a["tone"] == "watch")
    gaps = [(a.get("scope"), a.get("progress_target_gap")) for a in assessments if a.get("progress_target_gap") is not None]
    gap_scope, gap_val = max(gaps, key=lambda x: x[1]) if gaps else ("N/A", None)
    baseline_max = max((int(a["baseline"].get("max_delay", 0)) for a in assessments), default=0)
    exposure_pairs = [(a.get("scope"), a["cost"].get("exposure_pct")) for a in assessments if a["cost"].get("exposure_pct") is not None]
    exp_scope, exp_pct = max(exposure_pairs, key=lambda x: x[1]) if exposure_pairs else ("N/A", None)
    posture_tone = "critical" if intervention else ("watch" if watch or total_delayed else "good")
    action_tone = "critical" if total_delayed else ("watch" if total_near else "good")
    variance_tone = "critical" if gap_val is not None and gap_val >= 8 else ("watch" if gap_val is not None and gap_val > 0 else "good")
    baseline_tone = "critical" if baseline_max > 14 else ("watch" if baseline_max > 0 else "primary")
    action_button = _action_popover_button_v32("Portfolio delayed and near-due actions", delayed_rows + near_rows, total_delayed + total_near, label=f"{total_delayed}/{total_near}", class_name="pm-click-card")
    st.markdown("<div class='pm-health-grid'>" +
        f"<div class='pm-health-card {posture_tone}'><span>Portfolio posture</span><b>{_html(str(intervention))}</b><p>intervention scopes; {watch} watch scopes</p></div>" +
        f"<div class='pm-health-card {action_tone} click-wrap'><span>Action pressure</span><b>{action_button}</b><p>delayed / near-due active items</p><em class='click-hint'>Click number to view list</em></div>" +
        f"<div class='pm-health-card {variance_tone}'><span>Progress target check</span><b>{_html('N/A' if gap_val is None else f'{gap_val:.1f}%')}</b><p>gap to 10% monthly minimum on {_html(str(gap_scope))}</p></div>" +
        f"<div class='pm-health-card {baseline_tone}'><span>Baseline / exposure check</span><b>+{baseline_max}d</b><p>max BL slip; exposure {_html(_pm_pct(exp_pct))} on {_html(str(exp_scope))}</p></div></div>", unsafe_allow_html=True)
