def render_pm_scope_summary(rec: Dict[str, Any], selected_year: int, selected_week: int, current_date: Optional[pd.Timestamp]) -> None:
    a = _pm_scope_assessment(rec, selected_year, selected_week, current_date)
    actions, baseline, cost = a["actions"], a["baseline"], a["cost"]
    delayed_rows = _filter_action_rows_v32(actions.get("rows") or [], {"Delayed"})
    near_rows = _filter_action_rows_v32(actions.get("rows") or [], {"Near due"})
    action_button = _action_popover_button_v32(f"{a['scope']} delayed and near-due actions", delayed_rows + near_rows, int(actions.get("Delayed", 0)) + int(actions.get("Near due", 0)), label=f"{actions.get('Delayed', 0)} delayed", class_name="pm-click-card")
    st.markdown("<div class='pm-scope-summary'><div class='pm-scope-summary-grid'>" +
        f"<div class='pm-scope-summary-cell'><span class='label'>PM control status</span><b><span class='pm-status {a['tone']}'>{_html(a['label'])}</span></b><p>{_html(compact_text(a.get('first_delayed') or _matrix_driver(rec), 130))}</p></div>" +
        f"<div class='pm-scope-summary-cell click-wrap'><span class='label'>Actions</span><b>{action_button}</b><p>{actions.get('Near due', 0)} near due; {actions.get('TBC', 0)} TBC</p><em class='click-hint'>Click number to view list</em></div>" +
        f"<div class='pm-scope-summary-cell'><span class='label'>Progress target</span><b>{a.get('progress_target_gap', 0):.1f}% gap</b><p>minimum 10% monthly progress; construction {_html(_pm_pp(a.get('construction_dev')))}, engineering {_html(_pm_pp(a.get('engineering_dev')))}</p></div>" +
        f"<div class='pm-scope-summary-cell'><span class='label'>Baseline variance</span><b>+{baseline.get('max_delay', 0)} days</b><p>{baseline.get('slipped', 0)} slipped milestone matches</p></div>" +
        f"<div class='pm-scope-summary-cell'><span class='label'>Cost exposure</span><b>{_html(_pm_pct(cost.get('exposure_pct')))}</b><p>ETC {_html(_fmt_money(cost.get('etc')))}</p></div></div></div>", unsafe_allow_html=True)


def _pm_heatmap_figure(assessments: List[Dict[str, Any]]) -> go.Figure:
    metrics = ["Actions", "Progress vs 10%/month", "Gates", "Baseline", "Cost", "Total"]
    score_keys = ["Actions", "Progress", "Gates", "Baseline", "Cost", "Total"]
    scopes = [str(a.get("scope") or "Scope") for a in assessments]
    z = [[_pm_visual_scores(a)[m] for m in score_keys] for a in assessments]
    text = [[f"{val:.1f}" for val in row] for row in z]
    custom = []
    for a in assessments:
        custom.append([
            f"Progress target gap: {float(a.get('progress_target_gap') or 0.0):.1f}%",
            f"Construction actual: {_pm_pct(a.get('construction_actual'))}",
            f"Engineering actual: {_pm_pct(a.get('engineering_actual'))}",
        ])
    fig = go.Figure(data=go.Heatmap(
        z=z, x=metrics, y=scopes, text=text, texttemplate="%{text}", zmin=0, zmax=10,
        colorscale=[[0, "#e7f7ee"], [.45, "#fff5df"], [1, "#fdeaea"]],
        colorbar=dict(title="Pressure", len=.76),
        customdata=[[custom[i] for _ in metrics] for i in range(len(scopes))],
        hovertemplate="<b>%{y}</b><br>%{x}: %{z:.1f}/10<br>%{customdata[0]}<br>%{customdata[1]}<br>%{customdata[2]}<extra></extra>",
    ))
    fig.update_yaxes(autorange="reversed")
    return _pm_theme_figure(fig, height=330)


def _pm_action_variance_figure(assessments: List[Dict[str, Any]]) -> go.Figure:
    scopes = [str(a.get("scope") or "Scope") for a in assessments]
    delayed = [int((a.get("actions") or {}).get("Delayed", 0)) for a in assessments]
    near = [int((a.get("actions") or {}).get("Near due", 0)) for a in assessments]
    construction = [_safe_float(a.get("construction_dev")) or 0.0 for a in assessments]
    engineering = [_safe_float(a.get("engineering_dev")) or 0.0 for a in assessments]
    target_gap = [float(a.get("progress_target_gap") or 0.0) for a in assessments]
    fig = go.Figure()
    fig.add_trace(go.Bar(name="Delayed actions", x=scopes, y=delayed, marker_color="#c73535", yaxis="y"))
    fig.add_trace(go.Bar(name="Near due", x=scopes, y=near, marker_color="#b87000", yaxis="y"))
    fig.add_trace(go.Scatter(name="Gap to 10% monthly progress", x=scopes, y=target_gap, mode="lines+markers+text", text=[f"{v:.1f}%" for v in target_gap], textposition="top center", marker=dict(color="#39135c", size=9), line=dict(color="#39135c", width=2.4), yaxis="y2"))
    fig.add_trace(go.Scatter(name="Construction variance", x=scopes, y=construction, mode="lines+markers", marker=dict(color="#111111", size=8), line=dict(color="#111111", width=2, dash="dot"), yaxis="y2"))
    fig.add_trace(go.Scatter(name="Engineering variance", x=scopes, y=engineering, mode="lines+markers", marker=dict(color="#6f2da8", size=8), line=dict(color="#6f2da8", width=2, dash="dash"), yaxis="y2"))
    fig.update_layout(barmode="stack", yaxis=dict(title="Action count", rangemode="tozero", showgrid=True, gridcolor="#f0edf5"), yaxis2=dict(title="Progress % / variance %", overlaying="y", side="right", zeroline=True, zerolinecolor="#98a2b3", showgrid=False, ticksuffix="%"))
    return _pm_theme_figure(fig, height=330)


def render_pm_visuals(records: List[Dict[str, Any]], selected_year: int, selected_week: int, current_date: Optional[pd.Timestamp]) -> None:
    assessments = [_pm_scope_assessment(r, selected_year, selected_week, current_date) for r in records if r.get("scope_id") in {"rail", "ponds", "roads"}]
    if not assessments:
        return
    st.markdown("<div class='section-title'>PM analysis visuals</div>", unsafe_allow_html=True)
    left, right = st.columns([1.08, .92], gap="large")
    with left:
        st.markdown("<div class='pm-visual-card'><h3>Control pressure heatmap</h3><p><span class='target-note'>Progress pressure includes the 10% per month minimum</span> for every scope, plus actions, gates, baseline and cost exposure.</p>", unsafe_allow_html=True)
        st.plotly_chart(_pm_heatmap_figure(assessments), use_container_width=True)
        st.markdown("</div>", unsafe_allow_html=True)
    with right:
        st.markdown("<div class='pm-visual-card'><h3>Action pressure vs progress target</h3><p>Bars show action pressure; lines show the gap to the 10% monthly progress target and schedule variance.</p>", unsafe_allow_html=True)
        st.plotly_chart(_pm_action_variance_figure(assessments), use_container_width=True)
        st.markdown("</div>", unsafe_allow_html=True)
    st.markdown("<div class='pm-visual-card'><h3>Cost exposure and ETC</h3><p>Exposure is normalized against forecast; ETC remains in EUR.</p>", unsafe_allow_html=True)
    st.plotly_chart(_pm_cost_exposure_figure(assessments), use_container_width=True)
    st.markdown("</div>", unsafe_allow_html=True)


def _gate_pill_html(title: str, count: int, items: List[Any]) -> str:
    rows = _as_action_records_v32(items, int(st.session_state.get("selected_year_v32", 2026)), int(st.session_state.get("selected_week_v32", 1)), current_date=st.session_state.get("selected_cutoff_v32"))
    return "<div class='gate-click-wrap'>" + _action_popover_button_v32(title, rows, count, label=f"{int(count)}", class_name="gate-click-btn") + "</div>"


def _exec_cost_metric_rows_v32(scope_id: str, metric_label: str) -> List[Dict[str, Any]]:
    try:
        df = _history_for_scope(scope_id)
    except Exception:
        df = pd.DataFrame()
    if df is None or df.empty or metric_label not in df.columns:
        return []
    rows = []
    for _, r in df.tail(8).iloc[::-1].iterrows():
        rows.append({"action": f"{r.get('Month')}: {metric_label} {_fmt_money(r.get(metric_label))}", "responsible": "Cost control", "expected": r.get("Month") or "N/A", "status": "Cost detail", "class": "primary"})
    return rows


def _cost_cell_v32(scope_id: str, label: str, value: Any, metric_label: str, extra: str = "") -> str:
    rows = _exec_cost_metric_rows_v32(scope_id, metric_label)
    button = _action_popover_button_v32(f"{_scope_label_v32(scope_id)} - {label} history", rows, len(rows), label=_fmt_money(value), class_name="pm-click-card")
    return f"<div class='exec-cost-cell clickable'><span>{_html(label)}</span><b>{button}</b>{f'<p>{_html(extra)}</p>' if extra else ''}<em class='click-hint'>Click value for history</em></div>"


def _exec_cost_card_html_v25(scope_id: str) -> str:
    row = _active_history_row(scope_id)
    if not row:
        return "<div class='exec-cost-card'><h4>Cost status</h4><div class='action-empty'>No cost data loaded for this scope.</div></div>"
    forecast = _safe_float(row.get("Forecast"))
    vowd = _safe_float(row.get("VOWD"))
    etc = _safe_float(row.get("ETC"))
    exposure = _safe_float(row.get("Potential exposure"))
    potential = _safe_float(row.get("Potential forecast"))
    return (
        f"<div class='exec-cost-card'><h4>{_html(_scope_label_v32(scope_id))} cost status</h4>"
        "<div class='exec-cost-grid'>"
        f"{_cost_cell_v32(scope_id, 'Forecast', forecast, 'Forecast')}"
        f"{_cost_cell_v32(scope_id, 'VOWD', vowd, 'VOWD')}"
        f"{_cost_cell_v32(scope_id, 'ETC', etc, 'ETC')}"
        f"{_cost_cell_v32(scope_id, 'Exposure', exposure, 'Potential exposure', _pm_pct(_pm_ratio(exposure, forecast)) + ' of forecast')}"
        f"{_cost_cell_v32(scope_id, 'Potential FC', potential, 'Potential forecast')}"
        f"<div class='exec-cost-cell'><span>Active month</span><b>{_html(_active_month_label_v29())}</b></div>"
        "</div></div>"
    )


def render_scope_matrix(records: List[Dict[str, Any]], selected_year: int, selected_week: int) -> None:
    st.session_state["selected_year_v32"] = int(selected_year)
    st.session_state["selected_week_v32"] = int(selected_week)
    order = {"rail": 0, "ponds": 1, "roads": 2}
    records = [_with_display_scope(r) for r in records if r.get("scope_id") in order]
    records = sorted(records, key=lambda r: order.get(r.get("scope_id"), 99))
    cols = st.columns(3, gap="large")
    for col, rec in zip(cols, records):
        rec["name"] = _scope_label_v32(rec.get("scope_id"))
        rec["full_name"] = rec["name"]
        with col:
            construction_actual = rec.get("construction_actual")
            construction_forecast = rec.get("construction_forecast") if rec.get("construction_forecast") is not None else construction_actual
            construction_dev = rec.get("construction_deviation")
            if construction_dev is None and construction_actual is not None and construction_forecast is not None:
                construction_dev = construction_actual - construction_forecast
            engineering_actual = rec.get("engineering_actual")
            engineering_forecast = rec.get("engineering_forecast") if rec.get("engineering_forecast") is not None else engineering_actual
            engineering_dev = rec.get("engineering_deviation")
            if engineering_dev is None and engineering_actual is not None and engineering_forecast is not None:
                engineering_dev = engineering_actual - engineering_forecast
            construction_etc = _date_only_etc(_baseline_etc_for_scope(rec["scope_id"], selected_year, selected_week, mode="final"), fallback="TBC")
            engineering_etc = _date_only_etc(rec.get("engineering_etc") or _baseline_etc_for_scope(rec["scope_id"], selected_year, selected_week, mode="next"), fallback="TBC")
            icon = SCOPE_ICON.get(rec["scope_id"], "")
            html_block = (
                "<div class='matrix-col'>"
                "<div class='matrix-head'>"
                f"<h3><span><span class='scope-icon'>{icon}</span>{_html(rec['name'])}</span>{_scope_link_v32(rec['scope_id'])}</h3>"
                f"<span class='status-badge'>{_html(_matrix_driver(rec))}</span>"
                "</div>"
                f"{progress_bar_html('Construction progress', construction_actual, construction_forecast, construction_dev, construction_etc, next_week_forecast=_next_progress_label(rec, selected_year, selected_week, 'construction'))}"
                f"{progress_bar_html('Engineering progress', engineering_actual, engineering_forecast, engineering_dev, engineering_etc, next_week_forecast=_next_progress_label(rec, selected_year, selected_week, 'engineering'))}"
                "<div class='gate-row'>"
                f"{_gate_pill_html('Open quality gates', len(rec.get('quality_items', [])), rec.get('quality_items', []))}"
                f"{_gate_pill_html('Open engineering gates', len(rec.get('engineering_items', [])), rec.get('engineering_items', []))}"
                "</div>"
                f"{_exec_cost_card_html_v25(rec['scope_id'])}"
                f"{_next_fc_box_html(rec)}"
                "</div>"
            )
            st.markdown(html_block, unsafe_allow_html=True)


def _cost_health_cards(scope_id: str) -> None:
    row = _active_history_row(scope_id)
    if not row:
        return
    check1 = _safe_float(row.get("Budget + CO check"))
    check2 = _safe_float(row.get("Forecast + exposure check"))
    forecast = _safe_float(row.get("Forecast"))
    budget = _safe_float(row.get("Budget"))
    exposure = _safe_float(row.get("Potential exposure"))
    vowd = _safe_float(row.get("VOWD"))
    vs_budget = (forecast - budget) if forecast is not None and budget is not None else None
    exp_pct = _pm_ratio(exposure, forecast)
    vowd_pct = _pm_ratio(vowd, forecast)
    forecast_delta = _cost_month_delta(scope_id, "Forecast")
    balanced = abs(check1 or 0) < 1 and abs(check2 or 0) < 1
    items = [
        ("Forecast vs budget", _fmt_money(vs_budget), "Forecast", "bad" if (vs_budget or 0) > 0 else "good"),
        ("Exposure / forecast", f"{exp_pct:.1f}%" if exp_pct is not None else "N/A", "Potential exposure", "warn" if (exp_pct or 0) > 15 else "good"),
        ("VOWD / Forecast", f"{vowd_pct:.1f}%" if vowd_pct is not None else "N/A", "VOWD", "primary"),
        ("Forecast MoM", _fmt_money(forecast_delta), "Forecast", "bad" if (forecast_delta or 0) > 0 else "good"),
        ("Cost check", "Balanced" if balanced else "Review", "Forecast + exposure check", "good" if balanced else "bad"),
    ]
    cards = []
    for label, value, metric, cls in items:
        rows = _exec_cost_metric_rows_v32(scope_id, metric)
        button = _action_popover_button_v32(f"{_scope_label_v32(scope_id)} - {label}", rows, len(rows), label=str(value), class_name="pm-click-card")
        cards.append(f"<div class='cost-health-card {cls} clickable'><span>{_html(label)}</span><b>{button}</b><em class='click-hint'>Click value for history</em></div>")
    st.markdown("<div class='cost-health-row'>" + "".join(cards) + "</div>", unsafe_allow_html=True)


def render_cost_panel(bundle: Dict[str, Any], profiles: Dict[str, Any], selected_year: int, selected_week: int, current_date: Optional[pd.Timestamp] = None) -> None:
    active_report = _active_cost_report()
    active_month = active_report.get("label") or _active_month_label_from_cost(active_report.get("data") or {})
    cost_data = active_report.get("data") or cached_monthly_cost()
    meta = cost_data.get("metadata") or {}
    labels = list(COST_SCOPE_OPTIONS.values()) if "COST_SCOPE_OPTIONS" in globals() else ["All scopes", "Rail On Site (ROS)", "Ponds", "Roads"]
    label_to_id = {v: k for k, v in COST_SCOPE_OPTIONS.items()} if "COST_SCOPE_OPTIONS" in globals() else {"All scopes":"all", "Rail On Site (ROS)":"rail", "Ponds":"ponds", "Roads":"roads"}
    selected_scope_label = st.session_state.get("cost_scope_visual_selector", "All scopes")
    if selected_scope_label not in labels:
        selected_scope_label = labels[0]
        st.session_state["cost_scope_visual_selector"] = selected_scope_label
    scope_id = label_to_id.get(selected_scope_label, "all")
    st.markdown(f"<div class='cost-detail-card v32'><div class='cost-detail-grid v32'><div class='cost-detail-cell'><span>Active month</span><b>{_html(active_month)}</b></div><div class='cost-detail-cell'><span>Currency</span><b>{_html(meta.get('currency') or 'EUR')}</b></div><div class='cost-detail-cell'><span>Scope view</span><b>{_html(selected_scope_label)}</b></div></div></div>", unsafe_allow_html=True)
    try:
        _render_cost_kpi_cards(scope_id)
    except Exception:
        pass
    try:
        _cost_health_cards(scope_id)
    except Exception:
        pass
    if scope_id == "all":
        left, right = st.columns([1.0, 1.35], gap="large")
        with left:
            st.markdown("<div class='cost-chart-box'><h3>Active month comparison per scope</h3><p>Latest selected month, split by Rail On Site (ROS), Ponds and Roads.</p>", unsafe_allow_html=True)
            st.plotly_chart(_cost_scope_comparison_figure(), use_container_width=True)
