def _rows_popover_body_v33(rows: List[Dict[str, Any]]) -> str:
    if not rows:
        return "<div class='pm-empty-list'>No detail rows are loaded for this selection.</div>"
    body = []
    for i, row in enumerate(rows[:90], start=1):
        body.append(
            "<div class='pop-row'>"
            f"<i>{i:02d}</i><span>{_html(row.get('action'))}"
            f"<small>Responsible: {_html(row.get('responsible'))} | Expected: {_html(row.get('expected'))} | Status: {_html(row.get('status'))}</small></span></div>"
        )
    return "".join(body)


def _popover_markup_v33(title: str, rows: List[Dict[str, Any]], button_html: str, button_class: str) -> str:
    token = hashlib.sha1((title + "|" + "|".join(str(r.get("action", "")) for r in rows[:30])).encode("utf-8", "ignore")).hexdigest()[:12]
    pid = f"pop_v33_{token}"
    return (
        f"<button type='button' class='{button_class}' popovertarget='{pid}' popovertargetaction='toggle'>{button_html}</button>"
        f"<div id='{pid}' class='pm-popover-v33' popover><div class='pop-head'><b>{_html(title)}</b>"
        f"<span>{len(rows)} row(s). Click outside this list to close.</span></div><div class='pop-body'>{_rows_popover_body_v33(rows)}</div></div>"
    )


def _action_popover_button_v32(title: str, rows: List[Dict[str, Any]], count: int, label: Optional[str] = None, class_name: str = "action-count-button") -> str:
    return _popover_markup_v33(title, rows, _html(label or f"{count} items"), class_name)


def _full_action_card_v33(title: str, rows: List[Dict[str, Any]], card_class: str, label: str, value: str, note: str) -> str:
    html = f"<span>{_html(label)}</span><b>{_html(value)}</b><p>{_html(note)}</p><em class='click-hint'>Click anywhere on this box</em>"
    return _popover_markup_v33(title, rows, html, card_class + " rc-click-card")


def _cost_history_rows_v33(scope_id: str, metric_label: str) -> List[Dict[str, Any]]:
    return _exec_cost_metric_rows_v32(scope_id, metric_label) if "_exec_cost_metric_rows_v32" in globals() else []


def _cost_kpi_click_card(scope_id: str, metric_key: str, label: str, value: Any, active_label: str, cls: str, sub: str) -> str:
    token = hashlib.sha1((scope_id + metric_key + label + str(active_label)).encode("utf-8", "ignore")).hexdigest()[:12]
    pid = f"cost_hist_v33_{token}"
    tip = _cost_kpi_hover(scope_id, metric_key, label, active_label)
    button_html = (
        f"<div class='cost-kpi-label'>{_html(label)}</div>"
        f"<div class='cost-kpi-value'>{_html(_fmt_money(value))}</div>"
        f"<div class='cost-kpi-sub'>{_html(sub)} - click anywhere for history</div>"
    )
    return (
        f"<button type='button' class='cost-kpi-card {cls} rc-click-card' popovertarget='{pid}' popovertargetaction='toggle'>{button_html}</button>"
        f"<div id='{pid}' class='cost-popover pm-popover-v33' popover><div class='cost-popover-inner'>"
        f"<div class='cost-popover-title'>{_html(label)} history</div>{tip}</div></div>"
    )


def _cost_cell_v32(scope_id: str, label: str, value: Any, metric_label: str, extra: str = "") -> str:
    rows = _cost_history_rows_v33(scope_id, metric_label)
    note = (extra or "Monthly history") + " - click anywhere"
    button_html = f"<span>{_html(label)}</span><b>{_html(_fmt_money(value))}</b><p>{_html(note)}</p><em class='click-hint'>Click anywhere on this box</em>"
    return _popover_markup_v33(f"{_scope_label_v32(scope_id)} - {label} history", rows, button_html, "exec-cost-cell clickable rc-click-card")


def _cost_health_cards(scope_id: str) -> None:
    row = _active_history_row(scope_id)
    if not row:
        return
    check1 = _safe_float(row.get("Budget + CO check")); check2 = _safe_float(row.get("Forecast + exposure check"))
    forecast = _safe_float(row.get("Forecast")); budget = _safe_float(row.get("Budget")); exposure = _safe_float(row.get("Potential exposure")); vowd = _safe_float(row.get("VOWD"))
    vs_budget = (forecast - budget) if forecast is not None and budget is not None else None
    exp_pct = _pm_ratio(exposure, forecast); vowd_pct = _pm_ratio(vowd, forecast); forecast_delta = _cost_month_delta(scope_id, "Forecast")
    balanced = abs(check1 or 0) < 1 and abs(check2 or 0) < 1
    items = [
        ("Forecast vs budget", _fmt_money(vs_budget), "Forecast", "bad" if (vs_budget or 0) > 0 else "good"),
        ("Exposure / forecast", f"{exp_pct:.1f}%" if exp_pct is not None else "N/A", "Potential exposure", "warn" if (exp_pct or 0) > 15 else "good"),
        ("VOWD / Forecast", f"{vowd_pct:.1f}%" if vowd_pct is not None else "N/A", "VOWD", "primary"),
        ("Forecast MoM", _fmt_money(forecast_delta), "Forecast", "bad" if (forecast_delta or 0) > 0 else "good"),
        ("Cost check", "Balanced" if balanced else "Review", "Forecast + exposure check", "good" if balanced else "bad"),
    ]
    cards = []
    for label, value, metric, cls in items:
        rows = _cost_history_rows_v33(scope_id, metric)
        button_html = f"<span>{_html(label)}</span><b>{_html(str(value))}</b><em class='click-hint'>Click anywhere for history</em>"
        cards.append(_popover_markup_v33(f"{_scope_label_v32(scope_id)} - {label}", rows, button_html, f"cost-health-card {cls} clickable rc-click-card"))
    st.markdown("<div class='cost-health-row'>" + "".join(cards) + "</div>", unsafe_allow_html=True)


def _gate_pill_html(title: str, count: int, items: List[Any]) -> str:
    rows = _as_action_records_v32(items, int(st.session_state.get("selected_year_v32", 2026)), int(st.session_state.get("selected_week_v32", 1)), current_date=st.session_state.get("selected_cutoff_v32"))
    button_html = f"<span>{_html(title)}</span><b>{int(count)}</b><small>Click anywhere to open list</small>"
    return "<div class='gate-click-wrap'>" + _popover_markup_v33(title, rows, button_html, "gate-click-btn rc-click-card") + "</div>"


def _pm_scope_card_html(a: Dict[str, Any]) -> str:
    actions, baseline, cost = a["actions"], a["baseline"], a["cost"]
    all_rows = actions.get("rows") or []
    delayed_rows = _filter_action_rows_v32(all_rows, {"Delayed"})
    near_rows = _filter_action_rows_v32(all_rows, {"Near due"})
    action_signal = _popover_markup_v33(
        f"{a['scope']} delayed and near-due actions",
        delayed_rows + near_rows,
        f"<span>Actions</span><b>{actions.get('Delayed', 0)} delayed / {actions.get('Near due', 0)} near due<br><em class='click-hint'>Click row to view list</em></b>",
        "pm-signal-button",
    )
    signals = [
        action_signal,
        _pm_signal_html("Progress", f"Construction {_pm_pp(a.get('construction_dev'))}; Engineering {_pm_pp(a.get('engineering_dev'))}; target gap {a.get('progress_target_gap', 0):.1f}%"),
        _pm_signal_html("Baseline", f"{baseline.get('slipped', 0)} slipped / max +{baseline.get('max_delay', 0)} days"),
        _pm_signal_html("Cost", f"Exposure {_pm_pct(cost.get('exposure_pct'))}; ETC {_fmt_money(cost.get('etc'))}"),
    ]
    if a.get("first_delayed"):
        signals.append(_pm_signal_html("First late", compact_text(a["first_delayed"], 105)))
    return f"<div class='pm-scope-card'><h3>{_html(a['scope'])}{_scope_link_v32(a.get('scope_id'))}</h3><span class='pm-status {a['tone']}'>{_html(a['label'])}</span><div class='pm-signal-list'>{''.join(signals)}</div></div>"


def render_pm_control_health(records: List[Dict[str, Any]], selected_year: int, selected_week: int, current_date: Optional[pd.Timestamp]) -> None:
    assessments = [_pm_scope_assessment(r, selected_year, selected_week, current_date) for r in records if r.get("scope_id") in {"rail", "ponds", "roads"}]
    if not assessments:
        return
    all_rows = [row for a in assessments for row in ((a.get("actions") or {}).get("rows") or [])]
    delayed_rows = _filter_action_rows_v32(all_rows, {"Delayed"}); near_rows = _filter_action_rows_v32(all_rows, {"Near due"})
    total_delayed = len(delayed_rows); total_near = len(near_rows)
    intervention = sum(1 for a in assessments if a["tone"] == "critical"); watch = sum(1 for a in assessments if a["tone"] == "watch")
    gaps = [(a.get("scope"), a.get("progress_target_gap")) for a in assessments if a.get("progress_target_gap") is not None]
    gap_scope, gap_val = max(gaps, key=lambda x: x[1]) if gaps else ("N/A", None)
    baseline_max = max((int(a["baseline"].get("max_delay", 0)) for a in assessments), default=0)
    exposure_pairs = [(a.get("scope"), a["cost"].get("exposure_pct")) for a in assessments if a["cost"].get("exposure_pct") is not None]
    exp_scope, exp_pct = max(exposure_pairs, key=lambda x: x[1]) if exposure_pairs else ("N/A", None)
    posture_tone = "critical" if intervention else ("watch" if watch or total_delayed else "good")
    action_tone = "critical" if total_delayed else ("watch" if total_near else "good")
    variance_tone = "critical" if gap_val is not None and gap_val >= 8 else ("watch" if gap_val is not None and gap_val > 0 else "good")
    baseline_tone = "critical" if baseline_max > 14 else ("watch" if baseline_max > 0 else "primary")
    action_card = _full_action_card_v33("Portfolio delayed and near-due actions", delayed_rows + near_rows, f"pm-health-card {action_tone}", "Action pressure", f"{total_delayed}/{total_near}", "delayed / near-due active items")
    st.markdown("<div class='pm-health-grid'>" +
        f"<div class='pm-health-card {posture_tone}'><span>Portfolio posture</span><b>{_html(str(intervention))}</b><p>intervention scopes; {watch} watch scopes</p></div>" +
        action_card +
        f"<div class='pm-health-card {variance_tone}'><span>Progress target check</span><b>{_html('N/A' if gap_val is None else f'{gap_val:.1f}%')}</b><p>gap to 10% monthly minimum on {_html(str(gap_scope))}</p></div>" +
        f"<div class='pm-health-card {baseline_tone}'><span>Baseline / exposure check</span><b>+{baseline_max}d</b><p>max BL slip; exposure {_html(_pm_pct(exp_pct))} on {_html(str(exp_scope))}</p></div></div>", unsafe_allow_html=True)
    st.markdown("<div class='pm-scope-grid'>" + "".join(_pm_scope_card_html(a) for a in assessments) + "</div>", unsafe_allow_html=True)


def render_pm_scope_summary(rec: Dict[str, Any], selected_year: int, selected_week: int, current_date: Optional[pd.Timestamp]) -> None:
    a = _pm_scope_assessment(rec, selected_year, selected_week, current_date)
    actions, baseline, cost = a["actions"], a["baseline"], a["cost"]
    delayed_rows = _filter_action_rows_v32(actions.get("rows") or [], {"Delayed"}); near_rows = _filter_action_rows_v32(actions.get("rows") or [], {"Near due"})
    action_card = _full_action_card_v33(f"{a['scope']} delayed and near-due actions", delayed_rows + near_rows, "pm-scope-summary-cell", "Actions", f"{actions.get('Delayed', 0)} delayed", f"{actions.get('Near due', 0)} near due; {actions.get('TBC', 0)} TBC")
    st.markdown("<div class='pm-scope-summary'><div class='pm-scope-summary-grid'>" +
        f"<div class='pm-scope-summary-cell'><span class='label'>PM control status</span><b><span class='pm-status {a['tone']}'>{_html(a['label'])}</span></b><p>{_html(compact_text(a.get('first_delayed') or _matrix_driver(rec), 130))}</p></div>" +
        action_card +
        f"<div class='pm-scope-summary-cell'><span class='label'>Progress target</span><b>{a.get('progress_target_gap', 0):.1f}% gap</b><p>minimum 10% monthly progress; construction {_html(_pm_pp(a.get('construction_dev')))}, engineering {_html(_pm_pp(a.get('engineering_dev')))}</p></div>" +
        f"<div class='pm-scope-summary-cell'><span class='label'>Baseline variance</span><b>+{baseline.get('max_delay', 0)} days</b><p>{baseline.get('slipped', 0)} slipped milestone matches</p></div>" +
        f"<div class='pm-scope-summary-cell'><span class='label'>Cost exposure</span><b>{_html(_pm_pct(cost.get('exposure_pct')))}</b><p>ETC {_html(_fmt_money(cost.get('etc')))}</p></div></div></div>", unsafe_allow_html=True)



