def _scope_link_v32(scope_id: str, label: str = ">") -> str:
    panel = SCOPE_PANEL_BY_ID.get(str(scope_id or "").lower()) if "SCOPE_PANEL_BY_ID" in globals() else None
    if not panel:
        return ""
    token = hashlib.sha1((panel + "detail").encode("utf-8", "ignore")).hexdigest()[:10]
    return f"<a class='scope-detail-link icon-only' href='?panel={quote_plus(panel)}&nav={token}' target='_self' title='Open detail' aria-label='Open detail'>&gt;</a>"


def _chart_box_v34():
    try:
        return st.container(border=True)
    except TypeError:
        return st.container()


def _cost_value_rows_v34(scope_id: str, metric_label: str, rows: int = 8) -> str:
    try:
        df = _history_for_scope(scope_id).copy()
    except Exception:
        df = pd.DataFrame()
    if df is None or df.empty or metric_label not in df.columns:
        return "<div class='pm-empty-list'>No monthly values loaded.</div>"
    if "Date" in df.columns:
        df = df.sort_values("Date", ascending=True, na_position="last")
    else:
        df = df.copy()
    sub = df.tail(rows).iloc[::-1]
    vals = [_safe_float(v) for v in sub[metric_label].tolist()]
    max_val = max([abs(v) for v in vals if v is not None] or [1.0])
    html_rows = []
    for _, r in sub.iterrows():
        val = _safe_float(r.get(metric_label))
        pct = 0 if val is None else min(100, max(3, abs(val) / max_val * 100))
        html_rows.append(f"<div class='cost-time-row'><span>{_html(r.get('Month'))}</span><b>{_html(_fmt_money(val))}</b><i><u style='width:{pct:.0f}%'></u></i></div>")
    return "".join(html_rows)


def _cost_popover_v34(title: str, scope_id: str, metric_label: str, button_html: str, button_class: str) -> str:
    token = hashlib.sha1((title + scope_id + metric_label).encode("utf-8", "ignore")).hexdigest()[:12]
    pid = f"cost_v34_{token}"
    body = _cost_value_rows_v34(scope_id, metric_label)
    return (
        f"<button type='button' class='{button_class}' popovertarget='{pid}' popovertargetaction='toggle'>{button_html}</button>"
        f"<div id='{pid}' class='pm-popover-v33' popover><div class='pop-head'><b>{_html(title)}</b></div><div class='pop-body'>{body}</div></div>"
    )


def _cost_kpi_click_card(scope_id: str, metric_key: str, label: str, value: Any, active_label: str, cls: str, sub: str) -> str:
    button_html = f"<div class='cost-kpi-label'>{_html(label)}</div><div class='cost-kpi-value'>{_html(_fmt_money(value))}</div>"
    return _cost_popover_v34(f"{label}", scope_id, label, button_html, f"cost-kpi-card {cls} rc-click-card")


def _cost_cell_v32(scope_id: str, label: str, value: Any, metric_label: str, extra: str = "") -> str:
    button_html = f"<span>{_html(label)}</span><b>{_html(_fmt_money(value))}</b>"
    return _cost_popover_v34(label, scope_id, metric_label, button_html, "exec-cost-cell clickable rc-click-card")


