def _cost_waterfall_figure_v24(scope_id: str, cost_data: Optional[Dict[str, Any]] = None, title: str = "Cost candle bar") -> go.Figure:
    cost_data = cost_data or (_active_cost_report().get("data") or cached_monthly_cost())
    active_label = _active_cost_report().get("label") or _active_month_label_from_cost(cost_data)
    if scope_id == "all":
        row = _active_history_row("all")
        budget = _safe_float(row.get("Budget")) or 0.0
        co = _safe_float(row.get("CO")) or 0.0
        forecast = _safe_float(row.get("Forecast")) if row.get("Forecast") is not None else budget + co
        exposure = _safe_float(row.get("Potential exposure")) or 0.0
        potential_forecast = _safe_float(row.get("Potential forecast")) if row.get("Potential forecast") is not None else (forecast or 0.0) + exposure
    else:
        nums = _cost_numbers(scope_id, cost_data)
        budget = _safe_float(nums.get("budget")) or 0.0
        forecast = _safe_float(nums.get("forecast"))
        co = (forecast - budget) if forecast is not None else (_safe_float(nums.get("change_order")) or 0.0)
        forecast = forecast if forecast is not None else budget + co
        exposure = _safe_float(nums.get("potential_exposure")) or 0.0
        potential_forecast = _safe_float(nums.get("potential_forecast")) if nums.get("potential_forecast") is not None else forecast + exposure
    labels = ["Budget", "CO", "Forecast", "Exposure", "Potential FC"]
    y_vals = [budget, co, forecast, exposure, potential_forecast]
    measures = ["absolute", "relative", "total", "relative", "total"]
    custom = [[active_label, _fmt_money_full(v)] for v in y_vals]
    fig = go.Figure(go.Waterfall(
        x=labels, y=y_vals, measure=measures, text=[_fmt_money(v) for v in y_vals], textposition="outside",
        connector={"line": {"color": "#9aa1ad", "width": 1}},
        increasing={"marker": {"color": "#058b55"}}, decreasing={"marker": {"color": "#c73535"}}, totals={"marker": {"color": "#6f2da8"}},
        customdata=custom,
        hovertemplate="%{customdata[0]}<br>%{x}: %{customdata[1]}<extra></extra>",
    ))
    fig.update_layout(height=360, margin=dict(l=34, r=18, t=30, b=48), paper_bgcolor="rgba(0,0,0,0)", plot_bgcolor="rgba(0,0,0,0)", showlegend=False, yaxis_title="EUR", hovermode="closest")
    fig.update_xaxes(tickangle=-18)
    fig.update_yaxes(showgrid=True, gridcolor="#f0edf5", zeroline=False)
    return fig


def _cost_history_trend_figure(scope_id: str) -> go.Figure:
    try:
        df = _history_for_scope(scope_id).copy()
    except Exception:
        df = pd.DataFrame()
    fig = go.Figure()
    if df is not None and not df.empty and "Month" in df.columns:
        if "Date" in df.columns:
            df = df.sort_values("Date", ascending=True, na_position="last")
        metrics = [("Forecast", "#0b66c3"), ("VOWD", "#111111"), ("ETC", "#6f2da8"), ("Potential forecast", "#b87000")]
        x_vals = df["Month"].astype(str).tolist()
        for metric, color in metrics:
            if metric not in df.columns:
                continue
            y_vals = [_safe_float(v) for v in df[metric].tolist()]
            fig.add_trace(go.Scatter(x=x_vals, y=y_vals, mode="lines+markers", name=metric, line=dict(color=color, width=2.4), marker=dict(size=7), hovertemplate="%{x}<br>%{y:,.0f} EUR<extra></extra>"))
    fig.update_layout(height=360, margin=dict(l=40, r=18, t=30, b=54), paper_bgcolor="rgba(0,0,0,0)", plot_bgcolor="rgba(0,0,0,0)", hovermode="x unified", legend=dict(orientation="h", yanchor="bottom", y=1.02, xanchor="right", x=1, font=dict(size=10)))
    fig.update_xaxes(tickangle=-24, showgrid=False)
    fig.update_yaxes(showgrid=True, gridcolor="#f0edf5", zeroline=False, title="EUR")
    return fig


def _pm_heatmap_figure(assessments: List[Dict[str, Any]]) -> go.Figure:
    metrics = ["Actions", "Progress", "Gates", "Baseline", "Cost", "Total"]
    scopes = [str(a.get("scope") or "Scope") for a in assessments]
    z = [[_pm_visual_scores(a)[m] for m in metrics] for a in assessments]
    custom = []
    for a in assessments:
        custom.append([f"Target gap {float(a.get('progress_target_gap') or 0.0):.1f}%", f"Construction {_pm_pct(a.get('construction_actual'))}", f"Engineering {_pm_pct(a.get('engineering_actual'))}"])
    fig = go.Figure(data=go.Heatmap(
        z=z, x=metrics, y=scopes, zmin=0, zmax=10,
        colorscale=[[0, "#e7f7ee"], [.45, "#fff5df"], [1, "#fdeaea"]],
        colorbar=dict(title="Pressure", len=.72),
        customdata=[[custom[i] for _ in metrics] for i in range(len(scopes))],
        hovertemplate="%{y}<br>%{x}<br>%{customdata[0]}<br>%{customdata[1]}<br>%{customdata[2]}<extra></extra>",
    ))
    fig.update_yaxes(autorange="reversed")
    return _pm_theme_figure(fig, height=300)


def render_header(bundle: Dict[str, Any], selected_label: str, panel_choice: str = "Executive overview") -> Tuple[int, int]:
    _latest_defaults_v32(st.session_state.get("bundle", bundle))
    periods = available_periods(st.session_state.get("bundle", bundle))
    week_labels = [period_display(y, w) for y, w in periods]
    selected_year, selected_week = _selected_period_from_state_v32(st.session_state.get("bundle", bundle))
    current_week_idx = week_labels.index(st.session_state.get("week_selector_value")) if week_labels and st.session_state.get("week_selector_value") in week_labels else max(0, len(week_labels) - 1)
    cost_labels = _month_labels_v29()
    active_month = _active_month_label_v29()
    current_month_idx = cost_labels.index(active_month) if active_month in cost_labels else max(0, len(cost_labels) - 1)
    baseline_labels = [r.get("label") for r in _baseline_reports() if r.get("label")]
    scope_labels = list(COST_SCOPE_OPTIONS.values()) if "COST_SCOPE_OPTIONS" in globals() else ["All scopes", "Rail On Site (ROS)", "Ponds", "Roads"]
    if st.session_state.get("cost_scope_visual_selector") not in scope_labels:
        st.session_state["cost_scope_visual_selector"] = scope_labels[0]
    cutoff_week = _date_for_selected_week_v29(bundle, selected_year, selected_week)
    logo_src = logo_mark_data_uri() or logo_data_uri()
    logo_html = f"<div class='rc-logo-box'><img src='{logo_src}'></div>" if logo_src else ""
    try:
        header = st.container(key="rc_panel_header_v27")
    except TypeError:
        header = st.container()
    with header:
        st.markdown("<div class='rc-title-row'>" + logo_html + "<div><h1>Roger Campbell Scopes Control Center</h1></div></div>", unsafe_allow_html=True)
        if panel_choice == "Executive overview":
            cols = st.columns([1.25, .48, .48, .95], gap="small")
            with cols[0]:
                if week_labels: st.selectbox("Week", week_labels, key="week_selector_value", label_visibility="visible")
            with cols[1]: st.button("Back", key="week_back_exec_v34", use_container_width=True, disabled=(current_week_idx <= 0), on_click=_set_active_week_by_offset, args=(-1,))
            with cols[2]: st.button("Next", key="week_next_exec_v34", use_container_width=True, disabled=(not week_labels or current_week_idx >= len(week_labels) - 1), on_click=_set_active_week_by_offset, args=(1,))
            with cols[3]: st.markdown(f"<div class='cutoff-chip'><span>Cut-off</span><b>{_html(cutoff_week)}</b></div>", unsafe_allow_html=True)
        elif panel_choice == "Cost Status":
            cols = st.columns([1.05, 1.05, .48, .48], gap="small")
            with cols[0]:
                if cost_labels: st.selectbox("Month", cost_labels, key="monthly_cost_report_choice_portfolio", label_visibility="visible")
            with cols[1]: st.selectbox("View", scope_labels, key="cost_scope_visual_selector", label_visibility="visible")
            with cols[2]: st.button("Back", key="cost_month_back_v34", use_container_width=True, disabled=(current_month_idx <= 0), on_click=_set_active_month_by_offset_v29, args=(-1,))
            with cols[3]: st.button("Next", key="cost_month_next_v34", use_container_width=True, disabled=(not cost_labels or current_month_idx >= len(cost_labels) - 1), on_click=_set_active_month_by_offset_v29, args=(1,))
        else:
            cols = st.columns([1.05, 1.05, 1.35, .95], gap="small")
            with cols[0]:
                if week_labels: st.selectbox("Week", week_labels, key="week_selector_value", label_visibility="visible")
            with cols[1]:
                if cost_labels: st.selectbox("Month", cost_labels, key="monthly_cost_report_choice_portfolio", label_visibility="visible")
            with cols[2]:
                if baseline_labels: st.selectbox("Baseline", baseline_labels, key="baseline_choice", label_visibility="visible")
            with cols[3]: st.markdown(f"<div class='cutoff-chip'><span>Cut-off</span><b>{_html(cutoff_week)}</b></div>", unsafe_allow_html=True)
        active_text = _active_month_label_v29() if panel_choice == "Cost Status" else st.session_state.get("week_selector_value", selected_label)
        st.markdown(f"<div class='panel-title-v27'><h2>{_html(_panel_title_v27(panel_choice))}</h2><span>{_html(active_text)}</span></div>", unsafe_allow_html=True)
    return _selected_period_from_state_v32(st.session_state.get("bundle", bundle))


def _render_cost_charts_v34(scope_id: str, scope_label: str, cost_data: Dict[str, Any]) -> None:
    left, right = st.columns([1.0, 1.22], gap="large")
    with left:
        with _chart_box_v34():
            st.markdown("<div class='cost-chart-title-v34'>Candle bar</div>", unsafe_allow_html=True)
            st.plotly_chart(_cost_waterfall_figure_v24(scope_id, cost_data, title=f"{scope_label} candle bar"), use_container_width=True)
    with right:
        with _chart_box_v34():
            st.markdown("<div class='cost-chart-title-v34'>Cost history trend</div>", unsafe_allow_html=True)
            st.plotly_chart(_cost_history_trend_figure(scope_id), use_container_width=True)


def render_cost_panel(bundle: Dict[str, Any], profiles: Dict[str, Any], selected_year: int, selected_week: int, current_date: Optional[pd.Timestamp] = None) -> None:
    active_report = _active_cost_report()
    active_month = active_report.get("label") or _active_month_label_from_cost(active_report.get("data") or {})
    cost_data = active_report.get("data") or cached_monthly_cost()
    labels = list(COST_SCOPE_OPTIONS.values()) if "COST_SCOPE_OPTIONS" in globals() else ["All scopes", "Rail On Site (ROS)", "Ponds", "Roads"]
    label_to_id = {v: k for k, v in COST_SCOPE_OPTIONS.items()} if "COST_SCOPE_OPTIONS" in globals() else {"All scopes":"all", "Rail On Site (ROS)":"rail", "Ponds":"ponds", "Roads":"roads"}
    selected_scope_label = st.session_state.get("cost_scope_visual_selector", "All scopes")
    if selected_scope_label not in labels:
        selected_scope_label = labels[0]
        st.session_state["cost_scope_visual_selector"] = selected_scope_label
    scope_id = label_to_id.get(selected_scope_label, "all")
    st.markdown(f"<div class='cost-detail-card v32'><div class='cost-detail-grid v32'><div class='cost-detail-cell'><span>Month</span><b>{_html(active_month)}</b></div><div class='cost-detail-cell'><span>View</span><b>{_html(selected_scope_label)}</b></div></div></div>", unsafe_allow_html=True)
    try: _render_cost_kpi_cards(scope_id)
    except Exception: pass
    try: _cost_health_cards(scope_id)
    except Exception: pass
    _render_cost_charts_v34(scope_id, selected_scope_label, cost_data)


def render_scope_cost_section(rec: Dict[str, Any]) -> None:
    rec = _with_display_scope(rec)
    rec["name"] = _scope_label_v32(rec.get("scope_id"))
    cost = _select_cost_report(rec["scope_id"])
    active_month = st.session_state.get("monthly_cost_report_choice_portfolio") or _active_month_label_from_cost(cost)
    nums = _cost_numbers(rec["scope_id"], cost)
    forecast = _safe_float(nums.get("forecast")); vowd = _safe_float(nums.get("vowd")); etc = _safe_float(nums.get("forecast_minus_vowd")); exposure = _safe_float(nums.get("potential_exposure"))
    st.markdown("<div class='section-title'>Cost</div>", unsafe_allow_html=True)
    st.markdown("<div class='cost-scope-mini'><div class='cost-detail-grid v32'>" + f"<div class='cost-detail-cell'><span>Month</span><b>{_html(active_month)}</b></div><div class='cost-detail-cell'><span>Forecast</span><b>{_html(_fmt_money(forecast))}</b></div><div class='cost-detail-cell'><span>VOWD</span><b>{_html(_fmt_money(vowd))}</b></div><div class='cost-detail-cell'><span>ETC</span><b>{_html(_fmt_money(etc))}</b></div><div class='cost-detail-cell'><span>Exposure</span><b>{_html(_fmt_money(exposure))}</b></div></div></div>", unsafe_allow_html=True)
    _render_cost_charts_v34(rec["scope_id"], rec["name"], cost)


def render_scope_sections(rec: Dict[str, Any], selected_year: int, selected_week: int, current_date: Optional[pd.Timestamp] = None) -> None:
    rec = _with_display_scope(rec)
    rec["name"] = _scope_label_v32(rec.get("scope_id"))
    rec["full_name"] = rec["name"]
    selected_label = period_display(selected_year, selected_week)
    st.markdown(f"<div class='rc-v32-scope-sticky'><h2><span class='scope-icon'>{SCOPE_ICON.get(rec.get('scope_id'), '')}</span> {_html(rec['full_name'])}</h2></div>", unsafe_allow_html=True)
    render_pm_scope_summary(rec, selected_year, selected_week, current_date)
    col1, col2 = st.columns([1, 1])
    with col1: render_progress_gauge(rec)
    with col2: render_progress_trend(rec, selected_year, selected_week)
    render_milestone_timeline([rec], scope_filter=rec["scope_id"], title="Milestones", selected_year=selected_year, selected_week=selected_week, current_date=current_date)
    render_scope_baseline_section(rec, selected_year, selected_week)
    render_scope_cost_section(rec)
    render_action_table(f"{rec['name']} priority - {selected_label}", rec.get("priority_items", []), selected_year, selected_week, rec.get("default_responsible", "TBC"), max_items=999, current_date=current_date)
    st.markdown("<div class='section-title'>Engineering</div>", unsafe_allow_html=True)
    e1, e2 = st.columns([1, 1])
    with e1: render_engineering_gauge(rec, selected_year, selected_week)
    with e2: render_engineering_trend(rec, selected_year, selected_week)
    render_action_table("", rec.get("engineering_items", []), selected_year, selected_week, rec.get("default_responsible", "TBC"), max_items=999, current_date=current_date)
    st.markdown("<div class='section-title'>Quality</div>", unsafe_allow_html=True)
    render_action_table("", rec.get("quality_items", []), selected_year, selected_week, rec.get("default_responsible", "TBC"), max_items=999, current_date=current_date)
    st.markdown("<div class='section-title'>Interfaces</div>", unsafe_allow_html=True)
    render_action_table("", rec.get("interface_items", []), selected_year, selected_week, rec.get("default_responsible", "TBC"), max_items=999, current_date=current_date)



