st.markdown(V36_UX_CSS, unsafe_allow_html=True)


def _baseline_labels_v36() -> List[str]:
    return [r.get("label") for r in _baseline_reports() if r.get("label")]


def _set_active_baseline_by_offset_v36(offset: int) -> None:
    labels = _baseline_labels_v36()
    if not labels:
        return
    current = st.session_state.get("baseline_choice")
    idx = labels.index(current) if current in labels else len(labels) - 1
    idx = max(0, min(len(labels) - 1, idx + int(offset)))
    st.session_state["baseline_choice"] = labels[idx]


def _key_v36(*parts: Any) -> str:
    raw = "_".join(str(p) for p in parts if p is not None)
    return re.sub(r"[^A-Za-z0-9_]+", "_", raw).strip("_")[:90]


def _selector_nav_v36(label: str, labels: List[str], state_key: str, key_prefix: str, current_idx: int, callback: Any) -> None:
    if not labels:
        st.markdown(f"<div class='cutoff-chip'><span>{_html(label)}</span><b>N/A</b></div>", unsafe_allow_html=True)
        return
    left, middle, right = st.columns([.24, 1.0, .24], gap="small")
    with left:
        st.button("<", key=_key_v36(key_prefix, "prev", "v36"), use_container_width=True, disabled=(current_idx <= 0), on_click=callback, args=(-1,))
    with middle:
        st.selectbox(label, labels, key=state_key, label_visibility="visible")
    with right:
        st.button(">", key=_key_v36(key_prefix, "next", "v36"), use_container_width=True, disabled=(current_idx >= len(labels) - 1), on_click=callback, args=(1,))


def _action_popover_button_v32(title: str, rows: List[Dict[str, Any]], count: int, label: Optional[str] = None, class_name: str = "action-count-button") -> str:
    return _popover_markup_v33(title, rows, _html(label if label is not None else str(count)), class_name + " rc-click-card")


def _popover_markup_v33(title: str, rows: List[Dict[str, Any]], button_html: str, button_class: str) -> str:
    token = hashlib.sha1((title + "|" + "|".join(str(r.get("action", "")) for r in rows[:30])).encode("utf-8", "ignore")).hexdigest()[:12]
    pid = f"pop_v36_{token}"
    return (
        f"<button type='button' class='{button_class}' popovertarget='{pid}' popovertargetaction='toggle'>{button_html}</button>"
        f"<div id='{pid}' class='pm-popover-v33' popover><div class='pop-head'><b>{_html(title)}</b><span>{len(rows)}</span></div><div class='pop-body'>{_rows_popover_body_v33(rows)}</div></div>"
    )


def _full_action_card_v33(title: str, rows: List[Dict[str, Any]], card_class: str, label: str, value: str, note: str) -> str:
    html = f"<span>{_html(label)}</span><b>{_html(value)}</b>"
    return _popover_markup_v33(title, rows, html, card_class + " rc-click-card")


def _gate_pill_html(title: str, count: int, items: List[Any]) -> str:
    rows = _as_action_records_v32(items, int(st.session_state.get("selected_year_v32", 2026)), int(st.session_state.get("selected_week_v32", 1)), current_date=st.session_state.get("selected_cutoff_v32"))
    button_html = f"<span>{_html(title)}</span><b>{int(count)}</b>"
    return "<div class='gate-click-wrap'>" + _popover_markup_v33(title, rows, button_html, "gate-click-btn rc-click-card") + "</div>"


def render_action_table(title: str, items: List[Any], selected_year: int, selected_week: int, default_responsible: str = "TBC", max_items: int = 10, current_date: Optional[pd.Timestamp] = None) -> None:
    rows = _as_action_records_v32(items, selected_year, selected_week, default_responsible, current_date)
    if title:
        st.markdown(f"<div class='section-title'>{_html(title)} {_action_popover_button_v32(title, rows, len(rows), label=str(len(rows)), class_name='action-count-button')}</div>", unsafe_allow_html=True)
    if not rows:
        st.markdown("<div class='action-empty'>No active actions extracted for this section.</div>", unsafe_allow_html=True)
        return
    out = [[row["action"], row["responsible"], row["expected"], row["status"]] for row in rows[:max_items]]
    _copyable_table_component(["Action / issue", "Responsible", "Expected date", "Status"], out, key_prefix=title or "actions_v36")


def _pm_heatmap_figure(assessments: List[Dict[str, Any]]) -> go.Figure:
    metrics = ["Actions", "Progress", "Gates", "Baseline", "Cost", "Total"]
    scopes = [str(a.get("scope") or "Scope") for a in assessments]
    z = [[_pm_visual_scores(a)[m] for m in metrics] for a in assessments]
    custom = []
    for a in assessments:
        custom.append([f"Target gap {float(a.get('progress_target_gap') or 0.0):.1f}%", f"Construction {_pm_pct(a.get('construction_actual'))}", f"Engineering {_pm_pct(a.get('engineering_actual'))}"])
    fig = go.Figure(data=go.Heatmap(
        z=z, x=metrics, y=scopes, zmin=0, zmax=10,
        colorscale=[[0, "#e7f8ef"], [.34, "#bbf7d0"], [.55, "#fde68a"], [.75, "#fb923c"], [1, "#b91c1c"]],
        colorbar=dict(title="Pressure", len=.68, thickness=12),
        customdata=[[custom[i] for _ in metrics] for i in range(len(scopes))],
        hovertemplate="%{y}<br>%{x}<br>%{customdata[0]}<br>%{customdata[1]}<br>%{customdata[2]}<extra></extra>",
    ))
    fig.update_yaxes(autorange="reversed")
    return _pm_theme_figure(fig, height=285)


def _cost_history_trend_figure(scope_id: str) -> go.Figure:
    try:
        df = _history_for_scope(scope_id).copy()
    except Exception:
        df = pd.DataFrame()
    fig = go.Figure()
    if df is not None and not df.empty and "Month" in df.columns:
        if "Date" in df.columns:
            df = df.sort_values("Date", ascending=True, na_position="last")
        metrics = [("Forecast", "#2563eb"), ("VOWD", "#059669"), ("ETC", "#d97706"), ("Potential forecast", "#dc2626")]
        x_vals = df["Month"].astype(str).tolist()
        for metric, color in metrics:
            if metric not in df.columns:
                continue
            y_vals = [_safe_float(v) for v in df[metric].tolist()]
            fig.add_trace(go.Scatter(x=x_vals, y=y_vals, mode="lines+markers", name=metric, line=dict(color=color, width=2.6), marker=dict(size=7), hovertemplate="%{x}<br>%{y:,.0f} EUR<extra></extra>"))
    fig.update_layout(height=340, margin=dict(l=38, r=16, t=22, b=50), paper_bgcolor="rgba(0,0,0,0)", plot_bgcolor="rgba(0,0,0,0)", hovermode="x unified", legend=dict(orientation="h", yanchor="bottom", y=1.02, xanchor="right", x=1, font=dict(size=10)))
    fig.update_xaxes(tickangle=-22, showgrid=False)
    fig.update_yaxes(showgrid=True, gridcolor="#eef0f4", zeroline=False, title="EUR")
    return fig


def _cost_waterfall_figure_v24(scope_id: str, cost_data: Optional[Dict[str, Any]] = None, title: str = "Cost candle bar") -> go.Figure:
    cost_data = cost_data or (_active_cost_report().get("data") or cached_monthly_cost())
    active_label = _active_cost_report().get("label") or _active_month_label_from_cost(cost_data)
    if scope_id == "all":
        row = _active_history_row("all")
        budget = _safe_float(row.get("Budget")) or 0.0
        co = _safe_float(row.get("CO")) or 0.0
        forecast = _safe_float(row.get("Forecast")) if row.get("Forecast") is not None else budget + co
        exposure = _safe_float(row.get("Potential exposure")) or 0.0
        potential_forecast = _safe_float(row.get("Potential forecast")) if row.get("Potential forecast") is not None else (forecast or 0.0) + exposure
    else:
        nums = _cost_numbers(scope_id, cost_data)
        budget = _safe_float(nums.get("budget")) or 0.0
        forecast = _safe_float(nums.get("forecast"))
        co = (forecast - budget) if forecast is not None else (_safe_float(nums.get("change_order")) or 0.0)
        forecast = forecast if forecast is not None else budget + co
        exposure = _safe_float(nums.get("potential_exposure")) or 0.0
        potential_forecast = _safe_float(nums.get("potential_forecast")) if nums.get("potential_forecast") is not None else forecast + exposure
    labels = ["Budget", "CO", "Forecast", "Exposure", "Potential FC"]
    y_vals = [budget, co, forecast, exposure, potential_forecast]
    custom = [[active_label, _fmt_money_full(v)] for v in y_vals]
    fig = go.Figure(go.Bar(
        x=labels, y=y_vals, marker_color=["#2563eb", "#7c3aed", "#059669", "#d97706", "#dc2626"],
        text=[_fmt_money(v) for v in y_vals], textposition="outside", customdata=custom,
        hovertemplate="%{customdata[0]}<br>%{customdata[1]}<extra></extra>",
    ))
    fig.update_layout(height=340, margin=dict(l=34, r=16, t=22, b=48), paper_bgcolor="rgba(0,0,0,0)", plot_bgcolor="rgba(0,0,0,0)", showlegend=False, yaxis_title="EUR", hovermode="closest")
    fig.update_xaxes(tickangle=-16)
    fig.update_yaxes(showgrid=True, gridcolor="#eef0f4", zeroline=False)
    return fig


def render_header(bundle: Dict[str, Any], selected_label: str, panel_choice: str = "Executive overview") -> Tuple[int, int]:
    _latest_defaults_v32(st.session_state.get("bundle", bundle))
    periods = available_periods(st.session_state.get("bundle", bundle))
    week_labels = [period_display(y, w) for y, w in periods]
    selected_year, selected_week = _selected_period_from_state_v32(st.session_state.get("bundle", bundle))
    current_week_idx = week_labels.index(st.session_state.get("week_selector_value")) if week_labels and st.session_state.get("week_selector_value") in week_labels else max(0, len(week_labels) - 1)
    cost_labels = _month_labels_v29()
    active_month = _active_month_label_v29()
    current_month_idx = cost_labels.index(active_month) if active_month in cost_labels else max(0, len(cost_labels) - 1)
    baseline_labels = _baseline_labels_v36()
    if baseline_labels and st.session_state.get("baseline_choice") not in baseline_labels:
        st.session_state["baseline_choice"] = baseline_labels[-1]
    current_baseline_idx = baseline_labels.index(st.session_state.get("baseline_choice")) if baseline_labels and st.session_state.get("baseline_choice") in baseline_labels else max(0, len(baseline_labels) - 1)
    scope_labels = list(COST_SCOPE_OPTIONS.values()) if "COST_SCOPE_OPTIONS" in globals() else ["All scopes", "Rail On Site (ROS)", "Ponds", "Roads"]
    if st.session_state.get("cost_scope_visual_selector") not in scope_labels:
        st.session_state["cost_scope_visual_selector"] = scope_labels[0]
    cutoff_week = _date_for_selected_week_v29(bundle, selected_year, selected_week)
    logo_src = logo_mark_data_uri() or logo_data_uri()
    logo_html = f"<div class='rc-logo-box'><img src='{logo_src}'></div>" if logo_src else ""
    panel_key = _key_v36(panel_choice)
    try:
        header = st.container(key="rc_panel_header_v27")
    except TypeError:
        header = st.container()
    with header:
        st.markdown("<div class='rc-title-row'>" + logo_html + "<div><h1>Roger Campbell Scopes Control Center</h1></div></div>", unsafe_allow_html=True)
        if panel_choice == "Cost Status":
            cols = st.columns([1.12, .92, 1.28], gap="small")
            with cols[0]:
                _selector_nav_v36("Month", cost_labels, "monthly_cost_report_choice_portfolio", f"{panel_key}_month", current_month_idx, _set_active_month_by_offset_v29)
            with cols[1]:
                st.selectbox("View", scope_labels, key="cost_scope_visual_selector", label_visibility="visible")
            with cols[2]:
                _selector_nav_v36("Baseline", baseline_labels, "baseline_choice", f"{panel_key}_baseline", current_baseline_idx, _set_active_baseline_by_offset_v36)
        else:
            cols = st.columns([1.08, 1.08, 1.34, .70], gap="small")
            with cols[0]:
                _selector_nav_v36("Week", week_labels, "week_selector_value", f"{panel_key}_week", current_week_idx, _set_active_week_by_offset)
            with cols[1]:
                _selector_nav_v36("Month", cost_labels, "monthly_cost_report_choice_portfolio", f"{panel_key}_month", current_month_idx, _set_active_month_by_offset_v29)
            with cols[2]:
                _selector_nav_v36("Baseline", baseline_labels, "baseline_choice", f"{panel_key}_baseline", current_baseline_idx, _set_active_baseline_by_offset_v36)
            with cols[3]:
                st.markdown(f"<div class='cutoff-chip'><span>Cut-off</span><b>{_html(cutoff_week)}</b></div>", unsafe_allow_html=True)
        active_text = _active_month_label_v29() if panel_choice == "Cost Status" else st.session_state.get("week_selector_value", selected_label)
        st.markdown(f"<div class='panel-title-v27'><h2>{_html(_panel_title_v27(panel_choice))}</h2><span>{_html(active_text)}</span></div>", unsafe_allow_html=True)
    return _selected_period_from_state_v32(st.session_state.get("bundle", bundle))


