def _cost_history_chart_records_v38(df: pd.DataFrame, metric_label: str, title: str, rows: int = 8) -> Tuple[List[Tuple[str, float]], bool, str]:
    if df is None or df.empty:
        return [], False, "Amount"
    df = df.copy()
    if "Date" in df.columns:
        df = df.sort_values("Date", ascending=True, na_position="last")
    sub = df.tail(rows)
    title_l = (title or "").lower()
    percent_mode = ("/ forecast" in title_l) or (" / " in title_l and "forecast" in title_l)
    records: List[Tuple[str, float]] = []
    for _, r in sub.iterrows():
        month = str(r.get("Month") or r.get("Month key") or "").strip() or "Month"
        value: Optional[float] = None
        if percent_mode:
            numerator = _safe_float(r.get(metric_label))
            denominator = _safe_float(r.get("Forecast"))
            if numerator is not None and denominator not in (None, 0):
                value = numerator / denominator * 100.0
        elif title_l.startswith("forecast vs budget"):
            forecast = _safe_float(r.get("Forecast"))
            budget = _safe_float(r.get("Budget"))
            if forecast is not None and budget is not None:
                value = forecast - budget
        else:
            value = _safe_float(r.get(metric_label))
        if value is not None:
            records.append((month, float(value)))
    return records, percent_mode, ("Percent" if percent_mode else "Amount")


def _cost_bar_history_svg_v38(records: List[Tuple[str, float]], percent_mode: bool, axis_label: str) -> str:
    if not records:
        return "<div class='pm-empty-list'>No monthly values loaded.</div>"
    width, height = 610, 260
    left, right, top, bottom = 58, 18, 20, 54
    plot_w, plot_h = width - left - right, height - top - bottom
    values = [v for _, v in records]
    lo = min(min(values), 0.0)
    hi = max(max(values), 0.0)
    if percent_mode:
        hi = max(hi, 10.0)
        lo = min(lo, 0.0)
    if abs(hi - lo) < 1e-9:
        hi = lo + 1.0

    def y_for(value: float) -> float:
        return top + ((hi - value) / (hi - lo)) * plot_h

    zero_y = y_for(0.0)
    count = len(records)
    slot = plot_w / max(1, count)
    bar_w = max(20.0, min(44.0, slot * 0.58))
    elems: List[str] = [
        f"<div class='cost-bar-chart-v38'><div class='chart-note'><span>X: year-month</span><span>Y: {_html(axis_label)}</span></div>",
        f"<svg viewBox='0 0 {width} {height}' role='img' aria-label='Cost history bar chart'>",
        f"<line class='grid' x1='{left}' y1='{top}' x2='{width-right}' y2='{top}'/>",
        f"<line class='grid' x1='{left}' y1='{top + plot_h/2:.1f}' x2='{width-right}' y2='{top + plot_h/2:.1f}'/>",
        f"<line class='axis' x1='{left}' y1='{zero_y:.1f}' x2='{width-right}' y2='{zero_y:.1f}'/>",
        f"<line class='axis' x1='{left}' y1='{top}' x2='{left}' y2='{top+plot_h}'/>",
        f"<text class='ylabel' x='12' y='{top + 12}'>{_html('%' if percent_mode else 'EUR')}</text>",
        f"<text class='tick' x='8' y='{top + 4}'>{_html(_fmt_pct(hi) if percent_mode else _fmt_money(hi))}</text>",
        f"<text class='tick' x='8' y='{zero_y + 4:.1f}'>0</text>",
    ]
    for idx, (month, value) in enumerate(records):
        x_mid = left + slot * idx + slot / 2
        x = x_mid - bar_w / 2
        y_val = y_for(value)
        if value >= 0:
            y = y_val
            h = max(2.0, zero_y - y_val)
            label_y = max(12.0, y - 6.0)
            color = "#059669"
        else:
            y = zero_y
            h = max(2.0, y_val - zero_y)
            label_y = min(height - bottom + 24, y + h + 13.0)
            color = "#dc2626"
        label = f"{value:.1f}%" if percent_mode else _fmt_money(value)
        elems.extend([
            f"<rect x='{x:.1f}' y='{y:.1f}' width='{bar_w:.1f}' height='{h:.1f}' rx='4' fill='{color}'/>",
            f"<text class='value' x='{x_mid:.1f}' y='{label_y:.1f}' text-anchor='middle'>{_html(label)}</text>",
            f"<text class='tick' transform='translate({x_mid:.1f},{height-20}) rotate(-30)' text-anchor='end'>{_html(month)}</text>",
        ])
    elems.append("</svg></div>")
    return "".join(elems)


def _cost_value_rows_v34(scope_id: str, metric_label: str, rows: int = 8, title: str = "") -> str:
    try:
        df = _history_for_scope(scope_id).copy()
    except Exception:
        df = pd.DataFrame()
    if df is None or df.empty:
        return "<div class='pm-empty-list'>No monthly values loaded.</div>"
    if metric_label not in df.columns and not str(title or "").lower().startswith("forecast vs budget"):
        return "<div class='pm-empty-list'>No monthly values loaded.</div>"
    records, percent_mode, axis_label = _cost_history_chart_records_v38(df, metric_label, title, rows=rows)
    return _cost_bar_history_svg_v38(records, percent_mode, axis_label)


def _cost_popover_v34(title: str, scope_id: str, metric_label: str, button_html: str, button_class: str) -> str:
    token = hashlib.sha1((title + scope_id + metric_label + "v38").encode("utf-8", "ignore")).hexdigest()[:12]
    pid = f"cost_v38_{token}"
    body = _cost_value_rows_v34(scope_id, metric_label, title=title)
    return (
        f"<button type='button' class='{button_class}' popovertarget='{pid}' popovertargetaction='toggle'>{button_html}</button>"
        f"<div id='{pid}' class='pm-popover-v33' popover><div class='pop-head'><b>{_html(title)}</b></div><div class='pop-body'>{body}</div></div>"
    )


def _waterfall_cost_values_v38(scope_id: str, cost_data: Optional[Dict[str, Any]]) -> Dict[str, float]:
    if scope_id == "all":
        row = _active_history_row("all")
        budget = _safe_float(row.get("Budget")) or 0.0
        forecast = _safe_float(row.get("Forecast"))
        co = _safe_float(row.get("CO"))
        if forecast is not None and co is None:
            co = forecast - budget
        forecast = forecast if forecast is not None else budget + (co or 0.0)
        exposure = _safe_float(row.get("Potential exposure")) or 0.0
        potential_forecast = _safe_float(row.get("Potential forecast"))
        potential_forecast = potential_forecast if potential_forecast is not None else forecast + exposure
        vowd_raw = _safe_float(row.get("VOWD")) or 0.0
        vowd = -abs(vowd_raw)
        etc = max(0.0, forecast + vowd)
    else:
        nums = _cost_numbers(scope_id, cost_data)
        budget = _safe_float(nums.get("budget")) or 0.0
        forecast = _safe_float(nums.get("forecast"))
        co = (forecast - budget) if forecast is not None else (_safe_float(nums.get("change_order")) or 0.0)
        forecast = forecast if forecast is not None else budget + co
        exposure = _safe_float(nums.get("potential_exposure")) or 0.0
        potential_forecast = _safe_float(nums.get("potential_forecast"))
        potential_forecast = potential_forecast if potential_forecast is not None else forecast + exposure
        vowd_raw = _safe_float(nums.get("vowd")) or 0.0
        vowd = -abs(vowd_raw)
        etc = max(0.0, forecast + vowd)
    return {
        "Budget": float(budget or 0.0),
        "CO": float(co or 0.0),
        "Forecast": float(forecast or 0.0),
        "Exposure": float(exposure or 0.0),
        "Potential FC": float(potential_forecast or 0.0),
        "VOWD": float(vowd or 0.0),
        "ETC": float(etc or 0.0),
    }


def _cost_waterfall_figure_v24(scope_id: str, cost_data: Optional[Dict[str, Any]] = None, title: str = "Cost candle bar") -> go.Figure:
    cost_data = cost_data or (_active_cost_report().get("data") or cached_monthly_cost())
    active_label = _active_cost_report().get("label") or _active_month_label_from_cost(cost_data)
    vals = _waterfall_cost_values_v38(scope_id, cost_data)
    labels = ["Budget", "CO", "Forecast", "Exposure", "Potential FC", "VOWD", "ETC"]
    y_vals = [vals[label] for label in labels]
    measures = ["absolute", "relative", "total", "relative", "total", "relative", "total"]
    custom = []
    for label, value, measure in zip(labels, y_vals, measures):
        if label == "ETC":
            direction = "Forecast + VOWD"
        else:
            direction = "Increase" if measure == "relative" and value >= 0 else ("Decrease" if measure == "relative" else "Position")
        custom.append([active_label, _fmt_money_full(value), direction])
    fig = go.Figure(go.Waterfall(
        x=labels,
        y=y_vals,
        measure=measures,
        text=[_fmt_money(v) for v in y_vals],
        textposition="outside",
        connector={"line": {"color": "#98a2b3", "width": 1}},
        increasing={"marker": {"color": "#059669"}},
        decreasing={"marker": {"color": "#dc2626"}},
        totals={"marker": {"color": "#2563eb"}},
        customdata=custom,
        hovertemplate="<b>%{x}</b><br>%{customdata[0]}<br>%{customdata[2]}: %{customdata[1]}<extra></extra>",
    ))
    fig.update_layout(
        height=350,
        margin=dict(l=34, r=16, t=26, b=54),
        paper_bgcolor="rgba(0,0,0,0)",
        plot_bgcolor="rgba(0,0,0,0)",
        showlegend=False,
        yaxis_title="EUR",
        hovermode="closest",
    )
    fig.update_xaxes(tickangle=-18)
    fig.update_yaxes(showgrid=True, gridcolor="#eef0f4", zeroline=True, zerolinecolor="#cfd6e4")
    return fig


def _construction_etc_label_v38(rec: Dict[str, Any], selected_year: Optional[int], selected_week: Optional[int]) -> str:
    raw = rec.get("construction_etc")
    if (not raw or str(raw).strip().lower() in {"tbc", "to be provided", "nan"}) and selected_year and selected_week:
        try:
            raw = _baseline_etc_for_scope(rec.get("scope_id", ""), selected_year, selected_week, mode="final")
        except Exception:
            raw = None
    return _date_only_etc(raw, fallback="TBC")


def render_progress_trend(rec: Dict[str, Any], selected_year: Optional[int] = None, selected_week: Optional[int] = None) -> None:
    rec = _with_display_scope(rec)
    fig = _progress_trend_figure(rec, selected_year, selected_week, rec.get("progress_series", pd.DataFrame()), "Progress", f"{rec['name']} construction progress", "Progress %")
    if fig is None:
        st.info("No scope progress trend loaded for the selected period.")
        return
    etc_label = _construction_etc_label_v38(rec, selected_year, selected_week)
    fig.add_annotation(
        xref="paper",
        yref="paper",
        x=1.0,
        y=1.18,
        xanchor="right",
        yanchor="top",
        text=f"ETC: {etc_label}",
        showarrow=False,
        bgcolor="#101828",
        bordercolor="#101828",
        borderpad=6,
        font=dict(color="#ffffff", size=11),
    )
    fig.update_layout(margin=dict(l=30, r=20, t=102, b=62))
    st.plotly_chart(fig, use_container_width=True)


def render_sidebar(bundle: Dict[str, Any]) -> Tuple[str, int, int]:
    _apply_url_panel_v32()
    logo_src = logo_mark_data_uri() or logo_data_uri()
    if logo_src:
        st.sidebar.markdown(f"<div class='sidebar-logo'><img src='{logo_src}'><span>Roger Campbell PM</span></div>", unsafe_allow_html=True)
    else:
        st.sidebar.markdown("<div class='sidebar-logo'><span>Roger Campbell PM</span></div>", unsafe_allow_html=True)
    st.sidebar.title("Control settings")
    st.sidebar.markdown("<div class='subsection-title'>Panel</div>", unsafe_allow_html=True)
    panel_labels = ["Executive overview", "Cost Status", "Rail On Site (ROS)", "Ponds", "Roads"]
    if st.session_state.get("panel_choice") not in panel_labels:
        st.session_state["panel_choice"] = "Executive overview"
    nav_labels = {"Executive overview": "Overview", "Cost Status": "Cost Status", "Rail On Site (ROS)": "Rail On Site (ROS)", "Ponds": "Ponds", "Roads": "Roads"}
    for label in panel_labels:
        if st.sidebar.button(nav_labels.get(label, label), key=f"nav_v38_{label}", use_container_width=True):
            st.session_state["panel_choice"] = label
    st.sidebar.markdown(f"<div class='nav-active'>Current panel: {_html(st.session_state['panel_choice'])}</div>", unsafe_allow_html=True)
    st.sidebar.markdown("---")
    st.sidebar.markdown("<div class='subsection-title'>Upload / refresh</div>", unsafe_allow_html=True)
    uploaded_weekly = st.sidebar.file_uploader("Upload new weekly report PDF/PPTX", type=["pdf", "pptx"], accept_multiple_files=True, key="weekly_upload_v38")
    if uploaded_weekly:
        key = _upload_list_hash(uploaded_weekly)
        if key != st.session_state.get("last_weekly_upload_key_v38"):
            with st.spinner("Parsing uploaded weekly report(s) and refreshing the control center..."):
                try:
                    incoming = parse_uploaded_reports(uploaded_weekly)
                    st.session_state["bundle"] = merge_bundles(st.session_state["bundle"], incoming)
                    st.session_state["last_weekly_upload_key_v38"] = key
                    st.sidebar.success(f"{len(uploaded_weekly)} weekly report(s) parsed and loaded.")
                    _safe_rerun()
                except Exception as exc:
                    st.sidebar.error(f"Could not parse weekly upload: {exc}")
    uploaded_cost_reports = st.sidebar.file_uploader("Upload monthly cost report XLSX", type=["xlsx"], accept_multiple_files=True, key="cost_upload_v38")
    if uploaded_cost_reports:
        key = _upload_list_hash(uploaded_cost_reports)
        if key != st.session_state.get("last_cost_upload_key_v38"):
            loaded = 0
            errors: List[str] = []
            for uploaded in uploaded_cost_reports:
                try:
                    _register_uploaded_cost_report(uploaded)
                    loaded += 1
                except Exception as exc:
                    errors.append(f"{uploaded.name}: {exc}")
            st.session_state["last_cost_upload_key_v38"] = key
            try:
                cached_monthly_cost_reports.clear()
            except Exception:
                pass
            if loaded:
                refreshed = _cost_reports()
                if refreshed:
                    st.session_state["monthly_cost_report_choice_portfolio"] = refreshed[-1]["label"]
                st.sidebar.success(f"{loaded} cost report(s) uploaded and registered.")
            for msg in errors:
                st.sidebar.error(f"Could not parse cost report - {msg}")
            if loaded:
                _safe_rerun()
    uploaded_baselines = st.sidebar.file_uploader("Upload schedule baseline PDF", type=["pdf"], accept_multiple_files=True, key="baseline_upload_v38")
    if uploaded_baselines:
        key = _upload_list_hash(uploaded_baselines)
        if key != st.session_state.get("last_baseline_upload_key_v38"):
            loaded = 0
            errors: List[str] = []
            for uploaded in uploaded_baselines:
                try:
                    _register_uploaded_baseline(uploaded)
                    loaded += 1
                except Exception as exc:
                    errors.append(f"{uploaded.name}: {exc}")
            st.session_state["last_baseline_upload_key_v38"] = key
            try:
                cached_baseline_schedules.clear()
            except Exception:
                pass
            if loaded:
                refreshed = _baseline_reports()
                if refreshed:
                    st.session_state["baseline_choice"] = refreshed[-1]["label"]
                st.sidebar.success(f"{loaded} baseline file(s) uploaded and registered.")
            for msg in errors:
                st.sidebar.error(f"Could not parse baseline - {msg}")
            if loaded:
                _safe_rerun()
    if st.sidebar.button("Save current session data", use_container_width=True, key="save_session_v38"):
        save_bundle(st.session_state["bundle"], DATA_PATH)
        try:
            cached_bundle.clear()
        except Exception:
            pass
        st.sidebar.success("Saved weekly data to data/weekly_data_bundle.json")
    y, w = _selected_period_from_state_v32(st.session_state.get("bundle", bundle))
    return st.session_state["panel_choice"], int(y), int(w)


def render_header(bundle: Dict[str, Any], selected_label: str, panel_choice: str = "Executive overview") -> Tuple[int, int]:
    _latest_defaults_v32(st.session_state.get("bundle", bundle))
    periods = available_periods(st.session_state.get("bundle", bundle))
    week_labels = [period_display(y, w) for y, w in periods]
    selected_year, selected_week = _selected_period_from_state_v32(st.session_state.get("bundle", bundle))
    current_week_idx = week_labels.index(st.session_state.get("week_selector_value")) if week_labels and st.session_state.get("week_selector_value") in week_labels else max(0, len(week_labels) - 1)
    cost_labels = _month_labels_v29()
    active_month = _active_month_label_v29()
    current_month_idx = cost_labels.index(active_month) if active_month in cost_labels else max(0, len(cost_labels) - 1)
    baseline_labels = _baseline_labels_v36()
    if baseline_labels and st.session_state.get("baseline_choice") not in baseline_labels:
        st.session_state["baseline_choice"] = baseline_labels[-1]
    current_baseline_idx = baseline_labels.index(st.session_state.get("baseline_choice")) if baseline_labels and st.session_state.get("baseline_choice") in baseline_labels else max(0, len(baseline_labels) - 1)
    scope_labels = list(COST_SCOPE_OPTIONS.values()) if "COST_SCOPE_OPTIONS" in globals() else ["All scopes", "Rail On Site (ROS)", "Ponds", "Roads"]
    if st.session_state.get("cost_scope_visual_selector") not in scope_labels:
        st.session_state["cost_scope_visual_selector"] = scope_labels[0]
    cutoff_week = _date_for_selected_week_v29(bundle, selected_year, selected_week)
    logo_src = logo_mark_data_uri() or logo_data_uri()
    logo_html = f"<div class='rc-logo-box'><img src='{logo_src}'></div>" if logo_src else ""
    panel_key = _key_v36(panel_choice)
    panel_title = _panel_title_v27(panel_choice)
    try:
        header = st.container(key="rc_panel_header_v27")
    except TypeError:
        header = st.container()
    with header:
        st.markdown("<div class='rc-title-row'>" + logo_html + f"<div><h1>{_html(panel_title)}</h1></div></div>", unsafe_allow_html=True)
        if panel_choice == "Cost Status":
            cols = st.columns([1.12, .92, 1.28], gap="small")
            with cols[0]:
                _selector_nav_v36("Month", cost_labels, "monthly_cost_report_choice_portfolio", f"{panel_key}_month_v38", current_month_idx, _set_active_month_by_offset_v29)
            with cols[1]:
                st.selectbox("View", scope_labels, key="cost_scope_visual_selector", label_visibility="visible")
            with cols[2]:
                _selector_nav_v36("Baseline", baseline_labels, "baseline_choice", f"{panel_key}_baseline_v38", current_baseline_idx, _set_active_baseline_by_offset_v36)
        else:
            cols = st.columns([1.08, 1.08, 1.34, .70], gap="small")
            with cols[0]:
                _selector_nav_v36("Week", week_labels, "week_selector_value", f"{panel_key}_week_v38", current_week_idx, _set_active_week_by_offset)
            with cols[1]:
                _selector_nav_v36("Month", cost_labels, "monthly_cost_report_choice_portfolio", f"{panel_key}_month_v38", current_month_idx, _set_active_month_by_offset_v29)
            with cols[2]:
                _selector_nav_v36("Baseline", baseline_labels, "baseline_choice", f"{panel_key}_baseline_v38", current_baseline_idx, _set_active_baseline_by_offset_v36)
            with cols[3]:
                st.markdown(f"<div class='cutoff-chip'><span>Cut-off</span><b>{_html(cutoff_week)}</b></div>", unsafe_allow_html=True)
        active_text = _active_month_label_v29() if panel_choice == "Cost Status" else st.session_state.get("week_selector_value", selected_label)
        st.markdown(f"<div class='panel-title-v27'><h2>Active period</h2><span>{_html(active_text)}</span></div>", unsafe_allow_html=True)
    return _selected_period_from_state_v32(st.session_state.get("bundle", bundle))


