def render_header(bundle: Dict[str, Any], selected_label: str, panel_choice: str = "Executive overview") -> Tuple[int, int]:
    _latest_defaults_v32(st.session_state.get("bundle", bundle))
    periods = available_periods(st.session_state.get("bundle", bundle))
    week_labels = [period_display(y, w) for y, w in periods]
    selected_year, selected_week = _selected_period_from_state_v32(st.session_state.get("bundle", bundle))
    current_week_idx = week_labels.index(st.session_state.get("week_selector_value")) if week_labels and st.session_state.get("week_selector_value") in week_labels else max(0, len(week_labels) - 1)
    cost_labels = _month_labels_v29()
    active_month = _active_month_label_v29()
    current_month_idx = cost_labels.index(active_month) if active_month in cost_labels else max(0, len(cost_labels) - 1)
    baseline_labels = _baseline_labels_v36()
    if baseline_labels and st.session_state.get("baseline_choice") not in baseline_labels:
        st.session_state["baseline_choice"] = baseline_labels[-1]
    current_baseline_idx = baseline_labels.index(st.session_state.get("baseline_choice")) if baseline_labels and st.session_state.get("baseline_choice") in baseline_labels else max(0, len(baseline_labels) - 1)
    _ensure_cost_scope_v40()
    cutoff_week = _date_for_selected_week_v29(bundle, selected_year, selected_week)
    logo_src = logo_mark_data_uri() or logo_data_uri()
    logo_html = f"<div class='rc-logo-box'><img src='{logo_src}'></div>" if logo_src else ""
    panel_key = _key_v36(panel_choice)
    panel_title = _panel_title_v27(panel_choice)
    try:
        header = st.container(key="rc_panel_header_v27")
    except TypeError:
        header = st.container()
    with header:
        st.markdown("<div class='rc-title-row'>" + logo_html + f"<div><h1>{_html(panel_title)}</h1></div></div>", unsafe_allow_html=True)
        if panel_choice == "Cost Status":
            cols = st.columns([1.12, 1.05, 1.28], gap="small")
            with cols[0]:
                _selector_nav_v36("Month", cost_labels, "monthly_cost_report_choice_portfolio", f"{panel_key}_month_v40", current_month_idx, _set_active_month_by_offset_v29)
            with cols[1]:
                _render_cost_scope_buttons_v40()
            with cols[2]:
                _selector_nav_v36("Baseline", baseline_labels, "baseline_choice", f"{panel_key}_baseline_v40", current_baseline_idx, _set_active_baseline_by_offset_v36)
        else:
            cols = st.columns([1.08, 1.08, 1.34, .70], gap="small")
            with cols[0]:
                _selector_nav_v36("Week", week_labels, "week_selector_value", f"{panel_key}_week_v40", current_week_idx, _set_active_week_by_offset)
            with cols[1]:
                _selector_nav_v36("Month", cost_labels, "monthly_cost_report_choice_portfolio", f"{panel_key}_month_v40", current_month_idx, _set_active_month_by_offset_v29)
            with cols[2]:
                _selector_nav_v36("Baseline", baseline_labels, "baseline_choice", f"{panel_key}_baseline_v40", current_baseline_idx, _set_active_baseline_by_offset_v36)
            with cols[3]:
                st.markdown(f"<div class='cutoff-chip'><span>Cut-off</span><b>{_html(cutoff_week)}</b></div>", unsafe_allow_html=True)
        active_text = _active_month_label_v29() if panel_choice == "Cost Status" else st.session_state.get("week_selector_value", selected_label)
        st.markdown(f"<div class='panel-title-v27'><h2>Active period</h2><span>{_html(active_text)}</span></div>", unsafe_allow_html=True)
    return _selected_period_from_state_v32(st.session_state.get("bundle", bundle))


