def _management_signal_row_v41(label: str, value: str, raw: bool = False) -> str:
    body = value if raw else _html(value)
    return f"<div class='mgmt-signal-row'><span>{_html(label)}</span><b>{body}</b></div>"


def _management_scope_card_v41(a: Dict[str, Any]) -> str:
    actions, baseline, cost = a["actions"], a["baseline"], a["cost"]
    rows = actions.get("rows") or []
    delayed_rows = _filter_action_rows_v32(rows, {"Delayed"})
    near_rows = _filter_action_rows_v32(rows, {"Near due"})
    action_html = (
        f"{_action_popover_button_v32(f'{a['scope']} delayed actions', delayed_rows, len(delayed_rows), label=str(actions.get('Delayed', 0)), class_name='action-count-button')} delayed / "
        f"{_action_popover_button_v32(f'{a['scope']} near-due actions', near_rows, len(near_rows), label=str(actions.get('Near due', 0)), class_name='action-count-button')} near due"
    )
    first_late = compact_text(a.get("first_delayed") or "No primary late item loaded.", 120)
    signals = [
        _management_signal_row_v41("Actions", action_html, raw=True),
        _management_signal_row_v41("Construction", f"{_progress_dev_v40(a.get('construction_dev'))} vs forecast"),
        _management_signal_row_v41("Engineering", f"{_progress_dev_v40(a.get('engineering_dev'))} vs forecast"),
        _management_signal_row_v41("Baseline", f"{baseline.get('slipped', 0)} slipped / +{baseline.get('max_delay', 0)}d max"),
        _management_signal_row_v41("Cost", f"Exposure {_pm_pct(cost.get('exposure_pct'))}; ETC {_fmt_money(cost.get('etc'))}"),
        _management_signal_row_v41("First late", first_late),
    ]
    return (
        f"<div class='pm-scope-card management-v41'><div class='mgmt-card-title'><b>{_html(a['scope'])}</b>{_scope_link_v32(a.get('scope_id'))}</div>"
        f"<span class='pm-status {a['tone']}'>{_html(a['label'])}</span>"
        f"<div class='mgmt-signal-grid'>{''.join(signals)}</div></div>"
    )


def render_pm_management_scope_boxes_v41(records: List[Dict[str, Any]], selected_year: int, selected_week: int, current_date: Optional[pd.Timestamp]) -> None:
    assessments = [_pm_scope_assessment(r, selected_year, selected_week, current_date) for r in records if r.get("scope_id") in {"rail", "ponds", "roads"}]
    if not assessments:
        return
    order = {"rail": 0, "ponds": 1, "roads": 2}
    assessments = sorted(assessments, key=lambda a: order.get(str(a.get("scope_id")), 99))
    st.markdown("<div class='section-title'>Management scope summary</div>", unsafe_allow_html=True)
    st.markdown("<div class='pm-scope-grid management-v41'>" + "".join(_management_scope_card_v41(a) for a in assessments) + "</div>", unsafe_allow_html=True)


def _pm_cost_exposure_figure(assessments: List[Dict[str, Any]]) -> go.Figure:
    scope_names = [str(a.get("scope") or "Scope") for a in assessments]
    x_labels = [_scope_axis_label_v40(name) for name in scope_names]
    exposure = [_safe_float((a.get("cost") or {}).get("exposure_pct")) or 0.0 for a in assessments]
    etc = [_safe_float((a.get("cost") or {}).get("etc")) or 0.0 for a in assessments]
    custom = [[scope_names[i], _fmt_money_full(etc[i])] for i in range(len(scope_names))]
    colors = ["#c73535" if v > 100 else "#d97706" if v > 15 else "#058b55" for v in exposure]
    fig = go.Figure()
    fig.add_trace(go.Bar(
        name="Exposure / forecast",
        x=x_labels,
        y=exposure,
        marker_color=colors,
        width=.46,
        text=[f"{v:.1f}%" for v in exposure],
        textposition="outside",
        customdata=custom,
        hovertemplate="<b>%{customdata[0]}</b><br>Exposure: %{y:.1f}%<extra></extra>",
    ))
    fig.add_trace(go.Scatter(
        name="ETC",
        x=x_labels,
        y=etc,
        mode="lines+markers",
        yaxis="y2",
        line=dict(color="#2563eb", width=2.4),
        marker=dict(size=8, color="#2563eb", line=dict(width=1.5, color="#ffffff")),
        customdata=custom,
        hovertemplate="<b>%{customdata[0]}</b><br>ETC: %{customdata[1]}<extra></extra>",
    ))
    fig.update_layout(
        height=260,
        margin=dict(l=38, r=38, t=18, b=42),
        paper_bgcolor="rgba(0,0,0,0)",
        plot_bgcolor="rgba(0,0,0,0)",
        yaxis=dict(title="Exposure %", rangemode="tozero", ticksuffix="%", showgrid=True, gridcolor="#eef0f4"),
        yaxis2=dict(title="ETC EUR", overlaying="y", side="right", showgrid=False),
        hovermode="closest",
        legend=dict(orientation="h", yanchor="bottom", y=1.04, xanchor="right", x=1, font=dict(size=10)),
        font=dict(family="Segoe UI, Arial, sans-serif", color="#1f2937", size=11),
    )
    fig.update_xaxes(tickangle=0, tickfont=dict(size=10), automargin=True, showgrid=False)
    return fig


def render_pm_visuals(records: List[Dict[str, Any]], selected_year: int, selected_week: int, current_date: Optional[pd.Timestamp]) -> None:
    assessments = [_pm_scope_assessment(r, selected_year, selected_week, current_date) for r in records if r.get("scope_id") in {"rail", "ponds", "roads"}]
    if not assessments:
        return
    st.markdown("<div class='section-title'>PM analysis visuals</div>", unsafe_allow_html=True)
    left, right = st.columns([1.08, .92], gap="large")
    with left:
        st.markdown("<div class='pm-visual-card compact-v41'><h3>Control pressure heatmap</h3>", unsafe_allow_html=True)
        st.plotly_chart(_pm_heatmap_figure(assessments), use_container_width=True)
        st.markdown("</div>", unsafe_allow_html=True)
    with right:
        st.markdown("<div class='pm-visual-card compact-v41'><h3>Action pressure vs progress target</h3>", unsafe_allow_html=True)
        st.plotly_chart(_pm_action_variance_figure(assessments), use_container_width=True)
        st.markdown("</div>", unsafe_allow_html=True)
    st.markdown("<div class='pm-visual-card compact-v41'><h3>Cost exposure and ETC</h3>", unsafe_allow_html=True)
    st.plotly_chart(_pm_cost_exposure_figure(assessments), use_container_width=True)
    st.markdown("</div>", unsafe_allow_html=True)


def _cost_bar_history_svg_v38(records: List[Tuple[str, float]], percent_mode: bool, axis_label: str) -> str:
    if not records:
        return "<div class='pm-empty-list'>No monthly values loaded.</div>"
    width, height = 520, 208
    left, right, top, bottom = 54, 16, 18, 48
    plot_w, plot_h = width - left - right, height - top - bottom
    values = [v for _, v in records]
    lo = min(min(values), 0.0)
    hi = max(max(values), 0.0)
    if percent_mode:
        hi = max(hi, 10.0)
        lo = min(lo, 0.0)
    if abs(hi - lo) < 1e-9:
        hi = lo + 1.0

    def y_for(value: float) -> float:
        return top + ((hi - value) / (hi - lo)) * plot_h

    zero_y = y_for(0.0)
    count = len(records)
    slot = plot_w / max(1, count)
    bar_w = max(16.0, min(32.0, slot * 0.48))
    points: List[str] = []
    elems: List[str] = [
        f"<div class='cost-bar-chart-v38'><div class='chart-note'><span>X: month</span><span>Y: {_html(axis_label)}</span></div>",
        f"<svg viewBox='0 0 {width} {height}' role='img' aria-label='Cost history line and bar chart'>",
        f"<line class='grid' x1='{left}' y1='{top}' x2='{width-right}' y2='{top}'/>",
        f"<line class='grid' x1='{left}' y1='{top + plot_h/2:.1f}' x2='{width-right}' y2='{top + plot_h/2:.1f}'/>",
        f"<line class='axis' x1='{left}' y1='{zero_y:.1f}' x2='{width-right}' y2='{zero_y:.1f}'/>",
        f"<line class='axis' x1='{left}' y1='{top}' x2='{left}' y2='{top+plot_h}'/>",
        f"<text class='ylabel' x='12' y='{top + 12}'>{_html('%' if percent_mode else 'EUR')}</text>",
        f"<text class='tick' x='8' y='{top + 4}'>{_html(_fmt_pct(hi) if percent_mode else _fmt_money(hi))}</text>",
        f"<text class='tick' x='8' y='{zero_y + 4:.1f}'>0</text>",
    ]
    for idx, (month, value) in enumerate(records):
        x_mid = left + slot * idx + slot / 2
        x = x_mid - bar_w / 2
        y_val = y_for(value)
        points.append(f"{x_mid:.1f},{y_val:.1f}")
        if value >= 0:
            y = y_val
            h = max(2.0, zero_y - y_val)
            label_y = max(12.0, y - 5.0)
            color = "#059669"
        else:
            y = zero_y
            h = max(2.0, y_val - zero_y)
            label_y = min(height - bottom + 20, y + h + 12.0)
            color = "#dc2626"
        label = f"{value:.1f}%" if percent_mode else _fmt_money(value)
        elems.extend([
            f"<rect x='{x:.1f}' y='{y:.1f}' width='{bar_w:.1f}' height='{h:.1f}' rx='4' fill='{color}' opacity='.72'/>",
            f"<text class='value' x='{x_mid:.1f}' y='{label_y:.1f}' text-anchor='middle'>{_html(label)}</text>",
            f"<text class='tick' transform='translate({x_mid:.1f},{height-18}) rotate(-24)' text-anchor='end'>{_html(month)}</text>",
        ])
    if points:
        elems.append(f"<polyline fill='none' stroke='#2563eb' stroke-width='2.4' stroke-linejoin='round' stroke-linecap='round' points='{' '.join(points)}'/>")
        for pt in points:
            x_str, y_str = pt.split(",")
            elems.append(f"<circle cx='{x_str}' cy='{y_str}' r='3.2' fill='#2563eb' stroke='#ffffff' stroke-width='1.3'/>")
    elems.append("</svg></div>")
    return "".join(elems)


def render_executive_overview(bundle: Dict[str, Any], profiles: Dict[str, Any], selected_year: int, selected_week: int, current_date: Optional[pd.Timestamp] = None) -> None:
    records = build_scope_records(bundle, profiles, selected_year, selected_week, scopes=CONTROL_SCOPES)
    selected_label = period_display(selected_year, selected_week)
    cutoff = current_date if current_date is not None else selected_cutoff_date(bundle)
    render_pm_visuals(records, selected_year, selected_week, cutoff)
    render_pm_management_scope_boxes_v41(records, selected_year, selected_week, cutoff)
    render_executive_priority_delayed_near_table(records, selected_label, selected_year, selected_week, current_date=cutoff)
    render_milestone_timeline(records, title="Milestones", selected_year=selected_year, selected_week=selected_week, current_date=cutoff)


def render_scope_sections(rec: Dict[str, Any], selected_year: int, selected_week: int, current_date: Optional[pd.Timestamp] = None) -> None:
    rec = _with_display_scope(rec)
    rec["name"] = _scope_label_v32(rec.get("scope_id"))
    rec["full_name"] = rec["name"]
    selected_label = period_display(selected_year, selected_week)
    st.markdown(f"<div class='rc-v32-scope-sticky v41'><h2><span class='scope-icon'>{SCOPE_ICON.get(rec.get('scope_id'), '')}</span> {_html(rec['full_name'])}</h2></div>", unsafe_allow_html=True)
    render_pm_scope_summary(rec, selected_year, selected_week, current_date)
    col1, col2 = st.columns([1, 1])
    with col1:
        render_progress_gauge(rec)
    with col2:
        render_progress_trend(rec, selected_year, selected_week)
    render_milestone_timeline([rec], scope_filter=rec["scope_id"], title="Milestones", selected_year=selected_year, selected_week=selected_week, current_date=current_date)
    render_scope_baseline_section(rec, selected_year, selected_week)
    render_scope_cost_section(rec)
    render_action_table(f"{rec['name']} priority - {selected_label}", rec.get("priority_items", []), selected_year, selected_week, rec.get("default_responsible", "TBC"), max_items=999, current_date=current_date)
    st.markdown("<div class='section-title'>Engineering</div>", unsafe_allow_html=True)
    e1, e2 = st.columns([1, 1])
    with e1:
        render_engineering_gauge(rec, selected_year, selected_week)
    with e2:
        render_engineering_trend(rec, selected_year, selected_week)
    render_action_table("", rec.get("engineering_items", []), selected_year, selected_week, rec.get("default_responsible", "TBC"), max_items=999, current_date=current_date)
    st.markdown("<div class='section-title'>Quality</div>", unsafe_allow_html=True)
    render_action_table("", rec.get("quality_items", []), selected_year, selected_week, rec.get("default_responsible", "TBC"), max_items=999, current_date=current_date)
    st.markdown("<div class='section-title'>Interfaces</div>", unsafe_allow_html=True)
    render_action_table("", rec.get("interface_items", []), selected_year, selected_week, rec.get("default_responsible", "TBC"), max_items=999, current_date=current_date)


# -----------------------------------------------------------------------------
# v42 restore full overview information after v41 simplification.
