def _render_cost_scope_buttons_v40() -> None:
    active_label, _active_scope_id = _ensure_cost_scope_v40()
    labels = _cost_scope_labels_v40()
    short = {"Rail On Site (ROS)": "ROS", "Ponds": "Ponds", "Roads": "Roads"}
    try:
        selected = st.segmented_control(
            "View",
            labels,
            key="cost_scope_visual_selector",
            format_func=lambda label: short.get(label, str(label)),
            label_visibility="visible",
        )
        if selected is None:
            st.session_state["cost_scope_visual_selector"] = active_label
    except Exception:
        st.markdown("<div class='cost-scope-button-title'>View</div>", unsafe_allow_html=True)
        cols = st.columns(len(COST_SCOPE_BUTTONS_V40), gap="small")
        for col, (scope_id, label, short_label) in zip(cols, COST_SCOPE_BUTTONS_V40):
            with col:
                if st.button(short_label, key=f"cost_scope_btn_{scope_id}_v43", use_container_width=True, type="primary" if label == active_label else "secondary"):
                    st.session_state["cost_scope_visual_selector"] = label
                    _safe_rerun()


def _rows_tsv_v43(rows: List[Dict[str, Any]]) -> str:
    headers = ["Action / issue", "Responsible", "Expected date", "Status"]
    lines = ["\t".join(headers)]
    for row in rows or []:
        lines.append("\t".join(str(row.get(key, "") or "").replace("\t", " ").replace("\n", " ") for key in ["action", "responsible", "expected", "status"]))
    return "\n".join(lines)


def _popover_markup_v33(title: str, rows: List[Dict[str, Any]], button_html: str, button_class: str) -> str:
    rows = rows or []
    token = hashlib.sha1((title + "|" + "|".join(str(r.get("action", "")) for r in rows[:30]) + "|v43").encode("utf-8", "ignore")).hexdigest()[:12]
    pid = f"pop_v43_{token}"
    tid = f"copy_v43_{token}"
    tsv = _html(_rows_tsv_v43(rows))
    copy_block = (
        f"<button type='button' class='copy-list-v43' onclick=\"navigator.clipboard&&navigator.clipboard.writeText(document.getElementById('{tid}').value).then(()=>{{this.textContent='Copied';}});\">Copy list</button>"
        f"<textarea id='{tid}' readonly>{tsv}</textarea>"
    )
    return (
        f"<button type='button' class='{button_class}' popovertarget='{pid}' popovertargetaction='toggle'>{button_html}</button>"
        f"<div id='{pid}' class='pm-popover-v33' popover><div class='pop-head'><b>{_html(title)}</b><span>{len(rows)}</span></div><div class='pop-body'>{copy_block}{_rows_popover_body_v33(rows)}</div></div>"
    )


def _overview_cost_inline_v43(scope_id: str) -> str:
    row = _active_history_row(scope_id)
    active_month = _active_month_label_v29()
    potential = row.get("Potential forecast") if row else None
    vowd = row.get("VOWD") if row else None
    etc = row.get("ETC") if row else None
    items = [
        ("Active month", active_month),
        ("Potential FC", _fmt_money(potential)),
        ("VOWD", _fmt_money(vowd)),
        ("ETC", _fmt_money(etc)),
    ]
    return "<span class='overview-cost-inline-v43'>" + "".join(f"<span><i>{_html(label)}</i><strong>{_html(value)}</strong></span>" for label, value in items) + "</span>"


def _pm_scope_card_html(a: Dict[str, Any]) -> str:
    actions, baseline, cost = a["actions"], a["baseline"], a["cost"]
    all_rows = actions.get("rows") or []
    delayed_rows = _filter_action_rows_v32(all_rows, {"Delayed"})
    near_rows = _filter_action_rows_v32(all_rows, {"Near due"})
    action_html = (
        "<span class='action-inline-v43'>"
        + _action_popover_button_v32(f"{a['scope']} delayed actions", delayed_rows, len(delayed_rows), label=str(actions.get("Delayed", 0)), class_name="action-count-button")
        + "<em>delayed</em>"
        + _action_popover_button_v32(f"{a['scope']} near-due actions", near_rows, len(near_rows), label=str(actions.get("Near due", 0)), class_name="action-count-button")
        + "<em>near due</em></span>"
    )
    signals = [
        _pm_signal_html_v40("Actions", action_html, raw=True),
        _pm_signal_html_v40("Construction", f"{_progress_dev_v40(a.get('construction_dev'))} vs forecast; max 4%"),
        _pm_signal_html_v40("Engineering", f"{_progress_dev_v40(a.get('engineering_dev'))} vs forecast; max 4%"),
        _pm_signal_html_v40("Baseline", f"{baseline.get('slipped', 0)} slipped / max +{baseline.get('max_delay', 0)} days"),
        _pm_signal_html_v40("Cost", _overview_cost_inline_v43(a.get("scope_id")), raw=True),
    ]
    if a.get("first_delayed"):
        signals.append(_pm_signal_html_v40("First late", compact_text(a["first_delayed"], 105)))
    return (
        f"<div class='pm-scope-card'><h3><span>{_html(a['scope'])}</span>{_scope_link_v32(a.get('scope_id'))}</h3>"
        f"<span class='pm-status {a['tone']}'>{_html(a['label'])}</span><div class='pm-signal-list'>{''.join(signals)}</div></div>"
    )


def render_pm_scope_overview_cards_v43(records: List[Dict[str, Any]], selected_year: int, selected_week: int, current_date: Optional[pd.Timestamp]) -> None:
    order = {"rail": 0, "ponds": 1, "roads": 2}
    assessments = [_pm_scope_assessment(r, selected_year, selected_week, current_date) for r in records if r.get("scope_id") in order]
    assessments = sorted(assessments, key=lambda a: order.get(str(a.get("scope_id")), 99))
    st.markdown("<div class='pm-scope-grid'>" + "".join(_pm_scope_card_html(a) for a in assessments) + "</div>", unsafe_allow_html=True)


def _relative_scores_v43(values: List[float]) -> List[float]:
    clean = [float(v or 0.0) for v in values]
    lo, hi = min(clean or [0.0]), max(clean or [0.0])
    if abs(hi - lo) < 1e-9:
        return [0.0 if hi <= 0 else 5.0 for _ in clean]
    return [(v - lo) / (hi - lo) * 10.0 for v in clean]


def _pm_heatmap_figure(assessments: List[Dict[str, Any]]) -> go.Figure:
    metrics = ["Actions", "Progress", "Gates", "Baseline", "Cost"]
    scopes = [str(a.get("scope") or "Scope") for a in assessments]
    raw_actions = [float((a.get("actions") or {}).get("Delayed", 0)) * 2.0 + float((a.get("actions") or {}).get("Near due", 0)) for a in assessments]
    raw_gates = [float(a.get("open_gates") or 0.0) for a in assessments]
    raw_baseline = [float((a.get("baseline") or {}).get("max_delay", 0.0) or 0.0) for a in assessments]
    raw_cost = [float((a.get("cost") or {}).get("exposure_pct") or 0.0) for a in assessments]
    progress = []
    for a in assessments:
        con = _safe_float(a.get("construction_dev"))
        eng = _safe_float(a.get("engineering_dev"))
        progress.append(10.0 if (con is not None and con < 0) or (eng is not None and eng < 0) else 0.0)
    columns = [_relative_scores_v43(raw_actions), progress, _relative_scores_v43(raw_gates), _relative_scores_v43(raw_baseline), _relative_scores_v43(raw_cost)]
    z = [[columns[col][row] for col in range(len(metrics))] for row in range(len(scopes))]
    fig = go.Figure(data=go.Heatmap(
        z=z,
        x=metrics,
        y=scopes,
        zmin=0,
        zmax=10,
        xgap=6,
        ygap=6,
        colorscale=[[0, "#16a34a"], [.5, "#facc15"], [1, "#dc2626"]],
        showscale=False,
        hoverinfo="skip",
    ))
    fig.update_yaxes(autorange="reversed")
    fig.update_layout(height=285, margin=dict(l=38, r=12, t=20, b=34), paper_bgcolor="rgba(0,0,0,0)", plot_bgcolor="rgba(0,0,0,0)", font=dict(family="Segoe UI, Arial, sans-serif", size=11, color="#1f2937"))
    fig.update_xaxes(showgrid=False, zeroline=False)
    fig.update_yaxes(showgrid=False, zeroline=False)
    return fig


def _pm_action_variance_figure(assessments: List[Dict[str, Any]]) -> go.Figure:
    scopes = [str(a.get("scope") or "Scope") for a in assessments]
    x_labels = [_scope_axis_label_v40(s) for s in scopes]
    delayed = [int((a.get("actions") or {}).get("Delayed", 0)) for a in assessments]
    near = [int((a.get("actions") or {}).get("Near due", 0)) for a in assessments]
    construction = [_safe_float(a.get("construction_dev")) or 0.0 for a in assessments]
    engineering = [_safe_float(a.get("engineering_dev")) or 0.0 for a in assessments]
    fig = go.Figure()
    fig.add_trace(go.Bar(name="Delayed actions", x=x_labels, y=delayed, marker_color="#c73535", yaxis="y"))
    fig.add_trace(go.Bar(name="Near due", x=x_labels, y=near, marker_color="#d97706", yaxis="y"))
    fig.add_trace(go.Scatter(name="Construction variance", x=x_labels, y=construction, mode="lines+markers", marker=dict(color="#111111", size=8), line=dict(color="#111111", width=2, dash="dot"), yaxis="y2"))
    fig.add_trace(go.Scatter(name="Engineering variance", x=x_labels, y=engineering, mode="lines+markers", marker=dict(color="#6f2da8", size=8), line=dict(color="#6f2da8", width=2, dash="dash"), yaxis="y2"))
    fig.update_layout(barmode="stack", yaxis=dict(title="Action count", rangemode="tozero", showgrid=True, gridcolor="#f0edf5"), yaxis2=dict(title="Deviation vs forecast", overlaying="y", side="right", zeroline=True, zerolinecolor="#98a2b3", showgrid=False, ticksuffix="%"))
    return _pm_theme_figure(fig, height=315)


def _gate_action_tile_v43(title: str, rows: List[Dict[str, Any]], count: int) -> str:
    button = _popover_markup_v33(title, rows, str(int(count)), "gate-click-btn rc-click-card")
