def render_scope_matrix(records: List[Dict[str, Any]], selected_year: int, selected_week: int) -> None:
    st.session_state["selected_year_v32"] = int(selected_year)
    st.session_state["selected_week_v32"] = int(selected_week)
    current_date = st.session_state.get("selected_cutoff_v32")
    order = {"rail": 0, "ponds": 1, "roads": 2}
    records = [_with_display_scope(r) for r in records if r.get("scope_id") in order]
    records = sorted(records, key=lambda r: order.get(r.get("scope_id"), 99))
    cards = []
    for rec in records:
        scope_id = rec.get("scope_id")
        scope = _scope_label_v32(scope_id)
        actions = _pm_action_counts(rec, selected_year, selected_week, current_date)
        rows = actions.get("rows") or []
        delayed_rows = _filter_action_rows_v32(rows, {"Delayed"})
        near_rows = _filter_action_rows_v32(rows, {"Near due"})
        quality_rows = _as_action_records_v32(rec.get("quality_items", []), selected_year, selected_week, rec.get("default_responsible", "TBC"), current_date)
        engineering_rows = _as_action_records_v32(rec.get("engineering_items", []), selected_year, selected_week, rec.get("default_responsible", "TBC"), current_date)
        delayed = _popover_markup_v33(f"{scope} delayed actions", delayed_rows, str(actions.get("Delayed", 0)), "action-count-button rc-click-card")
        near = _popover_markup_v33(f"{scope} near-due actions", near_rows, str(actions.get("Near due", 0)), "action-count-button rc-click-card")
        cards.append(
            f"<div class='matrix-action-card-v43'><h3>{_html(scope)}</h3>{_scope_link_v32(scope_id)}"
            f"<div class='matrix-action-row-v43'>"
            f"<div class='gate-tile-v43'><span>Delayed actions</span>{delayed}</div>"
            f"<div class='gate-tile-v43'><span>Near due actions</span>{near}</div>"
            f"</div><div class='gate-row-v43'>"
            f"{_gate_action_tile_v43('Open quality gates', quality_rows, len(quality_rows))}"
            f"{_gate_action_tile_v43('Open engineering gates', engineering_rows, len(engineering_rows))}"
            f"</div></div>"
        )
    st.markdown("<div class='section-title'>Scope action controls</div>", unsafe_allow_html=True)
    st.markdown("<div class='matrix-action-grid-v43'>" + "".join(cards) + "</div>", unsafe_allow_html=True)


def render_scope_cost_section(rec: Dict[str, Any]) -> None:
    rec = _with_display_scope(rec)
    rec["name"] = _scope_label_v32(rec.get("scope_id"))
    cost = _select_cost_report(rec["scope_id"])
    active_month = st.session_state.get("monthly_cost_report_choice_portfolio") or _active_month_label_from_cost(cost)
    nums = _cost_numbers(rec["scope_id"], cost)
    budget = _safe_float(nums.get("budget"))
    co = _safe_float(nums.get("change_order"))
    forecast = _safe_float(nums.get("forecast"))
    vowd = _safe_float(nums.get("vowd"))
    etc = _safe_float(nums.get("forecast_minus_vowd"))
    exposure = _safe_float(nums.get("potential_exposure"))
    potential = _safe_float(nums.get("potential_forecast"))
    potential_vs_budget = (potential - budget) if (potential is not None and budget is not None) else None
    vowd_ratio = _pct_ratio(vowd, forecast)
    exposure_ratio = _pct_ratio(exposure, forecast)
    balanced = "Balanced" if (forecast is not None and budget is not None and co is not None and abs((budget + co) - forecast) < 1.0 and potential is not None and exposure is not None and abs((forecast + exposure) - potential) < 1.0) else "Review"
    st.markdown("<div class='section-title'>Cost position</div>", unsafe_allow_html=True)
    left, right = st.columns([1.0, 1.35], gap="large")
    with left:
        st.markdown(f"<div class='cost-chart-box'><h3>{_html(rec['name'])} candle bar</h3>", unsafe_allow_html=True)
        st.plotly_chart(_cost_waterfall_figure_v24(rec["scope_id"], cost, title=f"{rec['name']} candle bar"), use_container_width=True)
        st.markdown("</div>", unsafe_allow_html=True)
    with right:
        st.markdown(f"<div class='cost-chart-box'><h3>{_html(rec['name'])} monthly cost trend</h3>", unsafe_allow_html=True)
        st.plotly_chart(_cost_history_trend_figure(rec["scope_id"]), use_container_width=True)
        st.markdown("</div>", unsafe_allow_html=True)
    st.markdown(
        "<div class='cost-scope-mini'>"
        + f"<h3>{_html(rec['name'])} cost values - {_html(active_month)}</h3>"
        + "<div class='cost-detail-grid v32'>"
        + f"<div class='cost-detail-cell'><span>Budget</span><b>{_html(_fmt_money(budget))}</b></div>"
        + f"<div class='cost-detail-cell'><span>CO</span><b>{_html(_fmt_money(co))}</b></div>"
        + f"<div class='cost-detail-cell'><span>Forecast</span><b>{_html(_fmt_money(forecast))}</b></div>"
        + f"<div class='cost-detail-cell'><span>Potential FC</span><b>{_html(_fmt_money(potential))}</b></div>"
        + f"<div class='cost-detail-cell'><span>VOWD</span><b>{_html(_fmt_money(vowd))}</b></div>"
        + f"<div class='cost-detail-cell'><span>ETC</span><b>{_html(_fmt_money(etc))}</b></div>"
        + f"<div class='cost-detail-cell'><span>Potential forecast vs budget</span><b>{_html(_fmt_money(potential_vs_budget))}</b></div>"
        + f"<div class='cost-detail-cell'><span>Potential exposure</span><b>{_html(_fmt_money(exposure))}</b></div>"
        + f"<div class='cost-detail-driver'>VOWD / Forecast: <b>{_html(vowd_ratio)}</b> | Exposure / Forecast: <b>{_html(exposure_ratio)}</b> | Cost check: <b>{_html(balanced)}</b></div>"
        + "</div></div>",
        unsafe_allow_html=True,
    )


