def _cost_potential_forecast_rows_v49(scope_id: str) -> List[List[Any]]:
    summary = _active_history_row(scope_id)
    rows: List[List[Any]] = []
    if summary:
        rows.append([
            "Scope total",
            "Active-month potential forecast",
            "",
            _fmt_money_full(summary.get("Forecast")),
            _fmt_money_full(summary.get("Potential exposure")),
            _fmt_money_full(summary.get("Potential forecast")),
            "Forecast + potential exposure",
        ])

    for row in _cost_driver_rows(scope_id):
        padded = list(row) + [""] * max(0, 9 - len(row))
        rows.append([
            padded[0],
            padded[1],
            padded[2],
            padded[5],
            padded[6],
            padded[7],
            padded[8],
        ])

    for row in _cost_exposure_rows(scope_id):
        padded = list(row) + [""] * max(0, 8 - len(row))
        rows.append([
            f"Exposure item {padded[0]}",
            padded[5],
            padded[6],
            "",
            padded[2],
            "",
            f"{padded[3]} {padded[4]} | expected {padded[7]}".strip(),
        ])
    return rows


def render_cost_panel(bundle: Dict[str, Any], profiles: Dict[str, Any], selected_year: int, selected_week: int, current_date: Optional[pd.Timestamp] = None) -> None:
    active_report = _active_cost_report()
    active_month = active_report.get("label") or _active_month_label_from_cost(active_report.get("data") or {})
    cost_data = active_report.get("data") or cached_monthly_cost()
    meta = cost_data.get("metadata") or {}
    selected_scope_label, scope_id = _ensure_cost_scope_v40()

    left, right = st.columns([1.0, 1.35], gap="large")
    with left:
        st.markdown(f"<div class='cost-chart-box'><h3>{_html(selected_scope_label)} candle bar</h3>", unsafe_allow_html=True)
        st.plotly_chart(_cost_waterfall_figure_v24(scope_id, cost_data, title=f"{selected_scope_label} candle bar"), use_container_width=True)
        st.markdown("</div>", unsafe_allow_html=True)
    with right:
        st.markdown(f"<div class='cost-chart-box'><h3>{_html(selected_scope_label)} cost history trend</h3>", unsafe_allow_html=True)
        st.plotly_chart(_cost_history_trend_figure(scope_id), use_container_width=True)
        st.markdown("</div>", unsafe_allow_html=True)

    _render_cost_values_v44(scope_id, active_month, meta)

    potential_rows = _cost_potential_forecast_rows_v49(scope_id)
    if potential_rows:
        with st.expander(f"Potential forecast list - {selected_scope_label} - {active_month}", expanded=False):
            _copyable_table_component(
                ["Source", "Description", "Supplier / responsible", "Forecast", "Potential exposure", "Potential forecast", "Driver / note"],
                potential_rows,
                numeric_cols={3, 4, 5},
                key_prefix=f"cost_potential_forecast_{scope_id}_{active_month}_v49",
            )

    drivers = _cost_driver_rows(scope_id) if "_cost_driver_rows" in globals() else []
    with st.expander(f"Package drivers - {selected_scope_label} - {active_month}", expanded=False):
        if drivers:
            _copyable_table_component(
                ["Package", "Description", "Supplier", "Budget", "CO", "Forecast", "Exposure", "Potential forecast", "Driver / note"],
                drivers,
                numeric_cols={3, 4, 5, 6, 7},
                key_prefix=f"cost_drivers_{scope_id}_{active_month}_v49",
            )
        else:
            st.markdown(f"<div class='action-empty'>No package-driver rows loaded for {selected_scope_label} in {active_month}.</div>", unsafe_allow_html=True)

    exposures = _cost_exposure_rows(scope_id) if "_cost_exposure_rows" in globals() else []
    if exposures:
        with st.expander(f"Potential exposure / O&V items - {selected_scope_label} - {active_month}", expanded=False):
            _copyable_table_component(
                ["Item", "Package", "Amount", "Criticality", "Type", "Description", "Responsible", "Expected / award date"],
                exposures,
                numeric_cols={2},
                key_prefix=f"cost_exposures_{scope_id}_{active_month}_v49",
            )

    with st.expander(f"Monthly cost history - {selected_scope_label}", expanded=False):
        _copyable_table_component(
            ["Month", "Budget", "CO", "Forecast", "VOWD", "ETC", "Potential exposure", "Potential forecast", "Budget + CO check", "Forecast + exposure check"],
            _cost_history_table_rows(scope_id),
            numeric_cols={1, 2, 3, 4, 5, 6, 7, 8, 9},
            key_prefix=f"cost_monthly_history_{scope_id}_{active_month}_v49",
        )


