def _matrix_action_tile_v51(title: str, rows: List[Dict[str, Any]], count: int, label: str, tone: str) -> str:
    button_html = f"<span>{_html(label)}</span><b>{int(count)}</b><small>Click for list</small>"
    return _popover_markup_v33(title, rows, button_html, f"action-tile-v51 {tone} rc-click-card")


def _matrix_action_strip_v51(rec: Dict[str, Any], selected_year: int, selected_week: int, current_date: Optional[pd.Timestamp]) -> str:
    assessment = _pm_scope_assessment(rec, selected_year, selected_week, current_date)
    actions = assessment.get("actions") or {}
    rows = actions.get("rows") or []
    delayed_rows = _filter_action_rows_v32(rows, {"Delayed"})
    near_rows = _filter_action_rows_v32(rows, {"Near due"})
    delayed_count = int(actions.get("Delayed", len(delayed_rows)) or 0)
    near_count = int(actions.get("Near due", len(near_rows)) or 0)
    first_late = compact_text(assessment.get("first_delayed") or "No delayed action text loaded for this scope.", 128)
    scope = str(assessment.get("scope") or _scope_label_v32(rec.get("scope_id")))
    return (
        "<div class='matrix-action-strip-v51'>"
        f"{_matrix_action_tile_v51(scope + ' delayed actions', delayed_rows, delayed_count, 'Delayed actions', 'delayed')}"
        f"{_matrix_action_tile_v51(scope + ' near-due actions', near_rows, near_count, 'Near due actions', 'near')}"
        "</div>"
        f"<div class='matrix-first-action-v51'><span>First late</span><b>{_html(first_late)}</b></div>"
    )


