                f"{progress_bar_html('Engineering progress', engineering_actual, engineering_forecast, engineering_dev, engineering_etc, next_week_forecast=_next_progress_label(rec, selected_year, selected_week, 'engineering'))}"
                "<div class='gate-row'>"
