def render_header(bundle: Dict[str, Any], selected_label: str, panel_choice: str = "Executive overview") -> Tuple[int, int]:
    _latest_defaults_v32(st.session_state.get("bundle", bundle))
    periods = available_periods(st.session_state.get("bundle", bundle))
    week_labels = [period_display(y, w) for y, w in periods]
    selected_year, selected_week = _selected_period_from_state_v32(st.session_state.get("bundle", bundle))
    current_week_idx = week_labels.index(st.session_state.get("week_selector_value")) if week_labels and st.session_state.get("week_selector_value") in week_labels else max(0, len(week_labels) - 1)
    cost_labels = _month_labels_v29()
    active_month = _active_month_label_v29()
    current_month_idx = cost_labels.index(active_month) if active_month in cost_labels else max(0, len(cost_labels) - 1)
    baseline_labels = _baseline_labels_v36()
    if baseline_labels and st.session_state.get("baseline_choice") not in baseline_labels:
        st.session_state["baseline_choice"] = baseline_labels[-1]
    current_baseline_idx = baseline_labels.index(st.session_state.get("baseline_choice")) if baseline_labels and st.session_state.get("baseline_choice") in baseline_labels else max(0, len(baseline_labels) - 1)
    _ensure_cost_scope_v40()
    cutoff_week = _date_for_selected_week_v29(bundle, selected_year, selected_week)
    logo_src = logo_mark_data_uri() or logo_data_uri()
    logo_html = f"<div class='rc-logo-box'><img src='{logo_src}'></div>" if logo_src else ""
    panel_key = _key_v36(panel_choice)
    panel_title = _panel_title_v27(panel_choice)
    try:
        header = st.container(key="rc_panel_header_v27")
    except TypeError:
        header = st.container()
    with header:
        st.markdown("<div class='rc-title-row'>" + logo_html + f"<div><h1>{_html(panel_title)}</h1></div></div>", unsafe_allow_html=True)
        if panel_choice == "Cost Status":
            top_cols = st.columns([1.0, 1.34], gap="small")
            with top_cols[0]:
                _selector_nav_v36("Month", cost_labels, "monthly_cost_report_choice_portfolio", f"{panel_key}_month_v52", current_month_idx, _set_active_month_by_offset_v29)
            with top_cols[1]:
                _selector_nav_v36("Baseline", baseline_labels, "baseline_choice", f"{panel_key}_baseline_v52", current_baseline_idx, _set_active_baseline_by_offset_v36)
            try:
                scope_row = st.container(key="cost_scope_row_v52")
            except TypeError:
                scope_row = st.container()
            with scope_row:
                _render_cost_scope_buttons_v40()
        else:
            cols = st.columns([1.08, 1.08, 1.34, .70], gap="small")
            with cols[0]:
                _selector_nav_v36("Week", week_labels, "week_selector_value", f"{panel_key}_week_v52", current_week_idx, _set_active_week_by_offset)
            with cols[1]:
                _selector_nav_v36("Month", cost_labels, "monthly_cost_report_choice_portfolio", f"{panel_key}_month_v52", current_month_idx, _set_active_month_by_offset_v29)
            with cols[2]:
                _selector_nav_v36("Baseline", baseline_labels, "baseline_choice", f"{panel_key}_baseline_v52", current_baseline_idx, _set_active_baseline_by_offset_v36)
            with cols[3]:
                st.markdown(f"<div class='cutoff-chip'><span>Cut-off</span><b>{_html(cutoff_week)}</b></div>", unsafe_allow_html=True)
        active_text = _active_month_label_v29() if panel_choice == "Cost Status" else st.session_state.get("week_selector_value", selected_label)
        st.markdown(f"<div class='panel-title-v27'><h2>Active period</h2><span>{_html(active_text)}</span></div>", unsafe_allow_html=True)
    return _selected_period_from_state_v32(st.session_state.get("bundle", bundle))


def _text_value_v53(value: Any) -> str:
    if value is None:
        return ""
    try:
        if pd.isna(value):
            return ""
    except Exception:
        pass
    text = str(value).strip()
    if text.lower() in {"nan", "none", "null", "n/a"}:
        return ""
    return text


def _first_text_v53(*values: Any) -> str:
    for value in values:
        text = _text_value_v53(value)
        if text:
            return text
    return ""


def _package_source_v53(pkg: Dict[str, Any], idx: int, scope_id: str) -> str:
    source = _first_text_v53(
        pkg.get("package_number"),
        pkg.get("package"),
        pkg.get("package_id"),
        pkg.get("component"),
        pkg.get("row_label"),
    )
    if source:
        return source
    supplier = _text_value_v53(pkg.get("supplier"))
    if supplier:
        return supplier
    return f"{_scope_label_v32(scope_id)} package {idx}"


def _package_description_v53(pkg: Dict[str, Any], source: str, scope_id: str) -> str:
    desc = _first_text_v53(
        pkg.get("package_description"),
        pkg.get("description"),
        pkg.get("main_description"),
        pkg.get("scope_description"),
        pkg.get("component_description"),
        pkg.get("row_label"),
        pkg.get("component"),
    )
    if desc and desc != source:
        return desc
    note = _first_text_v53(pkg.get("basis"), pkg.get("driver"), pkg.get("allocation_note"), pkg.get("note"))
    if note:
        return note
    supplier = _text_value_v53(pkg.get("supplier"))
    if supplier and supplier != source:
        return f"{supplier} cost package"
    return f"{_scope_label_v32(scope_id)} cost package"


def _package_note_v53(pkg: Dict[str, Any], forecast: Any, exposure: Any, potential_fc: Any) -> str:
    note = _first_text_v53(
        pkg.get("basis"),
        pkg.get("driver"),
        pkg.get("allocation_note"),
        pkg.get("note"),
        pkg.get("description"),
    )
    if note:
        return note
    forecast_num = _safe_float(forecast)
    exposure_num = _safe_float(exposure)
    potential_num = _safe_float(potential_fc)
    if exposure_num and abs(exposure_num) > 0:
        return "Potential forecast includes active-month exposure."
    if potential_num is not None and forecast_num is not None and abs(potential_num - forecast_num) > 1:
        return "Potential forecast differs from current forecast."
    return "Active-month cost driver."


def _scope_package_rows(scope_id: str, cost_data: Dict[str, Any]) -> List[List[Any]]:
    rows: List[List[Any]] = []
    for idx, pkg in enumerate(_cost_packages(scope_id, cost_data), start=1):
        if scope_id in {"roads", "ponds", ""} and pkg.get("package_number") in {"BOD-BOP-019E", "BOD-BOP-019EA", "BOD-BOP-019EH"}:
            continue
        forecast = pkg.get("eac") if pkg.get("eac") is not None else pkg.get("forecast")
        exposure = pkg.get("potential_deviation") if pkg.get("potential_deviation") is not None else pkg.get("potential_exposure")
        potential_fc = pkg.get("potential_forecast")
        source = _package_source_v53(pkg, idx, scope_id)
        description = _package_description_v53(pkg, source, scope_id)
        rows.append([
            source,
            description,
            _text_value_v53(pkg.get("supplier")),
            _fmt_money_full(pkg.get("baseline_control_budget")),
            _fmt_money_full(pkg.get("approved_change_deviation") if pkg.get("approved_change_deviation") is not None else pkg.get("co")),
            _fmt_money_full(forecast),
            _fmt_money_full(exposure),
            _fmt_money_full(potential_fc),
            _package_note_v53(pkg, forecast, exposure, potential_fc),
        ])
    return rows


def _cost_driver_rows(scope_id: str) -> List[List[Any]]:
    active_report = _active_cost_report()
    cost_data = active_report.get("data") or cached_monthly_cost()
    return _scope_package_rows(scope_id, cost_data)


def _cost_potential_forecast_rows_v49(scope_id: str) -> List[List[Any]]:
    active_report = _active_cost_report()
    active_month = active_report.get("label") or _active_month_label_v29()
    summary = _active_history_row(scope_id)
    rows: List[List[Any]] = []
    if summary:
        rows.append([
            "Scope total",
            f"{active_month} active-month total",
            "Cost control",
            _fmt_money_full(summary.get("Forecast")),
            _fmt_money_full(summary.get("Potential exposure")),
            _fmt_money_full(summary.get("Potential forecast")),
            "Forecast + potential exposure for the selected active month.",
        ])

    for row in _cost_driver_rows(scope_id):
        padded = list(row) + [""] * max(0, 9 - len(row))
        source = _first_text_v53(padded[0], padded[2], f"{_scope_label_v32(scope_id)} package")
        description = _first_text_v53(padded[1], padded[8], f"{source} forecast / exposure driver")
        note = _first_text_v53(padded[8], "Package forecast plus active potential exposure.")
        rows.append([
            source,
            description,
            _first_text_v53(padded[2], "TBC"),
            padded[5],
            padded[6],
            padded[7],
            note,
        ])

    for row in _cost_exposure_rows(scope_id):
        padded = list(row) + [""] * max(0, 8 - len(row))
        item = _first_text_v53(padded[0], "exposure")
        description = _first_text_v53(padded[5], padded[3], f"Exposure item {item}")
        responsible = _first_text_v53(padded[6], "TBC")
        date_bits = " ".join(x for x in [_text_value_v53(padded[3]), _text_value_v53(padded[4])] if x)
        expected = _text_value_v53(padded[7])
        note = " | ".join(x for x in [date_bits, f"expected {expected}" if expected else ""] if x)
        rows.append([
            f"Exposure item {item}",
            description,
            responsible,
            "",
            padded[2],
            "",
            note or "Active exposure item.",
        ])
    return rows


def _cost_history_table_rows(scope_id: str) -> List[List[Any]]:
    df = _history_for_scope(scope_id)
    if df is None or df.empty:
        return []
    if "Date" in df.columns:
        df = df.sort_values("Date", ascending=False, na_position="last")
    else:
        df = df.iloc[::-1]
    rows: List[List[Any]] = []
    for _, row in df.iterrows():
        rows.append([
            row.get("Month"),
            _fmt_money_full(row.get("Budget")),
            _fmt_money_full(row.get("CO")),
            _fmt_money_full(row.get("Forecast")),
            _fmt_money_full(row.get("VOWD")),
            _fmt_money_full(row.get("ETC")),
            _fmt_money_full(row.get("Potential exposure")),
            _fmt_money_full(row.get("Potential forecast")),
            _fmt_money_full(row.get("Budget + CO check")),
            _fmt_money_full(row.get("Forecast + exposure check")),
        ])
    return rows


def _copyable_table_component(headers: List[str], rows: List[List[Any]], numeric_cols: Optional[set] = None, key_prefix: str = "tbl") -> None:
    numeric_cols = numeric_cols or set()
    if not rows:
        st.markdown("<div class='action-empty'>No rows available for this active selection.</div>", unsafe_allow_html=True)
        return
    keep = _table_column_keep(headers, rows)
    headers2 = [headers[i] for i in keep]
    rows2 = [[row[i] if i < len(row) else "" for i in keep] for row in rows]
    numeric2 = {new_i for new_i, old_i in enumerate(keep) if old_i in numeric_cols}
    tsv = "\n".join(["\t".join(str(h or "") for h in headers2)] + ["\t".join(str(c or "") for c in row) for row in rows2])
    widths = _preferred_col_widths(headers2)
    if len(widths) != len(headers2):
        widths = [int(100 / max(1, len(headers2)))] * len(headers2)
    colgroup = "".join(f"<col style='width:{w}%;'>" for w in widths)
    table_head = "".join(f"<th>{html.escape(str(h or ''))}</th>" for h in headers2)
    active_label = _active_cost_report().get("label") or _active_month_label_v29()
    key_lower = str(key_prefix).lower()
    first_header = str(headers2[0]).lower() if headers2 else ""
    is_month_table = first_header.startswith("month")
    is_potential_list = "potential_forecast" in key_lower
    body = []
    for row in rows2:
        first_cell = str(row[0] if row else "")
        row_class = ""
        if is_month_table and first_cell == active_label:
            row_class = "active-month-row"
        elif is_potential_list and first_cell == "Scope total":
            row_class = "active-month-row"
        cells = []
        for ci, val in enumerate(row):
            cls = "num" if ci in numeric2 else ""
            cells.append(f"<td class='{cls}'>{html.escape(str(val or ''))}</td>")
        body.append(f"<tr class='{row_class}'>{''.join(cells)}</tr>")
    ident = "tbl_" + hashlib.sha1((key_prefix + tsv).encode("utf-8", "ignore")).hexdigest()[:12]
    html_table = f"<table><colgroup>{colgroup}</colgroup><thead><tr>{table_head}</tr></thead><tbody>{''.join(body)}</tbody></table>"
    js_tsv = json.dumps(tsv)
    js_html = json.dumps("<html><head><meta charset='utf-8'></head><body>" + html_table + "</body></html>")
    doc = f"""
<!doctype html><html><head><meta charset='utf-8'>
<style>
body{{margin:0;font-family:Inter,Segoe UI,Arial,sans-serif;color:#1f2937;background:transparent;}}
.copybar{{display:flex;gap:8px;align-items:center;margin:0 0 8px 0;}}
.copybar button{{border:1px solid #d9c3ee;background:#fff;color:#39135c;border-radius:999px;padding:7px 13px;font-weight:900;font-size:12px;cursor:pointer;}}
.copybar button:hover{{background:#f8f3fd;border-color:#6f2da8;}}
.copybar .msg{{font-size:12px;color:#667085;}}
.table-wrap{{width:100%;border:1px solid #e7e2ed;border-radius:15px;overflow:hidden;background:#fff;box-shadow:0 1px 8px rgba(17,17,17,.04);}}
table{{width:100%;border-collapse:collapse;table-layout:fixed;}}
th{{background:#f7f7fa;color:#111;font-size:11px;letter-spacing:.06em;text-transform:uppercase;font-weight:900;line-height:1.18;padding:9px 8px;text-align:left;border-bottom:1px solid #e7e2ed;border-left:1px solid #eee8f4;white-space:normal;overflow-wrap:anywhere;}}
th:first-child{{border-left:0;}}
td{{font-size:12.5px;line-height:1.32;padding:8px 8px;vertical-align:top;border-top:1px solid #eee8f4;border-left:1px solid #eee8f4;white-space:normal;overflow-wrap:anywhere;word-break:normal;hyphens:auto;font-weight:450;}}
td:first-child{{border-left:0;}}
tbody tr:nth-child(even){{background:#fbfafc;}}
tbody tr.active-month-row td{{font-weight:950!important;background:#f8f3fd!important;color:#111!important;}}
tbody tr.active-month-row td.num{{font-weight:950!important;}}
td.num{{text-align:right;font-weight:520;white-space:nowrap;}}
textarea{{position:absolute;left:-9999px;top:-9999px;}}
</style></head><body>
<div class='copybar'><button id='{ident}_btn'>Copy table</button><span id='{ident}_msg' class='msg'>Copies an Excel-ready table.</span></div>
<textarea id='{ident}_tsv' readonly></textarea>
<div id='{ident}_wrap' class='table-wrap'>{html_table}</div>
<script>
const TSV = {js_tsv};
const HTML_TABLE = {js_html};
const ta = document.getElementById('{ident}_tsv');
ta.value = TSV;
const msg = document.getElementById('{ident}_msg');
function selectRenderedTable() {{
  const table = document.querySelector('#{ident}_wrap table');
  const range = document.createRange();
  range.selectNode(table);
  const sel = window.getSelection();
  sel.removeAllRanges();
  sel.addRange(range);
}}
async function richClipboard() {{
  if (navigator.clipboard && window.ClipboardItem) {{
    const item = new ClipboardItem({{'text/html': new Blob([HTML_TABLE], {{type:'text/html'}}),'text/plain': new Blob([TSV], {{type:'text/plain'}})}});
    await navigator.clipboard.write([item]);
    return true;
  }}
  return false;
}}
function execCopyTable() {{
  try {{ selectRenderedTable(); const ok = document.execCommand('copy'); window.getSelection().removeAllRanges(); return ok; }} catch(e) {{ return false; }}
}}
function execCopyText() {{
  try {{ ta.style.cssText='position:fixed;left:0;top:0;width:2px;height:2px;opacity:0;'; ta.focus(); ta.select(); return document.execCommand('copy'); }} catch(e) {{ return false; }}
}}
document.getElementById('{ident}_btn').addEventListener('click', async function(){{
  if (execCopyTable()) {{ msg.textContent='Copied as a real table. Paste into Excel / Teams.'; return; }}
  try {{ if (await richClipboard()) {{ msg.textContent='Copied as formatted table. Paste into Excel / Teams.'; return; }} }} catch(e) {{}}
  if (execCopyText()) {{ msg.textContent='Copied as tab-separated table. Paste into Excel.'; return; }}
  msg.textContent='Clipboard blocked. Select the table and press Ctrl+C.';
}});
</script></body></html>
"""
    height = _estimate_component_height(headers2, rows2)
    components.html(doc, height=height, scrolling=False)


