def _remember_selector_change_v55(state_key: str) -> None:
    if state_key == "week_selector_value":
        value = st.session_state.get(state_key)
        if value:
            st.session_state["_manual_week_choice_v55"] = value


def _set_active_week_by_offset(offset: int) -> None:
    periods = available_periods(st.session_state.get("bundle", {}))
    labels = [period_display(y, w) for y, w in periods]
    if not labels:
        return
    current = st.session_state.get("week_selector_value")
    idx = labels.index(current) if current in labels else len(labels) - 1
    idx = max(0, min(len(labels) - 1, idx + int(offset)))
    st.session_state["week_selector_value"] = labels[idx]
    st.session_state["_manual_week_choice_v55"] = labels[idx]


def _selector_nav_v36(label: str, labels: List[str], state_key: str, key_prefix: str, current_idx: int, callback: Any) -> None:
    if not labels:
        st.markdown(f"<div class='cutoff-chip'><span>{_html(label)}</span><b>N/A</b></div>", unsafe_allow_html=True)
        return
    if state_key == "week_selector_value":
        current = st.session_state.get(state_key)
        if current in labels:
            current_idx = labels.index(current)
    left, middle, right = st.columns([.24, 1.0, .24], gap="small")
    with left:
        st.button("<", key=_key_v36(key_prefix, "prev", "v55"), use_container_width=True, disabled=(current_idx <= 0), on_click=callback, args=(-1,))
    with middle:
        if state_key == "week_selector_value":
            st.selectbox(label, labels, key=state_key, label_visibility="visible", on_change=_remember_selector_change_v55, args=(state_key,))
        else:
            st.selectbox(label, labels, key=state_key, label_visibility="visible")
    with right:
        st.button(">", key=_key_v36(key_prefix, "next", "v55"), use_container_width=True, disabled=(current_idx >= len(labels) - 1), on_click=callback, args=(1,))


