def _set_panel_choice_v58(label: str) -> None:
    _remember_current_week_v58(st.session_state.get("bundle", {}))
    st.session_state["panel_choice"] = label
    try:
        st.query_params.clear()
    except Exception:
        pass


def render_sidebar(bundle: Dict[str, Any]) -> Tuple[str, int, int]:
    _apply_url_panel_v32()
    logo_src = logo_mark_data_uri() or logo_data_uri()
    if logo_src:
        st.sidebar.markdown(f"<div class='sidebar-logo'><img src='{logo_src}'><span>Roger Campbell PM</span></div>", unsafe_allow_html=True)
    else:
        st.sidebar.markdown("<div class='sidebar-logo'><span>Roger Campbell PM</span></div>", unsafe_allow_html=True)
    st.sidebar.title("Control settings")
    st.sidebar.markdown("<div class='subsection-title'>Panel</div>", unsafe_allow_html=True)
    panel_labels = ["Executive overview", "Cost Status", "Rail On Site (ROS)", "Ponds", "Roads"]
    if st.session_state.get("panel_choice") not in panel_labels:
        st.session_state["panel_choice"] = "Executive overview"
    nav_labels = {"Executive overview": "Overview", "Cost Status": "Cost Status", "Rail On Site (ROS)": "Rail On Site (ROS)", "Ponds": "Ponds", "Roads": "Roads"}
    for label in panel_labels:
        st.sidebar.button(
            nav_labels.get(label, label),
            key=f"nav_v58_{label}",
            use_container_width=True,
            on_click=_set_panel_choice_v58,
            args=(label,),
        )
    st.sidebar.markdown(f"<div class='nav-active'>Current panel: {_html(st.session_state['panel_choice'])}</div>", unsafe_allow_html=True)
    st.sidebar.markdown("---")
    st.sidebar.markdown("<div class='subsection-title'>Upload / refresh</div>", unsafe_allow_html=True)
    uploaded_weekly = st.sidebar.file_uploader("Upload new weekly report PDF/PPTX", type=["pdf", "pptx"], accept_multiple_files=True, key="weekly_upload_v58")
    if uploaded_weekly:
        key = _upload_list_hash(uploaded_weekly)
        if key != st.session_state.get("last_weekly_upload_key_v58"):
            with st.spinner("Parsing uploaded weekly report(s) and refreshing the control center..."):
                try:
                    incoming = parse_uploaded_reports(uploaded_weekly)
                    st.session_state["bundle"] = merge_bundles(st.session_state["bundle"], incoming)
                    st.session_state["last_weekly_upload_key_v58"] = key
                    st.sidebar.success(f"{len(uploaded_weekly)} weekly report(s) parsed and loaded.")
                    _safe_rerun()
                except Exception as exc:
                    st.sidebar.error(f"Could not parse weekly upload: {exc}")
    uploaded_cost_reports = st.sidebar.file_uploader("Upload monthly cost report XLSX", type=["xlsx"], accept_multiple_files=True, key="cost_upload_v58")
    if uploaded_cost_reports:
        key = _upload_list_hash(uploaded_cost_reports)
        if key != st.session_state.get("last_cost_upload_key_v58"):
            loaded = 0
            errors: List[str] = []
            for uploaded in uploaded_cost_reports:
                try:
                    _register_uploaded_cost_report(uploaded)
                    loaded += 1
                except Exception as exc:
                    errors.append(f"{uploaded.name}: {exc}")
            st.session_state["last_cost_upload_key_v58"] = key
            try:
                cached_monthly_cost_reports.clear()
            except Exception:
                pass
            if loaded:
                refreshed = _cost_reports()
                if refreshed:
                    st.session_state["monthly_cost_report_choice_portfolio"] = refreshed[-1]["label"]
                st.sidebar.success(f"{loaded} cost report(s) uploaded and registered.")
            for msg in errors:
                st.sidebar.error(f"Could not parse cost report - {msg}")
            if loaded:
                _safe_rerun()
    uploaded_baselines = st.sidebar.file_uploader("Upload schedule baseline PDF", type=["pdf"], accept_multiple_files=True, key="baseline_upload_v58")
    if uploaded_baselines:
        key = _upload_list_hash(uploaded_baselines)
        if key != st.session_state.get("last_baseline_upload_key_v58"):
            loaded = 0
            errors: List[str] = []
            for uploaded in uploaded_baselines:
                try:
                    _register_uploaded_baseline(uploaded)
                    loaded += 1
                except Exception as exc:
                    errors.append(f"{uploaded.name}: {exc}")
            st.session_state["last_baseline_upload_key_v58"] = key
            try:
                cached_baseline_schedules.clear()
            except Exception:
                pass
            if loaded:
                refreshed = _baseline_reports()
                if refreshed:
                    st.session_state["baseline_choice"] = refreshed[-1]["label"]
                st.sidebar.success(f"{loaded} baseline file(s) uploaded and registered.")
            for msg in errors:
                st.sidebar.error(f"Could not parse baseline - {msg}")
            if loaded:
                _safe_rerun()
    if st.sidebar.button("Save current session data", use_container_width=True, key="save_session_v58"):
        save_bundle(st.session_state["bundle"], DATA_PATH)
        try:
            cached_bundle.clear()
        except Exception:
            pass
        st.sidebar.success("Saved weekly data to data/weekly_data_bundle.json")
    y, w = _selected_period_from_state_v32(st.session_state.get("bundle", bundle))
    return st.session_state["panel_choice"], int(y), int(w)


# -----------------------------------------------------------------------------
# v59: Do not modify the Week widget key after the widget has been instantiated.
# Defaults run before controls; period reads are read-only after controls exist.
# -----------------------------------------------------------------------------

def _set_state_value_v59(key: str, value: Any) -> bool:
    if st.session_state.get(key) == value:
        return True
    try:
        st.session_state[key] = value
        return True
    except Exception:
        return False


