def _selected_period_from_state_v32(bundle: Dict[str, Any]) -> Tuple[int, int]:
    periods = available_periods(bundle)
    if not periods:
        iso = pd.Timestamp.today().isocalendar()
        return int(iso.year), int(iso.week)
    labels = [period_display(y, w) for y, w in periods]
    selected = st.session_state.get("week_selector_value")
    if selected in labels:
        return periods[labels.index(selected)]
    latest_year, latest_week = periods[-1]
    _set_state_value_v59("week_selector_value", period_display(latest_year, latest_week))
    return int(latest_year), int(latest_week)


# -----------------------------------------------------------------------------
# v60: Control pressure heatmap hover uses a compact six-week color bar only.
# -----------------------------------------------------------------------------

def _pm_heatmap_history_bar_v60(items: List[Tuple[str, float, str]]) -> str:
    if not items:
        return ""
    blocks = []
    for _week_label, score, _detail in items[-6:]:
        color = _heatmap_pressure_color_v55(score)
        blocks.append(f"<span style='color:{color};font-weight:900;font-size:17px;letter-spacing:1px'>&#9608;</span>")
    return "".join(blocks)


def _pm_heatmap_figure_v55(assessments: List[Dict[str, Any]], selected_year: int, selected_week: int, current_date: Optional[pd.Timestamp]) -> go.Figure:
    metrics, scopes, z = _pm_heatmap_matrix_v55(assessments)
    history = _pm_heatmap_history_v55(selected_year, selected_week, current_date)
    custom: List[List[List[str]]] = []
    for row_idx, assessment in enumerate(assessments):
        scope_id = str(assessment.get("scope_id") or assessment.get("scope") or "")
        row_custom = []
        for col_idx, metric in enumerate(metrics):
            current_detail = _pm_heatmap_detail_v55(assessment, metric)
            history_bar = _pm_heatmap_history_bar_v60(history.get((scope_id, metric), []))
            row_custom.append([_html(current_detail), history_bar])
        custom.append(row_custom)
    fig = go.Figure(data=go.Heatmap(
        z=z,
        x=metrics,
        y=scopes,
        zmin=0,
        zmax=10,
        xgap=6,
        ygap=6,
        colorscale=[[0, "#16a34a"], [.5, "#facc15"], [1, "#dc2626"]],
        showscale=False,
        customdata=custom,
        hovertemplate="<b>%{y}</b><br>%{x}: %{z:.1f}/10<br>%{customdata[0]}<br>%{customdata[1]}<extra></extra>",
    ))
    fig.update_yaxes(autorange="reversed")
    fig.update_layout(
        height=285,
        margin=dict(l=38, r=12, t=20, b=34),
        paper_bgcolor="rgba(0,0,0,0)",
        plot_bgcolor="rgba(0,0,0,0)",
        font=dict(family="Segoe UI, Arial, sans-serif", size=11, color="#1f2937"),
        hoverlabel=dict(bgcolor="#111827", bordercolor="#111827", font=dict(color="#ffffff", size=12)),
    )
    fig.update_xaxes(showgrid=False, zeroline=False)
    fig.update_yaxes(showgrid=False, zeroline=False)
    return fig


# -----------------------------------------------------------------------------
# v61: Treat any valid selected week as intentional. Only default to latest when
# there is no valid week in state yet.
# -----------------------------------------------------------------------------

def _latest_defaults_v32(bundle: Dict[str, Any]) -> None:
    periods = available_periods(bundle)
    week_labels = [period_display(y, w) for y, w in periods]
    preserved_week = st.session_state.pop("_preserve_week_after_cost_scope_v54", None)
    manual_week = st.session_state.get("_manual_week_choice_v55")
    if week_labels:
        latest_week = week_labels[-1]
        current_week = st.session_state.get("week_selector_value")
        previous_auto_week = st.session_state.get("_latest_week_applied_v32")
        if preserved_week in week_labels:
            if _set_state_value_v59("week_selector_value", preserved_week):
                st.session_state["_manual_week_choice_v55"] = preserved_week
                st.session_state["_latest_week_applied_v32"] = latest_week
        elif manual_week in week_labels:
            if _set_state_value_v59("week_selector_value", manual_week):
                st.session_state["_latest_week_applied_v32"] = latest_week
        elif current_week in week_labels:
            if current_week != latest_week:
                st.session_state["_manual_week_choice_v55"] = current_week
            elif previous_auto_week != latest_week:
                st.session_state["_latest_week_applied_v32"] = latest_week
        else:
            if _set_state_value_v59("week_selector_value", latest_week):
                st.session_state["_latest_week_applied_v32"] = latest_week

    cost_labels = _month_labels_v29() if "_month_labels_v29" in globals() else [r.get("label") for r in _cost_reports() if r.get("label")]
    preserved_month = st.session_state.pop("_preserve_month_after_cost_scope_v54", None)
    if cost_labels:
        latest_month = cost_labels[-1]
        current_month = st.session_state.get("monthly_cost_report_choice_portfolio")
        if preserved_month in cost_labels:
            if _set_state_value_v59("monthly_cost_report_choice_portfolio", preserved_month):
                st.session_state["_latest_month_applied_v32"] = latest_month
        elif current_month in cost_labels:
            if st.session_state.get("_latest_month_applied_v32") != latest_month:
                st.session_state["_latest_month_applied_v32"] = latest_month
        else:
            if _set_state_value_v59("monthly_cost_report_choice_portfolio", latest_month):
                st.session_state["_latest_month_applied_v32"] = latest_month

    bl_labels = [r.get("label") for r in _baseline_reports() if r.get("label")]
    preserved_baseline = st.session_state.pop("_preserve_baseline_after_cost_scope_v54", None)
    if bl_labels:
        latest_baseline = bl_labels[-1]
        current_baseline = st.session_state.get("baseline_choice")
        if preserved_baseline in bl_labels:
            if _set_state_value_v59("baseline_choice", preserved_baseline):
                st.session_state["_latest_baseline_applied_v32"] = latest_baseline
        elif current_baseline in bl_labels:
            if st.session_state.get("_latest_baseline_applied_v32") != latest_baseline:
                st.session_state["_latest_baseline_applied_v32"] = latest_baseline
        else:
            if _set_state_value_v59("baseline_choice", latest_baseline):
                st.session_state["_latest_baseline_applied_v32"] = latest_baseline


# -----------------------------------------------------------------------------
# v62: Rebuild the Cost Status scope control as one dropdown and remove all
# text from Control pressure heatmap hover details.
# -----------------------------------------------------------------------------

def _remember_current_week_v58(bundle: Optional[Dict[str, Any]] = None) -> None:
    source = bundle or st.session_state.get("bundle", {})
    labels = [period_display(y, w) for y, w in available_periods(source)]
    week = st.session_state.get("week_selector_value") or st.session_state.get("_manual_week_choice_v55")
    if week in labels:
        st.session_state["_manual_week_choice_v55"] = week
        st.session_state["_preserve_week_after_cost_scope_v54"] = week


def _remember_cost_scope_dropdown_v56() -> None:
    labels = _cost_scope_labels_v40()
    label = st.session_state.get("cost_scope_visual_selector")
    if label not in labels and labels:
        # The callback normally receives a valid selectbox value; this protects
        # old sessions that still hold the removed "All scopes" option.
        try:
            st.session_state["cost_scope_visual_selector"] = labels[0]
        except Exception:
            pass

    _remember_current_week_v58(st.session_state.get("bundle", {}))
    month = st.session_state.get("monthly_cost_report_choice_portfolio")
    baseline = st.session_state.get("baseline_choice")
    if month:
        st.session_state["_preserve_month_after_cost_scope_v54"] = month
    if baseline:
        st.session_state["_preserve_baseline_after_cost_scope_v54"] = baseline


