# -----------------------------------------------------------------------------
# v63: Keep the visible Week dropdown synchronized to the active week after
# using Cost Status, where the Week widget is intentionally hidden.
# -----------------------------------------------------------------------------

ACTIVE_WEEK_KEY_V63 = "_active_week_choice_v63"


def _week_labels_v63(bundle: Dict[str, Any]) -> List[str]:
    return [period_display(y, w) for y, w in available_periods(bundle)]


def _active_week_label_v63(bundle: Dict[str, Any]) -> str:
    labels = _week_labels_v63(bundle)
    if not labels:
        iso = pd.Timestamp.today().isocalendar()
        return period_display(int(iso.year), int(iso.week))
    for value in (
        st.session_state.get("_preserve_week_after_cost_scope_v54"),
        st.session_state.get("week_selector_value"),
        st.session_state.get(ACTIVE_WEEK_KEY_V63),
        st.session_state.get("_manual_week_choice_v55"),
    ):
        if value in labels:
            return str(value)
    return labels[-1]


def _sync_active_week_v63(bundle: Dict[str, Any], update_widget: bool = True) -> str:
    labels = _week_labels_v63(bundle)
    if not labels:
        return _active_week_label_v63(bundle)
    active = _active_week_label_v63(bundle)
    st.session_state[ACTIVE_WEEK_KEY_V63] = active
    st.session_state["_manual_week_choice_v55"] = active
    if update_widget:
        _set_state_value_v59("week_selector_value", active)
    return active


def _remember_selector_change_v55(state_key: str) -> None:
    if state_key == "week_selector_value":
        bundle = st.session_state.get("bundle", {})
        labels = _week_labels_v63(bundle)
        value = st.session_state.get(state_key)
        if value in labels:
            st.session_state[ACTIVE_WEEK_KEY_V63] = value
            st.session_state["_manual_week_choice_v55"] = value


def _set_active_week_by_offset(offset: int) -> None:
    bundle = st.session_state.get("bundle", {})
    periods = available_periods(bundle)
    labels = [period_display(y, w) for y, w in periods]
    if not labels:
        return
    current = _active_week_label_v63(bundle)
    idx = labels.index(current) if current in labels else len(labels) - 1
    idx = max(0, min(len(labels) - 1, idx + int(offset)))
    st.session_state["week_selector_value"] = labels[idx]
    st.session_state[ACTIVE_WEEK_KEY_V63] = labels[idx]
    st.session_state["_manual_week_choice_v55"] = labels[idx]


def _remember_current_week_v58(bundle: Optional[Dict[str, Any]] = None) -> None:
    source = bundle or st.session_state.get("bundle", {})
    labels = _week_labels_v63(source)
    week = _active_week_label_v63(source)
    if week in labels:
        st.session_state[ACTIVE_WEEK_KEY_V63] = week
        st.session_state["_manual_week_choice_v55"] = week
        st.session_state["_preserve_week_after_cost_scope_v54"] = week


def _latest_defaults_v32(bundle: Dict[str, Any]) -> None:
    periods = available_periods(bundle)
    week_labels = [period_display(y, w) for y, w in periods]
    preserved_week = st.session_state.pop("_preserve_week_after_cost_scope_v54", None)
    if week_labels:
        latest_week = week_labels[-1]
        chosen_week = next(
            (
                value
                for value in (
                    preserved_week,
                    st.session_state.get("week_selector_value"),
                    st.session_state.get(ACTIVE_WEEK_KEY_V63),
                    st.session_state.get("_manual_week_choice_v55"),
                )
                if value in week_labels
            ),
            latest_week,
        )
        st.session_state[ACTIVE_WEEK_KEY_V63] = chosen_week
        st.session_state["_manual_week_choice_v55"] = chosen_week
        _set_state_value_v59("week_selector_value", chosen_week)
        st.session_state["_latest_week_applied_v32"] = latest_week

    cost_labels = _month_labels_v29() if "_month_labels_v29" in globals() else [r.get("label") for r in _cost_reports() if r.get("label")]
    preserved_month = st.session_state.pop("_preserve_month_after_cost_scope_v54", None)
    if cost_labels:
        latest_month = cost_labels[-1]
        current_month = st.session_state.get("monthly_cost_report_choice_portfolio")
        if preserved_month in cost_labels:
            if _set_state_value_v59("monthly_cost_report_choice_portfolio", preserved_month):
                st.session_state["_latest_month_applied_v32"] = latest_month
        elif current_month in cost_labels:
            if st.session_state.get("_latest_month_applied_v32") != latest_month:
                st.session_state["_latest_month_applied_v32"] = latest_month
        else:
            if _set_state_value_v59("monthly_cost_report_choice_portfolio", latest_month):
                st.session_state["_latest_month_applied_v32"] = latest_month

    bl_labels = [r.get("label") for r in _baseline_reports() if r.get("label")]
    preserved_baseline = st.session_state.pop("_preserve_baseline_after_cost_scope_v54", None)
    if bl_labels:
        latest_baseline = bl_labels[-1]
        current_baseline = st.session_state.get("baseline_choice")
        if preserved_baseline in bl_labels:
            if _set_state_value_v59("baseline_choice", preserved_baseline):
                st.session_state["_latest_baseline_applied_v32"] = latest_baseline
        elif current_baseline in bl_labels:
            if st.session_state.get("_latest_baseline_applied_v32") != latest_baseline:
                st.session_state["_latest_baseline_applied_v32"] = latest_baseline
        else:
            if _set_state_value_v59("baseline_choice", latest_baseline):
                st.session_state["_latest_baseline_applied_v32"] = latest_baseline


def _selected_period_from_state_v32(bundle: Dict[str, Any]) -> Tuple[int, int]:
    periods = available_periods(bundle)
    if not periods:
        iso = pd.Timestamp.today().isocalendar()
        return int(iso.year), int(iso.week)
    labels = [period_display(y, w) for y, w in periods]
    selected = _active_week_label_v63(bundle)
    if selected in labels:
        st.session_state[ACTIVE_WEEK_KEY_V63] = selected
        return periods[labels.index(selected)]
    latest_year, latest_week = periods[-1]
    latest_label = period_display(latest_year, latest_week)
    st.session_state[ACTIVE_WEEK_KEY_V63] = latest_label
    _set_state_value_v59("week_selector_value", latest_label)
    return int(latest_year), int(latest_week)


